add_apostol {
  ["номер"] = 1,
  ["комментарий"] = "Деян., 1 зач., I, 1–8.",
  ["текст_ру"] = "Пе́рвое у́бо сло́во сотвори́х о всех, о Фео́филе, я́же нача́т Иису́с твори́ти же и учи́ти да́же до дне, во́ньже, запове́дав апо́столом Ду́хом Святы́м, и́хже избра́, вознесе́ся. Пред ни́миже и поста́ви Себе́ жи́ва по страда́нии Свое́м во мно́зех и́стинных зна́мениих, де́ньми четы́редесятьми явля́яся им и глаго́ля я́же о Ца́рствии Бо́жии. С ни́миже и яды́й, повеле́ им от Иерусали́ма не отлуча́тися, но жда́ти обетова́ния О́тча, е́же слы́шасте от Мене́: я́ко Иоа́нн у́бо крести́л есть водо́ю, вы же и́мате крести́тися Ду́хом Святы́м, не по мно́зех сих днех. Они́ же у́бо соше́дшеся, вопроша́ху Его́, глаго́люще: Го́споди, а́ще в ле́то сие́ устроя́еши ца́рствие Изра́илево? Рече́ же к ним: несть ва́ше разуме́ти времена́ и ле́та, я́же Оте́ц положи́ во Свое́й вла́сти. Но прии́мете си́лу, наше́дшу Свято́му Ду́ху на вы, и бу́дете Ми свиде́тели во Иерусали́ме же и во всей Иуде́и и Самари́и, и да́же до после́дних земли́. ",
  ["текст_цс"] = "﻿Пе́рвое ᲂу҆́бѡ сло́во сотвори́хъ ѡ҆ всѣ́хъ ѽ ѳео́фїле, ꙗ҆̀же нача́тъ і҆и҃съ твори́ти же и҆ ᲂу҆чи́ти, да́же до днѐ, во́ньже заповѣ́давъ а҆пⷭ҇толѡмъ дх҃омъ ст҃ы́мъ, и҆̀хже и҆збра̀, вознесе́сѧ. пред̾ ни́миже и҆ поста́ви себѐ жи́ва по страда́нїи свое́мъ, во мно́зѣхъ [и҆́стинныхъ] зна́менїихъ де́ньми четы́редесѧтьми ꙗ҆влѧ́ѧсѧ и҆̀мъ, и҆ глаго́лѧ ꙗ҆̀же ѡ҆ црⷭ҇твїи бж҃їи. съ ни́миже и҆ ꙗ҆ды́й, повелѣ̀ и҆̀мъ ѿ і҆ерꙋсали́ма не ѿлꙋча́тисѧ, но жда́ти ѡ҆бѣтова́нїѧ ѻ҆́ч҃а, є҆́же слы́шасте ѿ менѐ: ꙗ҆́кѡ і҆ѡа́ннъ ᲂу҆́бѡ крⷭ҇ти́лъ є҆́сть водо́ю, вы́ же и҆́мате крⷭ҇ти́тисѧ дх҃омъ ст҃ы́мъ, не по мно́зѣхъ си́хъ дне́хъ. ѻ҆ни́ же ᲂу҆̀бо соше́дшесѧ, вопроша́хꙋ є҆го̀, глаго́люще: гдⷭ҇и, а҆́ще въ лѣ́то сїѐ ᲂу҆строѧ́еши црⷭ҇твїе і҆и҃лево; рече́ же къ ни́мъ: нѣ́сть ва́ше разꙋмѣ́ти времена̀ и҆ лѣ́та, ꙗ҆̀же ѻ҆ц҃ъ положѝ во свое́й вла́сти. но прїи́мете си́лꙋ, наше́дшꙋ ст҃о́мꙋ дх҃ꙋ на вы̀: и҆ бꙋ́дете мѝ свидѣ́тели во і҆ерꙋсали́мѣ же и҆ во все́й і҆ꙋде́и и҆ самарі́и, и҆ да́же до послѣ́днихъ землѝ. ",
}

add_apostol {
  ["номер"] = 1,
  ["комментарий"] = "Деян., 1 зач., I, 1–12.",
  ["текст_ру"] = "Пе́рвое у́бо сло́во сотвори́х о всех, о Фео́филе, я́же нача́т Иису́с твори́ти же и учи́ти да́же до дне, во́ньже, запове́дав апо́столом Ду́хом Святы́м, и́хже избра́, вознесе́ся. Пред ни́миже и поста́ви Себе́ жи́ва по страда́нии Свое́м во мно́зех и́стинных зна́мениих, де́ньми четы́редесятьми явля́яся им и глаго́ля я́же о Ца́рствии Бо́жии. С ни́миже и яды́й, повеле́ им от Иерусали́ма не отлуча́тися, но жда́ти обетова́ния О́тча, е́же слы́шасте от Мене́: я́ко Иоа́нн у́бо крести́л есть водо́ю, вы же и́мате крести́тися Ду́хом Святы́м, не по мно́зех сих днех. Они́ же у́бо соше́дшеся, вопроша́ху Его́, глаго́люще: Го́споди, а́ще в ле́то сие́ устроя́еши ца́рствие Изра́илево? Рече́ же к ним: несть ва́ше разуме́ти времена́ и ле́та, я́же Оте́ц положи́ во Свое́й вла́сти. Но прии́мете си́лу, наше́дшу Свято́му Ду́ху на вы, и бу́дете Ми свиде́телие во Иерусали́ме же и во всей Иуде́и и Самари́и, и да́же до после́дних земли́. И сия́ рек, зря́щим им, взя́тся, и о́блак подъя́т Его́ от о́чию их. И я́ко взира́юще бя́ху на не́бо, иду́щу Ему́, и се му́жа два ста́ста пред ни́ми во оде́жди беле́. Я́же и реко́ста: му́жие Галиле́йстии, что стоите́ зря́ще на не́бо? Сей Иису́с, вознесы́йся от вас на не́бо, та́кожде прии́дет, и́мже о́бразом ви́десте Его́ иду́ща на не́бо. Тогда́ возврати́шася во Иерусали́м от горы́ нарица́емыя Елео́н, я́же есть близ Иерусали́ма, суббо́ты иму́щия путь. ",
  ["текст_цс"] = "Пе́рвое ᲂу҆́бѡ сло́во сотвори́хъ ѡ҆ всѣ́хъ ѽ ѳео́фїле, ꙗ҆̀же нача́тъ і҆и҃съ твори́ти же и҆ ᲂу҆чи́ти, да́же до днѐ, во́ньже заповѣ́давъ а҆пⷭ҇толѡмъ дх҃омъ ст҃ы́мъ, и҆̀хже и҆збра̀, вознесе́сѧ. пред̾ ни́миже и҆ поста́ви себѐ жи́ва по страда́нїи свое́мъ, во мно́зѣхъ [и҆́стинныхъ] зна́менїихъ де́ньми четы́редесѧтьми ꙗ҆влѧ́ѧсѧ и҆̀мъ, и҆ глаго́лѧ ꙗ҆̀же ѡ҆ црⷭ҇твїи бж҃їи. съ ни́миже и҆ ꙗ҆ды́й, повелѣ̀ и҆̀мъ ѿ і҆ерꙋсали́ма не ѿлꙋча́тисѧ, но жда́ти ѡ҆бѣтова́нїѧ ѻ҆́ч҃а, є҆́же слы́шасте ѿ менѐ: ꙗ҆́кѡ і҆ѡа́ннъ ᲂу҆́бѡ крⷭ҇ти́лъ є҆́сть водо́ю, вы́ же и҆́мате крⷭ҇ти́тисѧ дх҃омъ ст҃ы́мъ, не по мно́зѣхъ си́хъ дне́хъ. ѻ҆ни́ же ᲂу҆̀бо соше́дшесѧ, вопроша́хꙋ є҆го̀, глаго́люще: гдⷭ҇и, а҆́ще въ лѣ́то сїѐ ᲂу҆строѧ́еши црⷭ҇твїе і҆и҃лево; рече́ же къ ни́мъ: нѣ́сть ва́ше разꙋмѣ́ти времена̀ и҆ лѣ́та, ꙗ҆̀же ѻ҆ц҃ъ положѝ во свое́й вла́сти. но прїи́мете си́лꙋ, наше́дшꙋ ст҃о́мꙋ дх҃ꙋ на вы̀: и҆ бꙋ́дете мѝ свидѣ́тели во і҆ерꙋсали́мѣ же и҆ во все́й і҆ꙋде́и и҆ самарі́и, и҆ да́же до послѣ́днихъ землѝ. и҆ сїѧ̑ ре́къ, зрѧ́щымъ и҆̀мъ, взѧ́тсѧ: и҆ ѻ҆́блакъ под̾ѧ́тъ є҆го̀ ѿ ѻ҆́чїю и҆́хъ. и҆ ꙗ҆́кѡ взира́юще бѧ́хꙋ на нб҃о, и҆дꙋ́щꙋ є҆мꙋ̀, и҆ сѐ мꙋ́жа два̀ ста́ста пред̾ ни́ми во ѻ҆де́жди бѣлѣ̀, ꙗ҆̀же и҆ реко́ста: мꙋ́жїе галїле́йстїи, что̀ стоитѐ зрѧ́ще на нб҃о; се́й і҆и҃съ вознесы́йсѧ ѿ ва́съ на нб҃о, та́кожде прїи́детъ, и҆́мже ѻ҆́бразомъ ви́дѣсте є҆го̀ и҆дꙋ́ща на нб҃о. тогда̀ возврати́шасѧ во і҆ерꙋсали́мъ ѿ горы̀ нарица́емыѧ є҆леѡ́нъ, ꙗ҆́же є҆́сть бли́зъ і҆ерꙋсали́ма, сꙋббѡ́ты и҆мꙋ́щїѧ пꙋ́ть. ",
