add_apostol {
  ["номер"] = 2,
  ["комментарий"] = "Деян., 2 зач., I, 12–17, 21–26.",
  ["текст_ру"] = "Во дни о́ны, возврати́шася апо́столи во Иерусали́м от горы́ нарица́емыя Елео́н, я́же есть близ Иерусали́ма, суббо́ты иму́щия путь. И егда́ внидо́ша, взыдо́ша на го́рницу, иде́же бя́ху пребыва́юще, Петр же и Иа́ков, и Иоа́нн и Андре́й, Фили́пп и Фома́, Варфоломе́й и Матфе́й, Иа́ков Алфе́ов и Си́мон Зило́т и Иу́да Иа́ковль. Си́и вси бя́ху терпя́ще единоду́шно в моли́тве и моле́нии, с жена́ми и Мари́ею Ма́терию Иису́совою и с бра́тиею Его́. И во дни ты́я воста́в Петр посреде́ учени́к, рече́, бе же име́н наро́да вку́пе я́ко сто и два́десять: му́жие бра́тие, подоба́ше сконча́тися Писа́нию сему́, е́же предрече́ Дух Святы́й усты́ Дави́довыми о Иу́де, бы́вшем вожди́ е́мшим Иису́са, я́ко причте́н бе с на́ми и прия́л бя́ше жре́бий слу́жбы сея́, подоба́ет у́бо от сходи́вшихся с на́ми муже́й во вся́ко ле́то, в не́же вни́де и изы́де в нас Госпо́дь Иису́с, наче́н от креще́ния Иоа́ннова да́же до дне, во́ньже вознесе́ся на не́бо от нас, свиде́телю воскресе́ния Его́ бы́ти с на́ми еди́ному от сих. И поста́виша два, Ио́сифа нарица́емаго Варса́ву, и́же нарече́н бысть Иу́ст, и Матфи́а, и помоли́вшеся ре́ша: Ты, Го́споди, Сердцеве́дче всех, покажи́, его́же избра́л еси́ от сею́ двою́ еди́наго, прия́ти жре́бий служе́ния сего́ и апо́стольства, из него́же испаде́ Иу́да, ити́ в ме́сто свое́. И да́ша жре́бия и́ма, и паде́ жре́бий на Матфи́а, и причте́н бысть ко единона́десяти апо́столом. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, возврати́шасѧ а҆пⷭ҇ли во і҆ерꙋсали́мъ ѿ горы̀ нарица́емыѧ є҆леѡ́нъ, ꙗ҆́же є҆́сть бли́зъ і҆ерꙋсали́ма, сꙋббѡ́ты и҆мꙋ́щїѧ пꙋ́ть. и҆ є҆гда̀ внидо́ша, взыдо́ша на го́рницꙋ, и҆дѣ́же бѧ́хꙋ пребыва́юще, пе́тръ же и҆ і҆а́кѡвъ, и҆ і҆ѡа́ннъ и҆ а҆ндре́й, фїлі́ппъ и҆ ѳѡма̀, варѳоломе́й и҆ матѳе́й, і҆а́кѡвъ а҆лфе́овъ, и҆ сі́мѡнъ зилѡ́тъ, и҆ і҆ꙋ́да і҆а́кѡвль. сі́и всѝ бѧ́хꙋ терпѧ́ще є҆динодꙋ́шнѡ въ моли́твѣ и҆ моле́нїи, съ жена́ми, и҆ марі́ею мт҃рїю і҆и҃совою, и҆ съ бра́тїею є҆гѡ̀. и҆ во днѝ ты́ѧ, воста́въ пе́тръ посредѣ̀ ᲂу҆чени̑къ, речѐ: [бѣ́ же и҆ме́нъ наро́да вкꙋ́пѣ, ꙗ҆́кѡ сто̀ и҆ два́десѧть:] мꙋ́жїе бра́тїе, подоба́ше сконча́тисѧ писа́нїю семꙋ̀, є҆́же предречѐ дх҃ъ ст҃ы́й ᲂу҆сты̀ дв҃довыми ѡ҆ і҆ꙋ́дѣ, бы́вшемъ вождѝ є҆́мшымъ і҆и҃са: ꙗ҆́кѡ причте́нъ бѣ̀ съ на́ми, и҆ прїѧ́лъ бѧ́ше жре́бїй слꙋ́жбы сеѧ̀. подоба́етъ ᲂу҆̀бо ѿ сходи́вшихсѧ съ на́ми мꙋже́й, во всѧ́ко лѣ́то, въ не́же вни́де и҆ и҆зы́де въ на́съ гдⷭ҇ь і҆и҃съ: наче́нъ ѿ креще́нїѧ і҆ѡа́ннова, да́же до днѐ, во́ньже вознесе́сѧ [на нб҃о] ѿ на́съ, свидѣ́телю воскрⷭ҇нїѧ є҆гѡ̀ бы́ти съ на́ми є҆ди́номꙋ ѿ си́хъ. и҆ поста́виша два̀, і҆ѡ́сифа, нарица́емаго варса́вꙋ, и҆́же нарече́нъ бы́сть і҆ꙋ́стъ, и҆ матѳі́а. и҆ помоли́вшесѧ, рѣ́ша: ты̀ гдⷭ҇и сердцевѣ́дче всѣ́хъ, покажѝ є҆го́же и҆збра́лъ є҆сѝ ѿ сею̀ двою̀ є҆ди́наго, прїѧ́ти жре́бїй слꙋже́нїѧ сегѡ̀ и҆ а҆по́стольства, и҆з̾ негѡ́же и҆спадѐ і҆ꙋ́да, и҆тѝ въ мѣ́сто своѐ. и҆ да́ша жрє́бїѧ и҆́ма: и҆ падѐ жре́бїй на матѳі́а, и҆ причте́нъ бы́сть ко є҆динона́десѧти а҆пⷭ҇толѡмъ. ",
}

add_apostol {
  ["номер"] = 3,
  ["комментарий"] = "Деян., 3 зач., II, 1–11.",
  ["текст_ру"] = "Во дни о́ны, егда́ скончава́шася дни́е Пятьдеся́тницы, бе́ша вси апо́столи единоду́шно вку́пе. И бысть внеза́пу с небесе́ шум, я́ко носи́му дыха́нию бу́рну, и испо́лни весь дом, иде́же бя́ху седя́ще, и яви́шася им разделе́ни язы́цы я́ко о́гненни, се́де же на еди́ном ко́емждо их. И испо́лнишася вси Ду́ха Свя́та и нача́ша глаго́лати ины́ми язы́ки, я́коже Дух дая́ше им провещава́ти. Бя́ху же во Иерусали́ме живу́щии иуде́е, му́жие благогове́йнии, от всего́ язы́ка, и́же под небесе́м. Бы́вшу же гла́су сему́, сни́деся наро́д и смяте́ся, я́ко слы́шаху еди́н ко́йждо их свои́м язы́ком глаго́лющих их. Дивля́хуся же вси и чудя́хуся, глаго́люще друг ко дру́гу: не се ли, вси си́и суть глаго́лющии галиле́ане? И ка́ко мы слы́шим ко́ждо свой язы́к наш, в не́мже роди́хомся, па́рфяне и ми́дяне и елами́те, и живу́щии в Месопота́мии, во Иуде́и же и Каппадоки́и, в По́нте и во Аси́и, во Фриги́и же и Памфили́и, во Еги́пте и страна́х Ливи́и, я́же при Кирини́и, и приходя́щии ри́мляне, иуде́и же и прише́льцы, кри́тяне и ара́вляне, слы́шим глаго́лющих их на́шими язы́ки вели́чия Бо́жия. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, є҆гда̀ скончава́шасѧ дні́е пѧтьдесѧ́тницы, бѣ́ша всѝ а҆пⷭ҇ли є҆динодꙋ́шнѡ вкꙋ́пѣ. и҆ бы́сть внеза́пꙋ съ нб҃сѐ шꙋ́мъ, ꙗ҆́кѡ носи́мꙋ дыха́нїю бꙋ́рнꙋ, и҆ и҆спо́лни ве́сь до́мъ, и҆дѣ́же бѧ́хꙋ сѣдѧ́ще. и҆ ꙗ҆ви́шасѧ и҆̀мъ раздѣле́ни ѧ҆зы́цы ꙗ҆́кѡ ѻ҆́гненни, сѣ́де же на є҆ди́номъ ко́емждо и҆́хъ. и҆ и҆спо́лнишасѧ всѝ дх҃а ст҃а, и҆ нача́ша глаго́лати и҆ны́ми ѧ҆зы́ки, ꙗ҆́коже дх҃ъ даѧ́ше и҆̀мъ провѣщава́ти. бѧ́хꙋ же во і҆ерꙋсали́мѣ живꙋ́щїи і҆ꙋдє́и, мꙋ́жїе благоговѣ́йнїи ѿ всегѡ̀ ꙗ҆зы́ка, и҆́же под̾ нб҃се́мъ. бы́вшꙋ же гла́сꙋ семꙋ̀, сни́десѧ наро́дъ и҆ смѧте́сѧ, ꙗ҆́кѡ слы́шахꙋ є҆ди́нъ ко́йждо и҆́хъ свои́мъ ѧ҆зы́комъ глаго́лющихъ и҆̀хъ. дивлѧ́хꙋсѧ же всѝ и҆ чꙋдѧ́хꙋсѧ, глаго́люще дрꙋ́гъ ко дрꙋ́гꙋ: не се́ ли всѝ сі́и сꙋ́ть глаго́лющїи галїле́ане; и҆ ка́кѡ мы̀ слы́шимъ ко́ждо сво́й ѧ҆зы́къ на́шъ, въ не́мже роди́хомсѧ; па́рѳѧне, и҆ ми́дѧне, и҆ є҆ламі́те, и҆ живꙋ́щїи въ месопота́мїи, во і҆ꙋде́и же и҆ каппадокі́и, въ по́нтѣ и҆ во а҆сі́и, во фрѷгі́и же и҆ памфѷлі́и, во є҆гѵ́птѣ и҆ страна́хъ лївѵ́и, ꙗ҆́же при кѷрині́и, и҆ приходѧ́щїи ри́млѧне, і҆ꙋдє́и же и҆ прише́льцы, кри́тѧне и҆ а҆ра́влѧне, слы́шимъ глаго́лющихъ и҆̀хъ на́шими ѧ҆зы́ки вели́чїѧ бж҃їѧ. ",
}

