add_apostol {
  ["номер"] = 10,
  ["комментарий"] = "Деян., 10 зач., IV, 1–10.",
  ["текст_ру"] = "Во дни о́ны, глаго́лющым апо́столом к лю́дем, наидо́ша на них свяще́нницы и воево́да церко́вный и саддуке́и, жа́ляще си, за е́же учи́ти им лю́ди и возвеща́ти о Иису́се воскресе́ние ме́ртвых. И возложи́ша на них ру́ки и положи́ша их в соблюде́ние до у́трия, бе бо ве́чер уже́. Мно́зи же от слы́шавших сло́во ве́роваша: и бысть число́ муже́й я́ко ты́сящ пять. Бысть же нау́трие собра́тися князе́м их и ста́рцем и кни́жником во Иерусали́м, и А́нне архиере́ю и Каиа́фе и Иоа́нну и Алекса́ндру, и ели́цы бе́ша от ро́да архиере́йска, и поста́вльше их посреде́, вопроша́ху: ко́ею си́лою или́ ко́им и́менем сотвори́сте сие́ вы? Тогда́ Петр, испо́лнився Ду́ха Свя́та, рече́ к ним: кня́зи лю́дстии и ста́рцы изра́илевы, а́ще мы днесь истязу́еми есмы́ о благодея́нии челове́ка не́мощна, о чесо́м сей спасе́ся, разу́мно бу́ди всем вам и всем лю́дем изра́илевым, я́ко во и́мя Иису́са Христа́ Назоре́а, Его́же вы распя́сте, Его́же Бог воскреси́ от ме́ртвых, о Сем сей стои́т пред ва́ми здрав. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, глаго́лющымъ а҆пⷭ҇лѡмъ къ лю́демъ, наидо́ша на ни́хъ свѧще́нницы и҆ воево́да цр҃ко́вный, и҆ саддꙋкє́и: жа́лѧще сѝ, за є҆́же ᲂу҆чи́ти и҆̀мъ лю́ди, и҆ возвѣща́ти ѡ҆ і҆и҃сѣ воскрⷭ҇нїе ме́ртвыхъ: и҆ возложи́ша на ни́хъ рꙋ́ки, и҆ положи́ша и҆̀хъ въ соблюде́нїе до ᲂу҆́трїѧ: бѣ́ бо ве́черъ ᲂу҆жѐ. мно́зи же ѿ слы́шавшихъ сло́во, вѣ́роваша: и҆ бы́сть число̀ мꙋже́й ꙗ҆́кѡ ты́сѧщъ пѧ́ть. бы́сть же наꙋ́трїе собра́тисѧ кнѧзє́мъ и҆́хъ, и҆ ста́рцємъ, и҆ кни́жникѡмъ во і҆ерꙋсали́мъ: и҆ а҆́ннѣ а҆рхїере́ю, и҆ каїа́фѣ, и҆ і҆ѡа́ннꙋ, и҆ а҆леѯа́ндрꙋ, и҆ є҆ли́цы бѣ́ша ѿ ро́да а҆рхїере́йска. и҆ поста́вльше и҆̀хъ посредѣ̀, вопроша́хꙋ: ко́ею си́лою, и҆лѝ ко́имъ и҆́менемъ сотвори́сте сїѐ вы̀; тогда̀ пе́тръ и҆спо́лнивсѧ дх҃а ст҃а, речѐ къ ни́мъ: кнѧ́зи лю́дстїи и҆ ста́рцы і҆и҃левы, а҆́ще мы̀ дне́сь и҆стѧзꙋ́еми є҆смы̀ ѡ҆ благодѣѧ́нїи человѣ́ка не́мощна, ѡ҆ чесо́мъ се́й спасе́сѧ: разꙋ́мно бꙋ́ди всѣ́мъ ва́мъ, и҆ всѣ́мъ лю́демъ і҆и҃лєвымъ, ꙗ҆́кѡ во и҆́мѧ і҆и҃са хрⷭ҇та̀ назѡре́а, є҆го́же вы̀ распѧ́сте, є҆го́же бг҃ъ воскресѝ ѿ ме́ртвыхъ, ѡ҆ се́мъ се́й стои́тъ пред̾ ва́ми здра́въ. ",
}

add_apostol {
  ["номер"] = 11,
  ["комментарий"] = "Деян., 11 зач., IV, 13–22.",
  ["текст_ру"] = "Во дни о́ны, ви́дяще иуде́и Петро́во дерзнове́ние и Иоа́нново и разуме́вше, я́ко челове́ка некни́жна еста́ и про́ста, дивля́хуся, зна́ху же их, я́ко со Иису́сом бе́ста. Ви́дяще же исцеле́вшаго челове́ка с ни́ма стоя́ща, ничто́же имя́ху проти́ву рещи́. Повеле́вше же и́ма вон из со́нмища изы́ти, стяза́хуся ко друг дру́гу, глаго́люще: что сотвори́м челове́кома си́ма? Я́ко у́бо наро́читое зна́мение бысть и́ма, всем живу́щым во Иерусали́ме я́ве, и не мо́жем отврещи́ся, но да не бо́лее простре́тся в лю́дех, преще́нием да запрети́м и́ма ктому́ не глаго́лати о и́мени сем ни еди́ному от челове́к. И призва́вше их, запове́даша и́ма отню́д не провещава́ти ниже́ учи́ти о и́мени Иису́сове. Петр же и Иоа́нн отвеща́вше к ним ре́ста: а́ще пра́ведно есть пред Бо́гом вас послу́шати па́че, не́жели Бо́га, суди́те? Не мо́жем бо мы, я́же ви́дехом и слы́шахом, не глаго́лати. Они́ же призапре́щше и́ма, пусти́ша я́, ничто́же обре́тше ка́ко му́чити их, люде́й ра́ди, я́ко вси прославля́ху Бо́га о бы́вшем. Лет бо бя́ше мно́жае четы́редесяти челове́к той, на не́мже бысть чу́до сие́ исцеле́ния. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, ви́дѧще і҆ꙋдє́и петро́во дерзнове́нїе и҆ і҆ѡа́нново, и҆ разꙋмѣ́вше, ꙗ҆́кѡ человѣ́ка некни̑жна є҆ста̀ и҆ прѡ́ста, дивлѧ́хꙋсѧ: зна́хꙋ же и҆̀хъ, ꙗ҆́кѡ со і҆и҃сомъ бѣ́ста. ви́дѧще же и҆сцѣлѣ́вшаго человѣ́ка съ ни́ма стоѧ́ща, ничто́же и҆мѧ́хꙋ проти́вꙋ рещѝ. повелѣ́вше же и҆́ма во́нъ и҆з̾ со́нмища и҆зы́ти, стѧза́хꙋсѧ ко дрꙋгъдрꙋ́гꙋ, глаго́люще: что̀ сотвори́мъ человѣ́кома си́ма; ꙗ҆́кѡ ᲂу҆́бѡ наро́читое зна́менїе бы́сть и҆́ма, всѣ́мъ живꙋ́щымъ во і҆ерꙋсали́мѣ ꙗ҆́вѣ, и҆ не мо́жемъ ѿврещи́сѧ. но да не бо́лѣе простре́тсѧ въ лю́дехъ, преще́нїемъ да запрети́мъ и҆́ма, ктомꙋ̀ не глаго́лати ѡ҆ и҆́мени се́мъ ни є҆ди́номꙋ ѿ человѣ̑къ. и҆ призва́вше и҆̀хъ, заповѣ́даша и҆́ма ѿню́дъ не провѣщава́ти, нижѐ ᲂу҆чи́ти ѡ҆ и҆́мени і҆и҃совѣ. пе́тръ же и҆ і҆ѡа́ннъ ѿвѣща́вше къ ни́мъ, рѣ́ста: а҆́ще пра́ведно є҆́сть пред̾ бг҃омъ, ва́съ послꙋ́шати па́че, не́жели бг҃а, сꙋди́те; не мо́жемъ бо мы̀, ꙗ҆̀же ви́дѣхомъ и҆ слы́шахомъ, не глаго́лати. ѻ҆ни́ же призапре́щше и҆́ма, пꙋсти́ша ѧ҆̀, ничто́же ѡ҆брѣ́тше, ка́кѡ мꙋ́чити и҆̀хъ, люде́й ра́ди, ꙗ҆́кѡ всѝ прославлѧ́хꙋ бг҃а ѡ҆ бы́вшемъ. лѣ́тъ бо бѧ́ше мно́жае четы́редесѧти человѣ́къ то́й, на не́мже бы́сть чꙋ́до сїѐ и҆сцѣле́нїѧ. ",
}

add_apostol {
  ["номер"] = 12,
  ["комментарий"] = "Деян., 12 зач., IV, 23–31.",
  ["текст_ру"] = "Во дни о́ны, отпуще́на бы́вша апо́стола приидо́ста ко свои́м и возвести́ста, ели́ка к ни́ма архиере́и и ста́рцы ре́ша. Они́ же слы́шавше единоду́шно воздвиго́ша глас к Бо́гу и реко́ша: Влады́ко, Ты, Бо́же, сотвори́вый не́бо и зе́млю и мо́ре и вся, я́же в них, и́же усты́ Дави́да о́трока Твоего́ рече́: вску́ю шата́шася язы́цы, и лю́дие поучи́шася тще́тным? Предста́ша ца́рие зе́мстии, и кня́зи собра́шася вку́пе на Го́спода и на Христа́ Его́. Собра́шася бо вои́стинну во гра́де сем на Свята́го О́трока Твоего́ Иису́са, Его́же пома́зал еси́, И́род же и Понти́йский Пила́т с язы́ки и людьми́ изра́илевыми, сотвори́ти, ели́ка рука́ Твоя́ и сове́т Твой преднарече́ бы́ти. И ны́не, Го́споди, при́зри на преще́ния их и даждь рабо́м Твои́м со вся́ким дерзнове́нием глаго́лати сло́во Твое́, внегда́ ру́ку Твою́ простре́ти Ти во исцеле́ния, и зна́мением и чудесе́м быва́ти и́менем Святы́м О́трока Твоего́ Иису́са. И помоли́вшымся им, подви́жеся ме́сто, иде́же бя́ху со́брани, и испо́лнишася вси Ду́ха Свя́та и глаго́лаху сло́во Бо́жие со дерзнове́нием. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, ѿпꙋщє́на бы́вша а҆пⷭ҇ла прїидо́ста къ свои́мъ, и҆ возвѣсти́ста є҆ли̑ка къ ни́ма а҆рхїере́и и҆ ста́рцы рѣ́ша. ѻ҆ни́ же слы́шавше є҆динодꙋ́шнѡ воздвиго́ша гла́съ къ бг҃ꙋ, и҆ реко́ша: влⷣко, ты̀ бж҃е сотвори́вый нб҃о и҆ зе́млю и҆ мо́ре, и҆ всѧ̑ ꙗ҆̀же въ ни́хъ: и҆́же ᲂу҆сты̀ дв҃да ѻ҆́трока твоегѡ̀ речѐ: вскꙋ́ю шата́шасѧ ꙗ҆зы́цы, и҆ лю́дїе поꙋчи́шасѧ тщє́тнымъ; предста́ша ца́рїе зе́мстїи, и҆ кнѧ́зи собра́шасѧ вкꙋ́пѣ, на гдⷭ҇а и҆ на хрⷭ҇та̀ є҆гѡ̀. собра́шасѧ бо вои́стиннꙋ во гра́дѣ се́мъ на ст҃а́го ѻ҆́трока твоего̀ і҆и҃са, є҆го́же пома́залъ є҆сѝ, и҆́родъ же и҆ понті́йскїй пїла́тъ, съ ꙗ҆зы́ки и҆ людьмѝ і҆и҃левыми, сотвори́ти, є҆ли̑ка рꙋка̀ твоѧ̀ и҆ совѣ́тъ тво́й преднаречѐ бы́ти. и҆ ны́нѣ, гдⷭ҇и, при́зри на прещє́нїѧ и҆́хъ, и҆ да́ждь рабѡ́мъ твои́мъ со всѧ́кимъ дерзнове́нїемъ глаго́лати сло́во твоѐ: внегда̀ рꙋ́кꙋ твою̀ простре́ти тѝ во и҆сцѣлє́нїѧ, и҆ зна́менїємъ и҆ чꙋдесє́мъ быва́ти, и҆́менемъ ст҃ы́мъ ѻ҆́трока твоегѡ̀ і҆и҃са. и҆ помоли́вшымсѧ и҆̀мъ, подви́жесѧ мѣ́сто, и҆дѣ́же бѧ́хꙋ со́брани, и҆ и҆спо́лнишасѧ всѝ дх҃а ст҃а, и҆ глаго́лахꙋ сло́во бж҃їе со дерзнове́нїемъ. ",
}

add_apostol {
  ["номер"] = 13,
  ["комментарий"] = "Деян., 13 зач., V, 1–11.",
  ["текст_ру"] = "Во дни о́ны, муж же не́кий, Ана́ниа и́менем, с Сапфи́рою жено́ю свое́ю, прода́ста село́ и утаи́ от цены́, све́дущей и жене́ его́, и прине́с часть не́кую, пред нога́ми Апо́стол положи́. Рече́ же Петр: Ана́ние, почто́ испо́лни сатана́ се́рдце твое́ солга́ти Ду́ху Свято́му и утаи́ти от цены́ села́? Су́щее тебе́ не твое́ ли бе, и прода́ное не в твое́й ли вла́сти бя́ше? Что я́ко положи́л еси́ в се́рдце твое́м вещь сию́? Не челове́ком солга́л еси́, но Бо́гу. Слы́шав же Ана́ниа словеса́ сия́, пад и́здше. И бысть страх вели́к на всех слы́шащих сия́. Вста́вше же ю́ноши взя́ша его́ и изне́сше погребо́ша. Бысть же я́ко трем часо́м мину́вшым, и жена́ его́ не ве́дущи бы́вшаго вни́де. Отвеща́в же ей Петр: рцы ми, а́ще на толи́це село́ отда́ста? Она́ же рече́: ей, на толи́це. Петр же рече́ к ней: что я́ко согласи́стася искуси́ти Ду́ха Госпо́дня? Се, но́ги погре́бших му́жа твоего́ при две́рех, и изнесу́т тя. Паде́ же а́бие пред нога́ма его́ и и́здше, вше́дше же ю́ноши обрето́ша ю́ ме́ртву и изне́сше погребо́ша близ му́жа ея́. И бысть страх вели́к на всей це́ркви и на всех слы́шаших сия́. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, мꙋ́жъ нѣ́кїй а҆на́нїа и҆́менемъ, съ сапфі́рою жено́ю свое́ю, прода́ста село̀: и҆ ᲂу҆таѝ ѿ цѣны̀, свѣ́дꙋщей и҆ женѣ̀ є҆гѡ̀, и҆ прине́съ ча́сть нѣ́кꙋю, пред̾ нога́ми а҆пⷭ҇лъ положѝ. рече́ же пе́тръ: а҆на́нїе, почто̀ и҆спо́лни сатана̀ се́рдце твоѐ, солга́ти дх҃ꙋ ст҃о́мꙋ, и҆ ᲂу҆таи́ти ѿ цѣны̀ села̀; сꙋ́щее тебѣ̀, не твое́ ли бѣ̀; и҆ прода́ное, не въ твое́й ли вла́сти бѧ́ше; что̀ ꙗ҆́кѡ положи́лъ є҆сѝ въ се́рдцѣ твое́мъ ве́щь сїю̀; не человѣ́кѡмъ солга́лъ є҆сѝ, но бг҃ꙋ. слы́шавъ же а҆на́нїа словеса̀ сїѧ̑, па́дъ и҆́здше. и҆ бы́сть стра́хъ вели́къ на всѣ́хъ слы́шащихъ сїѧ̑. вста́вше же ю҆́ноши, взѧ́ша є҆го̀, и҆ и҆зне́сше погребо́ша. бы́сть же ꙗ҆́кѡ тре́мъ часѡ́мъ минꙋ́вшымъ и҆ жена̀ є҆гѡ̀ не вѣ́дꙋщи бы́вшагѡ, вни́де. ѿвѣща́въ же є҆́й пе́тръ: рцы́ ми, а҆́ще на толи́цѣ село̀ ѿда́ста; ѻ҆на́ же речѐ: є҆́й, на толи́цѣ. пе́тръ же речѐ къ не́й: что̀ ꙗ҆́кѡ согласи́стасѧ и҆скꙋси́ти дх҃а гдⷭ҇нѧ; сѐ но́ги погре́бшихъ мꙋ́жа твоего̀ при две́рехъ, и҆ и҆знесꙋ́тъ тѧ̀. паде́ же а҆́бїе пред̾ нога́ма є҆гѡ̀, и҆ и҆́здше. вше́дше же ю҆́ноши ѡ҆брѣто́ша ю҆̀ ме́ртвꙋ, и҆ и҆зне́сше погребо́ша бли́зъ мꙋ́жа є҆ѧ̀. и҆ бы́сть стра́хъ вели́къ на все́й це́ркви, и҆ на всѣ́хъ слы́шащихъ сїѧ̑. ",
}

add_apostol {
