  ["текст_ру"] = "Во дни о́ны, А́нгел Госпо́день рече́ к Фили́ппу, глаго́ля: воста́ни и иди́ на полу́дне, на путь сходя́щий от Иерусали́ма в Га́зу, и той есть пуст. И воста́в по́йде. И се муж Му́рин, евну́х си́лен Кандаки́и цари́цы Му́ринския, и́же бе над все́ми сокро́вищи ея́, и́же прии́де поклони́тися во Иерусали́м. Бе же возвраща́яся, и седя́ на колесни́це свое́й, чтя́ше проро́ка Иса́ию. Рече́ же Дух к Фили́ппу: приступи́ и прилепи́ся колесни́це сей. Прите́к же Фили́пп услы́ша его́ чту́ща проро́ка Иса́ию и рече́: у́бо разуме́еши ли, я́же чте́ши? Он же рече́: ка́ко у́бо могу́ разуме́ти, а́ще не кто наста́вит мя? Умоли́ же Фили́ппа, возше́дша се́сти с ним. Сло́во же Писа́ния, е́же чтя́ше, бе сие́: я́ко овча́ на заколе́ние веде́ся, и я́ко а́гнец пря́мо стригу́щему его́ безгла́сен, та́ко не отверза́ет уст Свои́х. Во смире́нии Его́ суд Его́ взя́тся, род же Его́ кто испове́сть? Я́ко взе́млется от земли́ живо́т Его́. Отвеща́в же ка́женик к Фили́ппу, рече́: молю́ тя, о ком проро́к глаго́лет сие́? О себе́ ли, или́ о ино́м не́коем? Отве́рз же Фили́пп уста́ своя́ и наче́н от Писа́ния сего́, благовести́ ему́ Иису́са. Я́коже идя́ху путе́м, приидо́ша на не́кую во́ду, и рече́ ка́женик: се вода́: что возбраня́ет ми крести́тися? Рече́ же ему́ Фили́пп: а́ще ве́руеши от всего́ се́рдца твоего́, мо́щно ти есть. Отвеща́в же рече́: ве́рую Сы́на Бо́жия бы́ти Иису́са Христа́. И повеле́ ста́ти колесни́це, и снидо́ста о́ба на во́ду, Фили́пп же и ка́женик, и крести́ его́. Егда́ же изыдо́ста от воды́, Дух Святы́й нападе́ на ка́женика. А́нгел же Госпо́день восхи́ти Фили́ппа, и не ви́де его́ ктому́ ка́женик, идя́ше бо в путь свой ра́дуяся. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, а҆́гг҃лъ гдⷭ҇нь речѐ къ фїлі́ппꙋ, глаго́лѧ: воста́ни и҆ и҆дѝ на полꙋ́дне, на пꙋ́ть сходѧ́щїй ѿ і҆ерꙋсали́ма въ га́зꙋ, и҆ то́й є҆́сть пꙋ́стъ. и҆ воста́въ по́йде: и҆ сѐ мꙋ́жъ мꙋ́рїнъ, є҆ѵнꙋ́хъ, си́ленъ кандакі́и цари́цы мꙋ́рїнскїѧ, и҆́же бѣ̀ над̾ всѣ́ми сокро́вищи є҆ѧ̀: и҆́же прїи́де поклони́тисѧ во і҆ерꙋсали́мъ. бѣ́ же возвраща́ѧсѧ, и҆ сѣдѧ̀ на колесни́цѣ свое́й, чтѧ́ше прⷪ҇ро́ка и҆са́їю. рече́ же дх҃ъ къ фїлі́ппꙋ: пристꙋпѝ, и҆ прилѣпи́сѧ колесни́цѣ се́й. прите́къ же фїлі́ппъ, ᲂу҆слы́ша є҆го̀ чтꙋ́ща прⷪ҇ро́ка и҆са́їю, и҆ речѐ: ᲂу҆̀бо разꙋмѣ́еши ли, ꙗ҆̀же чте́ши; ѻ҆́нъ же речѐ: ка́кѡ ᲂу҆́бѡ могꙋ̀ [разꙋмѣ́ти], а҆́ще не кто̀ наста́витъ мѧ̀; ᲂу҆моли́ же фїлі́ппа возше́дша сѣ́сти съ ни́мъ. сло́во же писа́нїѧ, є҆́же чтѧ́ше, бѣ̀ сїѐ: ꙗ҆́кѡ ѻ҆вча̀ на заколе́нїе веде́сѧ, и҆ ꙗ҆́кѡ а҆́гнецъ прѧ́мѡ стригꙋ́щемꙋ є҆го̀ безгла́сенъ, та́кѡ не ѿверза́етъ ᲂу҆́стъ свои́хъ. во смире́нїи є҆гѡ̀ сꙋ́дъ є҆гѡ̀ взѧ́тсѧ: ро́дъ же є҆гѡ̀ кто̀ и҆сповѣ́сть; ꙗ҆́кѡ взе́млетсѧ ѿ землѝ живо́тъ є҆гѡ̀. ѿвѣща́въ же ка́женикъ къ фїлі́ппꙋ, речѐ: молю́ тѧ, ѡ҆ ко́мъ прⷪ҇ро́къ глаго́летъ сїѐ; ѡ҆ себѣ́ ли, и҆лѝ ѡ҆ и҆но́мъ нѣ́коемъ; ѿве́рзъ же фїлі́ппъ ᲂу҆ста̀ своѧ̀, и҆ наче́нъ ѿ писа́нїѧ сегѡ̀, благовѣстѝ є҆мꙋ̀ і҆и҃са. ꙗ҆́коже и҆дѧ́хꙋ пꙋте́мъ, прїидо́ша на нѣ́кꙋю во́дꙋ, и҆ речѐ ка́женикъ: сѐ вода̀, что̀ возбранѧ́етъ мѝ крⷭ҇ти́тисѧ; рече́ же є҆мꙋ̀ фїлі́ппъ: а҆́ще вѣ́рꙋеши ѿ всегѡ̀ се́рдца твоегѡ̀, мо́щно тѝ є҆́сть. ѿвѣща́въ же речѐ: вѣ́рꙋю сн҃а бж҃їѧ бы́ти і҆и҃са хрⷭ҇та̀. и҆ повелѣ̀ ста́ти колесни́цѣ: и҆ снидо́ста ѻ҆́ба на во́дꙋ, фїлі́ппъ же и҆ ка́женикъ: и҆ крⷭ҇тѝ є҆го̀. є҆гда́ же и҆зыдо́ста ѿ воды̀, дх҃ъ ст҃ы́й нападѐ на ка́женика. а҆́гг҃лъ же гдⷭ҇нь восхи́ти фїлі́ппа, и҆ не ви́дѣ є҆гѡ̀ ктомꙋ̀ ка́женикъ: и҆дѧ́ше бо въ пꙋ́ть сво́й ра́дꙋѧсѧ. ",
}

add_apostol {
  ["номер"] = 21,
  ["комментарий"] = "Деян., 21 зач., VIII, 40 – IX, 19.",
  ["текст_ру"] = "Во дни о́ны, Фили́пп обре́теся во Азо́те и проходя́ благовествова́ше градо́м всем, до́ндеже приити́ ему́ в Кесари́ю. Савл же, еще́ дыха́я преще́нием и уби́йством на ученики́ Госпо́дни, присту́пль ко архиере́ю, испроси́ от него́ посла́ния в Дама́ск к собо́рищем, я́ко да а́ще не́кия обря́щет того́ пути́ су́щыя, му́жы же и жены́, свя́заны приведе́т во Иерусали́м. Внегда́ же ити́, бысть ему́ прибли́житися к Дама́ску, и внеза́пу облиста́ его́ свет от небесе́, и пад на зе́млю, слы́ша глас глаго́лющь ему́: Са́вле, Са́вле, что Мя го́ниши? Рече́ же: кто еси́, Го́споди? Госпо́дь же рече́: Аз есмь Иису́с, Его́же ты го́ниши. Жестоко́ ти есть проти́ву рожну́ пра́ти. Трепе́ща же и ужаса́яся глаго́ла: Го́споди, что мя хо́щеши твори́ти? И Госпо́дь рече́ к нему́: воста́ни и вни́ди во град, и рече́тся ти, что ти подоба́ет твори́ти. Му́жие же иду́щии с ним стоя́ху чудя́щеся, слы́шаще у́бо глас, никого́же ви́дяще. Воста́в же Савл от земли́ и отве́рстыма очи́ма свои́ма ни еди́наго ви́дяше, веду́ще же его́ за ру́ку, введо́ша в Дама́ск, и бе дни три не ви́дя, и ни яде́, ниже́ пит. Бе же не́кто учени́к в Дама́сце, и́менем Ана́ниа, и рече́ к нему́ Госпо́дь в виде́нии: Ана́ние. Он же рече́: се аз, Го́споди. Госпо́дь же к нему́: воста́в поиди́ на сто́гну нарица́емую Пра́вую и взыщи́ в дому́ Иу́дове Са́вла и́менем, Тарсяни́на, се бо, моли́тву де́ет и ви́де в виде́нии му́жа, и́менем Ана́нию, вше́дша и возло́жша нань ру́ку, я́ко да про́зрит. Отвеща́ же Ана́ниа: Го́споди, слы́шах от мно́гих о му́жи сем, коли́ка зла сотвори́ святы́м Твои́м во Иерусали́ме: и зде и́мать власть от архиере́й связа́ти вся нарица́ющыя и́мя Твое́. Рече́ же к нему́ Госпо́дь: иди́, я́ко сосу́д избра́н Ми есть сей, пронести́ и́мя Мое́ пред язы́ки и царьми́ и сынми́ изра́илевыми. Аз бо скажу́ ему́, ели́ка подоба́ет ему́ о и́мени Мое́м пострада́ти. По́йде же Ана́ниа и вни́де в хра́мину, и возло́жь нань ру́це, рече́: Са́вле бра́те, Госпо́дь Иису́с явле́й ти ся на пути́, и́мже шел еси́, посла́ мя, я́ко да про́зриши и испо́лнишися Ду́ха Свя́та. И а́бие отпадо́ша от о́чию его́ я́ко чешуя́: прозре́ же а́бие, и воста́в крести́ся, и прие́м пи́щу, укрепи́ся. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, фїлі́ппъ ѡ҆брѣ́тесѧ во а҆зѡ́тѣ: и҆ проходѧ̀ благовѣствова́ше градѡ́мъ всѣ́мъ, до́ндеже прїитѝ є҆мꙋ̀ въ кесарі́ю. са́ѵлъ же, є҆щѐ дыха́ѧ преще́нїемъ и҆ ᲂу҆бі́йствомъ на ᲂу҆ченикѝ гдⷭ҇ни, пристꙋ́пль ко а҆рхїере́ю, и҆спросѝ ѿ негѡ̀ посла̑нїѧ въ дама́скъ къ собо́рищємъ, ꙗ҆́кѡ да а҆́ще нѣ̑кїѧ ѡ҆брѧ́щетъ тогѡ̀ пꙋтѝ сꙋ́щыѧ, мꙋ́жы же и҆ жєны̀, свѧ́заны приведе́тъ во і҆ерꙋсали́мъ. внегда́ же и҆тѝ, бы́сть є҆мꙋ̀ прибли́житисѧ къ дама́скꙋ, и҆ внеза́пꙋ ѡ҆блиста̀ є҆го̀ свѣ́тъ ѿ небесѐ: и҆ па́дъ на зе́млю, слы́ша гла́съ глаго́лющъ є҆мꙋ̀: са́ѵле, са́ѵле, что́ мѧ го́ниши; рече́ же: кто́ є҆си гдⷭ҇и; гдⷭ҇ь же речѐ: а҆́зъ є҆́смь і҆и҃съ, є҆го́же ты̀ го́ниши: жестоко́ ти є҆́сть проти́вꙋ рожнꙋ̀ пра́ти. трепе́ща же и҆ ᲂу҆жаса́ѧсѧ, глаго́ла: гдⷭ҇и, что́ мѧ хо́щеши твори́ти; и҆ гдⷭ҇ь речѐ къ немꙋ̀: воста́ни и҆ вни́ди во гра́дъ, и҆ рече́тсѧ тѝ, что́ ти подоба́етъ твори́ти. мꙋ́жїе же и҆дꙋ́щїи съ ни́мъ, стоѧ́хꙋ чꙋдѧ́щесѧ, слы́шаще ᲂу҆́бѡ гла́съ, никогѡ́же ви́дѧще. воста́въ же са́ѵлъ ѿ землѝ, и҆ ѿве́рстыма ѻ҆чи́ма свои́ма ни є҆ди́нагѡ ви́дѧше: ведꙋ́ще же є҆го̀ за рꙋ́кꙋ, введо́ша въ дама́скъ. и҆ бѣ̀ днѝ трѝ не ви́дѧ, и҆ ни ꙗ҆дѐ, нижѐ пи́тъ. бѣ́ же нѣ́кто ᲂу҆чени́къ въ дама́сцѣ, и҆́менемъ а҆на́нїа, и҆ речѐ къ немꙋ̀ гдⷭ҇ь въ видѣ́нїи: а҆на́нїе. ѻ҆́нъ же речѐ, сѐ а҆́зъ гдⷭ҇и. гдⷭ҇ь же къ немꙋ̀: воста́въ поидѝ на сто́гнꙋ нарица́емꙋю пра́вꙋю, и҆ взыщѝ въ домꙋ̀ і҆ꙋ́довѣ са́ѵла и҆́менемъ, тарсѧни́на: се́ бо моли́твꙋ дѣ́етъ. [и҆ ви́дѣ въ видѣ́нїи мꙋ́жа и҆́менемъ а҆на́нїю, вше́дша и҆ возло́жша на́нь рꙋ́кꙋ, ꙗ҆́кѡ да про́зритъ.] ѿвѣща́ же а҆на́нїа: гдⷭ҇и, слы́шахъ ѿ мно́гихъ ѡ҆ мꙋ́жи се́мъ, коли̑ка ѕла̀ сотворѝ ст҃ы̑мъ твои́мъ во і҆ерꙋсали́мѣ. и҆ здѣ̀ и҆́мать вла́сть ѿ а҆рхїерє́й, свѧза́ти всѧ̀ нарица́ющыѧ и҆́мѧ твоѐ. рече́ же къ немꙋ̀ гдⷭ҇ь: и҆дѝ, ꙗ҆́кѡ сосꙋ́дъ и҆збра́нъ мѝ є҆́сть се́й, пронестѝ и҆́мѧ моѐ пред̾ ꙗ҆зы́ки, и҆ царьмѝ и҆ сынмѝ і҆и҃левыми. а҆́зъ бо скажꙋ̀ є҆мꙋ̀, є҆ли̑ка подоба́етъ є҆мꙋ̀ ѡ҆ и҆́мени мое́мъ пострада́ти. по́йде же а҆на́нїа, и҆ вни́де въ хра́минꙋ, и҆ возло́жъ на́нь рꙋ́цѣ, речѐ: са́ѵле бра́те, гдⷭ҇ь і҆и҃съ ꙗ҆вле́й ти сѧ на пꙋтѝ, и҆́мже ше́лъ є҆сѝ, посла́ мѧ, ꙗ҆́кѡ да про́зриши, и҆ и҆спо́лнишисѧ дх҃а ст҃а. и҆ а҆́бїе ѿпадо́ша ѿ ѻ҆́чїю є҆гѡ̀ ꙗ҆́кѡ чешꙋѧ̀: прозрѣ́ же а҆́бїе, и҆ воста́въ крести́сѧ: и҆ прїе́мъ пи́щꙋ, ᲂу҆крѣпи́сѧ. ",
}

