  ["текст_ру"] = "Во дни о́ны, бысть Петру́, посеща́ющу всех, сни́ти и ко святы́м живу́щим в Ли́дде. Обре́те же та́мо челове́ка не́коего, и́менем Ене́а, от осми́ лет лежа́ща на одре́, и́же бе разсла́блен. И рече́ ему́ Петр: Ене́е, исцеля́ет тя Иису́с Христо́с, воста́ни с посте́ли твоея́. И а́бие воста́, и ви́деша его́ вси живу́щии в Ли́дде и во Ассаро́не, и́же обрати́шася ко Го́споду. Во Иоппи́и же бе не́кая учени́ца, и́менем Тави́фа, я́же сказа́ема глаго́лется: се́рна, сия́ бя́ше испо́лнена благи́х дел и ми́лостынь, я́же творя́ше. Бысть же во дни ты́я, боле́вшей ей умре́ти, омы́вше же ю́, положи́ша в го́рнице. Близ же су́щей Ли́дде Иоппи́и, ученицы́ слы́шавше, я́ко Петр есть в ней, посла́ша два му́жа к нему́, моля́ще его́ не облени́тися приити́ до них. Воста́в же Петр и́де с ни́ма, его́же прише́дша возведо́ша в го́рницу, и предста́ша ему́ вся вдови́цы пла́чуща, и показу́юща ри́зы и оде́жды, ели́ка творя́ше, с ни́ми су́щи, Се́рна. Изгна́в же вон вся Петр, прекло́нь коле́на помоли́ся, и обра́щься к те́лу, рече́: Тави́фо, воста́ни. Она́ же отве́рзе о́чи свои́, и ви́девши Петра́, се́де. Пода́в же ей ру́ку, воздви́же ю́, и призва́в святы́я и вдови́цы, поста́ви ю́ жи́ву. Уве́дано же бысть се по всей Иоппи́и, и мно́зи ве́роваша в Го́спода. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, бы́сть петрꙋ̀ посѣща́ющꙋ всѣ́хъ, сни́ти и҆ ко ст҃ы́мъ живꙋ́щымъ въ лѵ́ддѣ. ѡ҆брѣ́те же та́мѡ человѣ́ка нѣ́коего, и҆́менемъ є҆не́а, ѿ ѻ҆смѝ лѣ́тъ лежа́ща на ѻ҆дрѣ̀, и҆́же бѣ̀ разсла́бленъ. и҆ речѐ є҆мꙋ̀ пе́тръ: є҆не́е, и҆сцѣлѧ́етъ тѧ̀ і҆и҃съ хрⷭ҇то́съ, воста́ни съ посте́ли твоеѧ̀. и҆ а҆́бїе воста̀. и҆ ви́дѣша є҆го̀ всѝ живꙋ́щїи въ лѵ́ддѣ и҆ во а҆ссарѡ́нѣ, и҆̀же ѡ҆брати́шасѧ ко гдⷭ҇ꙋ. во і҆ѻппі́и же бѣ̀ нѣ́каѧ ᲂу҆чени́ца и҆́менемъ таві́ѳа, ꙗ҆́же сказа́ема глаго́летсѧ, се́рна: сїѧ̀ бѧ́ше и҆спо́лнена благи́хъ дѣ́лъ и҆ млⷭ҇тынь, ꙗ҆̀же творѧ́ше. бы́сть же во днѝ ты́ѧ болѣ́вшей є҆́й ᲂу҆мре́ти: ѡ҆мы́вше же ю҆̀, положи́ша въ го́рницѣ. бли́зъ же сꙋ́щей лѵ́ддѣ і҆ѻппі́и, ᲂу҆ченицы̀ слы́шавше, ꙗ҆́кѡ пе́тръ є҆́сть въ не́й, посла́ша два̀ мꙋ́жа къ немꙋ̀, молѧ́ще є҆го̀ не ѡ҆блѣни́тисѧ прїитѝ до ни́хъ. воста́въ же пе́тръ и҆́де съ ни́ма, є҆го́же прише́дша возведо́ша въ го́рницꙋ: и҆ предста́ша є҆мꙋ̀ всѧ̀ вдови́цы пла́чꙋщѧ, и҆ показꙋ́ющѧ ри̑зы и҆ ѻ҆дє́жды, є҆ли̑ка творѧ́ше съ ни́ми сꙋ́щи се́рна. и҆згна́въ же во́нъ всѧ̑ пе́тръ, прекло́нь колѣ̑на помоли́сѧ, и҆ ѡ҆бра́щсѧ къ тѣ́лꙋ, речѐ: таві́ѳо, воста́ни. ѻ҆на́ же ѿве́рзе ѻ҆́чи своѝ, и҆ ви́дѣвши петра̀, сѣ́де. пода́въ же є҆́й рꙋ́кꙋ, воздви́же ю҆̀: и҆ призва́въ ст҃ы́ѧ и҆ вдови̑цы, поста́ви ю҆̀ жи́вꙋ. ᲂу҆вѣ́дано же бы́сть сѐ по все́й і҆ѻппі́и, и҆ мно́зи вѣ́роваша въ гдⷭ҇а. ",
}

add_apostol {
  ["номер"] = 24,
  ["комментарий"] = "Деян., 24 зач., X, 1–16.",
  ["текст_ру"] = "Во дни о́ны, муж не́кий бе в Кесари́и, и́менем Корни́лий, со́тник от спи́ры нарица́ющияся Итали́йския, благогове́ин и боя́йся Бо́га со всем до́мом свои́м, творя́й ми́лостыни мно́ги лю́дем и моля́йся Бо́гу всегда́, ви́де в виде́нии я́ве, я́ко в час девя́тый дне, А́нгела Бо́жия сше́дша к нему́ и ре́кша ему́: Корни́лие. Он же воззре́в нань и пристра́шен быв рече́: что есть, Го́споди? Рече́ же ему́: моли́твы твоя́ и ми́лостыни твоя́ взыдо́ша на па́мять пред Бо́га. И ны́не посли́ во Иоппи́ю муже́й и призови́ Си́мона, нарица́емаго Петра́. Сей стра́нствует у не́коего Си́мона усмаря́, ему́же есть дом при мо́ри, той рече́т тебе́ глаго́лы, в ни́хже спасе́шися ты и весь дом твой. И я́коже оты́де А́нгел глаго́ляй Корни́лию, пригласи́в два от рабо́в свои́х и во́ина благочести́ва от служа́щих ему́, и сказа́в им вся, посла́ их во Иоппи́ю. Воу́трие же, путьше́ствующым им и ко гра́ду приближа́ющымся, взы́де Петр на го́рницу помоли́тися, в час шесты́й. Бысть же приа́лчен и хотя́ше вкуси́ти, гото́вящым же о́нем, нападе́ нань у́жас, и ви́де не́бо отве́рсто и сходя́щ нань сосу́д не́кий, я́ко плащани́цу ве́лию, по четы́рем кра́ем привя́зан и ни́зу спуща́емь на зе́млю, в не́мже бя́ху вся четвероно́гая земли́ и зве́рие и га́ди и пти́цы небе́сныя. И бысть глас к нему́: воста́в, Пе́тре, заколи́ и яждь. Петр же рече́: ника́коже, Го́споди, я́ко николи́же ядо́х вся́ко скве́рно или́ нечи́сто. И се глас па́ки к нему́ втори́цею: я́же Бог очи́стил есть, ты не скверни́. Сие́ же бысть три́щи, и па́ки взя́ся сосу́д на не́бо. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, мꙋ́жъ нѣ́кїй бѣ̀ въ кесарі́и, и҆́менемъ корни́лїй, со́тникъ ѿ спі́ры нарица́ющїѧсѧ і҆талі́йскїѧ, благоговѣ́инъ и҆ боѧ́йсѧ бг҃а со всѣ́мъ до́момъ свои́мъ, творѧ́й ми́лѡстыни мнѡ́ги лю́демъ, и҆ молѧ́йсѧ бг҃ꙋ всегда̀: ви́дѣ въ видѣ́нїи ꙗ҆́вѣ, ꙗ҆́кѡ въ ча́съ девѧ́тый днѐ, а҆́гг҃ла бж҃їѧ сше́дша къ немꙋ̀, и҆ ре́кша є҆мꙋ̀: корни́лїе. ѻ҆́нъ же воззрѣ́въ на́нь, и҆ пристра́шенъ бы́въ, речѐ: что́ є҆сть гдⷭ҇и; рече́ же є҆мꙋ̀: моли́твы твоѧ̀, и҆ ми́лѡстыни твоѧ̀ взыдо́ша на па́мѧть пред̾ бг҃а. и҆ ны́нѣ послѝ во і҆ѻппі́ю мꙋже́й, и҆ призовѝ сі́мѡна нарица́емаго петра̀. се́й стра́нствꙋетъ ᲂу҆ нѣ́коегѡ сі́мѡна ᲂу҆смарѧ̀, є҆мꙋ́же є҆́сть до́мъ при мо́ри: то́й рече́тъ тебѣ̀ глаго́лы, въ ни́хже спасе́шисѧ ты̀, и҆ ве́сь до́мъ тво́й. и҆ ꙗ҆́коже ѿи́де а҆́гг҃лъ глаго́лѧй корни́лїю, пригласи́въ два̀ ѿ рабѡ́въ свои́хъ, и҆ во́ина бл҃гочести́ва ѿ слꙋжа́щихъ є҆мꙋ̀, и҆ сказа́въ и҆̀мъ всѧ̑, посла̀ и҆̀хъ во і҆ѻппі́ю. воꙋ́трїе же пꙋтьше́ствꙋющымъ и҆̀мъ, и҆ ко гра́дꙋ приближа́ющымсѧ, взы́де пе́тръ на го́рницꙋ помоли́тисѧ, въ ча́съ шесты́й. бы́сть же прїа́лченъ, и҆ хотѧ́ше вкꙋси́ти: гото́вѧщымъ же ѻ҆́нѣмъ, нападѐ на́нь ᲂу҆́жасъ, и҆ ви́дѣ нб҃о ѿве́рсто, и҆ сходѧ́щъ на́нь сосꙋ́дъ нѣ́кїй ꙗ҆́кѡ плащани́цꙋ ве́лїю, по четы́ремъ кра́ємъ привѧ́занъ, и҆ ни́зꙋ спꙋща́емь на зе́млю: въ не́мже бѧ́хꙋ всѧ̀ четверонѡ́гаѧ землѝ, и҆ ѕвѣ́рїе и҆ га́ди, и҆ пти́цы нбⷭ҇ныѧ. и҆ бы́сть гла́съ къ немꙋ̀: воста́въ пе́тре, заколѝ и҆ ꙗ҆́ждь. пе́тръ же речѐ: ника́коже гдⷭ҇и, ꙗ҆́кѡ николи́же ꙗ҆до́хъ всѧ́ко скве́рно и҆лѝ нечи́сто. и҆ сѐ гла́съ па́ки къ немꙋ̀ втори́цею: ꙗ҆̀же бг҃ъ ѡ҆чи́стилъ є҆́сть, ты̀ не сквернѝ. сїе́ же бы́сть три́щи: и҆ па́ки взѧ́сѧ сосꙋ́дъ на нб҃о. ",
}

