  ["комментарий"] = "Деян., 27 зач., X, 44 – XI, 10.",
  ["текст_ру"] = "Во дни о́ны, глаго́лющу Петру́ глаго́лы сия́, нападе́ Дух Святы́й на вся слы́шащыя сло́во. И ужасо́шася и́же от обре́зания ве́рнии, ели́цы приидо́ша с Петро́м, я́ко и на язы́ки дар Свята́го Ду́ха излия́ся: слы́шаху бо их глаго́лющих язы́ки и велича́ющих Бо́га. Тогда́ отвеща́ Петр: еда́ во́ду возбрани́ти мо́жет кто, е́же не крести́тися сим, и́же Дух Святы́й прия́ша, я́коже и мы? Повеле́ же им крести́тися во и́мя Иису́с Христо́во. Тогда́ моли́ша его́ пребы́ти у них дни не́кия. Слы́шаша же Апо́столи и бра́тия су́щии во Иуде́и, я́ко и язы́цы прия́ша сло́во Бо́жие. И егда́ взы́де Петр во Иерусали́м, препира́хуся с ним и́же от обре́зания, глаго́люще, я́ко к муже́м обре́зания не иму́щым вшел еси́ и ял еси́ с ни́ми. Наче́н же Петр, ска́зоваше им поря́ду, глаго́ля: аз бех во гра́де Иоппи́йстем моля́ся и ви́дех во у́жасе виде́ние, сходя́щь сосу́д не́кий, я́ко плащани́цу ве́лию, от четы́рех кра́ев низпуща́ему с небесе́, и прии́де да́же до мене́, в ню́же воззре́в смотря́х, и ви́дех четвероно́гая земна́я и зве́ри и га́ды и пти́цы небе́сныя. Слы́шах же глас глаго́лющь мне: воста́в, Пе́тре, заколи́ и яждь. Рех же: ника́коже, Го́споди, я́ко вся́ко скве́рно или́ нечи́сто николи́же вни́де во уста́ моя́. Отвеща́ же ми глас втори́цею с небесе́ глаго́лющь: я́же Бог очи́стил есть, ты не скверни́. Сие́ же бысть три́жды, и па́ки взя́шася вся на не́бо. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, глаго́лющꙋ петрꙋ̀ глаго́лы сїѧ̑, нападѐ дх҃ъ ст҃ы́й на всѧ̑ слы́шащыѧ сло́во. и҆ ᲂу҆жасо́шасѧ и҆̀же ѿ ѡ҆брѣ́занїѧ вѣ́рнїи, є҆ли́цы прїидо́ша съ петро́мъ, ꙗ҆́кѡ и҆ на ꙗ҆зы́ки да́ръ ст҃а́гѡ дх҃а и҆злїѧ́сѧ: слы́шахꙋ бо и҆̀хъ глаго́лющихъ ѧ҆зы́ки, и҆ велича́ющихъ бг҃а. тогда̀ ѿвѣща̀ пе́тръ: є҆да̀ во́дꙋ возбрани́ти мо́жетъ кто̀, є҆́же не крести́тисѧ си̑мъ, и҆̀же дх҃ъ ст҃ы́й прїѧ́ша, ꙗ҆́коже и҆ мы̀; повелѣ́ же и҆̀мъ крⷭ҇ти́тисѧ во и҆́мѧ і҆и҃съ хрⷭ҇то́во: тогда̀ моли́ша є҆го̀ пребы́ти ᲂу҆ ни́хъ днѝ нѣ́кїѧ. слы́шаша же а҆пⷭ҇ли и҆ бра́тїѧ сꙋ́щїи во і҆ꙋде́и, ꙗ҆́кѡ и҆ ꙗ҆зы́цы прїѧ́ша сло́во бж҃їе. и҆ є҆гда̀ взы́де пе́тръ во і҆ерⷭ҇ли́мъ, препира́хꙋсѧ съ ни́мъ и҆̀же ѿ ѡ҆брѣ́занїѧ, глаго́люще: ꙗ҆́кѡ къ мꙋжє́мъ ѡ҆брѣ́занїѧ не и҆мꙋ́щымъ вше́лъ є҆сѝ, и҆ ꙗ҆́лъ є҆сѝ съ ни́ми. наче́нъ же пе́тръ, ска́зоваше и҆̀мъ по рѧ́дꙋ, глаго́лѧ: а҆́зъ бѣ́хъ во гра́дѣ і҆ѻппі́йстѣмъ молѧ́сѧ, и҆ ви́дѣхъ во ᲂу҆́жасѣ видѣ́нїе, сходѧ́щъ сосꙋ́дъ нѣ́кїй, ꙗ҆́кѡ плащани́цꙋ ве́лїю, ѿ четы́рехъ кра́євъ низпꙋща́емꙋ съ нб҃сѐ, и҆ прїи́де да́же до менѐ: въ ню́же воззрѣ́въ смотрѧ́хъ, и҆ ви́дѣхъ четверонѡ́гаѧ земна́ѧ, и҆ ѕвѣ́ри, и҆ га́ды, и҆ пти̑цы нбⷭ҇ныѧ. слы́шахъ же гла́съ глаго́лющъ мнѣ̀: воста́въ пе́тре, заколѝ и҆ ꙗ҆́ждь. рѣ́хъ же: ника́коже гдⷭ҇и, ꙗ҆́кѡ всѧ́ко скве́рно и҆ нечи́сто николи́же вни́де во ᲂу҆ста̀ моѧ̀. ѿвѣща́ же мѝ гла́съ втори́цею съ нб҃сѐ глаго́лющъ: ꙗ҆̀же бг҃ъ ѡ҆чи́стилъ є҆́сть, ты̀ не сквернѝ. сїе́ же бы́сть три́жды: и҆ па́ки взѧ́шасѧ всѧ̑ на нб҃о. ",
}

add_apostol {
  ["номер"] = 28,
  ["комментарий"] = "Деян., 28 зач., XI, 19–26, 29–30.",
  ["текст_ру"] = "Во дни о́ны, разсе́явшиися апо́столи от ско́рби, бы́вшия при Стефа́не, проидо́ша да́же до Финики́и, и Ки́пра, и Антиохи́и, ни еди́ному же глаго́люще сло́ва, то́кмо иуде́ем. Бя́ху же не́цыи от них му́жие ки́прстии и кирине́йстии, и́же вше́дше во Антиохи́ю, глаго́лаху к е́ллином, благовеству́юще Го́спода Иису́са. И бе рука́ Госпо́дня с ни́ми: мно́гое же число́ ве́ровавше обрати́шася ко Го́споду. Слы́шано же бысть сло́во о них во у́шию це́ркве су́щия во Иерусали́ме, и посла́ша Варна́ву преити́ да́же до Антиохи́и. И́же прише́д и ви́дев благода́ть Бо́жию, возра́довася и утеша́ше вся изволе́нием се́рдца терпе́ти о Го́споде. Я́ко бе муж благ, и испо́лнь Ду́ха Свя́та и ве́ры. И приложи́ся наро́д мног Го́сподеви. Изы́де же Варна́ва в Тарс взыска́ти Са́вла, и обре́т его́, приведе́ его́ во Антиохи́ю. Бысть же им ле́то це́ло собира́тися в це́ркви, и учи́ти наро́д мног, нарещи́ же пре́жде во Антиохи́и ученики́, христиа́ны. От учени́к же, по ели́ку кто име́яше что, изво́лиша ки́йждо их на слу́жбу посла́ти живу́щим во Иуде́и бра́тиям, е́же и сотвори́ша, посла́вше к ста́рцем руко́ю Варна́влею и Са́влею. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, разсѣ́ѧвшїисѧ а҆по́столи ѿ ско́рби бы́вшїѧ при стефа́нѣ, проидо́ша да́же до фїнїкі́и, и҆ кѵ́пра, и҆ а҆нтїохі́и, ни є҆ди́номꙋ же глаго́люще сло́ва, то́кмѡ і҆ꙋде́ємъ. бѧ́хꙋ же нѣ́цыи ѿ ни́хъ мꙋ́жїе кѵ́прстїи и҆ кѷрине́йстїи, и҆̀же вше́дше во а҆нтїохі́ю, глаго́лахꙋ къ є҆́ллинѡмъ, благовѣствꙋ́юще гдⷭ҇а і҆и҃са. и҆ бѣ̀ рꙋка̀ гдⷭ҇нѧ съ ни́ми: мно́гое же число̀ вѣ́ровавше, ѡ҆брати́шасѧ ко гдⷭ҇ꙋ. слы́шано же бы́сть сло́во ѡ҆ ни́хъ во ᲂу҆́шїю цр҃кве, сꙋ́щїѧ во і҆ерꙋсали́мѣ: и҆ посла́ша варна́вꙋ преитѝ да́же до а҆нтїохі́и. и҆́же прише́дъ, и҆ ви́дѣвъ благода́ть бж҃їю, возра́довасѧ: и҆ ᲂу҆тѣша́ше всѧ̑ и҆зволе́нїемъ се́рдца терпѣ́ти ѡ҆ гдⷭ҇ѣ. ꙗ҆́кѡ бѣ̀ мꙋ́жъ бла́гъ, и҆ и҆спо́лнь дх҃а ст҃а и҆ вѣ́ры: и҆ приложи́сѧ наро́дъ мно́гъ гдⷭ҇ви. и҆зы́де же варна́ва въ та́рсъ взыска́ти са́ѵла: и҆ ѡ҆брѣ́тъ є҆го̀, приведѐ и҆̀ во а҆нтїохі́ю. бы́сть же и҆̀мъ лѣ́то цѣ́ло собира́тисѧ въ цр҃кви, и҆ ᲂу҆чи́ти наро́дъ мно́гъ, нарещи́ же пре́жде во а҆нтїохі́и ᲂу҆ченикѝ, хрїстїа́ны. ѿ ᲂу҆ч҃ни̑къ же, по є҆ли́кꙋ кто̀ и҆мѣ́ѧше что̀, и҆зво́лиша кі́йждо и҆́хъ на слꙋ́жбꙋ посла́ти живꙋ́щымъ во і҆ꙋде́и бра́тїѧмъ: е҆́же и҆ сотвори́ша, посла́вше къ ста́рцємъ рꙋко́ю варна́влею и҆ са́ѵлею. ",
}

add_apostol {
  ["номер"] = 29,
  ["комментарий"] = "Деян., 29 зач., XII, 1–11.",
  ["текст_ру"] = "Во дни о́ны, возложи́ И́род царь ру́це озло́бити не́кия и́же от це́ркве, уби́ же Иа́кова, бра́та Иоа́ннова, мече́м. И ви́дев, я́ко го́де есть Иуде́ем, приложи́ я́ти и Петра́, бя́ху же дни́е опресно́чнии. Его́же и емь всади́ в темни́цу, преда́в четы́рем четвери́цам во́инов стрещи́ его́, хотя́ по Па́сце извести́ его́ к лю́дем. И у́бо Петра́ стрежа́ху в темни́це: моли́тва же бе приле́жна быва́емая от це́ркве к Бо́гу о нем. Егда́ же хотя́ше его́ извести́ И́род, в нощи́ той бе Петр спя между́ двема́ во́инома, свя́зан желе́знома у́жема двема́, стра́жие же пред две́рьми стрежа́ху темни́цы. И се А́нгел Госпо́день предста́, и свет возсия́ в хра́мине: толкну́в же в ре́бра Петра́, воздви́же его́, глаго́ля: воста́ни вско́ре. И спадо́ша ему́ у́жя желе́зная с руку́. Рече́ же А́нгел к нему́: препоя́шися и вступи́ в плесни́цы твоя́. Сотвори́ же та́ко. И глаго́ла ему́: облецы́ся в ри́зу твою́ и после́дствуй ми. И изше́д вслед его́ идя́ше и не ве́дяше, я́ко и́стина есть бы́вшее от А́нгела, мня́ше же виде́ние зре́ти. Проше́дша же пе́рвую стра́жу и втору́ю, приидо́ста ко врато́м желе́зным, вводя́щым во град, я́же о себе́ отверзо́шася и́ма, и изше́дше преидо́ша сто́гну еди́ну, и а́бие отступи́ А́нгел от него́. И Петр быв в себе́, рече́: ны́не вем вои́стинну, я́ко посла́ Бог А́нгела Своего́ и изъя́т мя из руки́ И́родовы и от всего́ ча́яния люде́й иуде́йских. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, возложѝ и҆́рѡдъ ца́рь рꙋ́цѣ ѡ҆ѕло́бити нѣ̑кїѧ и҆̀же ѿ цр҃кве. ᲂу҆би́ же і҆а́кѡва бра́та і҆ѡа́ннова мече́мъ. и҆ ви́дѣвъ, ꙗ҆́кѡ го́дѣ є҆́сть і҆ꙋде́ємъ, приложѝ ꙗ҆́ти и҆ петра̀: [бѧ́хꙋ же дні́е ѡ҆прѣсно́чнїи.] є҆го́же и҆ є҆́мъ всадѝ въ темни́цꙋ, преда́въ четы́рємъ четвери́цамъ во́инѡвъ стрещѝ є҆го̀, хотѧ̀ по па́сцѣ и҆звестѝ є҆го̀ къ лю́демъ. и҆ ᲂу҆̀бо петра̀ стрежа́хꙋ въ темни́цѣ: мл҃тва же бѣ̀ прилѣ́жна, быва́емаѧ ѿ цр҃кве къ бг҃ꙋ ѡ҆ не́мъ. є҆гда́ же хотѧ́ше є҆го̀ и҆звестѝ и҆́рѡдъ, въ нощѝ то́й бѣ̀ пе́тръ спѧ̀ междꙋ̀ двѣма̀ во́инома, свѧ́занъ желѣ́знома ᲂу҆́жема двѣма̀, стра́жїе же пред̾ две́рьми стрежа́хꙋ темни́цы. и҆ сѐ а҆́гг҃лъ гдⷭ҇нь предста̀, и҆ свѣ́тъ возсїѧ̀ въ хра́минѣ: толкнꙋ́въ же въ ре́бра петра̀, воздви́же є҆го̀, глаго́лѧ: воста́ни вско́рѣ. и҆ спадо́ша є҆мꙋ̀ ᲂу҆́жѧ желѣ́знаѧ съ рꙋкꙋ̀. рече́ же а҆́гг҃лъ къ немꙋ̀: препоѧ́шисѧ, и҆ встꙋпѝ въ плесни́цы твоѧ̀: сотвори́ же та́кѡ. и҆ глаго́ла є҆мꙋ̀: ѡ҆блецы́сѧ въ ри́зꙋ твою̀, и҆ послѣ́дствꙋй мѝ. и҆ и҆зше́дъ въ слѣ́дъ є҆гѡ̀ и҆дѧ́ше, и҆ не вѣ́дѧше, ꙗ҆́кѡ и҆́стина є҆́сть бы́вшее ѿ а҆́гг҃ла: мнѧ́ше же видѣ́нїе зрѣ́ти. проше́дша же пе́рвꙋю стра́жꙋ и҆ вторꙋ́ю, прїидо́ста ко вратѡ́мъ желѣ́знымъ, вводѧ́щымъ во гра́дъ, ꙗ҆̀же ѡ҆ себѣ̀ ѿверзо́шасѧ и҆́ма. и҆ и҆зше́дше преидо́ша сто́гнꙋ є҆ди́нꙋ, и҆ а҆́бїе ѿстꙋпѝ а҆́гг҃лъ ѿ негѡ̀. и҆ пе́тръ бы́въ въ себѣ̀, речѐ: ны́нѣ вѣ́мъ вои́стиннꙋ, ꙗ҆́кѡ посла̀ бг҃ъ а҆́гг҃ла своего̀, и҆ и҆з̾ѧ́тъ мѧ̀ и҆з̾ рꙋкѝ и҆́рѡдовы, и҆ ѿ всегѡ̀ ча́ѧнїѧ люде́й і҆ꙋде́йскихъ. ",
}

add_apostol {
  ["номер"] = 30,
  ["комментарий"] = "Деян., 30 зач., XII, 12–17.",
  ["текст_ру"] = "Во дни о́ны, смотри́в Петр прии́де в дом Мари́ин ма́тере Иоа́нновы, нарица́емаго Ма́рка, иде́же бя́ху мно́зи со́брани и моля́щеся. Толкну́вшу же Петру́ во врата́ двора́, приступи́ слы́шати отрокови́ца, и́менем Ро́ди, и позна́вши глас Петро́в, от ра́дости не отве́рзе врат, прите́кши же сказа́ Петра́ стоя́ща пред враты́. Они́ же к ней ре́ша: бесну́еши ли ся? Она́ же крепля́шеся та́ко бы́ти. Они́ же глаго́лаху: А́нгел его́ есть. Петр же пребыва́ше толки́й: отве́рзше же ви́деша его́ и ужасо́шася. Помаа́в же им руко́ю молча́ти, сказа́ им, ка́ко Госпо́дь его́ изведе́ из темни́цы. Рече́ же: возвести́те Иа́кову и бра́тиям сия́. И изше́д и́де во и́но ме́сто. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, смотри́въ пе́тръ прїи́де въ до́мъ марі́инъ мт҃ре і҆ѡа́нновы, нарица́емагѡ ма́рка, и҆дѣ́же бѧ́хꙋ мно́зи со́брани и҆ молѧ́щесѧ. толкнꙋ́вшꙋ же петрꙋ̀ во врата̀ двора̀, пристꙋпѝ слы́шати ѻ҆трокови́ца и҆́менемъ ро́ди: и҆ позна́вши гла́съ петро́въ, ѿ ра́дости не ѿве́рзе вра́тъ: прите́кши же сказа̀ петра̀ стоѧ́ща пред̾ враты̀. ѻ҆ни́ же къ не́й рѣ́ша: бѣснꙋ́еши ли сѧ; ѻ҆на́ же крѣплѧ́шесѧ та́кѡ бы́ти. ѻ҆ни́ же глаго́лахꙋ: а҆́гг҃лъ є҆гѡ̀ є҆́сть. пе́тръ же пребыва́ше толкі́й: ѿве́рзше же ви́дѣша є҆го̀, и҆ ᲂу҆жасо́шасѧ. помаа́въ же и҆̀мъ рꙋко́ю молча́ти, сказа̀ и҆̀мъ, ка́кѡ гдⷭ҇ь є҆го̀ и҆зведѐ и҆з̾ темни́цы. рече́ же: возвѣсти́те і҆а́кѡвꙋ и҆ бра́тїѧмъ сїѧ̑. и҆ и҆зше́дъ и҆́де во и҆́но мѣ́сто. ",
}

add_apostol {
  ["номер"] = 31,
  ["комментарий"] = "Деян., 31 зач., XII, 25 – XIII, 12.",
  ["текст_ру"] = "Во дни о́ны, Варна́ва и Савл возврати́стася из Иерусали́ма во Антиохи́ю, испо́лнивше слу́жбу, пое́мше с собо́ю и Иоа́нна, нарица́емаго Ма́рка. Бя́ху же не́цыи во це́ркви су́щей во Антиохи́и проро́цы и учи́телие: Варна́ва же и Симео́н, нарица́емый Ни́гер, и Луки́й Кирине́анин, и Манаи́н со И́родом четвертовла́стником воспита́нный, и Савл. Служа́щым же им Го́сподеви и постя́щымся, рече́ Дух Святы́й: отдели́те Ми Варна́ву и Са́вла на де́ло, на не́же призва́х их. Тогда́ пости́вшеся и помоли́вшеся и возло́жше ру́ки на ня, отпусти́ша их. Сия́ у́бо по́слана бы́вша от Ду́ха Свя́та, снидо́ста в Селевки́ю, отту́ду же отплы́ша в Кипр, и бы́вше в Салами́не, возвеща́ста сло́во Бо́жие в со́нмищах Иуде́йских, име́ста же и Иоа́нна слугу́. Проше́дша же о́стров да́же до Па́фа, обрето́ста не́коего му́жа волхва́ лжепроро́ка Иуде́анина, ему́же и́мя Вариису́с, и́же бе со анфипа́том Се́ргием Па́влом, му́жем разу́мным. Сей призва́в Варна́ву и Са́вла, взыска́ услы́шати сло́во Бо́жие. Сопротивля́шеся же и́ма Елли́ма волхв, та́ко бо сказу́ется и́мя его́, иски́й разврати́ти анфипа́та от ве́ры. Савл же, и́же и Па́вел, испо́лнися Ду́ха Свя́та, и воззре́в нань, рече́: о, испо́лненне вся́кия льсти и вся́кия зло́бы, сы́не диа́воль, вра́же вся́кия пра́вды, не преста́неши ли развраща́я пути́ Госпо́дни пра́выя? И ны́не, се рука́ Госпо́дня на тя, и бу́деши слеп, не ви́дя со́лнца до вре́мене. Внеза́пу же нападе́ нань мрак и тма, и осяза́я иска́ше вожда́. Тогда́ ви́дев анфипа́т бы́вшее, ве́рова, дивя́ся о уче́нии Госпо́дни. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, варна́ва и҆ са́ѵлъ возврати́стасѧ и҆з̾ і҆ерⷭ҇ли́ма во а҆нтїохі́ю, и҆спо́лнивше слꙋ́жбꙋ, пое́мше съ собо́ю и҆ і҆ѡа́нна, нарица́емаго ма́рка. бѧ́хꙋ же нѣ́цыи во цр҃кви сꙋ́щей во а҆нтїохі́и, проро́цы и҆ ᲂу҆чи́телїе, варна́ва же и҆ сѷмеѡ́нъ, нарица́емый ні́геръ, и҆ лꙋкі́й кѷрине́анинъ, и҆ манаи́нъ со и҆́рѡдомъ четвертовла́стникомъ воспита́нный, и҆ са́ѵлъ. слꙋжа́щымъ же и҆̀мъ гдⷭ҇ви, и҆ постѧ́щымсѧ, речѐ дх҃ъ ст҃ы́й: ѿдѣли́те мѝ варна́вꙋ и҆ са́ѵла на дѣ́ло, на не́же призва́хъ и҆̀хъ. тогда̀ пости́вшесѧ, и҆ помоли́вшесѧ, и҆ возло́жше рꙋ́ки на нѧ̀, ѿпꙋсти́ша и҆̀хъ. сїѧ̀ ᲂу҆́бѡ по́слана бы́вша ѿ дх҃а ст҃а, снидо́ста въ селеѵкі́ю, ѿтꙋ́дꙋ же ѿплы́ша въ кѵ́пръ. и҆ бы́вше въ саламі́нѣ, возвѣща́ста сло́во бж҃їе въ со́нмищахъ і҆ꙋде́йскихъ: и҆мѣ́ста же и҆ і҆ѡа́нна слꙋгꙋ̀. проше́дша же ѻ҆́стровъ да́же до па́фа, ѡ҆брѣто́ста нѣ́коего мꙋ́жа волхва̀ лжепроро́ка і҆ꙋде́анина, є҆мꙋ́же и҆́мѧ варїисꙋ́съ: и҆́же бѣ̀ со а҆нѳѷпа́томъ се́ргїемъ па́ѵломъ, мꙋ́жемъ разꙋ́мнымъ. се́й призва́въ варна́вꙋ и҆ са́ѵла, взыска̀ ᲂу҆слы́шати сло́во бж҃їе. сопротивлѧ́шесѧ же и҆́ма є҆ллѵ́ма во́лхвъ, [та́кѡ бо сказꙋ́етсѧ и҆́мѧ є҆гѡ̀,] и҆скі́й разврати́ти а҆нѳѷпа́та ѿ вѣ́ры. са́ѵлъ же, и҆́же и҆ па́ѵелъ, и҆спо́лнисѧ дх҃а ст҃а, и҆ воззрѣ́въ на́нь, речѐ: ѽ и҆спо́лненне всѧ́кїѧ льстѝ и҆ всѧ́кїѧ ѕло́бы, сы́не дїа́воль, вра́же всѧ́кїѧ пра́вды, не преста́неши ли развраща́ѧ пꙋтѝ гдⷭ҇ни пра̑выѧ; и҆ ны́нѣ сѐ рꙋка̀ гдⷭ҇нѧ на тѧ̀, и҆ бꙋ́деши слѣ́пъ, не ви́дѧ со́лнца до вре́мене. внеза́пꙋ же нападѐ на́нь мра́къ и҆ тма̀, и҆ ѡ҆сѧза́ѧ и҆ска́ше вожда̀. тогда̀ ви́дѣвъ а҆нѳѷпа́тъ бы́вшее, вѣ́рова, дивѧ́сѧ ѡ҆ ᲂу҆че́нїи гдⷭ҇ни. ",
}

add_apostol {
  ["номер"] = 32,
  ["комментарий"] = "Деян., 32 зач., XIII, 13–24.",
  ["текст_ру"] = "Во дни о́ны, отве́зшеся от Па́фа Па́вел и су́щии с ним, приидо́ша в Перги́ю Памфили́йскую. Иоа́нн же, отлучи́вся от них, возврати́ся во Иерусали́м. Они́ же, проше́дше от Перги́и, приидо́ша во Антиохи́ю Писиди́йскую, и вше́дше в со́нмище в день суббо́тный, седо́ша. По чте́нии же зако́на и проро́к, посла́ша нача́льницы со́нмища к ним, глаго́люще: му́жие бра́тие, а́ще есть сло́во в вас утеше́ния к лю́дем, глаго́лите. Воста́в же Па́вел и помаа́в руко́ю, рече́: му́жие изра́ильтяне и боя́щиися Бо́га, услы́шите. Бог люде́й сих избра́ отцы́ на́ши и лю́ди вознесе́ в прише́льствии в земли́ Еги́петстей, и мы́шцею высо́кою изведе́ их из нея́ и до четы́редесяти лет препита́ их в пусты́ни. И низложи́в язы́к седмь в земли́ Ханаа́нстей, даде́ им в насле́дие зе́млю их, и по сих, я́ко лет четы́реста и пятьдеся́т, даде́ им судии́ до Саму́ила проро́ка. И отту́ду проси́ша царя́, и даде́ им Бог Сау́ла сы́на Ки́сова, му́жа от коле́на Вениами́нова, лет четы́редесять. И преста́вль его́, воздви́же им Дави́да в царя́, ему́же и рече́ свиде́тельствовав: обрето́х Дави́да сы́на Иессе́ова, му́жа по се́рдцу Моему́, и́же сотвори́т вся хоте́ния Моя́. От сего́ се́мене Бог по обетова́нию воздви́же Изра́илю спасе́ние Иису́са, пропове́давшу Иоа́нну пред лице́м вни́тия Его́ креще́ние покая́ния всем лю́дем изра́илевым. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, ѿве́зшесѧ ѿ па́фа, па́ѵелъ и҆ сꙋ́щїи съ ни́мъ, прїидо́ша въ пергі́ю памфѷлі́йскꙋю. і҆ѡа́ннъ же ѿлꙋчи́всѧ ѿ ни́хъ, возврати́сѧ во і҆ерꙋсали́мъ: ѻ҆ни́ же проше́дше ѿ пергі́и, прїидо́ша во а҆нтїохі́ю пїсїді́йскꙋю: и҆ вше́дше въ со́нмище въ де́нь сꙋббѡ́тный, сѣдо́ша. по чте́нїи же зако́на и҆ прорѡ́къ, посла́ша нача́льницы со́нмища къ ни́мъ, глаго́люще: мꙋ́жїе бра́тїе, а҆́ще є҆́сть сло́во въ ва́съ ᲂу҆тѣше́нїѧ къ лю́демъ, глаго́лите. воста́въ же па́ѵелъ, и҆ помаа́въ рꙋко́ю, речѐ: мꙋ́жїе і҆и҃льтѧне, и҆ боѧ́щїисѧ бг҃а, ᲂу҆слы́шите. бг҃ъ люде́й си́хъ, и҆збра̀ ѻ҆ц҃ы̀ на́шы, и҆ лю́ди вознесѐ въ прише́льствїи въ землѝ є҆гѵ́петстѣй: и҆ мы́шцею высо́кою и҆зведѐ и҆̀хъ и҆з̾ неѧ̀. и҆ до четы́редесѧти лѣ́тъ препита̀ и҆̀хъ въ пꙋсты́ни. и҆ низложи́въ ꙗ҆зы̑къ се́дмь, въ землѝ ханаа́нстѣй, дадѐ и҆̀мъ въ наслѣ́дїе зе́млю и҆́хъ. и҆ по си́хъ ꙗ҆́кѡ лѣ́тъ четы́реста и҆ пѧтьдесѧ́тъ, дадѐ и҆̀мъ сꙋдїи̑ до самꙋ́ила проро́ка. и҆ ѿтꙋ́дꙋ проси́ша царѧ̀, и҆ дадѐ и҆̀мъ бг҃ъ саꙋ́ла, сы́на кі́сова, мꙋ́жа ѿ колѣ́на венїамі́нова, лѣ́тъ четы́редесѧть. и҆ преста́вль є҆го̀, воздви́же и҆̀мъ дв҃да въ царѧ̀, є҆мꙋ́же и҆ речѐ, свидѣ́тельствовавъ: ѡ҆брѣто́хъ дв҃да сн҃а і҆ессе́ова, мꙋ́жа по се́рдцꙋ моемꙋ̀, и҆́же сотвори́тъ всѧ̑ хотѣ́нїѧ моѧ̀. ѿ сегѡ̀ сѣ́мене бг҃ъ, по ѡ҆бѣтова́нїю, воздви́же і҆и҃лю спасе́нїе, і҆и҃са: проповѣ́давшꙋ і҆ѡа́ннꙋ пред̾ лице́мъ вни́тїѧ є҆гѡ̀ креще́нїе покаѧ́нїѧ, всѣ́мъ лю́демъ і҆и҃левымъ. ",
}

add_apostol {
  ["номер"] = 33,
  ["комментарий"] = "Деян., 33 зач., XIII, 25–32.",
  ["текст_ру"] = "Во дни о́ны, я́коже скончава́ше Иоа́нн тече́ние, глаго́лаше: кого́ мя непщу́ете бы́ти, несмь аз, но се гряде́т по мне, Ему́же несмь досто́ин разреши́ти реме́нь сапогу́ Его́. Му́жие, бра́тие, сы́нове ро́да Авраа́мля, и и́же в вас, боя́щиися Бо́га, вам сло́во спасе́ния Сего́ посла́ся. Живу́щии бо во Иерусали́ме и кня́зи их сего́ не разуме́вше, и гла́сы проро́ческия, по вся суббо́ты что́мыя, осуди́вше Его́, испо́лниша. И ни еди́ныя вины́ сме́ртныя обре́тше, проси́ша у Пила́та уби́ти Его́. Я́коже сконча́ша вся, я́же о Нем пи́сана, сне́мше с дре́ва, положи́ша во гро́бе. Бог же воскреси́ Его́ от ме́ртвых. И́же яви́ся на дни мно́ги совозше́дшим с Ним от Галиле́и во Иерусали́м, и́же ны́не суть свиде́телие Его́ к лю́дем. И мы вам благовеству́ем обетова́ние, бы́вшее ко отце́м, я́ко сие́ Бог испо́лнил есть нам, ча́дом их, воздви́г Иису́са. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, ꙗ҆́коже скончава́ше і҆ѡа́ннъ тече́нїе, глаго́лаше: кого́ мѧ непщꙋ́ете бы́ти, нѣ́смь а҆́зъ, но сѐ грѧде́тъ по мнѣ̀, є҆мꙋ́же нѣ́смь досто́инъ разрѣши́ти реме́нь сапогꙋ̀ є҆гѡ̀. мꙋ́жїе бра́тїе, сы́нове ро́да а҆враа́млѧ, и҆ и҆̀же въ ва́съ боѧ́щїисѧ бг҃а: ва́мъ сло́во спасе́нїѧ сегѡ̀ посла́сѧ. живꙋ́щїи бо во і҆ерꙋсали́мѣ, и҆ кнѧ́зи и҆́хъ сегѡ̀ не разꙋмѣ́вше, и҆ гла́сы проро́ческїѧ, по всѧ̀ сꙋббѡ́ты чтѡ́мыѧ, ѡ҆сꙋди́вше є҆го̀, и҆спо́лниша. и҆ ниеди́ныѧ вины̀ сме́ртныѧ ѡ҆брѣ́тше, проси́ша ᲂу҆ пїла́та ᲂу҆би́ти є҆го̀. ꙗ҆́коже сконча́ша всѧ̑, ꙗ҆̀же ѡ҆ не́мъ пи́сана, сне́мше съ дре́ва, положи́ша во гро́бѣ. бг҃ъ же воскресѝ є҆го̀ ѿ ме́ртвыхъ: и҆́҆́же ꙗ҆ви́сѧ на днѝ мнѡ́ги, совозше́дшымъ съ ни́мъ ѿ галїле́и во і҆ерꙋсали́мъ, и҆̀же ны́нѣ сꙋ́ть свидѣ́телїе є҆гѡ̀ къ лю́демъ. и҆ мы̀ ва́мъ благовѣствꙋ́емъ ѡ҆бѣтова́нїе бы́вшее ко ѻ҆ц҃є́мъ, ꙗ҆́кѡ сїѐ бг҃ъ и҆спо́лнилъ є҆́сть на́мъ ча́дѡмъ и҆́хъ, воздви́гъ і҆и҃са. ",
}

