  ["комментарий"] = "Деян., 34 зач., XIV, 6–18.",
  ["текст_ру"] = "Во дни о́ны, Па́вел и Варна́ва прибего́ста во гра́ды Ликао́нския, в Ли́стру и Де́рвию, и во окре́стныя их, и та́мо бе́ста благовеству́юща. И не́кто муж в Ли́стрех не́мощен нога́ма седя́ше, хром от чре́ва ма́тере своея́ сый, и́же николи́же бе ходи́л. Сей слы́шаше Па́вла глаго́люща, и́же воззре́в нань и ви́дев, я́ко ве́ру и́мать здрав бы́ти, рече́ ве́лиим гла́сом: тебе́ глаго́лю во и́мя Го́спода Иису́са Христа́, вста́ни на но́гу твою́ прав. И а́бие возскочи́ и хожда́ше. Наро́ди же ви́девше, е́же сотвори́ Па́вел, воздвиго́ша глас свой, ликао́нски глаго́люще: бо́зи уподо́бльшеся челове́ком снидо́ша к нам. Нарица́ху же у́бо Варна́ву Ди́а, Па́вла же Ерми́а, поне́же той бя́ше нача́льник сло́ва. Жрец же Ди́ев, су́щаго пред гра́дом их, приведе́ юнцы́, и принесе́ венцы́ пред врата́, с наро́ды хотя́ше жре́ти. Слы́шавша же апо́стола Варна́ва и Па́вел, растерза́вша ри́зы своя́, вскочи́ста в наро́д, зову́ща и глаго́люща: му́жие, что сия́ твори́те? И мы подобостра́стна есма́ вам челове́ка, благовеству́юща вам, от сих су́етных обраща́тися к Бо́гу жи́ву, И́же сотвори́ не́бо и зе́млю, и мо́ре и вся, я́же в них. И́же в мимоше́дшия ро́ды оста́вил бе вся язы́ки ходи́ти в путе́х их. И у́бо не несвиде́тельствована Себе́ оста́ви, благотворя́, с небесе́ нам дожде́вы дая́, и времена́ плодоно́сна, исполня́я пи́щею и весе́лием сердца́ на́ша. И сия́ глаго́люща, едва́ уста́виста наро́ды не жре́ти и́ма, но отыти́ коему́ждо во своя́си. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, па́ѵелъ и҆ варна́ва прибѣго́ста во гра́ды лѷкао́нскїѧ, въ лѵ́стрꙋ и҆ де́рвїю, и҆ во ѻ҆крє́стныѧ и҆́хъ: и҆ та́мѡ бѣ́ста благовѣствꙋ́юща. и҆ нѣ́кто мꙋ́жъ въ лѵ́стрѣхъ не́мощенъ нога́ма сѣдѧ́ше, хро́мъ ѿ чре́ва ма́тере своеѧ̀ сы́й, и҆́же николи́же бѣ̀ ходи́лъ. се́й слы́шаше па́ѵла глаго́люща: и҆́же воззрѣ́въ на́нь, и҆ ви́дѣвъ, ꙗ҆́кѡ вѣ́рꙋ и҆́мать здра́въ бы́ти, речѐ ве́лїимъ гла́сомъ: тебѣ̀ глаго́лю, во и҆́мѧ гдⷭ҇а і҆и҃са хрⷭ҇та̀, вста́ни на нѡ́гꙋ твою̀ пра́въ: и҆ а҆́бїе возскочѝ и҆ хожда́ше. наро́ди же ви́дѣвше, є҆́же сотворѝ па́ѵелъ, воздвиго́ша гла́съ сво́й лѷкао́нски глаго́люще: бо́зи ᲂу҆подо́бльшесѧ человѣ́кѡмъ снидо́ша къ на́мъ. нарица́хꙋ же ᲂу҆̀бо варна́вꙋ ді́а, па́ѵла же є҆рмі́а, поне́же то́й бѧ́ше нача́льникъ сло́ва. жре́цъ же ді́евъ сꙋ́щагѡ пред̾ гра́домъ и҆́хъ, приведѐ ю҆нцы̀, и҆ принесѐ вѣнцы̀ пред̾ врата̀, съ наро́ды хотѧ́ше жре́ти. слы́шавша же а҆пⷭ҇ла, варна́ва и҆ па́ѵелъ, растерза́вша ри̑зы своѧ̀, вскочи́ста въ наро́дъ зовꙋ́ща, и҆ глаго́люща: мꙋ́жїе, что̀ сїѧ̑ творитѐ; и҆ мы̀ подобостра́стна є҆сма̀ ва́мъ человѣ́ка, бл҃говѣствꙋ́юща ва́мъ, ѿ си́хъ сꙋ́етныхъ ѡ҆браща́тисѧ къ бг҃ꙋ жи́вꙋ, и҆́же сотворѝ нб҃о и҆ зе́млю, и҆ мо́ре, и҆ всѧ̑ ꙗ҆̀же въ ни́хъ. и҆́же въ мимоше́дшыѧ ро́ды ѡ҆ста́вилъ бѣ̀ всѧ̀ ꙗ҆зы́ки ходи́ти въ пꙋте́хъ и҆́хъ. и҆ ᲂу҆̀бо не несвидѣ́тельствована себѐ ѡ҆ста́ви, благотворѧ̀, съ нб҃сѐ на́мъ дожде́вы даѧ̀, и҆ времена̀ плодонѡ́сна, и҆сполнѧ́ѧ пи́щею и҆ весе́лїемъ сердца̀ на́ша. и҆ сїѧ̑ глаго́люща, є҆два̀ ᲂу҆ста́виста наро́ды не жре́ти и҆́ма: но ѿитѝ коемꙋ́ждо во своѧ́си. ",
}

add_apostol {
  ["номер"] = 35,
  ["комментарий"] = "Деян., 35 зач., XIV, 20–27.",
  ["текст_ру"] = "Во дни о́ны, изы́де Па́вел с Варна́вою в Де́рвию. Благовествова́ста же гра́ду тому́ и научи́ста мно́ги, возврати́стася в Ли́стру и Икони́ю и Антиохи́ю, утвержда́юща ду́шы ученико́в, моля́ща пребы́ти в ве́ре, и я́ко мно́гими скорбьми́ подоба́ет нам вни́ти в Ца́рствие Бо́жие. Рукополо́жше же им пресви́теры на вся це́ркви и помоли́вшеся с посто́м, преда́ста их Го́сподеви, в Него́же ве́роваша. И проше́дша Писиди́ю, приидо́ста в Памфили́ю. И глаго́лавша в Перги́и сло́во Госпо́дне, снидо́ста во Аттали́ю. И отту́ду отплы́ста во Антиохи́ю, отню́дуже бе́ста пре́дана благода́ти Бо́жией в де́ло, е́же сконча́ста. Прише́дша же и собра́вша це́рковь, сказа́ста, ели́ка сотвори́ Бог с ни́ма и я́ко отве́рзе язы́ком дверь ве́ры. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, и҆зы́де па́ѵелъ съ варна́вою въ де́рвїю. бл҃говѣствова́ста же гра́дꙋ томꙋ̀ и҆ наꙋчи́ста мно́ги, возврати́стасѧ въ лѵ́стрꙋ, и҆ і҆коні́ю, и҆ а҆нтїохі́ю: ᲂу҆твержда́юще дꙋ́шы ᲂу҆ченикѡ́въ, молѧ́ще пребы́ти въ вѣ́рѣ, и҆ ꙗ҆́кѡ мно́гими скорбьмѝ подоба́етъ на́мъ вни́ти въ црⷭ҇твїе бж҃їе. рꙋкополо́жше же и҆̀мъ пресвѵ́теры на всѧ̀ цр҃кви, и҆ помоли́вшесѧ съ посто́мъ, преда́ста и҆̀хъ гдⷭ҇ви, въ него́же вѣ́роваша. и҆ проше́дша пїсїді́ю, прїидо́ста въ памфѷлі́ю: и҆ глаго́лавша въ пергі́и сло́во гдⷭ҇не, снидо́ста во а҆тталі́ю. и҆ ѿтꙋ́дꙋ ѿплы́ста во а҆нтїохі́ю, ѿню́дꙋже бѣ́ста пре́дана бл҃года́ти бж҃їей въ дѣ́ло, є҆́же сконча́ста. прише́дша же и҆ собра́вша цр҃ковь, сказа́ста є҆ли̑ка сотворѝ бг҃ъ съ ни́ма, и҆ ꙗ҆́кѡ ѿве́рзе ꙗ҆зы́кѡмъ две́рь вѣ́ры. ",
}

add_apostol {
  ["номер"] = 36,
  ["комментарий"] = "Деян., 36 зач., XV, 5–34.",
  ["текст_ру"] = "Во дни о́ны, воста́ша не́цыи от е́реси фарисе́йския ве́ровавшии, глаго́люще, я́ко подоба́ет обре́зати их, завещава́ти же блюсти́ зако́н Моисе́ов. Собра́шася же Апо́столи и ста́рцы ве́дети о словеси́ сем. Мно́гу же взыска́нию бы́вшу, воста́в Петр рече́ к ним: му́жие бра́тие, вы ве́сте, я́ко от дний пе́рвых Бог в нас избра́ усты́ мои́ми услы́шати язы́ком сло́во Благове́стия и ве́ровати, и Сердцеве́дец Бог свиде́тельствова им, дав им Ду́ха Свята́го, я́коже и нам, и ничто́же разсуди́ между́ на́ми же и о́неми, ве́рою очи́щь сердца́ их. Ны́не у́бо что искуша́ете Бо́га, хотя́ще возложи́ти и́го на вы́и ученико́м, его́же ни отцы́ на́ши, ни мы возмого́хом понести́? Но благода́тию Го́спода Иису́са Христа́ ве́руем спасти́ся, я́коже и они́. Умолча́ же все мно́жество и послу́шаху Варна́вы и Па́вла пове́дающих, ели́ка сотвори́ Бог зна́мения и чудеса́ во язы́цех и́ма. По умолча́нии же их отвеща́ Иа́ков глаго́ля: му́жие бра́тие, послу́шайте мене́. Симео́н пове́да, я́ко пре́жде Бог посети́ прия́ти от язы́к лю́ди о и́мени Свое́м. И сему́ согласу́ют словеса́ проро́к, я́коже пи́шет: по сих обращу́ся и сози́жду кров Дави́дов па́дший, и раско́паная его́ сози́жду и испра́влю его́, я́ко да взы́щут про́чии челове́цы Го́спода, и вси язы́цы, в ни́хже нарече́ся и́мя Мое́, глаго́лет Госпо́дь, творя́й сия́ вся. Разу́мна от ве́ка суть Бо́гови вся дела́ Его́. Сего́ ра́ди аз сужду́ не стужа́ти от язы́к обраща́ющымся к Бо́гу, но запове́дати им огреба́тися от треб и́дольских и от блуда́ и уда́вленины и от кро́ве, и ели́ка неуго́дна себе́ бы́ти, ины́м не твори́ти. Моисе́й бо от родо́в дре́вних по вся гра́ды пропове́дающыя его́ и́мать, в со́нмищах по вся суббо́ты что́мый. Тогда́ изво́лися Апо́столом и ста́рцем со все́ю це́рковию, избра́вше му́жа от них, посла́ти во Антиохи́ю с Па́влом и Варна́вою, Иу́ду нарица́емаго Варса́ву, и Си́лу, му́жа наро́чита в бра́тии, написа́вше рука́ма их сия́: Апо́столи и ста́рцы и бра́тия, су́щым во Антиохи́и и Сири́и и Килики́и бра́тии, и́же от язы́к, о Го́споде ра́доватися. Поне́же у́бо слы́шахом, я́ко не́цыи от нас изше́дше возмути́ша вас словесы́, развраща́юще ду́шы ва́ша, глаго́люще обре́затися и блюсти́ зако́н, и́мже мы не завеща́хом, изво́лися нам собра́вшымся единоду́шно, избра́нныя му́жы посла́ти к вам, с возлю́бленныма на́шима Варна́вою и Па́влом, челове́кома преда́вшема душа́ своя́ о и́мени Го́спода на́шего Иису́са Христа́. Посла́хом у́бо Иу́ду и Си́лу, и тех сло́вом сказу́ющих та́яжде. Изво́лися бо Свято́му Ду́ху и нам, ничто́же мно́жае возложи́ти вам тяготы́, ра́зве ну́ждных сих: огреба́тися от идоложе́ртвенных и кро́ве, и уда́вленины, и блуда́, и ели́ка не хо́щете вам бы́ти, други́м не твори́те. От ни́хже соблюда́юще себе́, до́бре сотворите́. Здра́вствуйте. Они́ же у́бо по́слани бы́вше приидо́ша во Антиохи́ю, и собра́вше наро́д, вда́ша посла́ние. Проче́тше же, возра́довашася о утеше́нии. Иу́да же и Си́ла, и та проро́ка су́ща, сло́вом мно́зем уте́шиста бра́тию и утверди́ста. Пребы́вше же та́мо вре́мя, отпуще́на бы́ста с ми́ром от бра́тий ко Апо́столом. Изво́лися же Си́ле пребы́ти та́мо, Иу́да же возврати́ся во Иерусали́м. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, воста́ша нѣ́цыи ѿ є҆́реси фарїсе́йскїѧ вѣ́ровавшїи, глаго́люще: ꙗ҆́кѡ подоба́етъ ѡ҆брѣ́зати и҆̀хъ, завѣщава́ти же блюстѝ зако́нъ мѡѷсе́овъ. собра́шасѧ же а҆пⷭ҇ли и҆ ста́рцы вѣ́дѣти ѡ҆ словесѝ се́мъ. мно́гꙋ же взыска́нїю бы́вшꙋ, воста́въ пе́тръ речѐ къ ни́мъ: мꙋ́жїе бра́тїе, вы̀ вѣ́сте, ꙗ҆́кѡ ѿ дні́й пе́рвыхъ бг҃ъ въ на́съ и҆збра̀, ᲂу҆сты̀ мои́ми ᲂу҆слы́шати ꙗ҆зы́кѡмъ сло́во бл҃говѣ́стїѧ, и҆ вѣ́ровати. и҆ сердцевѣ́децъ бг҃ъ свидѣ́тельствова и҆̀мъ, да́въ и҆̀мъ дх҃а ст҃а́го, ꙗ҆́коже и҆ на́мъ. и҆ ничто́же разсꙋдѝ междꙋ̀ на́ми же и҆ ѻ҆́нѣми, вѣ́рою ѡ҆чи́щъ сердца̀ и҆́хъ. ны́нѣ ᲂу҆̀бо что̀ и҆скꙋша́ете бг҃а, хотѧ́ще возложи́ти и҆́го на вы̑и ᲂу҆чн҃кѡ́мъ, є҆гѡ́же ни ѻ҆тцы̀ на́ши, ни мы̀ возмого́хомъ понестѝ; но бл҃года́тїю гдⷭ҇а і҆и҃са хрⷭ҇та̀ вѣ́рꙋемъ спасти́сѧ, ꙗ҆́коже и҆ ѻ҆нѝ. ᲂу҆молча́ же всѐ мно́жество, и҆ послꙋ́шахꙋ варна́вы и҆ па́ѵла повѣ́дающихъ, є҆ли́ка сотворѝ бг҃ъ зна́мєнїѧ и҆ чꙋдеса̀ во ꙗ҆зы́цѣхъ и҆́ма. по ᲂу҆молча́нїи же и҆́хъ ѿвѣща̀ і҆а́кѡвъ, глаго́лѧ: мꙋ́жїе бра́тїе, послꙋ́шайте менѐ. сѷмеѡ́нъ повѣ́да, ꙗ҆́кѡ пре́жде бг҃ъ посѣтѝ прїѧ́ти ѿ ꙗ҆зы̑къ лю́ди ѡ҆ и҆́мени свое́мъ. и҆ семꙋ̀ согласꙋ́ютъ словеса̀ прорѡ́къ, ꙗ҆́коже пи́шетъ: по си́хъ ѡ҆бращꙋ́сѧ, и҆ сози́ждꙋ кро́въ дв҃довъ па́дшїй, и҆ раскѡ́панаѧ є҆гѡ̀ сози́ждꙋ, и҆ и҆спра́влю є҆го̀: ꙗ҆́кѡ да взы́щꙋтъ про́чїи человѣ́цы гдⷭ҇а, и҆ всѝ ꙗ҆зы́цы, въ ни́хже нарече́сѧ и҆́мѧ моѐ: глаго́летъ гдⷭ҇ь, творѧ́й сїѧ̑ всѧ̑. разꙋ̑мна ѿ вѣ́ка сꙋ́ть бг҃ови всѧ̀ дѣла̀ є҆гѡ̀. сегѡ̀ ра́ди а҆́зъ сꙋждꙋ̀, не стꙋжа́ти ѿ ꙗ҆зы̑къ ѡ҆браща́ющымсѧ къ бг҃ꙋ: но заповѣ́дати и҆̀мъ ѡ҆греба́тисѧ ѿ тре́бъ і҆́дѡльскихъ, и҆ ѿ блꙋда̀, и҆ ᲂу҆да́вленины, и҆ ѿ кро́ве: и҆, є҆ли̑ка неꙋгѡ́дна себѣ̀ бы́ти, и҆ны̑мъ не твори́ти. мѡѷсе́й бо ѿ родѡ́въ дре́внихъ, по всѧ̀ гра́ды проповѣ́дающыѧ є҆го̀ и҆́мать въ со́нмищахъ, по всѧ̀ сꙋббѡ́ты что́мый. тогда̀ и҆зво́лисѧ а҆пⷭ҇толѡмъ и҆ ста́рцємъ со все́ю цр҃ковїю, и҆збра́вше мꙋ́жа ѿ ни́хъ, посла́ти во а҆нтїохі́ю съ па́ѵломъ и҆ варна́вою: і҆ꙋ́дꙋ, нарица́емаго варса́вꙋ, и҆ сі́лꙋ, мꙋ́жа нарѡ́чита въ бра́тїи. написа́вше рꙋка́ма и҆́хъ сїѧ̑: а҆пⷭ҇толи, и҆ ста́рцы, и҆ бра́тїѧ, сꙋ́щымъ во а҆нтїохі́и, и҆ сѷрі́и, и҆ кїлїкі́и бра́тїи, и҆̀же ѿ ꙗ҆зы̑къ, ѡ҆ гдⷭ҇ѣ ра́доватисѧ. поне́же ᲂу҆́бѡ слы́шахомъ, ꙗ҆́кѡ нѣ́цыи ѿ на́съ и҆зше́дше возмꙋти́ша ва́съ словесы̀, развраща́юще дꙋ́шы ва́шѧ, глаго́люще, ѡ҆брѣ́затисѧ и҆ блюстѝ зако́нъ, и҆̀мже мы̀ не завѣща́хомъ: и҆зво́лисѧ на́мъ собра́вшымсѧ є҆динодꙋ́шнѡ, и҆збра́нныѧ мꙋ́жы посла́ти къ ва́мъ, съ возлю́бленныма на́шима варна́вою и҆ па́ѵломъ, человѣ́кома преда́вшема дꙋшѧ̀ своѧ̀ ѡ҆ и҆́мени гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀. посла́хомъ ᲂу҆̀бо і҆ꙋ́дꙋ и҆ сі́лꙋ, и҆ тѣ́хъ сло́вомъ сказꙋ́ющихъ та̑ѧжде. и҆зво́лисѧ бо ст҃о́мꙋ дх҃ꙋ и҆ на́мъ, ничто́же мно́жае возложи́ти ва́мъ тѧготы̀, ра́звѣ нꙋ́ждныхъ си́хъ: ѡ҆греба́тисѧ ѿ і҆дѡложе́ртвенныхъ, и҆ кро́ве, и҆ ᲂу҆да́вленины, и҆ блꙋда̀: и҆, є҆ли̑ка не хо́щете ва́мъ бы́ти дрꙋги̑мъ не твори́те: ѿ ни́хже соблюда́юще себѐ до́брѣ сотворитѐ. здра́вствꙋйте. ѻ҆ни́ же ᲂу҆̀бо по́слани бы́вше, прїидо́ша во а҆нтїохі́ю: и҆ собра́вше наро́дъ, вда́ша посла́нїе. проче́тше же возра́довашасѧ ѡ҆ ᲂу҆тѣше́нїи. і҆ꙋ́да же и҆ сі́ла, и҆ та̀ прорѡ́ка сꙋ́ща, сло́вомъ мно́зѣмъ ᲂу҆тѣ́шиста бра́тїю и҆ ᲂу҆тверди́ста. пребы́вше же та́мѡ вре́мѧ, ѿпꙋщє́на бы́ста съ ми́ромъ ѿ бра́тїй ко а҆пⷭ҇лѡмъ. и҆зво́лисѧ же сі́лѣ пребы́ти та́мѡ, і҆ꙋ́да же возврати́сѧ во і҆ерꙋсали́мъ. ",
}

add_apostol {
  ["номер"] = 37,
  ["комментарий"] = "Деян., 37 зач., XV, 35–41.",
  ["текст_ру"] = "Во дни о́ны, Па́вел и Варна́ва живя́ста во Антиохи́и, уча́ща и благовеству́юща сло́во Госпо́дне, и со ине́ми мно́гими. По не́ких же днех рече́ Па́вел к Варна́ве: возвра́щшеся подоба́ет посети́ти бра́тию на́шу во всех гра́дех, в ни́хже пропове́дахом сло́во Госпо́дне, ка́ко пребыва́ют. Варна́ва же восхоте́ поя́ти с собо́ю Иоа́нна нарица́емаго Ма́рка. Па́вел же глаго́лаше отсту́пльшаго от на́ю от Памфили́и и не ше́дшаго с на́ма на де́ло, на не́же положе́ни бы́хом, не поя́ти сего́ с собо́ю. Бысть у́бо ра́спря, я́ко отлучи́тися и́ма от себе́: Варна́ва у́бо пое́м Ма́рка отплы́ в Кипр. Па́вел же избра́в Си́лу изы́де пре́дан благода́ти Бо́жией от бра́тий, прохожда́ше же Сири́ю и Килики́ю, утвержда́я це́ркви. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, па́ѵелъ и҆ варна́ва живѧ́ста во а҆нтїохі́и, ᲂу҆ча́ще и҆ благовѣствꙋ́юще сло́во гдⷭ҇не, и҆ со и҆нѣ́ми мно́гими. по нѣ́кихъ же дне́хъ, речѐ па́ѵелъ къ варна́вѣ: возвра́щшесѧ подоба́етъ посѣти́ти бра́тїю на́шꙋ во всѣ́хъ гра́дѣхъ, въ ни́хже проповѣ́дахомъ сло́во гдⷭ҇не, ка́кѡ пребыва́ютъ. варна́ва же восхотѣ̀ поѧ́ти съ собо́ю і҆ѡа́нна, нарица́емаго ма́рка. па́ѵелъ же глаго́лаше: ѿстꙋ́пльшагѡ ѿ на́ю ѿ памфѷлі́и, и҆ не ше́дшагѡ съ на́ми на дѣ́ло, въ не́же положе́ни бы́хомъ, не поѧ́ти сегѡ̀ съ собо́ю. бы́сть ᲂу҆̀бо ра́спрѧ, ꙗ҆́кѡ ѿлꙋчи́тисѧ и҆́ма ѿ себѐ, варна́ва ᲂу҆́бѡ пое́мъ ма́рка, ѿплы̀ въ кѵ́пръ: па́ѵелъ же и҆збра́въ сі́лꙋ, и҆зы́де пре́данъ бл҃года́ти бж҃їей, ѿ бра́тїй. прохожда́ше сѷрі́ю и҆ кїлїкі́ю, ᲂу҆твержда́ѧ цє́ркви. ",
}

add_apostol {
  ["номер"] = 38,
  ["комментарий"] = "Деян., 38 зач., XVI, 16–34.",
  ["текст_ру"] = "Во дни о́ны, бысть иду́щим апо́столом на моли́тву, отрокови́ца не́кая иму́щая дух пытли́в сре́те нас, я́же стяжа́ние мно́го дая́ше господе́м свои́м волхву́ющи. Та после́довавши Па́влу и нам, взыва́ше глаго́лющи: си́и челове́цы раби́ Бо́га Вы́шняго суть, и́же возвеща́ют нам путь спасе́ния. Се же творя́ше на мно́ги дни. Стужи́в же си Па́вел, и обра́щся, ду́хови рече́: запреща́ю ти и́менем Иису́са Христа́, изы́ди из нея́. И изы́де в том часе́. Ви́девше же госпо́дие ея́, я́ко изы́де наде́жда тяжа́ния их, пое́мше Па́вла и Си́лу, влеко́ша на торг ко князе́м. И вве́дше их к воево́дам, ре́ша: си́и челове́цы возмуща́ют град наш, иуде́е су́ще. И завещава́ют обы́чаи, я́же не досто́ит нам приима́ти, ни твори́ти, ри́мляном су́щим. И сни́деся наро́д на них, и воево́ды растерза́вше им ри́зы, веля́ху па́лицами би́ти их. Мно́ги же да́вше им ра́ны, всади́ша в темни́цу, завеща́вше темни́чному стра́жу тве́рдо стрещи́ их. И́же таково́ завеща́ние прие́м, всади́ их во вну́треннюю темни́цу, и но́ги их заби́ в кла́де. В полу́нощи же Па́вел и Си́ла моля́щася поя́ста Бо́га, послу́шаху же их ю́зницы. Внеза́пу же трус бысть ве́лий, я́ко поколеба́тися основа́нию темни́чному, отверзо́ша же ся а́бие две́ри вся, и всем ю́зы ослабе́ша. Возбу́ждься же темни́чный страж, и ви́дев отве́рсты две́ри темни́цы, извле́к нож, хотя́ше себе́ уби́ти, мня избе́гша ю́зники. Возгласи́ же гла́сом ве́лиим Па́вел, глаго́ля: ничто́же сотвори́ себе́ зла, вси бо есмы́ зде. Проси́в же свещи́, вскочи́, и тре́петен быв, припаде́ к Па́влу и Си́ле. И изве́д их вон, рече́: госпо́дие, что ми подоба́ет твори́ти, да спасу́ся? О́на же реко́ста: ве́руй в Го́спода Иису́са Христа́, и спасе́шися ты и весь дом твой. И глаго́ласта ему́ сло́во Госпо́дне, и всем и́же в дому́ его́. И пое́м я́ в той же час но́щи, измы́ от ран, и крести́ся сам и свои́ ему́ вси а́бие. Введ же я́ в дом свой, поста́ви трапе́зу, и возра́довася со всем до́мом свои́м, ве́ровав Бо́гу. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, бы́сть и҆дꙋ́щымъ а҆по́столѡмъ на моли́твꙋ, ѻ҆трокови́ца нѣ́каѧ и҆мꙋ́щаѧ дꙋ́хъ пытли́въ срѣ́те на́съ, ꙗ҆́же тѧжа́нїе мно́го даѧ́ше господє́мъ свои́мъ волхвꙋ́ющи. та̀ послѣ́довавши па́ѵлꙋ и҆ на́мъ, взыва́ше глаго́лющи: сі́и человѣ́цы рабѝ бг҃а вы́шнѧгѡ сꙋ́ть, и҆̀же возвѣща́ютъ на́мъ пꙋ́ть спасе́нїѧ. се́ же творѧ́ше на мно́ги днѝ. стꙋжи́въ же сѝ па́ѵелъ, и҆ ѡ҆бра́щсѧ, дꙋ́хови речѐ: запреща́ю тѝ и҆́менемъ і҆и҃са хрⷭ҇та̀, и҆зы́ди и҆з̾ неѧ̀: и҆ и҆зы́де въ то́мъ часѣ̀. ви́дѣвше же госпо́дїе є҆ѧ̀, ꙗ҆́кѡ и҆зы́де наде́жда тѧжа́нїѧ и҆́хъ, пое́мше па́ѵла и҆ сі́лꙋ, влеко́ша на то́ргъ ко кнѧзє́мъ. и҆ вве́дше и҆̀хъ къ воево́дамъ, рѣ́ша: сі́и человѣ́цы возмꙋща́ютъ гра́дъ на́шъ, і҆ꙋде́є сꙋ́ще. и҆ завѣщава́ютъ ѻ҆бы́чаи, ꙗ҆̀же не досто́итъ на́мъ прїима́ти, ни твори́ти, ри́млѧнѡмъ сꙋ́щымъ. и҆ сни́десѧ наро́дъ на ни́хъ, и҆ воевѡ́ды растерза́вше и҆̀мъ ри́зы, велѧ́хꙋ па́лицами би́ти и҆̀хъ. мно́ги же да́вше и҆̀мъ ра̑ны, всади́ша въ темни́цꙋ, завѣща́вше темни́чномꙋ стра́жꙋ тве́рдѡ стрещѝ и҆̀хъ: и҆́же таково̀ завѣща́нїе прїе́мъ, всадѝ и҆̀хъ во внꙋ́треннюю темни́цꙋ, и҆ но́ги и҆́хъ забѝ въ кла́дѣ. въ полꙋ́нощи же па́ѵелъ и҆ сі́ла молѧ́щасѧ поѧ́ста бг҃а: послꙋ́шахꙋ же и҆́хъ ю҆́зницы. внеза́пꙋ же трꙋ́съ бы́сть ве́лїй, ꙗ҆́кѡ поколеба́тисѧ ѡ҆снова́нїю темни́чномꙋ: ѿверзо́ша же сѧ а҆́бїе двє́ри всѧ̀, и҆ всѣ̑мъ ю҆́зы ѡ҆слабѣ́ша. возбꙋ́ждьсѧ же темни́чный стра́жъ, и҆ ви́дѣвъ ѿве́рсты двє́ри темни́цы, и҆звле́къ но́жъ, хотѧ́ше себѐ ᲂу҆би́ти, мнѧ̀ и҆збѣ́гшѧ ю҆́зники. возгласи́ же гла́сомъ ве́лїимъ па́ѵелъ, глаго́лѧ: ничто́же сотворѝ себѣ̀ ѕла̀, вси́ бо є҆смы̀ здѣ̀. проси́въ же свѣщѝ, вскочѝ, и҆ тре́петенъ бы́въ, припадѐ къ па́ѵлꙋ и҆ сі́лѣ: и҆ и҆зве́дъ и҆̀хъ во́нъ, речѐ: госпо́дїе, что́ ми подоба́етъ твори́ти, да спасꙋ́сѧ; ѻ҆́на же реко́ста: вѣ́рꙋй въ гдⷭ҇а і҆и҃са хрⷭ҇та̀, и҆ спасе́шисѧ ты̀, и҆ ве́сь до́мъ тво́й. и҆ глаго́ласта є҆мꙋ̀ сло́во гдⷭ҇не, и҆ всѣ̑мъ и҆̀же въ домꙋ̀ є҆гѡ̀. и҆ пое́мъ ѧ҆̀ въ то́й же ча́съ но́щи, и҆змы̀ ѿ ра́нъ, и҆ крести́сѧ са́мъ, и҆ своѝ є҆мꙋ̀ всѝ а҆́бїе. вве́дъ же ѧ҆̀ въ до́мъ сво́й, поста́ви трапе́зꙋ, и҆ возра́довасѧ со всѣ́мъ до́момъ свои́мъ, вѣ́ровавъ бг҃ꙋ. ",
}

