add_apostol {
  ["номер"] = 40,
  ["комментарий"] = "Деян., 40 зач., XVIII, 1-11.",
  ["текст_ру"] = "Во дни о́ны, отлучи́ся Па́вел от Афи́н, прии́де в Кори́нф. И обре́те не́коего иуде́анина и́менем Аки́лу, По́нтянина ро́дом, но́во прише́дша от Итали́и, и Приски́ллу жену́ его́, зане́ повеле́л бя́ше Клавди́й отлучи́тися всем Иуде́ем от Ри́ма, прии́де к ним, и зане́ единохудо́жником бы́ти им, пребы́сть у них и де́лаше, бя́ху бо скинотво́рцы хи́тростию. Стяза́шеся же на со́нмищах по вся суббо́ты и препира́ше иуде́и и е́ллины. И я́коже снидо́ста от Македо́нии Си́ла же и Тимофе́й, тужа́ше ду́хом Па́вел, свиде́тельствуя иуде́ом Иису́са бы́ти Христа́. Проти́вящымся же им и ху́лящым, отря́с ри́зы своя́, рече́ к ним: кровь ва́ша на глава́х ва́ших, чист аз, отны́не во язы́ки иду́. И преше́д отту́ду, прии́де в дом не́коего и́менем Иу́ста, чту́ща Бо́га, ему́же хра́мина бе вскрай со́нмища. Крисп же нача́льник собо́ра ве́рова Го́сподеви со всем до́мом свои́м, и мно́зи от Кори́нфян слы́шавше ве́роваху и креща́хуся. Рече́ же Госпо́дь в виде́нии нощно́м Па́влу: не бо́йся, но глаго́ли и да не умо́лкнеши, зане́ Аз есмь с тобо́ю, и никто́же приложи́т озло́бити тя, зане́ лю́дие суть Ми мно́зи во гра́де сем. Седя́ше же та́мо ле́то и ме́сяц шесть, учя́ в них сло́ву Бо́жию. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, ѿлꙋчи́сѧ па́ѵелъ ѿ а҆ѳи́нъ, прїи́де въ корі́нѳъ. и҆ ѡ҆брѣ́те нѣ́коего і҆ꙋде́анина и҆́менемъ а҆кѵ́лꙋ, по́нтѧнина ро́домъ, но́вѡ прише́дша ѿ і҆талі́и, и҆ прїскі́ллꙋ женꙋ̀ є҆гѡ̀, [занѐ повелѣ́лъ бѧ́ше клаѵді́й ѿлꙋчи́тисѧ всѣ́мъ і҆ꙋде́ємъ ѿ ри́ма,] прїи́де къ ни́мъ: и҆ занѐ є҆динохꙋдо́жникѡмъ бы́ти и҆̀мъ, пребы́сть ᲂу҆ ни́хъ, и҆ дѣ́лаше: бѧ́хꙋ бо скинотво́рцы хи́тростїю. стѧза́шесѧ же на со́нмищахъ по всѧ̀ сꙋббѡ́ты, и҆ препира́ше і҆ꙋдє́и и҆ є҆́ллины. и҆ ꙗ҆́коже снидо́ста ѿ македо́нїи сі́ла же и҆ тїмоѳе́й, тꙋжа́ше дх҃омъ па́ѵелъ, свидѣ́тельствꙋѧ і҆ꙋде́ѡмъ і҆и҃са бы́ти хрⷭ҇та̀. проти́вѧщымсѧ же и҆̀мъ и҆ хꙋ́лѧщымъ, ѡ҆трѧ́съ ри̑зы своѧ̀, речѐ къ ни́мъ: кро́вь ва́ша на глава́хъ ва́шихъ: чи́стъ а҆́зъ, ѿ нн҃ѣ во ꙗ҆зы́ки и҆дꙋ̀. и҆ преше́дъ ѿтꙋ́дꙋ, прїи́де въ до́мъ нѣ́коегѡ и҆́менемъ і҆ꙋ́ста, чтꙋ́ща бг҃а, є҆мꙋ́же хра́мина бѣ̀ вскра́й со́нмища. крі́спъ же нача́льникъ собо́ра, вѣ́рова гдⷭ҇ви со всѣ́мъ до́момъ свои́мъ: и҆ мно́зи ѿ корі́нѳѧнъ слы́шавше вѣ́ровахꙋ, и҆ креща́хꙋсѧ. рече́ же гдⷭ҇ь въ видѣ́нїи нощно́мъ па́ѵлꙋ: не бо́йсѧ, но глаго́ли, и҆ да не ᲂу҆мо́лкнеши: занѐ а҆́зъ є҆́смь съ тобо́ю, и҆ никто́же приложи́тъ ѡ҆ѕло́бити тѧ̀: занѐ лю́дїе сꙋ́ть мѝ мно́зи во гра́дѣ се́мъ. сѣдѧ́ше же та́мѡ лѣ́то и҆ мѣ̑сѧцъ ше́сть, ᲂу҆чѧ̀ въ ни́хъ сло́вꙋ бж҃їю. ",
}

add_apostol {
