  ["комментарий"] = "Деян., 41 зач., XVIII, 22–28.",
  ["текст_ру"] = "Во дни о́ны, сшед Па́вел в Кесари́ю, возше́д и целова́в це́рковь, сни́де во Антиохи́ю, и сотво́рь вре́мя не́кое, изы́де, проходя́ поря́ду Галати́йскую страну́ и Фриги́ю, утвержда́я вся ученики́. Иуде́анин же не́кто, Аполло́с и́менем, алекса́ндрянин ро́дом, муж слове́сен, прии́де во Ефе́с, си́лен сый в кни́гах. Сей бе оглаше́н пути́ Госпо́дню, и горя́ ду́хом, глаго́лаше и уча́ше изве́стно я́же о Го́споде, ве́дый то́кмо креще́ние Иоа́нново. Сей же нача́т дерза́ти на со́нмищах. Слы́шавша же его́ Аки́ла и Приски́лла, прия́ша его́ и изве́стнее тому́ сказа́ша путь Госпо́день. Хотя́щу же ему́ преити́ во Аха́ию, предпосла́вше бра́тия написа́ша ученико́м прия́ти его́, и́же прише́д та́мо посо́бствова мно́го ве́ровавшым благода́тию. Тве́рдо бо иуде́и не престая́ облича́ше пред людьми́, сказу́я Писа́ньми, Иису́са бы́ти Христа́. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, сше́дъ па́ѵелъ въ кесарі́ю, возше́дъ и҆ цѣлова́въ цр҃ковь, сни́де бо а҆нтїохі́ю: и҆ сотво́рь вре́мѧ нѣ́кое, и҆зы́де проходѧ̀ по рѧ́дꙋ галаті́йскꙋю странꙋ̀ и҆ фрѷгі́ю, ᲂу҆твержда́ѧ всѧ̀ ᲂу҆ченикѝ. і҆ꙋде́анинъ же нѣ́кто а҆поллѡ́съ и҆́менемъ, а҆леѯа́ндрѧнинъ ро́домъ, мꙋ́жъ слове́сенъ, прїи́де во є҆фе́съ, си́ленъ сы́й въ кни́гахъ: се́й бѣ̀ ѡ҆глаше́нъ пꙋтѝ гдⷭ҇ню, и҆ горѧ̀ дх҃омъ, глаго́лаше и҆ ᲂу҆ча́ше и҆звѣ́стнѡ ꙗ҆̀же ѡ҆ гдⷭ҇ѣ, вѣ́дый то́кмѡ креще́нїе і҆ѡа́нново. се́й же нача́тъ дерза́ти на со́нмищахъ: слы́шавше же є҆го̀ а҆кѵ́ла и҆ прїскі́лла, прїѧ́ша є҆го̀, и҆ и҆звѣ́стнѣе томꙋ̀ сказа́ша пꙋ́ть гдⷭ҇нь. хотѧ́щꙋ же є҆мꙋ̀ преитѝ во а҆ха́їю, предпосла́вше бра́тїѧ, написа́ша ᲂу҆ченикѡ́мъ прїѧ́ти є҆го̀: и҆́же прише́дъ та́мѡ, посо́бствова мно́гѡ вѣ́ровавшымъ бл҃года́тїю. тве́рдѡ бо і҆ꙋдє́и не престаѧ̀ ѡ҆блича́ше пред̾ людьмѝ, сказꙋ́ѧ писа́ньми, і҆и҃са бы́ти хрⷭ҇та̀. ",
}

add_apostol {
