add_apostol {
  ["номер"] = 44,
  ["комментарий"] = "Деян., 44 зач., XX, 16-18, 28-36.",
  ["текст_ру"] = "Во дни о́ны, суди́ Па́вел ми́мо ити́ Ефе́с, я́ко да не бу́дет ему́ закосне́ти во Аси́и, тща́ше бо ся, а́ще возмо́жно бу́дет, в день Пятьдеся́тный бы́ти во Иерусали́ме. От Мили́та же посла́в во Ефе́с, призва́ пресви́теры церко́вныя. И я́коже приидо́ша к нему́, рече́ к ним: внима́йте у́бо себе́ и всему́ ста́ду, в не́мже вас Дух Святы́й поста́ви епи́скопы, пасти́ Це́рковь Го́спода и Бо́га, ю́же стяжа́ Кро́вию Свое́ю. Аз бо вем сие́, я́ко по отше́ствии мое́м вни́дут во́лцы тя́жцы в вас, не щадя́щии ста́да. И от вас саме́х воста́нут му́жие глаго́лющии развраще́ная, е́же отторга́ти ученики́ вслед себе́. Сего́ ра́ди бди́те, помина́юще, я́ко три ле́та нощь и день не престая́х уча́ со слеза́ми еди́наго кого́ждо вас. И ны́не предаю́ вас, бра́тие, Бо́гови и сло́ву благода́ти Его́, могу́щему назда́ти и да́ти вам насле́дие во освяще́нных всех. Сребра́ или́ зла́та или́ риз ни еди́наго возжела́х. Са́ми ве́сте, я́ко тре́бованию моему́ и су́щим со мно́ю послужи́сте ру́це мои́ си́и. Вся сказа́х вам, я́ко та́ко тружда́ющимся подоба́ет заступа́ти немощны́я, помина́ти же сло́во Го́спода Иису́са, я́ко Сам рече́: блаже́ннее есть па́че дая́ти, не́жели приима́ти. И сия́ рек, прекло́нь коле́на своя́, со все́ми и́ми помоли́ся. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны, сꙋдѝ па́ѵелъ ми́мѡ и҆тѝ є҆фе́съ, ꙗ҆́кѡ да не бꙋ́детъ є҆мꙋ̀ закоснѣ́ти во а҆сі́и: тща́ше бо сѧ, а҆́ще возмо́жно бꙋ́детъ, въ де́нь пѧтьдесѧ́тный бы́ти во і҆ерⷭ҇ли́мѣ. ѿ мїли́та же посла́въ во є҆фе́съ, призва̀ пресвѵ́теры цр҃ко́вныѧ. и҆ ꙗ҆́коже прїидо́ша къ немꙋ̀, речѐ къ ни́мъ: внима́йте ᲂу҆̀бо себѣ̀, и҆ всемꙋ̀ ста́дꙋ, въ не́мже ва́съ дх҃ъ ст҃ы́й поста́ви є҆пⷭ҇копы, пастѝ цр҃ковь гдⷭ҇а и҆ бг҃а, ю҆́же стѧжа̀ кро́вїю свое́ю. а҆́зъ бо вѣ́мъ сїѐ, ꙗ҆́кѡ по ѿше́ствїи мое́мъ вни́дꙋтъ во́лцы тѧ́жцы въ ва́съ, не щадѧ́щїи ста́да. и҆ ѿ ва́съ самѣ́хъ воста́нꙋтъ мꙋ́жїе глаго́лющїи развращє́наѧ, є҆́же ѿторга́ти ᲂу҆чн҃кѝ въ слѣ́дъ себѐ. сегѡ̀ ра́ди бди́те, помина́юще, ꙗ҆́кѡ трѝ лѣ̑та но́щь и҆ де́нь не престаѧ́хъ ᲂу҆чѧ̀ со слеза́ми є҆ди́наго кого́ждо ва́съ. и҆ ны́нѣ предаю̀ ва́съ, бра́тїе, бг҃ови, и҆ сло́вꙋ бл҃года́ти є҆гѡ̀, могꙋ́щемꙋ назда́ти, и҆ да́ти ва́мъ наслѣ́дїе во ѡ҆свѧще́нныхъ всѣ́хъ. сребра̀ и҆лѝ зла́та и҆лѝ ри́зъ, ни є҆ди́нагѡ возжела́хъ. са́ми вѣ́сте, ꙗ҆́кѡ тре́бованїю моемꙋ̀ и҆ сꙋ́щымъ со мно́ю, послꙋжи́стѣ рꙋ́цѣ моѝ сі́и. всѧ̑ сказа́хъ ва́мъ, ꙗ҆́кѡ та́кѡ трꙋжда́ющымсѧ подоба́етъ застꙋпа́ти немощны̑ѧ, помина́ти же сло́во гдⷭ҇а і҆и҃са, ꙗ҆́кѡ са́мъ речѐ: блаже́ннѣе є҆́сть па́че даѧ́ти, не́жели прїима́ти. и҆ сїѧ̑ ре́къ, прекло́нь кѡлѣ́на своѧ̀, со всѣ́ми и҆́ми помоли́сѧ. ",
}

add_apostol {
