  ["номер"] = 58,
  ["комментарий"] = "1 Пет., 58 зач., I, 1–2, 10–12; II, 6–10.",
  ["текст_ру"] = "Петр, Апо́стол Иису́с Христо́в, избра́нным прише́льцем разсе́яния По́нта, Галати́и, Каппадоки́и, Аси́и и Вифини́и, по прозре́нию Бо́га Отца́, во святы́ню Ду́ха, в послуша́ние и кропле́ние Кро́ве Иису́с Христо́вы, благода́ть вам и мир да умно́жится. О не́мже спасе́нии взыска́ша и испыта́ша проро́цы, и́же о ва́шей благода́ти прореко́ша, испыта́юще, в каково́ или́ в ко́е вре́мя явля́ше в них Дух Христо́в, пре́жде свиде́тельствуя о Христо́вых страсте́х, и я́же по сих сла́вах. И́мже откры́ся, я́ко не им саме́м, но нам служа́ху сия́, я́же ны́не возвести́шася вам благовествова́вшими вам Ду́хом Святы́м по́сланным с небесе́, в ня́же жела́ют А́нгели прини́кнути. Зане́ пи́сано есть в Писа́нии: се полага́ю в Сио́не ка́мень краеуго́лен, избра́н, че́стен, и ве́руяй вонь не постыди́тся. Вам у́бо честь ве́рующым, а проти́вящымся ка́мень, его́же небрего́ша зи́ждущии, сей бысть во главу́ у́гла, и ка́мень претыка́ния и ка́мень собла́зна. О не́мже и претыка́ются сло́ву противля́ющиися, на не́же и положе́ни бы́ша. Вы же род избра́н, ца́рское свяще́ние, язы́к свят, лю́дие обновле́ния, я́ко да доброде́тели возвестите́ из тмы вас Призва́вшаго в чу́дный Его́ свет, и́же иногда́ не лю́дие, ны́не же лю́дие Бо́жии; и́же не поми́ловани, ны́не же поми́ловани бы́сте. ",
  ["текст_цс"] = "Пе́тръ а҆пⷭ҇лъ і҆и҃съ хрⷭ҇то́въ, и҆збра́ннымъ прише́льцємъ разсѣ́ѧнїѧ, по́нта, галаті́и, каппадокі́и, а҆сі́и и҆ вїѳѷні́и, по прозрѣ́нїю бг҃а ѻ҆ц҃а̀, во ст҃ы́ню дх҃а, въ послꙋша́нїе и҆ кропле́нїе кро́ве і҆и҃съ хрⷭ҇то́вы благода́ть ва́мъ и҆ ми́ръ да ᲂу҆мно́житсѧ. ѡ҆ не́мже спасе́нїи взыска́ша и҆ и҆спыта́ша прⷪ҇ро́цы, и҆̀же ѡ҆ ва́шей бл҃года́ти прореко́ша: и҆спыта́юще, въ каково̀ и҆лѝ въ ко́е вре́мѧ ꙗ҆влѧ́ше въ ни́хъ дх҃ъ хрⷭ҇то́въ, пре́жде свидѣ́тельствꙋѧ ѡ҆ хрⷭ҇то́выхъ стрⷭ҇те́хъ, и҆ ꙗ҆̀же по си́хъ сла́вахъ. и҆̀мже ѿкры́сѧ, ꙗ҆́кѡ не и҆̀мъ самѣ́мъ, но на́мъ слꙋжа́хꙋ сїѧ̑, ꙗ҆̀же ны́нѣ возвѣсти́шасѧ ва́мъ благовѣствова́вшими ва́мъ дх҃омъ ст҃ы́мъ, по́сланнымъ съ нб҃сѐ, въ нѧ́же жела́ютъ а҆́гг҃ли прини́кнꙋти. занѐ пи́сано є҆́сть въ писа́нїи: сѐ полага́ю въ сїѡ́нѣ ка́мень краеꙋго́ленъ, и҆збра́нъ, че́стенъ: и҆ вѣ́рꙋѧй во́нь, не постыди́тсѧ. ва́мъ ᲂу҆́бѡ че́сть вѣ́рꙋющымъ: а҆ проти́вѧщымсѧ ка́мень, є҆гѡ́же небрего́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла, и҆ ка́мень претыка́нїѧ, и҆ ка́мень собла́зна: ѡ҆ не́мже и҆ претыка́ютсѧ, сло́вꙋ противлѧ́ющїисѧ, на не́же и҆ положе́ни бы́ша. вы́ же ро́дъ и҆збра́нъ, црⷭ҇кое свѧще́нїе ꙗ҆зы́къ ст҃ъ, лю́дїе ѡ҆бновле́нїѧ: ꙗ҆́кѡ да добродѣ́тєли возвѣститѐ, и҆з̾ тмы̀ ва́съ призва́вшагѡ въ чꙋ́дный є҆гѡ̀ свѣ́тъ: и҆́же и҆ногда̀ не лю́дїе, ны́нѣ же лю́дїе бж҃їи: и҆̀же не поми́ловани, ны́нѣ же поми́ловани бы́сте. ",
}

add_apostol {
  ["номер"] = 58,
  ["комментарий"] = "1 Пет., 58 зач., I, 3-9.",
  ["текст_ру"] = "Бра́тие, благослове́н Бог и Оте́ц Го́спода на́шего Иису́са Христа́, И́же по мно́зей Свое́й ми́лости порожде́й нас во упова́ние жи́во воскресе́нием Иису́с Христо́вым от ме́ртвых, в насле́дие нетле́нно, и нескве́рно, и неувяда́емо, соблюде́но на Небесе́х вас ра́ди, и́же си́лою Бо́жиею соблюде́ни ве́рою во спасе́ние, гото́вое яви́тися во вре́мя после́днее. О не́мже ра́дуйтеся, ма́ло ны́не, а́ще ле́по есть, приско́рбни бы́вше в разли́чных напа́стех, да искуше́ние ва́шея ве́ры многочестне́йше зла́та ги́бнуща, огне́м же искуше́на, обря́щется в похвалу́ и честь и сла́ву, во открове́нии Иису́с Христо́ве, Его́же не ви́девше, лю́бите, и на Него́же ны́не не зря́ще, ве́рующе же, ра́дуетеся ра́достию неизглаго́ланною и просла́вленною, прие́млюще кончи́ну ве́ре ва́шей, спасе́ние душа́м. ",
  ["текст_цс"] = "Бра́тїе, бл҃гослове́нъ бг҃ъ и҆ ѻ҆ц҃ъ гдⷭ҇а на́шегѡ і҆и҃съ хрⷭ҇та̀, и҆́же по мно́зѣй свое́й млⷭ҇ти порожде́й на́съ во ᲂу҆пова́нїе жи́во, воскрⷭ҇нїемъ і҆и҃съ хрⷭ҇то́вымъ ѿ ме́ртвыхъ, въ наслѣ́дїе нетлѣ́нно, и҆ нескве́рно, и҆ неꙋвѧда́емо, соблюде́но на нб҃сѣ́хъ ва́съ ра́ди: и҆̀же си́лою бж҃їею соблюде́ни вѣ́рою, во спасе́нїе гото́вое ꙗ҆ви́тисѧ во вре́мѧ послѣ́днее. ѡ҆ не́мже ра́дꙋйтесѧ, ма́лѡ ны́нѣ, а҆́ще лѣ́по є҆́сть, приско́рбни бы́вше въ разли́чныхъ напа́стехъ: да и҆скꙋше́нїе ва́шеѧ вѣ́ры, многочестнѣ́йше зла́та ги́бнꙋща, ѻ҆гне́мъ же и҆скꙋше́на, ѡ҆брѧ́щетсѧ въ похвалꙋ̀ и҆ че́сть и҆ сла́вꙋ, во ѿкрове́нїи і҆и҃съ хрⷭ҇то́вѣ. є҆го́же не ви́дѣвше лю́бите, и҆ на него́же ны́нѣ не зрѧ́ще, вѣ́рꙋюще же, ра́дꙋетесѧ ра́достїю неизглаго́лаиною и҆ просла́вленною: прїе́млюще кончи́нꙋ вѣ́рѣ ва́шей, спасе́нїе дꙋша́мъ. ",
}

add_apostol {
  ["номер"] = 58,
  ["комментарий"] = "1 Пет., 58 зач., I, 13-19.",
  ["текст_ру"] = "Возлю́бленнии, препоя́савше чре́сла помышле́ния ва́шего, трезвя́щеся соверше́нне, упова́йте на приноси́мую вам благода́ть открове́нием Иису́с Христо́вым. Я́ко ча́да послуша́ния, не преобразу́ющеся пе́рвыми неве́дения ва́шего похоте́нии, но по зва́вшему вы Свято́му, и са́ми свя́ти во всем житии́ бу́дите. Зане́ пи́сано есть: свя́ти бу́дите, я́ко Аз Свят есмь. И а́ще Отца́ называ́ете, нелицеме́рно судя́ща кому́ждо по де́лу, со стра́хом жития́ ва́шего вре́мя жи́тельствуйте, ве́дяще, я́ко не истле́нным сребро́м или́ зла́том изба́вистеся от су́етнаго ва́шего жития́, отцы́ пре́даннаго, но честно́ю кро́вию, я́ко а́гнца непоро́чна и пречи́ста, Христа́. ",
  ["текст_цс"] = "Возлю́бленнїи, препоѧ́савше чре́сла помышле́нїѧ ва́шегѡ, трезвѧ́щесѧ, соверше́ннѣ ᲂу҆пова́йте на приноси́мꙋю ва́мъ благода́ть, ѿкрове́нїемъ і҆и҃съ хрⷭ҇то́вымъ: ꙗ҆́кѡ ча̑да послꙋша́нїѧ, не преѡбразꙋ́ющесѧ пе́рвыми невѣ́дѣнїѧ ва́шегѡ похотѣ́нїи: но по зва́вшемꙋ вы̀ ст҃о́мꙋ, и҆ са́ми ст҃и во все́мъ житїѝ бꙋ́дите. занѐ пи́сано є҆́сть: ст҃и бꙋ́дите, ꙗ҆́кѡ а҆́зъ ст҃ъ є҆́смь. и҆ а҆́ще ѻ҆ц҃а̀ называ́ете нелицемѣ́рнѡ сꙋдѧ́ща комꙋ́ждо по дѣ́лꙋ, со стра́хомъ житїѧ̀ ва́шегѡ вре́мѧ жи́тельствꙋйте: вѣ́дѧще, ꙗ҆́кѡ не и҆стлѣ́ннымъ сребро́мъ, и҆лѝ зла́томъ и҆зба́вистесѧ ѿ сꙋ́етнагѡ ва́шегѡ житїѧ̀ ѻ҆ц҃ы̀ пре́даннагѡ: но честно́ю кро́вїю, ꙗ҆́кѡ а҆́гнца непоро́чна, и҆ пречи́ста хрⷭ҇та̀. ",
}

add_apostol {
  ["номер"] = 58,
  ["комментарий"] = "1 Пет., 58 зач., II, 11-24.",
  ["текст_ру"] = "Возлю́бленнии, молю́, я́ко прише́льцы и стра́нники, огреба́тися от плотски́х похоте́й, я́же вою́ют на ду́шу, житие́ ва́ше иму́ще добро́ во язы́цех, да о не́мже клеве́щут вас, а́ки злоде́ев, от до́брых дел ви́девше, просла́вят Бо́га в день посеще́ния. Повини́теся у́бо вся́кому челове́чу созда́нию, Го́спода ра́ди, а́ще царю́, я́ко преоблада́ющу, а́ще ли же князе́м, я́ко от Него́ по́сланным, во отмще́ние у́бо злоде́ем, в похвалу́ же благотво́рцем. Я́ко та́ко есть во́ля Бо́жия, благотворя́щим обуздова́ти безу́мных челове́к неве́жество, я́ко свобо́дни, а не я́ко прикрове́ние иму́ще зло́бы свобо́ду, но я́ко раби́ Бо́жии. Всех почита́йте, бра́тство возлюби́те, Бо́га бо́йтеся, царя́ чти́те. Раби́, повину́йтеся во вся́ком стра́се влады́кам, не то́кмо благи́м и кро́тким, но и стропти́вым. Се бо есть уго́дно пред Бо́гом, а́ще со́вести ра́ди Бо́жия терпи́т кто ско́рби, стражда́ без пра́вды. Ка́я бо похвала́, а́ще согреша́юще, му́чими, терпите́? Но а́ще добро́ творя́ще и стра́ждуще терпите́, сие́ уго́дно пред Бо́гом. На сие́ бо и зва́ни бы́сте, зане́ и Христо́с пострада́ по нас, нам оста́вль о́браз, да после́дуем стопа́м Его́. И́же греха́ не сотвори́, ни обре́теся лесть во усте́х Его́. И́же укоря́емь, проти́ву не укоря́ше, стражда́ не преща́ше, предая́ше же судя́щему пра́ведно. И́же грехи́ на́ша Сам вознесе́ на те́ле Свое́м на дре́во, да от грех избы́вше, пра́вдою поживе́м. ",
  ["текст_цс"] = "Возлю́бленнїи, молю̀ ꙗ҆́кѡ прише́льцы и҆ стра́нники, ѡ҆греба́тисѧ ѿ плотски́хъ похоте́й, ꙗ҆̀же вою́ютъ на дꙋ́шꙋ: житїѐ ва́ше и҆мꙋ́ще добро́ бо ꙗ҆зы́цѣхъ: да ѡ҆ не́мже клеве́щꙋтъ ва́съ, а҆́ки ѕлодѣ́євъ, ѿ до́брыхъ дѣ́лъ ви́дѣвше, просла́вѧтъ бг҃а въ де́нь посѣще́нїѧ. повини́тесѧ ᲂу҆̀бо всѧ́комꙋ человѣ́чꙋ созда́нїю, гдⷭ҇а ра́ди: а҆́ще царю̀, ꙗ҆́кѡ преѡблада́ющꙋ: а҆́ще ли же кнѧзє́мъ, ꙗ҆́кѡ ѿ негѡ̀ пѡ́сланнымъ, во ѿмще́нїе ᲂу҆́бѡ ѕлодѣ́ємъ, въ похвалꙋ́ же бл҃готво́рцємъ. ꙗ҆́кѡ та́кѡ є҆́сть во́лѧ бж҃їѧ, бл҃готворѧ́щымъ ѡ҆бꙋздова́ти безꙋ́мныхъ человѣ̑къ невѣ́жство: ꙗ҆́кѡ свобо́дни, а҆ не ꙗ҆́кѡ прикрове́нїе и҆мꙋ́ще ѕло́бы свобо́дꙋ, но ꙗ҆́кѡ рабѝ бж҃їи. всѣ́хъ почита́йте: бра́тство возлюби́те: бг҃а бо́йтесѧ: царѧ̀ чти́те. рабѝ, повинꙋ́йтесѧ во всѧ́комъ стра́сѣ влады́камъ, не то́кмѡ благи́мъ и҆ крѡ́ткимъ, но и҆ стропти̑вымъ. се́ бо є҆́сть ᲂу҆го́дно пред̾ бг҃омъ, а҆́ще со́вѣсти ра́ди бж҃їѧ терпи́тъ кто̀ скѡ́рби, стражда̀ без̾ пра́вды. ка́ѧ бо похвала̀, а҆́ще согрѣша́юще мꙋ́чими терпитѐ; но а҆́ще добро̀ творѧ́ще, и҆ стра́ждꙋще терпитѐ, сїѐ ᲂу҆го́дно пред̾ бг҃омъ: на сїе́ бо и҆ зва́ни бы́сте. занѐ и҆ хрⷭ҇то́съ пострада̀ по на́съ, на́мъ ѡ҆ста́вль ѻ҆́бразъ, да послѣ́дꙋемъ стопа́мъ є҆гѡ̀. и҆́же грѣха̀ не сотворѝ, ни ѡ҆брѣ́тесѧ ле́сть во ᲂу҆стѣ́хъ є҆гѡ̀: и҆́же ᲂу҆корѧ́емь, проти́вꙋ не ᲂу҆корѧ́ше: стражда̀ не преща́ше: предаѧ́ше же сꙋдѧ́щемꙋ пра́веднѡ. и҆́же грѣхѝ на́шѧ са́мъ вознесѐ на тѣ́лѣ свое́мъ на дре́во: да ѿ грѣ̑хъ и҆збы́вше, пра́вдою поживе́мъ. ",
}

