  ["номер"] = 59,
  ["комментарий"] = "1 Пет., 59 зач., II, 21 – III, 9.",
  ["текст_ру"] = "Возлю́бленнии, Христо́с пострада́ по нас, нам оста́вль о́браз, да после́дуем стопа́м Его́. И́же греха́ не сотвори́, ни обре́теся лесть во усте́х Его́, И́же укаря́емь проти́ву не укаря́ше, стражда́ не преща́ше, предая́ше же Судя́щему пра́ведно, И́же грехи́ на́ша Сам вознесе́ на те́ле Свое́м на дре́во, да от грех избы́вше, пра́вдою поживе́м. Его́же я́звою изцеле́сте. Бе́сте бо я́ко о́вцы заблу́ждшыя не иму́щя па́стыря, но возврати́стеся ны́не к Па́стырю и Посети́телю душ ва́ших. Та́кожде же и жены́, повину́ющяся свои́м муже́м, да и а́ще не́цыи не повину́ются сло́ву, же́нским житие́м без сло́ва плене́ни бу́дут, ви́девше е́же со стра́хом чи́сто житие́ ва́ше. И́мже да бу́дет не вне́шняя, плете́ния влас и обложе́ния зла́та, или́ одея́ния риз, ле́пота, но потае́ный се́рдца челове́к, в неистле́нии кро́ткаго и молчали́ваго ду́ха, е́же есть пред Бо́гом многоце́нно. Та́ко бо иногда́ и святы́я жены́, упова́ющыя на Бо́га, украша́ху себе́, повину́ющяся свои́м муже́м, я́коже Са́рра послу́шаше Авраа́ма, господи́на того́ зову́щи, ея́же бы́сте ча́да, благотворя́щя и не боя́щяся ни еди́наго стра́ха. Му́жие та́кожде, вку́пе живу́ще со свои́ми жена́ми по ра́зуму, я́ко немощне́йшу сосу́ду же́нскому воздаю́ще честь, я́ко и снасле́дницы благода́тныя жи́зни, во е́же не прекраща́тися моли́твам ва́шим. Коне́ц же, вси единому́дрени бу́дите, ми́лостиви, братолю́бцы, милосе́рдни, благоутро́бни, мудролю́бцы, смиреному́дри, не воздаю́ще зла за зло, или́ досажде́ния за досажде́ние, супроти́вное же благословя́ще, ве́дяще, я́ко на се зва́ни бы́сте, да благослове́ние насле́дите. ",
  ["текст_цс"] = "Возлю́бленнїи, хрⷭ҇то́съ пострада̀ по на́съ, на́мъ ѡ҆ста́вль ѻ҆́бразъ, да послѣ́дꙋемъ стопа́мъ є҆гѡ̀. и҆́же грѣха̀ не сотворѝ, ни ѡ҆брѣ́тесѧ ле́сть во ᲂу҆стѣ́хъ є҆гѡ̀: и҆́же ᲂу҆корѧ́емь, проти́вꙋ не ᲂу҆корѧ́ше: стражда̀ не преща́ше: предаѧ́ше же сꙋдѧ́щемꙋ пра́веднѡ. и҆́же грѣхѝ на́шѧ са́мъ вознесѐ на тѣ́лѣ свое́мъ на дре́во: да ѿ грѣ̑хъ и҆збы́вше, пра́вдою поживе́мъ: є҆гѡ́же ꙗ҆́звою и҆сцѣлѣ́сте. бѣ́сте бо ꙗ҆́кѡ ѻ҆́вцы заблꙋ́ждшыѧ, не и҆мꙋ́щѧ па́стырѧ: но возврати́стесѧ ны́нѣ къ па́стырю и҆ посѣти́телю дꙋ́шъ ва́шихъ. та́кожде же и҆ жєны̀, повинꙋ́ющѧсѧ свои́мъ мꙋжє́мъ, да и҆ а҆́ще нѣ́цыи не повинꙋ́ютсѧ сло́вꙋ, же́нскимъ житїе́мъ без̾ сло́ва плѣне́ни бꙋ́дꙋтъ: ви́дѣвше є҆́же со стра́хомъ чи́сто житїѐ ва́ше, и҆̀мже да є҆́сть не внѣ́шнѧѧ плетє́нїѧ вла̑съ, и҆ ѡ҆бложє́нїѧ зла́та, и҆лѝ ѡ҆дѣѧ̑нїѧ ри́зъ лѣ́пота. но потае́ный се́рдца человѣ́къ, въ неистлѣ́нїи кро́ткагѡ и҆ молчали́вагѡ дх҃а, є҆́же є҆́сть пред̾ бг҃омъ многоцѣ́нно. та́кѡ бо и҆ногда̀ и҆ ст҃ы́ѧ жєны̀, ᲂу҆пова́ющыѧ на бг҃а, ᲂу҆краша́хꙋ себѐ, повинꙋ́ющѧсѧ свои́мъ мꙋжє́мъ: ꙗ҆́коже са́рра послꙋ́шаше а҆враа́ма, господи́на того̀ зовꙋ́щи: є҆ѧ́же бы́сте ча̑да, благотворѧ́щѧ, и҆ не боѧ́щѧсѧ ни є҆ди́нагѡ стра́ха. мꙋ́жїе та́кожде, вкꙋ́пѣ живꙋ́ще съ свои́ми жена́ми по ра́зꙋмꙋ, ꙗ҆́кѡ немощнѣ́йшꙋ сосꙋ́дꙋ же́нскомꙋ воздаю́ще че́сть, ꙗ҆́кѡ и҆ снаслѣ́дницы бл҃года́тныѧ жи́зни, во є҆́же не прекраща́тисѧ моли́твамъ ва́шымъ. коне́цъ же, всѝ є҆диномꙋ́дрени бꙋ́дите, ми́лостиви, братолю́бцы, милосе́рди, благоꙋтро́бни, мꙋдролю́бцы, смиреномꙋ́дри: не воздаю́ще ѕла̀ за ѕло̀, и҆лѝ досажде́нїѧ за досажде́нїе, сопроти́вное же благословѧ́ще: вѣ́дѧще, ꙗ҆́кѡ на сѐ зва́ни бы́сте, да благослове́нїе наслѣ́дите. ",
}

add_apostol {
  ["номер"] = 60,
  ["комментарий"] = "1 Пет., 60 зач., III, 10–22.",
  ["текст_ру"] = "Возлю́бленнии, хотя́й живо́т люби́ти и ви́дети дни бла́ги, да удержи́т язы́к свой от зла, и устне́ свои́ е́же не глаго́лати льсти. Да уклони́тся от зла, и да сотвори́т бла́го, да взы́щет ми́ра и да держи́тся его́, зане́ о́чи Госпо́дни на пра́ведныя, и у́ши Его́ в моли́тву их, лице́ же Госпо́дне на творя́щыя злая, е́же потреби́ти их от земли́. И кто озло́бит вас, а́ще благо́му подо́бницы бу́дете? Но а́ще и стра́ждете пра́вды ра́ди, блаже́ни есте́, стра́ха же их не убо́йтеся, ниже́ смуща́йтеся. Го́спода же Бо́га освяти́те в сердца́х ва́ших: гото́ви же при́сно ко отве́ту вся́кому вопроша́ющему вы сло́во о ва́шем упова́нии, с кро́тостию и стра́хом, со́весть иму́ще бла́гу, да о не́мже клеве́щут вас а́ки злоде́ев, постыдя́тся злосло́вящии ва́ше благо́е о Христе́ житие́. Лу́чше бо есть благо́е творя́щым, а́ще хо́щет во́ля Бо́жия, пострада́ти, не́жели зло творя́щым. Зане́ и Христо́с еди́ною о гресе́х на́ших пострада́, пра́ведник за непра́ведники, да приведе́т ны Бо́гови, умерщвле́н у́бо быв пло́тию, ожи́в же ду́хом, о не́мже и су́щым в темни́це духово́м соше́д пропове́да, проти́вльшымся иногда́, егда́ ожида́ше Бо́жие долготерпе́ние, во дни Но́евы, де́лаему ковче́гу, в не́мже ма́ло, си́речь осмь душ, спасо́шася от воды́. Его́же воображе́ние ны́не и нас спаса́ет креще́ние, не плотски́я отложе́ние скве́рны, но со́вести бла́ги вопроше́ние у Бо́га, воскресе́нием Иису́с Христо́вым, И́же есть одесну́ю Бо́га, возше́д на не́бо, поко́ршымся Ему́ А́нгелом и Власте́м и Си́лам. ",
  ["текст_цс"] = "Возлю́бленнїи, хотѧ́й живо́тъ люби́ти, и҆ ви́дѣти днѝ бла́ги, да ᲂу҆держи́тъ ѧ҆зы́къ сво́й ѿ ѕла̀, и҆ ᲂу҆стнѣ̀ своѝ є҆́же не глаго́лати льстѝ: да ᲂу҆клони́тсѧ ѿ ѕла̀, и҆ да сотвори́тъ бла́го, да взы́щетъ ми́ра, и҆ да держи́тсѧ є҆гѡ̀: занѐ ѻ҆́чи гдⷭ҇ни на пра́вєдныѧ, и҆ ᲂу҆́ши є҆гѡ̀ въ моли́твꙋ и҆́хъ: лице́ же гдⷭ҇не на творѧ́щыѧ ѕла̑ѧ, є҆́же потреби́ти и҆̀хъ ѿ землѝ. и҆ кто̀ ѡ҆ѕло́битъ ва́съ, а҆́ще благо́мꙋ подо́бницы бꙋ́дете; но а҆́ще и҆ стра́ждете пра́вды ра́ди, блаже́ни є҆стѐ: стра́ха же и҆́хъ не ᲂу҆бо́йтесѧ, нижѐ смꙋща́йтесѧ. гдⷭ҇а же бг҃а ѡ҆свѧти́те въ срⷣца́хъ ва́шихъ: гото́ви же при́снѡ ко ѿвѣ́тꙋ всѧ́комꙋ вопроша́ющемꙋ вы̀ сло́во ѡ҆ ва́шемъ ᲂу҆пова́нїи, съ кро́тостїю и҆ стра́хомъ, со́вѣсть и҆мꙋ́ще бла́гꙋ: да ѡ҆ не́мже клеве́щꙋтъ ва́съ а҆́ки ѕлодѣ́євъ, постыдѧ́тсѧ ѕлосло́вѧщїи ва́ше благо́е ѡ҆ хрⷭ҇тѣ̀ житїѐ. лꙋ́чше бо є҆́сть благо́е творѧ́щымъ, [а҆́ще хо́щетъ во́лѧ бж҃їѧ,] пострада́ти, не́жели ѕло̀ творѧ́щымъ. занѐ и҆ хрⷭ҇то́съ є҆ди́ною ѡ҆ грѣсѣ́хъ на́шихъ пострада̀, првⷣникъ за непра́ведники, да приведе́тъ ны̀ бг҃ови: ᲂу҆мерщвле́нъ ᲂу҆́бѡ бы́въ пло́тїю, ѡ҆жи́въ же дх҃омъ: ѡ҆ не́мже и҆ сꙋ́щымъ въ темни́цѣ дꙋховѡ́мъ соше́дъ проповѣ́да, проти́вльшымсѧ и҆ногда̀, є҆гда̀ ѡ҆жида́ше бж҃їе долготерпѣ́нїе, во днѝ нѡ́евы дѣ́лаемꙋ ковче́гꙋ, въ не́мже ма́лѡ, си́рѣчь ѻ҆́смь дꙋ́шъ, спасо́шасѧ ѿ воды̀. є҆гѡ́же воѡбраже́нїе ны́нѣ и҆ на́съ спаса́етъ креще́нїе, не плотскі́ѧ ѿложе́нїе скве́рны, но со́вѣсти бла́ги вопроше́нїе ᲂу҆ бг҃а, воскрⷭ҇нїемъ і҆и҃съ хрⷭ҇то́вымъ: и҆́же є҆́сть ѡ҆деснꙋ́ю бг҃а, возше́дъ на нб҃о, поко́ршымсѧ є҆мꙋ̀ а҆́гг҃лѡмъ, и҆ властє́мъ и҆ си́ламъ. ",
}

add_apostol {
  ["номер"] = 61,
  ["комментарий"] = "1 Пет., 61 зач., IV, 1–11.",
  ["текст_ру"] = "Возлю́бленнии, Христу́ пострада́вшу за ны пло́тию, и вы в ту же мысль вооружи́теся, зане́ пострада́вый пло́тию, преста́ от греха́, во е́же не ктому́ в челове́ческия по́хоти, но в во́лю Бо́жию про́чее во пло́ти жи́ти вре́мя. Довле́ет бо вам мимоше́дшее вре́мя жития́, во́лю язы́ческую твори́вшым, хо́ждшым в нечистота́х, в по́хотех, в скотоло́жстве, в по́мыслех, в пия́нстве, в козлогласова́ниих, в лихоима́ниих и богоме́рзких идолослуже́ниих. О не́мже дивя́тся, не сходя́щымся вам в то же блуда́ разлия́ние, ху́ляще, и́же воздадя́т сло́во гото́ву Су́щему суди́ти живы́м и ме́ртвым. На се бо и ме́ртвым благовести́ся, да суд у́бо прии́мут по челове́ку пло́тию, поживу́т же по Бо́зе ду́хом. Всем же кончи́на прибли́жися. Уцелому́дритеся у́бо и трезви́теся в моли́твах. Пре́жде же всех друг ко дру́гу любо́вь приле́жну име́йте, зане́ любо́вь покрыва́ет мно́жество грехо́в. Страннолю́бцы друг ко дру́гу, без ропта́ний. Ко́ждо я́коже прия́т дарова́ние, между́ себе́ сим служа́ще, я́ко до́брии строи́телие разли́чныя благода́ти Бо́жия. А́ще кто глаго́лет, я́ко словеса́ Бо́жия, а́ще кто слу́жит, я́ко от кре́пости, ю́же подае́т Бог, да о всем сла́вится Бог Иису́с Христо́м, Ему́же есть сла́ва и держа́ва во ве́ки веко́в. Ами́нь. ",
  ["текст_цс"] = "Возлю́бленнїи, хрⷭ҇тꙋ̀ ᲂу҆́бѡ пострада́вшꙋ за ны̀ пло́тїю, и҆ вы̀ въ тꙋ́ же мы́сль воѡрꙋжи́тесѧ: занѐ пострада́вый пло́тїю, преста̀ ѿ грѣха̀, во є҆́же не ктомꙋ̀ въ человѣ́ческїѧ по́хѡти, но въ во́лю бж҃їю про́чее во пло́ти жи́ти вре́мѧ. довлѣ́етъ бо ва́мъ мимоше́дшее вре́мѧ житїѧ̀, во́лю ꙗ҆зы́ческꙋю твори́вшымъ, хо́ждшымъ въ нечистота́хъ, въ по́хотехъ, въ скотоло́жствѣ, въ по́мыслѣхъ, въ пїѧ́нствѣ, въ козлогласова́нїихъ, въ лихоима́нїихъ, и҆ бг҃оме́рзскихъ і҆дѡлослꙋже́нїихъ. ѡ҆ не́мже дивѧ́тсѧ, не сходѧ́щымсѧ ва́мъ въ то́ же блꙋда̀ разлїѧ́нїе, хꙋ́лѧще: и҆́же воздадѧ́тъ сло́во гото́вꙋ сꙋ́щемꙋ сꙋди́ти живы̑мъ и҆ мє́ртвымъ. на се́ бо и҆ мє́ртвымъ благовѣсти́сѧ, да сꙋ́дъ ᲂу҆́бѡ прїи́мꙋтъ по человѣ́кꙋ пло́тїю, поживꙋ́тъ же по бз҃ѣ дх҃омъ. всѣ̑мъ же кончи́на прибли́жисѧ. ᲂу҆цѣломꙋ́дритесѧ ᲂу҆̀бо, и҆ трезви́тесѧ въ моли́твахъ. пре́жде же всѣ́хъ дрꙋ́гъ ко дрꙋ́гꙋ любо́вь прилѣ́жнꙋ и҆мѣ́йте: занѐ любо́вь покрыва́етъ мно́жество грѣхѡ́въ. страннолю́бцы дрꙋ́гъ ко дрꙋ́гꙋ, без̾ ропта́нїй. ко́ждо ꙗ҆́коже прїѧ́тъ дарова́нїе, междꙋ̀ себѐ си́мъ слꙋжа́ще, ꙗ҆́кѡ до́брїи строи́телїе разли́чныѧ благода́ти бж҃їѧ. а҆́ще кто̀ глаго́летъ, ꙗ҆́кѡ словеса̀ бж҃їѧ: а҆́ще кто̀ слꙋ́житъ, ꙗ҆́кѡ ѿ крѣ́пости, ю҆́же подае́тъ бг҃ъ: да ѡ҆ все́мъ сла́витсѧ бг҃ъ і҆и҃съ хрⷭ҇то́мъ, є҆мꙋ́же є҆́сть сла́ва и҆ держа́ва во вѣ́ки вѣкѡ́въ, а҆ми́нь. ",
}

