  ["комментарий"] = "2 Пет., 66 зач., I, 20 – II, 9.",
  ["текст_ру"] = "Возлю́бленнии, сие́ пре́жде ве́дуще, я́ко вся́ко проро́чество кни́жное по своему́ сказа́нию не быва́ет. Ни бо во́лею бысть когда́ челове́ком проро́чество, но от Свята́го Ду́ха просвеща́еми глаго́лаша святи́и Бо́жии челове́цы. Бы́ша же и лжи́вии проро́цы в лю́дех, я́коже и в вас бу́дут лжи́вии учи́телие, и́же внесу́т е́реси поги́бели, и иску́пльшаго их Влады́ки отмета́ющеся, приводя́ще себе́ ско́ру поги́бель. И мно́зи после́дствуют их нечистота́м, и́миже путь и́стинный поху́лится. И в преумноже́нии льсти́вых слове́с вас уловя́т: и́хже суд искони́ не косни́т, и поги́бель их не дре́млет. А́ще бо Бог а́ггелов согреши́вших не пощаде́, но плени́цами мра́ка связа́в, предаде́ на суд му́чимы блюсти́. И пе́рваго ми́ра не пощаде́, но осма́го Но́а пра́вды пропове́дника сохрани́, пото́п ми́ру нече́ствовавших наведе́. И гра́ды Содо́мския и Гомо́ррския сжег, разоре́нием осуди́, о́браз хотя́щым нече́ствовати положи́в. И пра́веднаго Ло́та, оби́дима от беззако́нных в нечистоте́ сожи́тия, изба́ви. Виде́нием бо и слу́хом пра́ведный, живы́й в них, день от дне ду́шу пра́ведну беззако́нными де́лы му́чаше. Весть Госпо́дь благочести́выя от напа́сти избавля́ти, непра́ведники же на день су́дный му́чимы блюсти́. ",
  ["текст_цс"] = "Возлю́бленнїи, сїѐ пре́жде вѣ́дꙋще, ꙗ҆́кѡ всѧ́ко проро́чество кни́жное, по своемꙋ̀ сказа́нїю не быва́етъ. ни бо̀ во́лею бы́сть когда̀ чл҃вѣ́кѡмъ прⷪ҇ро́чество, но ѿ ст҃а́гѡ дх҃а просвѣща́еми глаго́лаша ст҃і́и бж҃їи чл҃вѣ́цы. бы́ша же и҆ лжи́вїи проро́цы въ лю́дехъ, ꙗ҆́коже и҆ въ ва́съ бꙋ́дꙋтъ лжи́вїи ᲂу҆чи́тели, и҆̀же внесꙋ́тъ є҆́рєси поги́бели, и҆ и҆скꙋ́пльшагѡ и҆̀хъ влⷣки ѿмета́ющесѧ, приводѧ́ще себѣ̀ ско́рꙋ поги́бель: и҆ мно́зи послѣ́дствꙋютъ и҆́хъ нечистота́мъ, и҆́миже пꙋ́ть и҆́стинный похꙋ́литсѧ. и҆ въ преꙋмноже́нїи льсти́выхъ слове́съ ва́съ ᲂу҆ловѧ́тъ: и҆́хже сꙋ́дъ и҆сконѝ не косни́тъ, и҆ поги́бель и҆́хъ не дре́млетъ. а҆́ще бо бг҃ъ а҆́ггелѡвъ согрѣши́вшихъ не пощадѣ̀, но плени́цами мра́ка свѧза́въ предадѐ на сꙋ́дъ мꙋ́чимы блюстѝ: и҆ пе́рвагѡ мі́ра не пощадѣ̀, но ѻ҆сма́го нѡ́а пра́вды проповѣ́дника сохранѝ, пото́пъ мі́рꙋ нече́ствовавшихъ наведѐ. и҆ гра́ды содѡ́мскїѧ и҆ гомѡ́ррскїѧ сже́гъ, разоре́нїемъ ѡ҆сꙋдѝ, ѻ҆́бразъ хотѧ́щымъ нече́ствовати положи́въ. и҆ пра́веднаго лѡ́та ѡ҆би́дима ѿ беззако́нныхъ въ нечистотѣ̀ сожи́тїѧ и҆зба́ви: видѣ́нїемъ бо и҆ слꙋ́хомъ првⷣный живы́й въ ни́хъ, де́нь ѿ днѐ дꙋ́шꙋ пра́веднꙋ беззако́нными дѣ́лы мꙋ́чаше. вѣ́сть гдⷭ҇ь благочєсти́выѧ ѿ напа́сти и҆збавлѧ́ти, непра́ведники же на де́нь сꙋ́дный мꙋ́чимы блюстѝ. ",
}

add_apostol {
  ["номер"] = 67,
  ["комментарий"] = "2 Пет., 67 зач., II, 9–22.",
  ["текст_ру"] = "Возлю́бленнии, весть Госпо́дь благочести́выя от напа́сти избавля́ти, непра́ведники же на день су́дный му́чимы блюсти́, наипа́че же во след плотски́я по́хоти скверне́ния ходя́щыя и о госпо́дьстве нерадя́щыя, продерза́теле, себе́ уго́дницы, сла́вы не трепе́щут ху́ляще, иде́же А́нгели кре́постию и си́лою бо́льши су́ще, не терпя́т на ся от Го́спода укори́знена суда́. Си́и же, я́ко ско́ти живо́тни естество́м бы́вше в поги́бель и тлю, в ни́хже не разуме́ют ху́ляще, во истле́нии свое́м истле́ют, прие́млюще мзду непра́ведну, сласть мня́ще вседне́вное насыще́ние, скверни́тели и поро́чницы, пита́ющеся лестьми́ свои́ми, яду́ще с ва́ми, о́чи иму́ще испо́лнь блудодея́ния и непреста́емаго греха́, прельща́юще ду́шы неутвержде́ны, се́рдце науче́но лихои́мству иму́ще, кля́твы ча́да, оста́вльше пра́вый путь заблуди́ша, после́довавше пути́ Валаа́мову Восо́рова, и́же мзду непра́ведну возлюби́, обличе́ние же име́ своего́ беззако́ния, подъяре́мник безгла́сен, челове́ческим гла́сом провеща́вш, возбрани́ проро́ка безу́мие. Си́и суть исто́чницы безво́дни, о́блацы и мглы от ветр преноси́ми, и́мже мрак те́мный во ве́ки блюде́тся. Прего́рдая бо суеты́ веща́юще, прельща́ют в скве́рны плотски́я по́хоти, отбега́юще их отню́д живу́щих во льсти, свобо́ду им обещава́юще, са́ми раби́ су́ще тле́ния, и́мже бо кто побежде́н быва́ет, сему́ и рабо́тен есть. А́ще бо отбе́гше скверн ми́ра в ра́зум Го́спода и Спа́са на́шего Иису́са Христа́, си́ми же па́ки спле́тшеся побежда́еми быва́ют, бы́ша им после́дняя го́рша пе́рвых. Лу́чше бо бе им не позна́ти пути́ пра́вды, не́жели позна́вшым возврати́тися вспять от пре́данныя им святы́я за́поведи. Случи́ся бо им и́стинная при́тча: пес возвра́щься на свою́ блево́тину, и свиния́, омы́вшися, в кал ти́нный. ",
  ["текст_цс"] = "Возлю́бленнїи, вѣ́сть гдⷭ҇ь благочєсти́выѧ ѿ напа́сти и҆збавлѧ́ти, непра́ведники же на де́нь сꙋ́дный мꙋ́чимы блюстѝ. наипа́че же во слѣ́дъ плотскі́ѧ по́хоти скверне́нїѧ ходѧ́щыѧ, и҆ ѡ҆ гдⷭ҇ьствѣ нерадѧ́щыѧ, продерза́телє себѣ̀ ᲂу҆гѡ́дницы, сла́вы не трепе́щꙋтъ хꙋ́лѧще: и҆дѣ́же а҆́гг҃ли крѣ́постїю и҆ си́лою бо́льши сꙋ́ще, не терпѧ́тъ на сѧ̀ ѿ гдⷭ҇а ᲂу҆кори́знена сꙋда̀. сі́и же, ꙗ҆́кѡ ско́ти живо́тни є҆стество́мъ бы́вше въ поги́бель и҆ тлю̀, въ ни́хже не разꙋмѣ́ютъ хꙋ́лѧще, во и҆стлѣ́нїи свое́мъ и҆стлѣ́ютъ, прїе́млюще мздꙋ̀ непра́веднꙋ, сла́сть мнѧ́ще вседне́вное насыще́нїе, скверни́тели и҆ поро́чницы, пита́ющесѧ лестьмѝ свои́ми, ꙗ҆дꙋ́ще съ ва́ми, ѻ҆́чи и҆мꙋ́ще и҆спо́лнь блꙋдодѣѧ́нїѧ, и҆ непреста́емагѡ грѣха̀, прельща́юще дꙋ́шы неꙋтвержде́ны, се́рдце наꙋче́но лихои́мствꙋ и҆мꙋ́ще, клѧ́твы ча̑да: ѡ҆ста́вльше пра́вый пꙋ́ть, заблꙋди́ша, послѣ́довавше пꙋтѝ валаа́мовꙋ восо́рова, и҆́же мздꙋ̀ непра́веднꙋ возлюбѝ. ѡ҆бличе́нїе же и҆мѣ̀ своегѡ̀ беззако́нїѧ: под̾ѧре́мникъ безгла́сенъ, человѣ́ческимъ гла́сомъ провѣща́вшъ, возбранѝ прⷪ҇ро́ка безꙋ́мїе. сі́и сꙋ́ть и҆сто́чницы безво́дни, ѻ҆́блацы и҆ мглы̑ ѿ вѣ̑тръ преноси́ми, и҆̀мже мра́къ те́мный во вѣ́ки блюде́тсѧ. прегѡ́рдаѧ бо сꙋеты̀ вѣща́юще, прельща́ютъ въ сквє́рны плотскі́ѧ по́хоти, ѿбѣга́юще и҆́хъ ѿню́дъ живꙋ́щихъ во льстѝ, свобо́дꙋ и҆̀мъ ѡ҆бѣщава́юще, са́ми рабѝ сꙋ́ще тлѣ́нїѧ: и҆́мже бо кто̀ побѣжде́нъ быва́етъ, семꙋ̀ и҆ рабо́тенъ є҆́сть. а҆́ще бо ѿбѣ́гше скве́рнъ мі́ра, въ ра́зꙋмъ гдⷭ҇а и҆ сп҃са на́шегѡ і҆и҃са хрⷭ҇та̀, си́ми же па́ки спле́тшесѧ побѣжда́еми быва́ютъ: бы́ша же и҆̀мъ послѣ̑днѧѧ гѡ́рша пе́рвыхъ. лꙋ́чше бо бѣ̀ и҆̀мъ не позна́ти пꙋтѝ пра́вды, не́жели позна́вшымъ возврати́тисѧ вспѧ́ть ѿ пре́данныѧ и҆̀мъ ст҃ы́ѧ за́повѣди. слꙋчи́сѧ бо и҆̀мъ и҆́стиннаѧ при́тча: пе́съ возвра́щсѧ на свою̀ блево́тинꙋ, и҆ свинїѧ̀ ѡ҆мы́вшисѧ, въ ка́лъ ти́нный. ",
}

add_apostol {
  ["номер"] = 68,
  ["комментарий"] = "2 Пет., 68 зач., III, 1–18.",
  ["текст_ру"] = "Возлю́бленнии, сие́ уже́ второ́е вам пишу́ посла́ние, в ни́хже возбужда́ю воспомина́нием ваш чи́стый смысл, помяну́ти пре́жде рече́нныя глаго́лы от святы́х проро́к, и Апо́стол ва́ших за́поведь Го́спода и Спа́са. Сие́ пре́жде ве́дяще, я́ко прии́дут в после́дния дни руга́теле, по свои́х по́хотех ходя́ще и глаго́люще: где есть обетова́ние прише́ствия Его́, отне́леже бо отцы́ успо́ша, вся та́ко пребыва́ют от нача́ла созда́ния. Таи́тся бо им сие́ хотя́щым, я́ко небеса́ бе́ша испе́рва, и земля́ от воды́ и водо́ю соста́влена, Бо́жиим сло́вом, и́миже тогда́шний мир, водо́ю потопле́н быв, поги́бе. А ны́нешняя небеса́ и земля́ те́мже Сло́вом сокрове́на суть, огню́ блюдо́ма на день суда́ и поги́бели нечести́вых челове́к. Еди́но же сие́ да не утаи́тся вас, возлю́бленнии, я́ко еди́н день пред Го́сподем я́ко ты́сяща лет, и ты́сяща лет я́ко день еди́н. Не косни́т Госпо́дь обетова́ния, я́коже не́цыи косне́ние мнят, но долготерпи́т на нас, не хотя́ да кто поги́бнет, но да вси в покая́ние прии́дут. Прии́дет же день Госпо́день я́ко тать в нощи́, во́ньже небеса́ у́бо с шу́мом ми́мо и́дут, стихи́и же сжига́емы разоря́тся, земля́ же и я́же на ней дела́ сгоря́т. Сим у́бо всем разоря́емым, ка́цем подоба́ет бы́ти вам во святы́х пребыва́ниих и благоче́стиих, ча́ющым и скоре́е бы́ти жела́ющым прише́ствия Бо́жияго дне, его́же ра́ди небеса́ жего́ма разоря́тся, и стихи́и опаля́емы раста́ются? Но́ва же небесе́ и но́вы земли́ по обетова́нию Его́ ча́ем, в ни́хже пра́вда живе́т. Те́мже, возлю́бленнии, сих ча́юще, потщи́теся нескве́рни и непоро́чни Тому́ обрести́ся в ми́ре, и Го́спода на́шего долготерпе́ние спасе́ние непщу́йте, я́коже и возлю́бленный наш брат Па́вел по да́нней ему́ прему́дрости написа́ вам, я́коже и во всех свои́х посла́ниих, глаго́ля в них о сих, в ни́хже суть неудо́бь разу́мна не́кая, я́же ненауче́ни и неутвержде́ни развраща́ют, я́коже и про́чая Писа́ния, к свое́й поги́бели им. Вы же у́бо, возлю́бленнии, предве́дяще храни́теся, да не ле́стию беззако́нных сведе́ни бы́вше, отпаде́те своего́ утвержде́ния. Но да расте́те во благода́ти и ра́зуме Го́спода на́шего и Спа́са Иису́са Христа́. Тому́ сла́ва и ны́не и в день ве́ка. Ами́нь. ",
  ["текст_цс"] = "Возлю́бленнїи, сїѐ ᲂу҆жѐ второ́е ва́мъ пишꙋ̀ посла́нїе, въ ни́хже возбꙋжда́ю воспомина́нїемъ ва́шъ чи́стый смы́слъ: помѧнꙋ́ти пре́жде речє́нныѧ глаго́лы ѿ ст҃ы́хъ прорѡ́къ, и҆ а҆пⷭ҇лъ ва́шихъ и҆ за́повѣдей гдⷭ҇а и҆ сп҃са. сїѐ пре́жде вѣ́дѧще, ꙗ҆́кѡ прїи́дꙋтъ въ послѣ́днїѧ днѝ рꙋга́телє, по свои́хъ по́хотехъ ходѧ́ще, и҆ глаго́люще: гдѣ́ є҆сть ѡ҆бѣтова́нїе прише́ствїѧ є҆гѡ̀; ѿне́лѣже бо ѻ҆ц҃ы̀ ᲂу҆спо́ша, всѧ̑ та́кѡ пребыва́ютъ ѿ нача́ла созда́нїѧ. таи́тсѧ бо и҆̀мъ сїѐ хотѧ́щымъ, ꙗ҆́кѡ нб҃са̀ бѣ́ша и҆спе́рва, и҆ землѧ̀ ѿ воды̀, и҆ водо́ю соста́влена, бж҃їимъ сло́вомъ: и҆́миже тогда́шнїй мі́ръ, водо́ю потопле́нъ бы́въ, поги́бе. а҆ ны́нѣшнѧѧ нб҃са̀ и҆ землѧ̀ тѣ́мже сло́вомъ сокровє́на сꙋ́ть, ѻ҆гню̀ блюдѡ́ма на де́нь сꙋда̀, и҆ поги́бели нечести́выхъ человѣ̑къ. є҆ди́но же сїѐ да не ᲂу҆таи́тсѧ ва́съ возлю́бленнїи, ꙗ҆́кѡ є҆ди́нъ де́нь пред̾ гдⷭ҇емъ ꙗ҆́кѡ ты́сѧща лѣ́тъ, и҆ ты́сѧща лѣ́тъ ꙗ҆́кѡ де́нь є҆ди́нъ. не косни́тъ гдⷭ҇ь ѡ҆бѣтова́нїѧ, ꙗ҆́коже нѣ́цыи коснѣ́нїе мнѧ́тъ: но долготерпи́тъ на на́съ, не хотѧ̀ да кто̀ поги́бнетъ, но да всѝ въ покаѧ́нїе прїи́дꙋтъ. прїи́детъ же де́нь гдⷭ҇нь ꙗ҆́кѡ та́ть въ нощѝ, во́ньже нб҃са̀ ᲂу҆́бѡ съ шꙋ́момъ ми́мѡ и҆́дꙋтъ, стїхі́и же сжига́емы разорѧ́тсѧ, землѧ́ же и҆ ꙗ҆̀же на не́й дѣла̀ сгорѧ́тъ. си̑мъ ᲂу҆̀бо всѣ́мъ разорѧ́ємымъ, ка́цѣмъ подоба́етъ бы́ти ва́мъ, во ст҃ы́хъ пребыва́нїихъ и҆ благоче́стїихъ; ча́ющымъ и҆ скорѣ́е бы́ти жела́ющымъ прише́ствїѧ бж҃їѧгѡ днѐ, є҆гѡ́же ра́ди нб҃са̀ жего́ма разорѧ́тсѧ, и҆ стїхі́и ѡ҆палѧ́еми раста́ютсѧ. но́ва же нб҃сѐ, и҆ но́вы землѝ по ѡ҆бѣтова́нїю є҆гѡ̀ ча́емъ, въ ни́хже пра́вда живе́тъ. тѣ́мже возлю́бленнїи, си́хъ ча́юще, потщи́тесѧ нескве́рни и҆ непоро́чни томꙋ̀ ѡ҆брѣсти́сѧ въ ми́рѣ: и҆ гдⷭ҇а на́шегѡ долготерпѣ́нїе, спасе́нїе непщꙋ́йте: ꙗ҆́коже и҆ возлю́бленный на́шъ бра́тъ па́ѵелъ, по да́ннѣй є҆мꙋ̀ премꙋ́дрости написа̀ ва́мъ. ꙗ҆́коже и҆ во всѣ́хъ свои́хъ посла́нїихъ, глаго́лѧ въ ни́хъ ѡ҆ си́хъ: въ ни́хже сꙋ́ть неꙋдо́бь разꙋ̑мна нѣ̑каѧ, ꙗ҆̀же ненаꙋче́ни и҆ неꙋтвержде́ни развраща́ютъ, ꙗ҆́коже и҆ прѡ́чаѧ писа̑нїѧ, къ свое́й поги́бели и҆̀мъ. вы́ же ᲂу҆̀бо возлю́бленнїи, предвѣ́дѧще храни́тесѧ, да не ле́стїю беззако́нныхъ сведе́ни бы́вше, ѿпаде́те своегѡ̀ ᲂу҆твержде́нїѧ: но да расте́те во бл҃года́ти и҆ ра́зꙋмѣ гдⷭ҇а на́шегѡ и҆ сп҃са і҆и҃са хрⷭ҇та̀. томꙋ́ сла́ва, и҆ ны́нѣ, и҆ въ де́нь вѣ́ка. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 68,
  ["комментарий"] = "1 Ин., 68 зач., I, 1-7.",
  ["текст_ру"] = "Е́же бе испе́рва, е́же слы́шахом, е́же ви́дехом очи́ма на́шима, е́же узре́хом, и ру́ки на́ша осяза́ша, о Словеси́ Живо́тнем. И Живо́т яви́ся, и ви́дехом, и свиде́тельствуем, и возвеща́ем вам Живо́т ве́чный, И́же бе у Отца́, и яви́ся нам. Е́же ви́дехом и слы́шахом, пове́даем вам, да и вы обще́ние и́мате с на́ми: обще́ние же на́ше со Отце́м и с Сы́ном Его́ Иису́сом Христо́м. И сия́ пи́шем вам, да ра́дость ва́ша бу́дет испо́лнена. И сие́ есть обетова́ние, е́же слы́шахом от Него́, и пове́даем вам, я́ко Бог Свет есть, и тмы в Нем несть ни еди́ныя. А́ще рече́м, я́ко обще́ние и́мамы с Ним, и во тме хо́дим, лжем и не твори́м и́стины. А́ще ли же во све́те хо́дим, я́коже Сам Той есть во све́те, обще́ние и́мамы друг ко дру́гу, и кровь Иису́са Христа́ Сы́на Его́ очища́ет нас от вся́каго греха́. ",
  ["текст_цс"] = "Є҆́же бѣ̀ и҆спе́рва, є҆́же слы́шахомъ, є҆́же ви́дѣхомъ ѻ҆чи́ма на́шима, є҆́же ᲂу҆зрѣ́хомъ, и҆ рꙋ́ки на́шѧ ѡ҆сѧза́ша ѡ҆ словесѝ живо́тнѣмъ: [и҆ живо́тъ ꙗ҆ви́сѧ, и҆ ви́дѣхомъ, и҆ свидѣ́тельствꙋемъ, и҆ возвѣща́емъ ва́мъ живо́тъ вѣ́чный, и҆́же бѣ̀ ᲂу҆ ѻ҆ц҃а̀, и҆ ꙗ҆ви́сѧ на́мъ.] є҆́же ви́дѣхомъ и҆ слы́шахомъ, повѣ́даемъ ва́мъ, да и҆ вы̀ ѻ҆бще́нїе и҆́мате съ на́ми: ѻ҆бще́нїе же на́ше со ѻ҆ц҃е́мъ и҆ съ сн҃омъ є҆гѡ̀ і҆и҃сомъ хрⷭ҇то́мъ. и҆ сїѧ̑ пи́шемъ ва́мъ, да ра́дость ва́ша бꙋ́детъ и҆спо́лнена. и҆ сїѐ є҆́сть ѡ҆бѣтова́нїе, є҆́же слы́шахомъ ѿ негѡ̀, и҆ повѣ́даемъ ва́мъ ꙗ҆́кѡ бг҃ъ свѣ́тъ є҆́сть, и҆ тмы̀ въ не́мъ нѣ́сть ни є҆ди́ныѧ. а҆́ще рече́мъ, ꙗ҆́кѡ ѻ҆бще́нїе и҆́мамы съ ни́мъ, и҆ во тмѣ̀ хо́димъ, лже́мъ, и҆ не твори́мъ и҆́стины. а҆́ще ли же во свѣ́тѣ хо́димъ, ꙗ҆́коже са́мъ то́й є҆́сть во свѣ́тѣ, ѻ҆бще́нїе и҆́мамы дрꙋ́гъ ко дрꙋ́гꙋ, и҆ кро́вь і҆и҃са хрⷭ҇та̀ сн҃а є҆гѡ̀ ѡ҆чища́етъ на́съ ѿ всѧ́кагѡ грѣха̀. ",
