  ["комментарий"] = "1 Ин., 70 зач., II, 7–17.",
  ["текст_ру"] = "Возлю́бленнии, не за́поведь но́ву пишу́ вам, но за́поведь ве́тху, ю́же име́сте испе́рва. За́поведь ве́тха есть сло́во, е́же слы́шасте испе́рва. Па́ки за́поведь но́ву пишу́ вам, е́же есть пои́стинне в Нем и в вас, я́ко тма ми́мо хо́дит и свет и́стинный сей сия́ет. Глаго́ляй во све́те бы́ти, а бра́та своего́ ненави́дит, во тме есть досе́ле. Любя́й бра́та своего́ во све́те пребыва́ет, и собла́зна в нем несть. А ненави́дяй бра́та своего́ во тме есть, и во тме хо́дит, и не весть ка́мо и́дет, я́ко тма ослепи́ о́чи ему́. Пишу́ вам ча́дца, я́ко оставля́ются вам греси́ и́мене Его́ ра́ди. Пишу́ вам отцы́, я́ко позна́сте Безнача́льнаго. Пишу́ вам ю́ноши, я́ко победи́сте лука́ваго. Пишу́ вам де́ти, я́ко позна́сте Отца́. Писа́х вам отцы́, я́ко позна́сте Иско́ннаго. Писа́х вам ю́ноши, я́ко кре́пцы есте́, и сло́во Бо́жие в вас пребыва́ет, и победи́сте лука́ваго. Не люби́те ми́ра, ни я́же в ми́ре, а́ще кто лю́бит мир, несть любве́ О́тчи в нем. Я́ко все е́же в ми́ре, по́хоть плотска́я и по́хоть очи́ма и го́рдость жите́йская, несть от Отца́, но от ми́ра сего́ есть. И мир прехо́дит, и по́хоть его́, а творя́й во́лю Бо́жию пребыва́ет во ве́ки. ",
  ["текст_цс"] = "Возлю́бленнїи, не за́повѣдь но́вꙋ пишꙋ̀ ва́мъ, но за́повѣдь ве́тхꙋ, ю҆́же и҆мѣ́сте и҆спе́рва: за́повѣдь ве́тха є҆́сть сло́во, є҆́же слы́шасте и҆спе́рва. па́ки за́повѣдь но́вꙋ пишꙋ̀ ва́мъ, є҆́же є҆́сть пои́стиннѣ въ не́мъ и҆ въ ва́съ, ꙗ҆́кѡ тма̀ ми́мѡ хо́дитъ, и҆ свѣ́тъ и҆́стинный се́й сїѧ́етъ. глаго́лѧй во свѣ́тѣ бы́ти, а҆ бра́та своего̀ ненави́дитъ, во тмѣ̀ є҆́сть досе́лѣ. любѧ́й бра́та своего̀, во свѣ́тѣ пребыва́етъ, и҆ собла́зна въ не́мъ нѣ́сть: а҆ ненави́дѧй бра́та своего̀, во тмѣ̀ є҆́сть, и҆ во тмѣ̀ хо́дитъ, и҆ не вѣ́сть ка́мѡ и҆́детъ, ꙗ҆́кѡ тма̀ ѡ҆слѣпѝ ѻ҆́чи є҆мꙋ̀. пишꙋ̀ ва́мъ ча́дца, ꙗ҆́кѡ ѡ҆ставлѧ́ютсѧ ва́мъ грѣсѝ и҆́мене є҆гѡ̀ ра́ди. пишꙋ̀ ва́мъ ѻ҆тцы̀, ꙗ҆́кѡ позна́сте безнача́льнаго. пишꙋ̀ ва́мъ ю҆́нѡши, ꙗ҆́кѡ побѣди́сте лꙋка́ваго. пишꙋ̀ ва́мъ дѣ́ти, ꙗ҆́кѡ позна́сте ѻ҆ц҃а̀. писа́хъ ва́мъ ѻ҆тцы̀, ꙗ҆́кѡ позна́сте и҆ско́ннаго. писа́хъ ва́мъ ю҆́нѡши, ꙗ҆́кѡ крѣ́пцы є҆стѐ, и҆ сло́во бж҃їе въ ва́съ пребыва́етъ, и҆ побѣди́сте лꙋка́ваго. не люби́те мі́ра, ни ꙗ҆̀же въ мі́рѣ: а҆́ще кто̀ лю́битъ мі́ръ, нѣ́сть любвѐ ѻ҆́ч҃и въ не́мъ. ꙗ҆́кѡ всѐ є҆́же въ мі́рѣ, по́хоть плотска́ѧ, и҆ по́хоть ѻ҆чи́ма, и҆ го́рдость жите́йскаѧ, нѣ́сть ѿ ѻ҆ц҃а̀, но ѡ҆ мі́ра сегѡ̀ є҆́сть. и҆ мі́ръ прехо́дитъ, и҆ по́хоть є҆гѡ̀: а҆ творѧ́й во́лю бж҃їю пребыва́етъ во вѣ́ки. ",
}

add_apostol {
  ["номер"] = 71,
  ["комментарий"] = "1 Ин., 71 зач., II, 18 – III, 10.",
  ["текст_ру"] = "Де́ти, после́дняя годи́на есть. И я́коже слы́шасте, я́ко анти́христ гряде́т, и ны́не анти́христи мно́зи бы́ша, от сего́ разумева́ем, я́ко после́дний час есть. От нас изыдо́ша, но не бе́ша от нас, а́ще бы от нас бы́ли, пребы́ли у́бо бы́ша с на́ми, но да явя́тся, я́ко не суть вси от нас. И вы пома́зание и́мате от Свята́го, и ве́сте вся. Не писа́х вам, я́ко не ве́сте и́стины, но я́ко ве́сте ю́ и я́ко вся́ка лжа от и́стины несть. Кто есть лжи́вый, то́чию отмета́яйся, я́ко Иису́с несть Христо́с? Сей есть анти́христ, отмета́яйся Отца́ и Сы́на. Всяк отмета́яйся Сы́на, ни Отца́ и́мать, а испове́даяй Сы́на, и Отца́ и́мать. Вы у́бо е́же слы́шасте испе́рва, в вас да пребыва́ет, и а́ще в вас пребу́дет, е́же испе́рва слы́шасте, и вы в Сы́не и Отце́ пребу́дете. И сие́ есть обетова́ние, е́же Сам обеща́ нам, живо́т ве́чный. Сия́ писа́х вам о льстя́щих вас. И вы е́же пома́зание е́же прия́сте от Него́, в вас пребыва́ет, и не тре́буете, да кто учи́т вы, но я́ко то са́мо пома́зание учи́т вы о всем, и и́стинно есть, и несть ло́жно, и я́коже научи́ вас, пребыва́йте в нем. И ны́не ча́дца, пребыва́йте в Нем, да егда́ яви́тся, и́мамы дерзнове́ние и не посрами́мся от Него́ в прише́ствии Его́. А́ще ве́сте, я́ко пра́ведник есть, разуме́йте, я́ко всяк творя́й пра́вду от Него́ роди́ся. Ви́дите, какову́ любо́вь дал есть Оте́ц нам, да ча́да Бо́жия нарече́мся, и есмы́. Сего́ ра́ди мир не зна́ет нас, зане́ не позна́ Его́. Возлю́бленнии, ны́не ча́да Бо́жия есмы́, и не у яви́ся, что бу́дем: ве́мы же, я́ко егда́ яви́тся, подо́бни Ему́ бу́дем, и у́зрим Его́, я́коже есть. И всяк име́яй наде́жду сию́ Нань, очища́ет себе́, я́коже Он чист есть. Всяк творя́й грех, и беззако́ние твори́т, и грех есть беззако́ние. И ве́сте, я́ко Он яви́ся, да грехи́ на́ша во́змет, и греха́ в Нем несть. Всяк, и́же в Нем пребыва́яй, не согреша́ет, всяк согреша́яй не ви́де Его́, ни позна́ Его́. Ча́дца, никто́же да льстит вас. Творя́й пра́вду пра́ведник есть, я́коже Он пра́веден есть. Творя́й грех от диа́вола есть, я́ко испе́рва диа́вол согреша́ет. Сего́ ра́ди яви́ся Сын Бо́жий да разруши́т дела́ диа́воля. Всяк рожде́нный от Бо́га греха́ не твори́т, я́ко се́мя Его́ в нем пребыва́ет, и не мо́жет согреша́ти, я́ко от Бо́га рожде́н есть. Сего́ ра́ди явле́на суть ча́да Бо́жия и ча́да диа́воля. ",
  ["текст_цс"] = "Дѣ́ти, послѣ́днѧѧ годи́на є҆́сть: и҆ ꙗ҆́коже слы́шасте, ꙗ҆́кѡ а҆нті́хрїстъ грѧде́тъ, и҆ ны́нѣ а҆нті́хрїсти мно́зи бы́ша: ѿ сегѡ̀ разꙋмѣва́емъ, ꙗ҆́кѡ послѣ́днїй ча́съ є҆́сть. ѿ на́съ и҆зыдо́ша, но не бѣ́ша ѿ на́съ: а҆́ще бы ѿ на́съ бы́ли, пребы́ли ᲂу҆́бѡ бы́ша съ на́ми: но да ꙗ҆вѧ́тсѧ, ꙗ҆́кѡ не сꙋ́ть всѝ ѿ на́съ. и҆ вы̀ пома́занїе и҆́мате ѿ ст҃а́гѡ, и҆ вѣ́сте всѧ̑. не писа́хъ ва́мъ, ꙗ҆́кѡ не вѣ́сте и҆́стины, но ꙗ҆́кѡ вѣ́сте ю҆̀: и҆ ꙗ҆́кѡ всѧ́ка лжа̀ ѿ и҆́стины нѣ́сть. кто́ є҆сть лжи́вый, то́чїю ѿмета́ѧйсѧ, ꙗ҆́кѡ і҆и҃съ нѣ́сть хрⷭ҇то́съ: се́й є҆́сть а҆нті́хрїстъ, ѿмета́ѧйсѧ ѻ҆ц҃а̀ и҆ сн҃а. всѧ́къ ѿмета́ѧйсѧ сн҃а, ни ѻ҆ц҃а̀ и҆́мать: а҆ и҆сповѣ́даѧй сн҃а, и҆ ѻ҆ц҃а̀ и҆́мать. вы̀ ᲂу҆́бѡ є҆́же слы́шасте и҆спе́рва, въ ва́съ да пребыва́етъ. и҆ а҆́ще въ ва́съ пребꙋ́детъ є҆́же и҆спе́рва слы́шасте, и҆ вы̀ въ сн҃ѣ и҆ ѻ҆ц҃ѣ̀ пребꙋ́дете. и҆ сїѐ є҆́сть ѡ҆бѣтова́нїе, є҆́же са́мъ ѡ҆бѣща̀ на́мъ, живо́тъ вѣ́чный. сїѧ̑ писа́хъ ва́мъ ѡ҆ льстѧ́щихъ ва́съ: и҆ вы̀ пома́занїе є҆́же прїѧ́сте ѿ негѡ̀, въ ва́съ пребыва́етъ, и҆ не тре́бꙋете, да кто̀ ᲂу҆чи́тъ вы̀: но ꙗ҆́кѡ то̀ са́мо пома́занїе ᲂу҆чи́тъ вы̀ ѡ҆ все́мъ, и҆ и҆́стинно є҆́сть, и҆ нѣ́сть ло́жно: и҆ ꙗ҆́коже наꙋчѝ ва́съ, пребыва́йте въ не́мъ. и҆ ны́нѣ ча̑дца, пребыва́йте въ не́мъ, да є҆гда̀ ꙗ҆ви́тсѧ, и҆́мамы дерзнове́нїе, и҆ не посрами́мсѧ ѿ негѡ̀ въ прише́ствїи є҆гѡ̀. а҆́ще вѣ́сте, ꙗ҆́кѡ пра́ведникъ є҆́сть, разꙋмѣ́йте, ꙗ҆́кѡ всѧ́къ творѧ́й пра́вдꙋ, ѿ негѡ̀ роди́сѧ. ви́дите, каковꙋ̀ любо́вь да́лъ є҆́сть ѻ҆ц҃ъ на́мъ, да ча̑да бж҃їѧ нарече́мсѧ, и҆ є҆смы̀: сегѡ̀ ра́ди мі́ръ не зна́етъ на́съ, занѐ не позна̀ є҆гѡ̀. возлю́бленнїи, ны́нѣ ча̑да бж҃їѧ є҆смы̀, и҆ не ᲂу҆̀ ꙗ҆ви́сѧ, что̀ бꙋ́демъ: вѣ́мы же, ꙗ҆́кѡ є҆гда̀ ꙗ҆ви́тсѧ, подо́бни є҆мꙋ̀ бꙋ́демъ, и҆ ᲂу҆́зримъ є҆го̀, ꙗ҆́коже є҆́сть. и҆ всѧ́къ и҆мѣ́ѧй наде́ждꙋ сїю̀ на́нь, ѡ҆чища́етъ себѐ, ꙗ҆́коже ѻ҆́нъ чи́стъ є҆́сть. всѧ́къ творѧ́й грѣ́хъ, и҆ беззако́нїе твори́тъ: и҆ грѣ́хъ є҆́сть беззако́нїе. и҆ вѣ́сте, ꙗ҆́кѡ ѻ҆́нъ ꙗ҆ви́сѧ, да грѣхѝ на́шѧ во́з̾метъ и҆ грѣха̀ въ не́мъ нѣ́сть. всѧ́къ и҆́же въ не́мъ пребыва́ѧй, не согрѣша́етъ: всѧ́къ согрѣша́ѧй, не ви́дѣ є҆гѡ̀, ни позна̀ є҆гѡ̀. ча́дца, никто́же да льсти́тъ ва́съ: творѧ́й пра́вдꙋ, пра́ведникъ є҆́сть, ꙗ҆́коже ѻ҆́нъ пра́веденъ є҆́сть. творѧ́й грѣ́хъ, ѿ дїа́вола є҆́сть, ꙗ҆́кѡ и҆спе́рва дїа́волъ согрѣша́етъ. сегѡ̀ ра́ди ꙗ҆ви́сѧ сн҃ъ бж҃їй, да разрꙋши́тъ дѣла̀ дїа́волѧ. всѧ́къ рожде́нный ѿ бг҃а, грѣха̀ не твори́тъ, ꙗ҆́кѡ сѣ́мѧ є҆гѡ̀ въ не́мъ пребыва́етъ: и҆ не мо́жетъ согрѣша́ти, ꙗ҆́кѡ ѿ бг҃а рожде́нъ є҆́сть. сегѡ̀ ра́ди ꙗ҆вле́на сꙋ́ть ча́да бж҃їѧ, и҆ ча́да дїа́волѧ. ",
}

add_apostol {
  ["номер"] = 72,
  ["комментарий"] = "1 Ин., 72 зач., III, 10–20.",
  ["текст_ру"] = "Возлю́бленнии, всяк не творя́й пра́вды несть от Бо́га, и не любя́й бра́та своего́. Я́ко се есть завеща́ние, е́же слы́шасте испе́рва, да лю́бим друг дру́га, не я́коже Ка́ин от лука́ваго бе и закла́ бра́та своего́. За ку́ю вину́ закла́ его́? Я́ко дела́ его́ лука́ва бе́ша, а бра́та его́ пра́ведна. Не чуди́теся, бра́тие моя́, а́ще ненави́дит вас мир. Мы ве́мы, я́ко преидо́хом от сме́рти в живо́т, я́ко лю́бим бра́тию, не любя́й бо бра́та пребыва́ет в сме́рти. Всяк ненави́дяй бра́та своего́ человекоуби́йца есть, и ве́сте, я́ко всяк человекоуби́йца не и́мать живота́ ве́чнаго в себе́ пребыва́юща. О сем позна́хом любо́вь, я́ко Он по нас ду́шу Свою́ положи́, и мы до́лжни есмы́ по бра́тии ду́шы полага́ти. И́же у́бо и́мать бога́тство ми́ра сего́, и ви́дит бра́та своего́ тре́бующа, и затвори́т утро́бу свою́ от него́, ка́ко любы́ Бо́жия пребыва́ет в нем? Ча́дца моя́, не лю́бим сло́вом ниже́ язы́ком, но де́лом и и́стиною. И о сем разуме́ем, я́ко от и́стины есмы́, и пред Ним смиря́ем сердца́ на́ша, зане́ а́ще зазира́ет нам се́рдце на́ше, я́ко бо́лий есть Бог се́рдца на́шего и весть вся. ",
  ["текст_цс"] = "Возлю́бленнїи, всѧ́къ не творѧ́й пра́вды, нѣ́сть ѿ бг҃а, и҆ не любѧ́й бра́та своегѡ̀. ꙗ҆́кѡ сѐ є҆́сть завѣща́нїе, є҆́же слы́шасте и҆спе́рва, да лю́бимъ дрꙋгъдрꙋ́га: не ꙗ҆́коже ка́їнъ ѿ лꙋка́вагѡ бѣ̀, и҆ закла̀ бра́та своего̀: за кꙋ́ю винꙋ̀ закла̀ є҆го̀; ꙗ҆́кѡ дѣла̀ є҆гѡ̀ лꙋка́ва бѣ́ша, а҆ бра́та є҆гѡ̀ пра́вєдна. не чꙋди́тесѧ бра́тїе моѧ̀, а҆́ще ненави́дитъ ва́съ мі́ръ. мы̀ вѣ́мы, ꙗ҆́кѡ преидо́хомъ ѿ сме́рти въ живо́тъ, ꙗ҆́кѡ лю́бимъ бра́тїю: не любѧ́й бо бра́та, пребыва́етъ въ сме́рти. всѧ́къ ненави́дѧй бра́та своего̀, человѣкоꙋбі́йца є҆́сть: и҆ вѣ́сте, ꙗ҆́кѡ всѧ́къ человѣкоꙋбі́йца не и҆́мать живота̀ вѣ́чнагѡ въ себѣ̀ пребыва́юща. ѡ҆ се́мъ позна́хомъ любо́вь, ꙗ҆́кѡ ѻ҆́нъ по на́съ дꙋ́шꙋ свою̀ положѝ: и҆ мы̀ до́лжни є҆смы̀ по бра́тїи дꙋ́шы полага́ти. и҆́же ᲂу҆̀бо и҆́мать бога́тство мі́ра сегѡ̀, и҆ ви́дитъ бра́та своего̀ тре́бꙋюща, и҆ затвори́тъ ᲂу҆тро́бꙋ свою̀ ѿ негѡ̀, ка́кѡ любы̀ бж҃їѧ пребыва́етъ въ не́мъ; ча́дца моѧ̀, не лю́бимъ сло́вомъ, нижѐ ѧ҆зы́комъ, но дѣ́ломъ и҆ и҆́стиною. и҆ ѡ҆ се́мъ разꙋмѣ́емъ, ꙗ҆́кѡ ѿ и҆́стины є҆смы̀, и҆ пред̾ ни́мъ смирѧ́емъ сердца̀ на́ша: занѐ а҆́ще зазира́етъ на́мъ се́рдце на́ше, ꙗ҆́кѡ бо́лїй є҆́сть бг҃ъ се́рдца на́шегѡ, и҆ вѣ́сть всѧ̑. ",
}

