  ["текст_ру"] = "Возлю́бленнии, а́ще кто рече́т, я́ко люблю́ Бо́га, а бра́та своего́ ненави́дит, ложь есть, и́бо не любя́й бра́та своего́, его́же ви́де, Бо́га, Его́же не ви́де, ка́ко мо́жет люби́ти? И сию́ за́поведь и́мамы от Него́, да любя́й Бо́га лю́бит и бра́та своего́. Всяк ве́руяй, я́ко Иису́с есть Христо́с, от Бо́га рожде́н есть, и всяк любя́й Ро́ждшаго лю́бит и рожде́ннаго от Него́. О сем ве́мы, я́ко лю́бим ча́да Бо́жия, егда́ Бо́га лю́бим и за́поведи Его́ соблюда́ем. Сия́ бо есть любы́ Бо́жия, да за́поведи Его́ соблюда́ем, и за́поведи Его́ тя́жки не суть. Я́ко всяк рожде́нный от Бо́га побежда́ет мир, и сия́ есть побе́да, побе́ждшая мир, ве́ра на́ша. Кто есть побежда́яй мир, то́кмо ве́руяй, я́ко Иису́с есть Сын Бо́жий? ",
  ["текст_цс"] = "Возлю́бленнїи, а҆́ще кто̀ рече́тъ, ꙗ҆́кѡ люблю̀ бг҃а, а҆ бра́та своего̀ ненави́дитъ, ло́жъ є҆́сть: и҆́бо не любѧ́й бра́та своегѡ̀, є҆го́же ви́дѣ, бг҃а, є҆гѡ́же не ви́дѣ, ка́кѡ мо́жетъ люби́ти; и҆ сїю̀ за́повѣдь и҆́мамы ѿ негѡ̀, да любѧ́й бг҃а, лю́битъ и҆ бра́та своего̀. всѧ́къ вѣ́рꙋѧй, ꙗ҆́кѡ і҆и҃съ є҆́сть хрⷭ҇то́съ, ѿ бг҃а рожде́нъ є҆́сть: и҆ всѧ́къ любѧ́й ро́ждшаго, лю́битъ и҆ рожде́ннаго ѿ негѡ̀. ѡ҆ се́мъ вѣ́мы, ꙗ҆́кѡ лю́бимъ ча̑да бж҃їѧ, є҆гда̀ бг҃а лю́бимъ и҆ за́пѡвѣди є҆гѡ̀ соблюда́емъ. сїѧ́ бо є҆́сть любы̀ бж҃їѧ, да за́пѡвѣди є҆гѡ̀ соблюда́емъ, и҆ за́пѡвѣди є҆гѡ̀ тѧ́жки не сꙋ́ть. ꙗ҆́кѡ всѧ́къ рожде́нный ѿ бг҃а, побѣжда́етъ мі́ръ: и҆ сїѧ̀ є҆́сть побѣ́да побѣ́ждшаѧ мі́ръ, вѣ́ра на́ша. кто̀ є҆́сть побѣжда́ѧй мі́ръ, то́кмѡ вѣ́рꙋѧй, ꙗ҆́кѡ і҆и҃съ є҆́сть сн҃ъ бж҃їй; ",
}

add_apostol {
  ["номер"] = 74,
  ["комментарий"] = "1 Ин., 74 зач., IV, 20 – V, 21.",
  ["текст_ру"] = "Возлю́бленнии, а́ще кто рече́т, я́ко люблю́ Бо́га, а бра́та своего́ ненави́дит, ложь есть, и́бо не любя́й бра́та своего́, его́же ви́де, Бо́га, Его́же не ви́де, ка́ко мо́жет люби́ти? И сию́ за́поведь и́мамы от Него́, да любя́й Бо́га лю́бит и бра́та своего́. Всяк ве́руяй, я́ко Иису́с есть Христо́с, от Бо́га рожде́н есть, и всяк любя́й Ро́ждшаго лю́бит и рожде́ннаго от Него́. О сем ве́мы, я́ко лю́бим ча́да Бо́жия, егда́ Бо́га лю́бим и за́поведи Его́ соблюда́ем. Сия́ бо есть любы́ Бо́жия, да за́поведи Его́ соблюдаем, и за́поведи Его́ тя́жки не суть. Я́ко всяк рожде́нный от Бо́га побежда́ет мир, и сия́ есть побе́да, побе́ждшая мир, ве́ра на́ша. Кто есть побежда́яй мир, то́кмо ве́руяй, я́ко Иису́с есть Сын Бо́жий? Сей есть прише́дый водо́ю и кро́вию и Ду́хом, Иису́с Христо́с, не водо́ю то́чию, но водо́ю и кро́вию, и Дух есть свиде́тельствуяй, я́ко Дух есть и́стина. Я́ко трие́ суть свиде́тельствующии на небеси́, Оте́ц, Сло́во и Святы́й Дух, и Си́и три еди́но суть. И трие́ суть свиде́тельствующии на земли́, дух и вода́, и кровь, и трие́ во еди́но суть. А́ще свиде́тельство челове́ческое прие́млем, свиде́тельство Бо́жие бо́ле есть, я́ко сие́ есть свиде́тельство Бо́жие, е́же свиде́тельствова о Сы́не Свое́м. Ве́руяй в Сы́на Бо́жия и́мать свиде́тельство в себе́, не ве́руяй Бо́гови лжа сотвори́л есть Его́, я́ко не ве́рова во свиде́тельство, е́же свиде́тельствова Бог о Сы́не Свое́м. И сие́ есть свиде́тельство, я́ко живо́т ве́чный дал есть нам Бог, и сей живо́т в Сы́не Его́ есть. Име́яй Сы́на Бо́жия и́мать живо́т, а не име́яй Сы́на Бо́жия живота́ не и́мать. Сия́ писа́х вам ве́рующым во и́мя Сы́на Бо́жия, да ве́сте, я́ко живо́т ве́чный и́мате, и да ве́руете во и́мя Сы́на Бо́жия. И сие́ есть дерзнове́ние, е́же и́мамы к Нему́, я́ко а́ще чесо́ про́сим по во́ли Его́, послу́шает нас. И а́ще ве́мы, я́ко послу́шает нас, е́же а́ще про́сим, ве́мы, я́ко и́мамы проше́ния, и́хже проси́хом от Него́. А́ще кто у́зрит бра́та своего́ согреша́юща грех не к сме́рти, да про́сит, и даст ему́ живо́т, согреша́ющым не к сме́рти. Есть грех к сме́рти, не о том глаго́лю, да мо́лится. Вся́ка непра́вда грех есть, и есть грех не к сме́рти. Ве́мы, я́ко всяк рожде́нный от Бо́га не согреша́ет, но рожде́нный от Бо́га блюде́т себе́, и лука́вый не прикаса́ется ему́. Ве́мы, я́ко от Бо́га есмы́, и мир весь во зле лежи́т. Ве́мы же, я́ко Сын Бо́жий прии́де и дал есть нам свет и ра́зум, да позна́ем Бо́га и́стиннаго и да бу́дем во и́стиннем Сы́не Его́ Иису́се Христе́, Сей есть и́стинный Бог и живо́т ве́чный. Ча́дца, храни́те себе́ от треб и́дольских. Ами́нь. ",
  ["текст_цс"] = "Возлю́бленнїи, а҆́ще кто̀ рече́тъ, ꙗ҆́кѡ люблю̀ бг҃а, а҆ бра́та своего̀ ненави́дитъ, ло́жъ є҆́сть: и҆́бо не любѧ́й бра́та своегѡ̀, є҆го́же ви́дѣ, бг҃а, є҆гѡ́же не ви́дѣ, ка́кѡ мо́жетъ люби́ти; и҆ сїю̀ за́повѣдь и҆́мамы ѿ негѡ̀, да любѧ́й бг҃а, лю́битъ и҆ бра́та своего̀. всѧ́къ вѣ́рꙋѧй, ꙗ҆́кѡ і҆и҃съ є҆́сть хрⷭ҇то́съ, ѿ бг҃а рожде́нъ є҆́сть: и҆ всѧ́къ любѧ́й ро́ждшаго, лю́битъ и҆ рожде́ннаго ѿ негѡ̀. ѡ҆ се́мъ вѣ́мы, ꙗ҆́кѡ лю́бимъ ча̑да бж҃їѧ, є҆гда̀ бг҃а лю́бимъ и҆ за́пѡвѣди є҆гѡ̀ соблюда́емъ. сїѧ́ бо є҆́сть любы̀ бж҃їѧ, да за́пѡвѣди є҆гѡ̀ соблюда́емъ, и҆ за́пѡвѣди є҆гѡ̀ тѧ́жки не сꙋ́ть. ꙗ҆́кѡ всѧ́къ рожде́нный ѿ бг҃а, побѣжда́етъ мі́ръ: и҆ сїѧ̀ є҆́сть побѣ́да побѣ́ждшаѧ мі́ръ, вѣ́ра на́ша. кто̀ є҆́сть побѣжда́ѧй мі́ръ, то́кмѡ вѣ́рꙋѧй, ꙗ҆́кѡ і҆и҃съ є҆́сть сн҃ъ бж҃їй; се́й є҆́сть прише́дый водо́ю и҆ кро́вїю и҆ дх҃омъ, і҆и҃съ хрⷭ҇то́съ, не водо́ю то́чїю, но водо́ю и҆ кро́вїю: и҆ дх҃ъ є҆́сть свидѣ́тельствꙋѧй, ꙗ҆́кѡ дх҃ъ є҆́сть и҆́стина. ꙗ҆́кѡ трїѐ сꙋ́ть свидѣ́тельствꙋющїи на нб҃сѝ, ѻ҆ц҃ъ, сло́во, и҆ ст҃ы́й дх҃ъ: и҆ сі́и трѝ є҆ди́но сꙋ́ть. и҆ трїѐ сꙋ́ть свидѣ́тельствꙋющїи на землѝ, дх҃ъ и҆ вода̀, и҆ кро́вь: и҆ трїѐ во є҆ди́но сꙋ́ть. а҆́ще свидѣ́тельство человѣ́ческое прїе́млемъ, свидѣ́тельство бж҃їе бо́ле є҆́сть: ꙗ҆́кѡ сїѐ є҆́сть свидѣ́тельство бж҃їе, є҆́же свидѣ́тельствова ѡ҆ сн҃ѣ свое́мъ. вѣ́рꙋѧй въ сн҃а бж҃їѧ, и҆́мать свидѣ́тельство въ себѣ̀: не вѣ́рꙋѧй бг҃ови, лжа̀ сотвори́лъ є҆́сть є҆го̀, ꙗ҆́кѡ не вѣ́рова во свидѣ́тельство, є҆́же свидѣ́тельствова бг҃ъ ѡ҆ сн҃ѣ свое́мъ. и҆ сїѐ є҆́сть свидѣ́тельство, ꙗ҆́кѡ живо́тъ вѣ́чный да́лъ є҆́сть на́мъ бг҃ъ, и҆ се́й живо́тъ въ сн҃ѣ є҆гѡ̀ є҆́сть. и҆мѣ́ѧй сн҃а бж҃їѧ, и҆́мать живо́тъ: а҆ не и҆мѣ́ѧй сн҃а бж҃їѧ, живота̀ не и҆́мать. сїѧ̑ писа́хъ ва́мъ вѣ́рꙋющымъ во и҆́мѧ сн҃а бж҃їѧ, да вѣ́сте, ꙗ҆́кѡ живо́тъ вѣ́чный и҆́мате, и҆ да вѣ́рꙋете во и҆́мѧ сн҃а бж҃їѧ. и҆ сїѐ є҆́сть дерзнове́нїе, є҆́же и҆́мамы къ немꙋ̀, ꙗ҆́кѡ а҆́ще чесѡ̀ про́симъ по во́ли є҆гѡ̀, послꙋ́шаетъ на́съ. и҆ а҆́ще вѣ́мы, ꙗ҆́кѡ послꙋ́шаетъ на́съ, є҆́же а҆́ще про́симъ, вѣ́мы, ꙗ҆́кѡ и҆́мамы прошє́нїѧ, и҆́хже проси́хомъ ѿ негѡ̀. а҆́ще кто̀ ᲂу҆́зритъ бра́та своего̀ согрѣша́юща грѣ́хъ не къ сме́рти, да про́ситъ, и҆ да́стъ є҆мꙋ̀ живо́тъ, согрѣша́ющымъ не къ сме́рти. є҆́сть грѣ́хъ къ сме́рти: не ѡ҆ то́мъ глаго́лю, да мо́литсѧ. всѧ́ка непра́вда грѣ́хъ є҆́сть, и҆ є҆́сть грѣ́хъ не къ сме́рти. вѣ́мы, ꙗ҆́кѡ всѧ́къ рожде́нный ѿ бг҃а не согрѣша́етъ: но рожде́нный ѿ бг҃а блюде́тъ себѐ, и҆ лꙋка́вый не прикаса́етсѧ є҆мꙋ̀. вѣ́мы, ꙗ҆́кѡ ѿ бг҃а є҆смы̀, и҆ мі́ръ ве́сь во ѕлѣ̀ лежи́тъ. вѣ́мы же, ꙗ҆́кѡ сн҃ъ бж҃їй прїи́де, и҆ да́лъ є҆́сть на́мъ свѣ́тъ и҆ ра́зꙋмъ, да позна́емъ бг҃а и҆́стиннаго, и҆ да бꙋ́демъ во и҆́стиннѣмъ сн҃ѣ є҆гѡ̀ і҆и҃сѣ хрⷭ҇тѣ̀: се́й є҆́сть и҆́стинный бг҃ъ, и҆ живо́тъ вѣ́чный. ча̑дца, храни́те себѐ ѿ тре́бъ і҆́дѡльскихъ. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 75,
  ["комментарий"] = "2 Ин., 75 зач., I, 1–13.",
  ["текст_ру"] = "Ста́рец избра́нней господы́не и ча́дом ея́, и́хже аз люблю́ вои́стинну, и не аз то́чию, но и вси разуме́вшии и́стину. За и́стину пребыва́ющую в нас, и с на́ми бу́дет во ве́ки. Да бу́дет с ва́ми благода́ть, ми́лость, мир от Бо́га Отца́, и от Го́спода Иису́са Христа́, Сы́на О́тча, во и́стине и любви́. Возра́довахся зело́, я́ко обрето́х от чад твои́х ходя́щя во и́стине, я́коже за́поведь прия́хом от Отца́. И ны́не молю́ тя, госпоже́, не я́ко за́поведь пишу́ тебе́ но́ву, но ю́же и́мамы испе́рва, да лю́бим друг дру́га. И сия́ есть любы́, да хо́дим по за́поведем Его́. Сия́ есть за́поведь, я́коже слы́шасте испе́рва, да в ней хо́дите. Зане́ мно́зи лестцы́ внидо́ша в мир, не испове́дающе Иису́са Христа́ прише́дша во пло́ти, сей есть льстец и анти́христ. Блюди́те себе́, да не погубите́ я́же де́ласте до́брая, но да мзду соверше́нну восприи́мете. Всяк преступа́яй и не пребыва́яй во уче́нии Христо́ве, Бо́га не и́мать, пребыва́яй же во уче́нии Христо́ве, сей и Отца́ и Сы́на и́мать. А́ще кто прихо́дит к вам, и сего́ уче́ния не прино́сит, не прие́млите его́ в дом, и ра́доватися ему́ не глаго́лите. Глаго́ляй бо ему́ ра́доватися, сообща́ется дело́м его́ злым. Мно́га име́х писа́ти вам, и не восхоте́х хартие́ю и черни́лом, но наде́юся приити́ к вам и усты́ ко усто́м глаго́лати, да ра́дость ва́ша бу́дет испо́лнена. Целу́ют тя ча́да сестры́ твоея́ избра́нныя. Ами́нь. ",
  ["текст_цс"] = "Ста́рецъ и҆збра́ннѣй господы́нѣ, и҆ ча́дѡмъ є҆ѧ̀, и҆̀хже а҆́зъ люблю̀ вои́стиннꙋ: и҆ не а҆́зъ то́чїю, но и҆ всѝ разꙋмѣ́вшїи и҆́стинꙋ: за и҆́стинꙋ пребыва́ющꙋю въ на́съ, и҆ съ на́ми бꙋ́детъ во вѣ́ки. да бꙋ́детъ съ ва́ми бл҃года́ть, ми́лость, ми́ръ ѿ бг҃а ѻ҆ц҃а̀, и҆ ѿ гдⷭ҇а і҆и҃са хрⷭ҇та̀ сн҃а ѻ҆́ч҃а, во и҆́стинѣ и҆ любвѝ. возра́довахсѧ ѕѣлѡ̀, ꙗ҆́кѡ ѡ҆брѣто́хъ ѿ ча̑дъ твои́хъ ходѧ́щѧ во и҆́стинѣ, ꙗ҆́коже за́повѣдь прїѧ́хомъ ѿ ѻ҆ц҃а̀. и҆ ны́нѣ молю́ тѧ, госпожѐ, не ꙗ҆́кѡ за́повѣдь пишꙋ̀ тебѣ̀ но́вꙋ, но ю҆́же и҆́мамы и҆спе́рва, да лю́бимъ дрꙋгъдрꙋ́га. и҆ сїѧ̀ є҆́сть любы̀, да хо́димъ по за́повѣдемъ є҆гѡ̀. сїѧ̀ є҆́сть за́повѣдь, ꙗ҆́коже слы́шасте и҆спе́рва, да въ не́й хо́дите. занѐ мно́зи лестцы̀ внидо́ша въ мі́ръ, не и҆сповѣ́дающе і҆и҃са хрⷭ҇та̀ прише́дша во пло́ти: се́й є҆́сть льсте́цъ и҆ а҆нті́хрїстъ. блюди́те себѐ, да не погꙋбитѐ ꙗ҆̀же дѣ́ласте дѡ́браѧ, но да мздꙋ̀ соверше́ннꙋ воспрїи́мете. всѧ́къ престꙋпа́ѧй, и҆ не пребыва́ѧй во ᲂу҆че́нїи хрⷭ҇то́вѣ, бг҃а не и҆́мать: пребыва́ѧй же во ᲂу҆че́нїи хрⷭ҇то́вѣ, се́й и҆ ѻ҆ц҃а̀ и҆ сн҃а и҆́мать. а҆́ще кто̀ прихо́дитъ къ ва́мъ, и҆ сегѡ̀ ᲂу҆че́нїѧ не прино́ситъ, не прїе́млите є҆го̀ въ до́мъ, и҆ ра́доватисѧ є҆мꙋ̀ не глаго́лите. глаго́лѧй бо є҆мꙋ̀ ра́доватисѧ, соѡбща́етсѧ дѣлѡ́мъ є҆гѡ̀ ѕлы́мъ. мнѡ́га и҆мѣ́хъ писа́ти ва́мъ, и҆ не восхотѣ́хъ хартїе́ю и҆ черни́ломъ: но надѣ́юсѧ прїитѝ къ ва́мъ, и҆ ᲂу҆сты̀ ко ᲂу҆стѡ́мъ глаго́лати, да ра́дость ва́ша бꙋ́детъ и҆спо́лнена. цѣлꙋ́ютъ тѧ̀ ча́да сестры̀ твоеѧ̀ и҆збра́нныѧ. а҆ми́нь. ",
}

