add_apostol {
  ["номер"] = 80,
  ["комментарий"] = "Рим., 80 зач., I, 18–27.",
  ["текст_ру"] = "Бра́тие, открыва́ется бо гнев Бо́жий с небесе́ на вся́кое нече́стие и непра́вду челове́ческую, содержа́щих и́стину в непра́вде. Зане́же разу́мное Бо́жие я́ве есть в них, Бог бо яви́л есть им. Неви́димая бо Его́, от созда́ния ми́ра творе́ньми помышля́ема, ви́дима суть, и присносу́щная си́ла Его́ и Божество́, во е́же бы́ти им безотве́тным. Зане́же разуме́вше Бо́га, не я́ко Бо́га просла́виша или́ благодари́ша, но осуети́шася помышле́нии свои́ми, и омрачи́ся неразу́мное их се́рдце. Глаго́лющеся бы́ти му́дры, объюроде́ша, и измени́ша сла́ву нетле́ннаго Бо́га в подо́бие о́браза тле́нна челове́ка и птиц и четвероно́г и гад. Те́мже и предаде́ их Бог в по́хотех серде́ц их в нечистоту́, во е́же скверни́тися телесе́м их в себе́ саме́х. И́же премени́ша и́стину Бо́жию во лжу, и почто́ша и послужи́ша тва́ри па́че Творца́, И́же есть благослове́н во ве́ки, ами́нь. Сего́ ра́ди предаде́ их Бог в стра́сти безче́стия. И жены́ бо их измени́ша есте́ственную подо́бу в презесте́ственную. Та́кожде и му́жи, оста́вльше есте́ственную подо́бу же́нска по́ла, разжего́шася по́хотию свое́ю друг на дру́га, му́жи на муже́х студ содева́юще, и возме́здие, е́же подоба́ше пре́лести их, в себе́ восприе́млюще. ",
  ["текст_цс"] = "Бра́тїе, ѿкрыва́етсѧ гнѣ́въ бж҃їй съ нб҃сѐ, на всѧ́кое нече́стїе и҆ непра́вдꙋ человѣ́ческꙋю, содержа́щихъ и҆́стинꙋ въ непра́вдѣ. зане́же разꙋ́мное бж҃їе, ꙗ҆́вѣ є҆́сть въ ни́хъ: бг҃ъ бо ꙗ҆ви́лъ є҆́сть и҆̀мъ. неви̑димаѧ бо є҆гѡ̀, ѿ созда́нїѧ мі́ра, творе́ньми помышлѧ́єма, ви̑дима сꙋ́ть, и҆ присносꙋ́щнаѧ си́ла є҆гѡ̀ и҆ бжⷭ҇тво̀: во є҆́же бы́ти и҆̀мъ без̾ѿвѣ́тнымъ. зане́же разꙋмѣ́вше бг҃а, не ꙗ҆́кѡ бг҃а просла́виша, и҆лѝ бл҃годари́ша: но ѡ҆сꙋети́шасѧ помышле́нїи свои́ми, и҆ ѡ҆мрачи́сѧ неразꙋ́мное и҆́хъ се́рдце. глаго́лющесѧ бы́ти мꙋ́дры, ѡ҆б̾юродѣ́ша: и҆ и҆змѣни́ша сла́вꙋ нетлѣ́ннагѡ бг҃а, въ подо́бїе ѻ҆́браза тлѣ́нна человѣ́ка, и҆ пти́цъ, и҆ четверонѡ́гъ, и҆ га̑дъ. тѣ́мже и҆ предадѐ и҆̀хъ бг҃ъ въ по́хотехъ серде́цъ и҆́хъ въ нечистотꙋ̀, во є҆́же скверни́тисѧ тѣлесє́мъ и҆́хъ въ себѣ̀ самѣ́хъ. и҆́же премѣни́ша и҆́стинꙋ бж҃їю во лжꙋ̀, и҆ почто́ша и҆ послꙋжи́ша тва́ри па́че творца̀, и҆́же є҆́сть блгⷭ҇ве́нъ во вѣ́ки, а҆ми́нь. сегѡ̀ ра́ди предадѐ и҆̀хъ бг҃ъ въ стра̑сти безче́стїѧ: и҆ жєны́ бо и҆́хъ и҆змѣни́ша є҆сте́ственнꙋю подо́бꙋ въ през̾есте́ственнꙋю. та́кожде и҆ мꙋ́жи, ѡ҆ста́вльше є҆сте́ственнꙋю подо́бꙋ же́нска по́ла, разжего́шасѧ по́хотїю свое́ю дрꙋ́гъ на дрꙋ́га, мꙋ́жи на мꙋже́хъ стꙋ́дъ содѣва́юще, и҆ возме́здїе є҆́же подоба́ше пре́лести и҆́хъ, въ себѣ̀ воспрїе́млюще. ",
}

add_apostol {
  ["номер"] = 81,
  ["комментарий"] = "Рим., 81 зач., I, 28 – II, 9.",
  ["текст_ру"] = "Бра́тие, я́коже не искуси́ша име́ти Бо́га в ра́зуме, сего́ ра́ди предаде́ их Бог в неиску́сен ум, твори́ти неподо́бная, испо́лнены вся́кия непра́вды, блуже́ния, лука́вства, лихоима́ния, зло́бы. Испо́лнены за́висти, уби́йства, рве́ния, льсти, злонра́вия. Шепотники́, клеветники́, богоме́рзки, досади́тели, велича́вы, го́рды, обрета́тели злых, роди́телем непокори́вы, неразу́мны, непримири́тельны, нелюбо́вны, неклятвохрани́тельны, неми́лостивны. Не́цыи же и оправда́ние Бо́жие разуме́вше, я́ко такова́я творя́щии досто́йни сме́рти суть, не то́чию са́ми творя́т, но и соизволя́ют творя́щым. Сего́ ра́ди безотве́тен еси́, о, челове́че всяк судя́й: и́мже бо судо́м су́диши дру́га, себе́ осужда́еши. Та́яжде бо твори́ши судя́й. Ве́мы же, я́ко суд Бо́жий есть пои́стинне на творя́щих такова́я. Помышля́еши ли же сия́, о челове́че, судя́й такова́я творя́щым и творя́ сам та́яжде, я́ко ты избежи́ши ли суда́ Бо́жия, или́ о бога́тстве бла́гости Его́ и кро́тости и долготерпе́нии неради́ши, неве́дый, я́ко бла́гость Бо́жия на покая́ние тя веде́т? По жесто́кости же твое́й и непока́янному се́рдцу, собира́еши себе́ гнев в день гне́ва и открове́ния пра́веднаго суда́ Бо́жия, И́же возда́ст коему́ждо по дело́м его́. О́вым у́бо, по терпе́нию де́ла блага́го, сла́ву и честь и нетле́ние и́щущым, живо́т ве́чный. А и́же по рве́нию противля́ющимся у́бо и́стине, повину́ющимся же непра́вде, я́рость и гнев. Скорбь и теснота́ на вся́ку ду́шу челове́ка творя́щаго зло́е, иуде́а же пре́жде и е́ллина. ",
  ["текст_цс"] = "Бра́тїе, ꙗ҆́коже не и҆скꙋси́ша и҆мѣ́ти бг҃а въ ра́зꙋмѣ, сегѡ̀ ра́ди предадѐ ѧ҆̀ бг҃ъ въ неискꙋ́сенъ ᲂу҆́мъ, твори́ти неподѡ́бнаѧ: и҆спо́лнены всѧ́кїѧ непра́вды, блꙋже́нїѧ, лꙋка́вства, лихоима́нїѧ, ѕло́бы: и҆спо́лнены за́висти, ᲂу҆бі́йства, рве́нїѧ, льстѝ, ѕлонра́вїѧ: шепотникѝ, клеветникѝ, богоме́рзски, досади́тели, велича́вы, го́рды, ѡ҆брѣта́тели ѕлы́хъ, роди́телємъ непокори́вы, неразꙋ́мны, непримири́тельны, нелюбо́вны, неклѧтвохрани́тельны, неми́лостивны. нѣ́цыи же и҆ ѡ҆правда́нїе бж҃їе разꙋмѣ́вше, ꙗ҆́кѡ такѡва́ѧ творѧ́щїи досто́йни сме́рти сꙋ́ть, не то́чїю са́ми творѧ́тъ, но и҆ соизволѧ́ютъ творѧ́щымъ. сегѡ̀ ра́ди без̾ѿвѣ́тенъ є҆сѝ, ѽ чл҃вѣ́че, всѧ́къ сꙋдѧ́й: и҆́мже бо сꙋдо́мъ сꙋ́диши дрꙋ́га, себѐ ѡ҆сꙋжда́еши: та̑ѧжде бо твори́ши сꙋдѧ́й. вѣ́мы же, ꙗ҆́кѡ сꙋ́дъ бж҃їй є҆́сть пои́стиннѣ на творѧ́щихъ такѡва́ѧ. помышлѧ́еши ли же сїѧ̑, ѽ чл҃вѣ́че! сꙋдѧ́й такѡва́ѧ творѧ́щымъ, и҆ творѧ̀ са́мъ та̑ѧжде, ꙗ҆́кѡ ты̀ и҆збѣжи́ши ли сꙋда̀ бж҃їѧ; и҆лѝ ѡ҆ бога́тствѣ бл҃гости є҆гѡ̀, и҆ кро́тости и҆ долготерпѣ́нїи неради́ши, невѣ́дый, ꙗ҆́кѡ бл҃гость бж҃їѧ на покаѧ́нїе тѧ̀ веде́тъ; по жесто́кости же твое́й, и҆ непока́ѧнномꙋ се́рдцꙋ, собира́еши себѣ̀ гнѣ́въ въ де́нь гнѣ́ва, и҆ ѿкрове́нїѧ пра́веднагѡ сꙋда̀ бж҃їѧ. и҆́же возда́стъ коемꙋ́ждо по дѣлѡ́мъ є҆гѡ̀: ѻ҆́вымъ ᲂу҆́бѡ по терпѣ́нїю дѣ́ла бл҃га́гѡ, сла́вꙋ и҆ че́сть и҆ нетлѣ́нїе и҆́щꙋщымъ, живо́тъ вѣ́чный: а҆ и҆̀же по рве́нїю противлѧ́ющымсѧ ᲂу҆́бѡ и҆́стинѣ, повинꙋ́ющымсѧ же непра́вдѣ, ꙗ҆́рость и҆ гнѣ́въ. ско́рбь и҆ тѣснота̀ на всѧ́кꙋ дꙋ́шꙋ человѣ́ка творѧ́щагѡ ѕло́е, і҆ꙋде́а же пре́жде и҆ є҆́ллина. ",
}

add_apostol {
  ["номер"] = 81,
  ["комментарий"] = "Рим., 81 зач., II, 10-16.",
  ["текст_ру"] = "Бра́тие, сла́ва и честь и мир вся́кому де́лающему благо́е, иуде́еви же пре́жде и е́ллину. Несть бо на лица́ зре́ния у Бо́га. Ели́цы бо беззако́нно согреши́ша, беззако́нно и поги́бнут, и ели́цы в зако́не согреши́ша, зако́ном суд прии́мут. Не слы́шателие бо зако́на пра́ведни пред Бо́гом, но творцы́ зако́на, си́и оправдя́тся. Егда́ бо язы́цы, не иму́ще зако́на, естество́м зако́нная творя́т; си́и, зако́на не иму́ще, са́ми себе́ суть зако́н. И́же явля́ют де́ло зако́нное напи́сано в сердца́х свои́х, спослушеству́ющи им со́вести, и между́ собо́ю помысло́м осужда́ющым или́ отвеща́ющым, в день, егда́ су́дит Бог та́йная челове́ком, по благове́стию моему́, Иису́сом Христо́м. ",
  ["текст_цс"] = "Бра́тїе, сла́ва и҆ че́сть и҆ ми́ръ всѧ́комꙋ дѣ́лающемꙋ бл҃го́е, і҆ꙋде́еви же пре́жде и҆ є҆́ллинꙋ. нѣ́сть бо на лица̀ зрѣ́нїѧ ᲂу҆ бг҃а. є҆ли́цы бо беззако́ннѡ согрѣши́ша, беззако́ннѡ и҆ поги́бнꙋтъ: и҆ є҆ли́цы въ зако́нѣ согрѣши́ша, зако́номъ сꙋ́дъ прїи́мꙋтъ. не слы́шателїе бо зако́на пра́ведни пред̾ бг҃омъ, но творцы̀ зако́на, сі́и ѡ҆правдѧ́тсѧ. є҆гда́ бо ꙗ҆зы́цы не и҆мꙋ́ще зако́на, є҆стество́мъ закѡ́ннаѧ творѧ́тъ: сі́и зако́на не и҆мꙋ́ще, са́ми себѣ̀ сꙋ́ть зако́нъ: и҆́же ꙗ҆влѧ́ютъ дѣ́ло зако́нное напи́сано въ сердца́хъ свои́хъ, спослꙋшествꙋ́ющи и҆̀мъ со́вѣсти, и҆ междꙋ̀ собо́ю помыслѡ́мъ, ѡ҆сꙋжда́ющымъ и҆лѝ ѿвѣща́ющымъ, въ де́нь є҆гда̀ сꙋ́дитъ бг҃ъ та̑йнаѧ человѣ́кѡмъ, по бл҃говѣ́стїю моемꙋ̀, і҆и҃сомъ хрⷭ҇то́мъ. ",
}

add_apostol {
  ["номер"] = 82,
  ["комментарий"] = "Рим., 82 зач., II, 14–29.",
  ["текст_ру"] = "Бра́тие, егда́ язы́цы, не иму́ще зако́на, естество́м зако́нная творя́т, си́и, зако́на не иму́ще, са́ми себе́ суть зако́н. И́же явля́ют де́ло зако́нное напи́сано в сердца́х свои́х, спослушеству́ющи им со́вести, и между́ собо́ю помысло́м осужда́ющым или́ отвеща́ющым, в день, егда́ су́дит Бог та́йная челове́ком, по благове́стию моему́, Иису́сом Христо́м. Се ты иуде́й имену́ешися, и почива́еши на зако́не, и хва́лишися о Бо́зе, и разуме́еши во́лю, и разсужда́еши лу́чшая, науча́емь от зако́на, упова́я же себе́ вожда́ бы́ти слепы́м, све́та су́щым во тме, наказа́теля безу́мным, учи́теля младе́нцем, иму́ща о́браз ра́зума и и́стины в зако́не. Науча́я у́бо ина́го, себе́ ли не учи́ши, пропове́дая не кра́сти, кра́деши; глаго́ля не прелюбы́ твори́ти, прелюбы́ твори́ши; гнуша́яся и́дол, свята́я кра́деши; и́же в зако́не хва́лишися, преступле́нием зако́на Бо́га безче́ствуеши. И́мя бо Бо́жие ва́ми ху́лится во язы́цех, я́коже есть пи́сано. Обре́зание у́бо по́льзует, а́ще зако́н твори́ши. А́ще же зако́на престу́пник еси́, обре́зание твое́ необре́зание бысть. А́ще у́бо необре́зание оправда́ние зако́на сохрани́т, не необре́зание ли его́ во обре́зание вмени́тся, и осу́дит е́же от естества́ необре́зание, зако́н соверша́ющее, тебе́, и́же Писа́нием и обре́занием су́ща престу́пника зако́на. Не бо и́же я́ве, иуде́й есть, ни е́же я́ве во пло́ти, обре́зание, но и́же вта́йне иуде́й, и обре́зание се́рдца ду́хом, а не Писа́нием, ему́же похвала́ не от челове́к, но от Бо́га. ",
  ["текст_цс"] = "Бра́тїе, є҆гда̀ ꙗ҆зы́цы не и҆мꙋ́ще зако́на, є҆стество́мъ закѡ́ннаѧ творѧ́тъ: сі́и зако́на не и҆мꙋ́ще, са́ми себѣ̀ сꙋ́ть зако́нъ: и҆́же ꙗ҆влѧ́ютъ дѣ́ло зако́нное напи́сано въ сердца́хъ свои́хъ, спослꙋшествꙋ́ющи и҆̀мъ со́вѣсти, и҆ междꙋ̀ собо́ю помыслѡ́мъ, ѡ҆сꙋжда́ющымъ и҆лѝ ѿвѣща́ющымъ, въ де́нь є҆гда̀ сꙋ́дитъ бг҃ъ та̑йнаѧ человѣ́кѡмъ, по бл҃говѣ́стїю моемꙋ̀, і҆и҃сомъ хрⷭ҇то́мъ. сѐ ты̀ і҆ꙋде́й и҆менꙋ́ешисѧ, и҆ почива́еши на зако́нѣ, и҆ хва́лишисѧ ѡ҆ бз҃ѣ: и҆ разꙋмѣ́еши во́лю, и҆ разсꙋжда́еши лꙋ̑чшаѧ, наꙋча́емь ѿ зако́на. ᲂу҆пова́ѧ же себѐ вожда̀ бы́ти слѣпы̑мъ, свѣ́та сꙋ́щымъ во тмѣ̀, наказа́телѧ безꙋ̑мнымъ, ᲂу҆чи́телѧ младе́нцємъ, и҆мꙋ́ща ѻ҆́бразъ ра́зꙋма и҆ и҆́стины въ зако́нѣ: наꙋча́ѧ ᲂу҆̀бо и҆на́го, себе́ ли не ᲂу҆чи́ши; проповѣ́даѧ не кра́сти, кра́деши; глаго́лѧ не прелюбы̀ твори́ти, прелюбы̀ твори́ши; гнꙋша́ѧсѧ і҆́дѡлъ, ст҃а̑ѧ кра́деши, и҆́же въ зако́нѣ хва́лишисѧ, престꙋпле́нїемъ зако́на бг҃а безче́ствꙋеши. и҆́мѧ бо бж҃їе ва́ми хꙋ́литсѧ во ꙗ҆зы́цѣхъ, ꙗ҆́коже є҆́сть пи́сано. ѡ҆брѣ́занїе ᲂу҆̀бо по́льзꙋетъ, а҆́ще зако́нъ твори́ши: а҆́ще же зако́на престꙋ́пникъ є҆сѝ, ѡ҆брѣ́занїе твоѐ неѡбрѣ́занїе бы́сть. а҆́ще ᲂу҆̀бо неѡбрѣ́занїе ѡ҆правда́нїе зако́на сохрани́тъ, не неѡбрѣ́занїе ли є҆гѡ̀ во ѡ҆брѣ́занїе вмѣни́тсѧ, и҆ ѡ҆сꙋ́дитъ є҆́же ѿ є҆стества̀ неѡбрѣ́занїе зако́нъ соверша́ющее, тебѐ, и҆́же писа́нїемъ и҆ ѡ҆брѣ́занїемъ сꙋ́ща престꙋ́пника зако́на. не бо̀ и҆́же ꙗ҆́вѣ і҆ꙋде́й є҆́сть, ни є҆́же ꙗ҆́вѣ во пло́ти, ѡ҆брѣ́занїе: но и҆́же вта́йнѣ і҆ꙋде́й, и҆ ѡ҆брѣ́занїе се́рдца дх҃омъ, а҆ не писа́нїемъ: є҆мꙋ́же похвала̀ не ѿ человѣ̑къ, но ѿ бг҃а. ",
}

add_apostol {
  ["номер"] = 83,
  ["комментарий"] = "Рим., 83 зач., II, 28 – III, 18.",
  ["текст_ру"] = "Бра́тие, не и́же я́ве, иуде́й есть, ни е́же я́ве во пло́ти, обре́зание. Но и́же вта́йне иуде́й, и обре́зание се́рдца ду́хом, а не Писа́нием, ему́же похвала́ не от челове́к, но от Бо́га. Что у́бо ли́шшее иуде́ю? Или́ ка́я по́льза обре́зания? Мно́го по вся́кому образу: пе́рвее у́бо, я́ко вве́рена бы́ша им словеса́ Бо́жия. Что бо, а́ще не ве́роваша не́цыи? Еда́ у́бо неве́рствие их ве́ру Бо́жию упраздни́т? Да не бу́дет: да бу́дет же Бог и́стинен, всяк же челове́к ложь, я́коже есть пи́сано: я́ко да оправди́шися во словесе́х Твои́х, и победи́ши, внегда́ суди́ти Ти. А́ще ли непра́вда на́ша Бо́жию пра́вду составля́ет, что рече́м? Еда́ ли непра́веден Бог нанося́й гнев? По челове́ку глаго́лю, да не бу́дет, поне́же ка́ко суди́ти и́мать Бог ми́ру? А́ще у́бо и́стина Бо́жия в мое́й лжи избы́точествова в сла́ву Его́, что еще́ и аз я́ко гре́шник осужда́юся, и не я́коже ху́лимся, и я́коже глаго́лют не́цыи нас глаго́лати, я́ко сотвори́м злая, да прии́дут блага́я, и́хже суд пра́веден есть. Что у́бо, преиме́ем ли? Ника́коже, предукори́хом бо иуде́и же и е́ллины вся под грехо́м бы́ти, я́коже есть пи́сано. Я́ко несть пра́веден никто́же, несть разумева́яй, и несть взыска́яй Бо́га, вси уклони́шася, вку́пе непотре́бни бы́ша. Несть творя́й благосты́ню, несть да́же до еди́наго. Гроб отве́рст горта́нь их, язы́ки свои́ми льща́ху. Яд а́спидов под устна́ми их. И́хже уста́ кля́твы и го́рести по́лна суть. Ско́ры но́ги их пролия́ти кровь, сокруше́ние и озлобле́ние на путе́х их, и пути́ ми́рнаго не позна́ша. Несть стра́ха Бо́жия пред очи́ма их. ",
  ["текст_цс"] = "Бра́тїе, не и҆́же ꙗ҆́вѣ і҆ꙋде́й є҆́сть, ни є҆́же ꙗ҆́вѣ во пло́ти, ѡ҆брѣ́занїе: но и҆́же вта́йнѣ і҆ꙋде́й, и҆ ѡ҆брѣ́занїе се́рдца дх҃омъ, а҆ не писа́нїемъ: є҆мꙋ́же похвала̀ не ѿ человѣ̑къ, но ѿ бг҃а. что̀ ᲂу҆̀бо ли́шше і҆ꙋде́ю; и҆лѝ ка́ѧ по́льза ѡ҆брѣ́занїѧ; мно́гѡ по всѧ́комꙋ ѻ҆́бразꙋ: пе́рвѣе ᲂу҆́бѡ, ꙗ҆́кѡ ввѣ́рена бы́ша и҆̀мъ словеса̀ бж҃їѧ. что́ бо, а҆́ще не вѣ́роваша нѣ́цыи; є҆да̀ ᲂу҆́бѡ невѣ́рствїе и҆́хъ вѣ́рꙋ бж҃їю ᲂу҆праздни́тъ; да не бꙋ́детъ: да бꙋ́детъ же бг҃ъ и҆́стиненъ, всѧ́къ же человѣ́къ ло́жъ, ꙗ҆́коже є҆́сть пи́сано: ꙗ҆́кѡ да ѡ҆правди́шисѧ во словесѣ́хъ твои́хъ, и҆ побѣди́ши внегда̀ сꙋди́ти тѝ. а҆́ще ли непра́вда на́ша бж҃їю пра́вдꙋ составлѧ́етъ, что̀ рече́мъ; є҆да́ ли непра́веденъ бг҃ъ, наносѧ́й гнѣ́въ; [по человѣ́кꙋ глаго́лю,] да не бꙋ́детъ: поне́же ка́кѡ сꙋди́ти и҆́мать бг҃ъ мі́рꙋ; а҆́ще ᲂу҆́бѡ и҆́стина бж҃їѧ въ мое́й лжѝ и҆збы́точествова въ сла́вꙋ є҆гѡ̀: что̀ є҆щѐ и҆ а҆́зъ ꙗ҆́кѡ грѣ́шникъ ѡ҆сꙋжда́юсѧ; и҆ не [ꙗ҆́коже хꙋ́лимсѧ, и҆ ꙗ҆́коже глаго́лютъ нѣ́цыи на́съ глаго́лати:] ꙗ҆́кѡ сотвори́мъ ѕла̑ѧ, да прїи́дꙋтъ блага̑ѧ: и҆́хже сꙋ́дъ пра́веденъ є҆́сть. что̀ ᲂу҆̀бо; преимѣ́емъ ли; ника́коже: пред̾ꙋкори́хомъ бо і҆ꙋдє́и же и҆ є҆́ллины всѧ̀ под̾ грѣхо́мъ бы́ти, ꙗ҆́коже є҆́сть пи́сано: ꙗ҆́кѡ нѣ́сть пра́веденъ никто́же. нѣ́сть разꙋмѣва́ѧй, и҆ нѣ́сть взыска́ѧй бг҃а. всѝ ᲂу҆клони́шасѧ, вкꙋ́пѣ непотре́бни бы́ша: нѣ́сть творѧ́й бл҃госты́ню, нѣ́сть да́же до є҆ди́нагѡ. гро́бъ ѿве́рстъ горта́нь и҆́хъ, ѧ҆зы́ки свои́ми льща́хꙋ: ꙗ҆́дъ а҆́спїденъ под̾ ᲂу҆стна́ми и҆́хъ: и҆́хже ᲂу҆ста̀ клѧ́твы и҆ го́рести пѡ́лна сꙋ́ть. ско́ры но́ги и҆́хъ пролїѧ́ти кро́вь: сокрꙋше́нїе и҆ ѡ҆ѕлобле́нїе на пꙋте́хъ и҆́хъ: и҆ пꙋтѝ ми́рнагѡ не позна́ша. нѣ́сть стра́ха бж҃їѧ пред̾ ѻ҆чи́ма и҆́хъ. ",
}

add_apostol {
  ["номер"] = 84,
  ["комментарий"] = "Рим., 84 зач., III, 19–26.",
  ["текст_ру"] = "Бра́тие, ве́мы, я́ко ели́ка зако́н глаго́лет, су́щым в зако́не глаго́лет, да вся́ка уста́ заградя́тся, и пови́нен бу́дет весь мир Бо́гови. Зане́ от дел зако́на не оправди́тся вся́ка плоть пред Ним, зако́ном бо позна́ние греха́. Ны́не же кроме́ зако́на пра́вда Бо́жия яви́ся, свиде́тельствуема от зако́на и проро́к. Пра́вда же Бо́жия ве́рою Иису́с Христо́вою во вся и на всех ве́рующих. Несть бо ра́знствия, вси бо согреши́ша, и лише́ни суть сла́вы Бо́жия, оправда́еми ту́не благода́тию Его́, избавле́нием, е́же о Христе́ Иису́се. Его́же предположи́ Бог очище́ние ве́рою в Кро́ви Его́, в явле́ние пра́вды Своея́, за отпуще́ние пре́жде бы́вших грехо́в, в долготерпе́нии Бо́жии, и в показа́ние пра́вды Его́ в ны́нешнее вре́мя, во е́же бы́ти Ему́ пра́ведну и оправда́ющу су́щаго от ве́ры Иису́совы. ",
  ["текст_цс"] = "Бра́тїе, вѣ́мы, ꙗ҆́кѡ є҆ли̑ка зако́нъ глаго́летъ, сꙋ́щымъ въ зако́нѣ глаго́летъ: да всѧ́ка ᲂу҆ста̀ заградѧ́тсѧ, и҆ пови́ненъ бꙋ́детъ ве́сь мі́ръ бг҃ови. занѐ ѿ дѣ́лъ зако́на не ѡ҆правди́тсѧ всѧ́ка пло́ть пред̾ ни́мъ: зако́номъ бо позна́нїе грѣха̀. ны́нѣ же кромѣ̀ зако́на пра́вда бж҃їѧ ꙗ҆ви́сѧ, свидѣ́тельствꙋема ѿ зако́на и҆ прорѡ́къ: пра́вда же бж҃їѧ вѣ́рою і҆и҃съ хрⷭ҇то́вою, во всѧ̀ и҆ на всѣ́хъ вѣ́рꙋющихъ. нѣ́сть бо ра́знствїѧ: вси́ бо согрѣши́ша, и҆ лише́ни сꙋ́ть сла́вы бж҃їѧ, ѡ҆правда́еми тꙋ́не бл҃года́тїю є҆гѡ̀, и҆збавле́нїемъ є҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. є҆го́же предположѝ бг҃ъ ѡ҆чище́нїе вѣ́рою въ кро́ви є҆гѡ̀, въ ꙗ҆вле́нїе пра́вды своеѧ̀, за ѿпꙋще́нїе пре́жде бы́вшихъ грѣхѡ́въ: въ долготерпѣ́нїи бж҃їи, и҆ въ показа́нїе пра́вды є҆гѡ̀ въ ны́нѣшнее вре́мѧ, во є҆́же бы́ти є҆мꙋ̀ пра́веднꙋ, и҆ ѡ҆правда́ющꙋ сꙋ́щаго ѿ вѣ́ры і҆и҃совы. ",
}

