  ["номер"] = 94,
  ["комментарий"] = "Рим., 94 зач., VII, 1–13.",
  ["текст_ру"] = "Бра́тие, ве́дущым зако́н глаго́лю, я́ко зако́н облада́ет над челове́ком, во ели́ко вре́мя живе́т? И́бо мужа́тая жена́ жи́ву му́жу привя́зана есть зако́ном, а́ще ли же у́мрет муж ея́, разреши́тся от зако́на му́жескаго. Те́мже у́бо, жи́ву су́щу му́жу, прелюбоде́йца быва́ет, а́ще бу́дет му́жеви ино́му, а́ще ли у́мрет муж ея́, свобо́дна есть от зако́на, не бы́ти ей прелюбоде́йце, бы́вшей му́жу ино́му. Те́мже, бра́тие моя́, и вы умро́сте зако́ну те́лом Христо́вым, во е́же бы́ти вам ино́му, Воста́вшему из ме́ртвых, да плод принесе́м Бо́гови. Егда́ бо бе́хом во пло́ти, стра́сти грехо́вныя, я́же зако́ном, де́йствоваху во у́дех на́ших, во е́же плод твори́ти сме́рти. Ны́не же упраздни́хомся от зако́на, уме́рше, и́мже держи́ми бе́хом, я́ко рабо́тати нам Бо́гови во обновле́нии ду́ха, а не в ве́тхости пи́смене. Что у́бо рече́м? Зако́н ли грех? Да не бу́дет. Но греха́ не знах, то́чию зако́ном, по́хоти же не ве́дах, а́ще не бы зако́н глаго́лаше: не похо́щеши. Вину́ же прие́м грех за́поведию, соде́ла во мне вся́ку по́хоть, без зако́на бо грех мертв есть. Аз же живя́х кроме́ зако́на иногда́, прише́дши же за́поведи, грех у́бо оживе́, аз же умро́х, и обре́теся ми за́поведь, я́же в живо́т, сия́ в смерть, грех бо вину́ прие́м за́поведию, прельсти́ мя, и то́ю умертви́ мя. Те́мже у́бо зако́н свят, и за́поведь свята́ и пра́ведна и блага́. Благо́е ли у́бо бысть мне смерть? Да не бу́дет, но грех, да яви́тся грех, благи́м ми содева́я смерть, да бу́дет по премно́гу гре́шен грех за́поведию. ",
  ["текст_цс"] = "Бра́тїе, вѣ́дꙋщымъ зако́нъ глаго́лю, ꙗ҆́кѡ зако́нъ ѡ҆блада́етъ над̾ чл҃вѣ́комъ, во є҆ли́ко вре́мѧ живе́тъ; и҆́бо мꙋжа́таѧ жена̀ жи́вꙋ мꙋ́жꙋ привѧ́зана є҆́сть зако́номъ: а҆́ще ли же ᲂу҆́мретъ мꙋ́жъ є҆ѧ̀, разрѣши́тсѧ ѿ зако́на мꙋ́жескагѡ. тѣ́мже ᲂу҆̀бо жи́вꙋ сꙋ́щꙋ мꙋ́жꙋ, прелюбодѣ́йца быва́етъ, а҆́ще бꙋ́детъ мꙋ́жеви и҆но́мꙋ. а҆́ще ли ᲂу҆́мретъ мꙋ́жъ є҆ѧ̀, свобо́дна є҆́сть ѿ зако́на, не бы́ти є҆́й прелюбодѣ́йцѣ, бы́вшей мꙋ́жꙋ и҆но́мꙋ. тѣ́мже бра́тїе моѧ̀, и҆ вы̀ ᲂу҆мро́сте зако́нꙋ тѣ́ломъ хрⷭ҇то́вымъ, во є҆́же бы́ти ва́мъ и҆но́мꙋ, воста́вшемꙋ и҆з̾ ме́ртвыхъ, да пло́дъ принесе́мъ бг҃ови. є҆гда́ бо бѣ́хомъ во пло́ти, стра̑сти грѣхѡ́вныѧ, ꙗ҆̀же зако́номъ, дѣ́йствовахꙋ во ᲂу҆́дѣхъ на́шихъ, во є҆́же пло́дъ твори́ти сме́рти. ны́нѣ же ᲂу҆праздни́хомсѧ ѿ зако́на, ᲂу҆ме́рше и҆́мже держи́ми бѣ́хомъ: ꙗ҆́кѡ рабо́тати на́мъ [бг҃ови] во ѡ҆бновле́нїи дх҃а, а҆ не въ ве́тхости пи́смене. что̀ ᲂу҆̀бо рече́мъ; зако́нъ ли грѣ́хъ; да не бꙋ́детъ. но грѣха̀ не зна́хъ, то́чїю зако́номъ: по́хоти же не вѣ́дахъ, а҆́ще не зако́нъ глаго́лаше: не похо́щеши. винꙋ́ же прїе́мъ грѣ́хъ за́повѣдїю, содѣ́ла во мнѣ̀ всѧ́кꙋ по́хоть: без̾ зако́на бо грѣ́хъ ме́ртвъ є҆́сть. а҆́зъ же живѧ́хъ кромѣ̀ зако́на и҆ногда̀: прише́дши же за́повѣди, грѣ́хъ ᲂу҆́бѡ ѡ҆живѐ, а҆́зъ же ᲂу҆мро́хъ: и҆ ѡ҆брѣ́тесѧ мѝ за́повѣдь, ꙗ҆́же въ живо́тъ, сїѧ̀ въ сме́рть. грѣ́хъ бо винꙋ̀ прїе́мъ за́повѣдїю, прельсти́ мѧ, и҆ то́ю ᲂу҆мертви́ мѧ. тѣ́мже ᲂу҆̀бо зако́нъ свѧ́тъ, и҆ за́повѣдь свѧта̀, и҆ пра́ведна и҆ блага̀. благо́е ли ᲂу҆̀бо бы́сть мнѣ̀ сме́рть; да не бꙋ́детъ: но грѣ́хъ, да ꙗ҆ви́тсѧ грѣ́хъ, бл҃ги́мъ мѝ содѣва́ѧ сме́рть: да бꙋ́детъ по премно́гꙋ грѣ́шенъ грѣ́хъ за́повѣдїю. ",
}

add_apostol {
  ["номер"] = 95,
  ["комментарий"] = "Рим., 95 зач., VII, 14 – VIII, 2.",
  ["текст_ру"] = "Бра́тие, ве́мы, я́ко зако́н духо́вен есть, аз же пло́тян есмь, про́дан под грех. Е́же бо содева́ю, не разуме́ю, не е́же бо хощу́, сие́ творю́, но е́же ненави́жду, то соде́ловаю. А́ще ли, е́же не хощу́, сие́ творю́, хвалю́ зако́н я́ко добр, ны́не же не ктому́ аз сие́ содева́ю, но живы́й во мне грех. Вем бо, я́ко не живе́т во мне, си́речь во пло́ти мое́й, до́брое: е́же бо хоте́ти прилежи́т ми, а е́же соде́яти до́брое, не обрета́ю. Не е́же бо хощу́ до́брое, творю́, но е́же не хощу́ зло́е, сие́ содева́ю. А́ще ли, е́же не хощу́ аз, сие́ творю́, уже́ не аз сие́ творю́, но живы́й во мне грех. Обрета́ю у́бо зако́н, хотя́щу ми твори́ти до́брое, я́ко мне зло́е прилежи́т. Соуслажда́юся бо зако́ну Бо́жию по вну́треннему челове́ку. Ви́жду же ин зако́н во у́дех мои́х, проти́ву вою́ющь зако́ну ума́ моего́ и пленя́ющь мя зако́ном грехо́вным, су́щим во у́дех мои́х. Окая́нен аз челове́к, кто мя изба́вит от те́ла сме́рти сея́? Благодарю́ Бо́га моего́ Иису́с Христо́м Го́сподем на́шим. Те́мже у́бо сам аз умо́м мои́м рабо́таю зако́ну Бо́жию, пло́тию же зако́ну грехо́вному. Ни еди́но у́бо ны́не осужде́ние су́щым о Христе́ Иису́се не по пло́ти ходя́щым, но по ду́ху. Зако́н бо ду́ха жи́зни о Христе́ Иису́се свободи́л мя есть от зако́на грехо́внаго и сме́рти. ",
  ["текст_цс"] = "Бра́тїе, вѣ́мы, ꙗ҆́кѡ зако́нъ дꙋхо́венъ є҆́сть: а҆́зъ же пло́тѧнъ є҆́смь, про́данъ под̾ грѣ́хъ. є҆́же бо содѣва́ю, не разꙋмѣ́ю: не є҆́же бо хощꙋ̀, сїѐ творю̀: но є҆́же ненави́ждꙋ, то̀ содѣ́ловаю. а҆́ще ли є҆́же не хощꙋ̀, сїѐ творю̀, хвалю̀ зако́нъ ꙗ҆́кѡ до́бръ. ны́нѣ же не ктомꙋ̀ а҆́зъ сїѐ содѣва́ю, но живы́й во мнѣ̀ грѣ́хъ. вѣ́мъ бо, ꙗ҆́кѡ не живе́тъ во мнѣ̀, си́рѣчь въ пло́ти мое́й, до́брое: є҆́же бо хотѣ́ти, прилѣжи́тъ мѝ: а҆ є҆́же содѣ́ѧти до́брое, не ѡ҆брѣта́ю. не є҆́же бо хощꙋ̀ до́брое, творю̀: но є҆́же не хощꙋ̀ ѕло́е, сїѐ содѣва́ю. а҆́ще ли є҆́же не хощꙋ̀ а҆́зъ, сїѐ творю̀: ᲂу҆жѐ не а҆́зъ сїѐ творю̀, но живы́й во мнѣ̀ грѣ́хъ. ѡ҆брѣта́ю ᲂу҆̀бо зако́нъ, хотѧ́щꙋ мѝ твори́ти до́брое, ꙗ҆́кѡ мнѣ̀ ѕло́е прилѣжи́тъ. соꙋслажда́юсѧ бо зако́нꙋ бж҃їю по внꙋ́треннемꙋ человѣ́кꙋ. ви́ждꙋ же и҆́нъ зако́нъ во ᲂу҆́дѣхъ мои́хъ, проти́вꙋ вою́ющъ зако́нꙋ ᲂу҆ма̀ моегѡ̀, и҆ плѣнѧ́ющъ мѧ̀ зако́номъ грѣхо́внымъ, сꙋ́щимъ во ᲂу҆́дѣхъ мои́хъ. ѻ҆каѧ́ненъ а҆́зъ человѣ́къ: кто́ мѧ и҆зба́витъ ѿ тѣ́ла сме́рти сеѧ̀; благодарю̀ бг҃а моего̀ і҆и҃съ хрⷭ҇то́мъ гдⷭ҇емъ на́шимъ. тѣ́мже ᲂу҆̀бо са́мъ а҆́зъ ᲂу҆мо́мъ мои́мъ рабо́таю зако́нꙋ бж҃їю, пло́тїю же зако́нꙋ грѣхо́вномꙋ. ни є҆ди́но ᲂу҆̀бо ны́нѣ ѡ҆сꙋжде́нїе сꙋ́щымъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, не по пло́ти ходѧ́щымъ, но по дꙋ́хꙋ. зако́нъ бо дх҃а жи́зни ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, свободи́лъ мѧ̀ є҆́сть ѿ зако́на грѣхо́внагѡ и҆ сме́рти. ",
}

add_apostol {
  ["номер"] = 96,
  ["комментарий"] = "Рим., 96 зач., VIII, 2–13.",
  ["текст_ру"] = "Бра́тие, зако́н ду́ха жи́зни о Христе́ Иису́се свободи́л мя есть от зако́на грехо́внаго и сме́рти. Немощно́е бо зако́на, в не́мже немоществова́ше пло́тию, Бог Сы́на Своего́ посла́ в подо́бии пло́ти греха́, и о гресе́ осуди́ грех во пло́ти, да оправда́ние зако́на испо́лнится в нас, не по пло́ти ходя́щих, но по ду́ху. Су́щии бо по пло́ти, плотска́я му́дрствуют. А и́же по ду́ху, духо́вная. Мудрова́ние бо плотско́е смерть есть, а мудрова́ние духо́вное живо́т и мир, зане́ мудрова́ние плотско́е вражда́ на Бо́га, зако́ну бо Бо́жию не покаря́ется, ниже́ бо мо́жет. Су́щии же во пло́ти, Бо́гу угоди́ти не мо́гут. Вы же не́сте во пло́ти, но в ду́се, поне́же Дух Бо́жий живе́т в вас. А́ще же кто Ду́ха Христо́ва не и́мать, сей несть Его́в. А́ще ли Христо́с в вас, плоть у́бо мертва́ греха́ ра́ди, дух же живе́т пра́вды ра́ди. А́ще ли же Дух Воскреси́вшаго Иису́са от ме́ртвых живе́т в вас, Воздви́гий Христа́ из ме́ртвых оживотвори́т и ме́ртвенная телеса́ ва́ша, живу́щим Ду́хом Его́ в вас. Те́мже у́бо, бра́тие, до́лжни есмы́ не пло́ти, е́же по пло́ти жи́ти. А́ще бо по пло́ти живете́, и́мате умре́ти, а́ще ли ду́хом дея́ния плотска́я умерщвля́ете, жи́ви бу́дете. ",
  ["текст_цс"] = "Бра́тїе, зако́нъ дх҃а жи́зни ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, свободи́лъ мѧ̀ є҆́сть ѿ зако́на грѣхо́внагѡ и҆ сме́рти. немощно́е бо зако́на, въ не́мже немоществова́ше пло́тїю, бг҃ъ сн҃а своего̀ посла̀ въ подо́бїи пло́ти грѣха̀, и҆ ѡ҆ грѣсѣ̀ ѡ҆сꙋдѝ грѣ́хъ во пло́ти: да ѡ҆правда́нїе зако́на и҆спо́лнитсѧ въ на́съ, не по пло́ти ходѧ́щихъ, но по дꙋ́хꙋ. сꙋ́щїи бо по пло́ти, плотска̑ѧ мꙋ́дрствꙋютъ: а҆ и҆̀же по дꙋ́хꙋ, дꙋхѡ́внаѧ. мꙋдрова́нїе бо плотско́е, сме́рть є҆́сть: а҆ мꙋдрова́нїе дꙋхо́вное, живо́тъ и҆ ми́ръ. занѐ мꙋдрова́нїе плотско́е, вражда̀ на бг҃а: зако́нꙋ бо бж҃їю не покорѧ́етсѧ, ниже́ бо мо́жетъ. сꙋ́щїи же во пло́ти бг҃ꙋ ᲂу҆годи́ти не мо́гꙋтъ. вы́ же нѣ́сте во пло́ти, но въ дꙋ́сѣ: поне́же дх҃ъ бж҃їй живе́тъ въ ва́съ. а҆́ще ли кто̀ дх҃а хрⷭ҇то́ва не и҆́мать, се́й нѣ́сть є҆гѡ́въ. а҆́ще ли хрⷭ҇то́съ въ ва́съ, пло́ть ᲂу҆́бѡ мертва̀ грѣха̀ ра́ди: дꙋ́хъ же живе́тъ пра́вды ра́ди. а҆́ще ли же дх҃ъ воскреси́вшагѡ і҆и҃са ѿ ме́ртвыхъ живе́тъ въ ва́съ, воздви́гїй хрⷭ҇та̀ и҆з̾ ме́ртвыхъ, ѡ҆животвори́тъ и҆ ме́ртвєннаѧ тѣлеса̀ ва́ша, живꙋ́щимъ дх҃омъ є҆гѡ̀ въ ва́съ. тѣ́мже ᲂу҆̀бо бра́тїе, до́лжни є҆смы̀ не пло́ти, є҆́же по пло́ти жи́ти. а҆́ще бо по пло́ти живетѐ, и҆́мате ᲂу҆мре́ти: а҆́ще ли дх҃омъ дѣѧ̑нїѧ плотска́ѧ ᲂу҆мерщвлѧ́ете, жи́ви бꙋ́дете. ",
}

