  ["комментарий"] = "Рим., 101 зач., IX, 6–19.",
  ["текст_ру"] = "Бра́тие, не та́коже я́ко отпаде́ сло́во Бо́жие, не вси бо су́щии от Изра́иля, си́и Изра́иль, ни зане́ суть се́мя Авраа́мле, вси ча́да, но во Исаа́це, рече́, нарече́тся ти се́мя. Си́речь, не ча́да плотска́я, сия́ ча́да Бо́жия, но ча́да обетова́ния причита́ются в се́мя. Обетова́ния бо сло́во сие́: на сие́ вре́мя прииду́, и бу́дет Са́рре сын. Не то́чию же, но и Реве́кка от еди́наго ло́жа Исаа́ка отца́ на́шего иму́щи. Не у́бо не ро́ждшымся, ни сотво́ршым чесо́ бла́го или́ зло, да по избра́нию предложе́ние Бо́жие пребу́дет, не от дел, но от Призыва́ющаго, рече́ся ей, я́ко бо́лий порабо́тает ме́ньшему, я́коже есть пи́сано: Иа́кова возлюби́х, Иса́ва же возненави́дех. Что у́бо рече́м? Еда́ непра́вда у Бо́га? Да не бу́дет. Моисе́ови бо глаго́лет: поми́лую, его́же а́ще поми́лую, и уще́дрю, его́же а́ще уще́дрю. Те́мже у́бо ни хотя́щаго, ни теку́щаго, но ми́лующаго Бо́га. Глаго́лет бо Писа́ние фарао́нови: я́ко на и́стое сие́ воздвиго́х тя, я́ко да покажу́ тобо́ю си́лу Мою́ и я́ко да возвести́тся и́мя Мое́ по всей земли́. Те́мже у́бо, его́же хо́щет, ми́лует, а его́же хо́щет, ожесточа́ет. Рече́ши же ми у́бо: чесо́ ра́ди у́бо укоря́ет, во́ли бо Его́ кто проти́витися мо́жет? ",
  ["текст_цс"] = "Бра́тїе, не та́коже ꙗ҆́кѡ ѿпадѐ сло́во бж҃їе: не вси́ бо сꙋ́щїи ѿ і҆и҃лѧ, сі́и і҆и҃ль: ни занѐ сꙋ́ть сѣ́мѧ а҆враа́мле, всѝ ча̑да: но ѡ҆ і҆саа́цѣ, речѐ, нарече́тсѧ тѝ сѣ́мѧ. си́рѣчь, не ча̑да плотска̑ѧ, сїѧ̀ ча̑да бж҃їѧ, но ча̑да ѡ҆бѣтова́нїѧ, причита́ютсѧ въ сѣ́мѧ: ѡ҆бѣтова́нїѧ бо сло́во сїѐ: на сїѐ вре́мѧ прїидꙋ̀, и҆ бꙋ́детъ са́ррѣ сы́нъ. не то́чїю же, но и҆ реве́кка ѿ є҆ди́нагѡ ло́жа і҆саа́ка ѻ҆ц҃а̀ на́шегѡ и҆мꙋ́щи. не ᲂу҆́бѡ ро́ждшымсѧ, ни сотво́ршымъ чесо̀ бла́го и҆лѝ ѕло̀ да по и҆збра́нїю предложе́нїе бж҃їе пребꙋ́детъ, не ѿ дѣ́лъ, но ѿ призыва́ющагѡ, рече́сѧ є҆́й: ꙗ҆́кѡ бо́лїй порабо́таетъ ме́ньшемꙋ. ꙗ҆́коже є҆́сть пи́сано: і҆а́кѡва возлюби́хъ, и҆са́ѵа же возненави́дѣхъ. что̀ ᲂу҆̀бо рече́мъ; є҆да̀ непра́вда ᲂу҆ бг҃а; да не бꙋ́детъ. мѡѷсе́ови бо глаго́летъ: поми́лꙋю, є҆го́же а҆́ще поми́лꙋю: и҆ ᲂу҆ще́дрю, є҆го́же а҆́ще ᲂу҆ще́дрю. тѣ́мже ᲂу҆̀бо ни хотѧ́щагѡ, ни текꙋ́щагѡ, но ми́лꙋющагѡ бг҃а. глаго́летъ бо писа́нїе фараѡ́нови: ꙗ҆́кѡ на и҆́стое сїѐ воздвиго́хъ тѧ̀, ꙗ҆́кѡ да покажꙋ̀ тобо́ю си́лꙋ мою̀: и҆ ꙗ҆́кѡ да возвѣсти́тсѧ и҆́мѧ моѐ по все́й землѝ. тѣ́мже ᲂу҆̀бо, є҆го́же хо́щетъ, ми́лꙋетъ: а҆ є҆го́же хо́щетъ, ѡ҆жесточа́етъ. рече́ши же мѝ ᲂу҆̀бо: чесѡ̀ ра́ди ᲂу҆́бѡ ᲂу҆корѧ́етъ; во́ли бо є҆гѡ̀ кто̀ проти́витисѧ мо́жетъ; ",
}

add_apostol {
  ["номер"] = 102,
  ["комментарий"] = "Рим., 102 зач., IX, 18–33.",
  ["текст_ру"] = "Бра́тие, Бог его́же хо́щет, ми́лует, а его́же хо́щет, ожесточа́ет. Рече́ши же ми у́бо: чесо́ ра́ди у́бо укоря́ет, во́ли бо Его́ кто проти́витися мо́жет? Те́мже у́бо, о челове́че, ты кто еси́, проти́в отвеща́яй Бо́гови? Еда́ рече́т зда́ние созда́вшему е́: почто́ мя сотвори́л еси́ та́ко? Или́ не и́мать вла́сти скуде́льник на бре́нии, от того́же смеше́ния сотвори́ти ов у́бо сосу́д в честь, ов же не в честь? А́ще ли же хотя́ Бог показа́ти гнев Свой и яви́ти си́лу Свою́, пренесе́ во мно́зе долготерпе́нии сосу́ды гне́ва соверше́ны в поги́бель, и да ска́жет бога́тство сла́вы Своея́ на сосу́дех ми́лости, я́же предугото́ва в сла́ву, и́хже и призва́ нас не то́чию от иуде́й, но и от язы́к. Я́коже и во Оси́и глаго́лет: нареку́ не лю́ди Моя́ лю́ди Моя́, и невозлю́бленую возлю́блену. И бу́дет на ме́сте, иде́же рече́ся им: не лю́дие Мои́ есте́ вы, та́мо нареку́тся сы́нове Бо́га жива́го. Иса́иа же вопие́т о Изра́или: а́ще бу́дет число́ сыно́в Изра́илевых я́ко песо́к морски́й, оста́нок спасе́тся. Сло́во бо скончава́я и сокраща́я в пра́вде, я́ко сло́во сокраще́но сотвори́т Госпо́дь на земли́. И я́коже прорече́ Иса́иа: а́ще не бы Госпо́дь Савао́ф оста́вил нам се́мене, я́коже Содо́м у́бо бы́ли бы́хом, и я́коже Гомо́рру уподо́билися бы́хом. Что у́бо рече́м, я́ко язы́цы, не гоня́щии пра́вду, постиго́ша пра́вду, пра́вду же, я́же от ве́ры. Изра́иль же, гоня́ зако́н пра́вды, в зако́н пра́вды не пости́же. Чесо́ ра́ди? Зане́ не от ве́ры, но от дел зако́на, преткну́шася бо о ка́мень претыка́ния. Я́коже есть пи́сано: се полага́ю в Сио́не ка́мень претыка́ния и ка́мень собла́зна, и всяк ве́руяй вонь не постыди́тся. ",
  ["текст_цс"] = "Бра́тїе, бг҃ъ є҆го́же хо́щетъ, ми́лꙋетъ: а҆ є҆го́же хо́щетъ, ѡ҆жесточа́етъ. рече́ши же мѝ ᲂу҆̀бо: чесѡ̀ ра́ди ᲂу҆́бѡ ᲂу҆корѧ́етъ; во́ли бо є҆гѡ̀ кто̀ проти́витисѧ мо́жетъ; тѣ́мже ᲂу҆̀бо, ѽ человѣ́че! ты̀ кто̀ є҆сѝ, проти́въ ѿвѣща́ѧй бг҃ови; є҆да̀ рече́тъ зда́нїе созда́вшемꙋ є҆̀: почто́ мѧ сотвори́лъ є҆сѝ та́кѡ; и҆лѝ не и҆́мать вла́сти скꙋде́льникъ на бре́нїи, ѿ тогѡ́же смѣше́нїѧ сотвори́ти, ѻ҆́въ ᲂу҆́бѡ сосꙋ́дъ въ че́сть, ѻ҆́въ же не въ че́сть; а҆́ще ли же хотѧ̀ бг҃ъ показа́ти гнѣ́въ сво́й, и҆ ꙗ҆ви́ти си́лꙋ свою̀, пренесѐ во мно́зѣ долготерпѣ́нїи сосꙋ́ды гнѣ́ва соверше́ны въ поги́бель: и҆ да ска́жетъ бога́тство сла́вы своеѧ̀ на сосꙋ́дѣхъ ми́лости, ꙗ҆̀же пред̾ꙋгото́ва въ сла́вꙋ: и҆̀хже и҆ призва̀ на́съ, не то́чїю ѿ і҆ꙋдє́й, но и҆ ѿ ꙗ҆зы̑къ. ꙗ҆́коже и҆ во і҆ѡсі́и глаго́летъ: нарекꙋ̀ не лю́ди моѧ̀ лю́ди моѧ̀, и҆ невозлю́бленꙋю возлю́бленꙋ. и҆ бꙋ́детъ на мѣ́стѣ, и҆дѣ́же рече́сѧ и҆̀мъ: не лю́дїе моѝ є҆стѐ вы̀, та́мѡ нарекꙋ́тсѧ сы́нове бг҃а жива́гѡ. и҆са́їа же вопїе́тъ ѡ҆ і҆и҃ли: а҆́ще бꙋ́детъ число̀ сынѡ́въ і҆и҃левыхъ, ꙗ҆́кѡ песо́къ морскі́й, ѡ҆ста́нокъ спасе́тсѧ. сло́во бо скончава́ѧ и҆ сокраща́ѧ въ пра́вдѣ, ꙗ҆́кѡ сло́во сокраще́но сотвори́тъ гдⷭ҇ь на землѝ. и҆ ꙗ҆́коже проречѐ и҆са́їа: а҆́ще не бы̀ гдⷭ҇ь саваѡ́ѳъ ѡ҆ста́вилъ на́мъ сѣ́мене, ꙗ҆́коже содо́мъ ᲂу҆́бѡ бы́ли бы́хомъ, и҆ ꙗ҆́коже гомо́ррꙋ ᲂу҆подо́билисѧ бы́хомъ. что̀ ᲂу҆̀бо рече́мъ; ꙗ҆́кѡ ꙗ҆зы́цы не гонѧ́щїи пра́вдꙋ, постиго́ша пра́вдꙋ: пра́вдꙋ же, ꙗ҆́же ѿ вѣ́ры. і҆и҃ль же гонѧ̀ зако́нъ пра́вды, въ зако́нъ пра́вды не пости́же. чесѡ̀ ра́ди; занѐ не ѿ вѣ́ры, но ѿ дѣ́лъ зако́на: преткнꙋ́шасѧ бо ѡ҆ ка́мень претыка́нїѧ. ꙗ҆́коже є҆́сть пи́сано: сѐ полага́ю въ сїѡ́нѣ ка́мень претыка́нїѧ, и҆ ка́мень собла́зна: и҆ всѧ́къ вѣ́рꙋѧй во́нь, не постыди́тсѧ. ",
}

add_apostol {
  ["номер"] = 103,
  ["комментарий"] = "Рим., 103 зач., X, 1–10.",
  ["текст_ру"] = "Бра́тие, благоволе́ние моего́ се́рдца и моли́тва, я́же к Бо́гу по Изра́или, есть во спасе́ние. Свиде́тельствую бо им, я́ко ре́вность Бо́жию и́мут, но не по ра́зуму. Не разуме́юще бо Бо́жия пра́вды и свою́ пра́вду и́щуще поста́вити, пра́вде Бо́жией не повину́шася. Кончи́на бо зако́на Христо́с, в пра́вду вся́кому ве́рующему. Моисе́й бо пи́шет пра́вду ю́же от зако́на, я́ко сотвори́вый та челове́к жив бу́дет в них. А я́же от ве́ры пра́вда си́це глаго́лет: да не рече́ши в се́рдцы твое́м, кто взы́дет на не́бо, си́речь Христа́ свести́. Или́ кто сни́дет в бе́здну, си́речь Христа́ от ме́ртвых возвести́. Но что глаго́лет Писа́ние? Близ ти глаго́л есть, во усте́х твои́х и в се́рдце твое́м, си́речь глаго́л ве́ры, его́же пропове́даем. Я́ко а́ще испове́си усты́ твои́ми Го́спода Иису́са, и ве́руеши в се́рдце твое́м, я́ко Бог Того́ воздви́же из ме́ртвых, спасе́шися. Се́рдцем бо ве́руется в пра́вду, усты́ же испове́дуется во спасе́ние. ",
  ["текст_цс"] = "Бра́тїе, благоволе́нїе моегѡ̀ се́рдца, и҆ моли́тва ꙗ҆́же къ бг҃ꙋ, по і҆и҃ли є҆́сть во спасе́нїе. свидѣ́тельствꙋю бо и҆̀мъ, ꙗ҆́кѡ ре́вность бж҃їю и҆́мꙋтъ, но не по ра́зꙋмꙋ. не разꙋмѣ́юще бо бж҃їѧ пра́вды, и҆ свою̀ пра́вдꙋ и҆́щꙋще поста́вити, пра́вдѣ бж҃їей не повинꙋ́шасѧ. кончи́на бо зако́на хрⷭ҇то́съ, въ пра́вдꙋ всѧ́комꙋ вѣ́рꙋющемꙋ. мѡѷсе́й бо пи́шетъ пра́вдꙋ, ю҆́же ѿ зако́на: ꙗ҆́кѡ сотвори́вый та̑ чл҃вѣ́къ, жи́въ бꙋ́детъ въ ни́хъ. а҆ ꙗ҆́же ѿ вѣ́ры пра́вда, си́це глаго́летъ: да не рече́ши въ се́рдцы твое́мъ: кто̀ взы́детъ на нб҃о; си́рѣчь хрⷭ҇та̀ свестѝ. и҆лѝ кто̀ сни́детъ въ бе́зднꙋ; си́рѣчь хрⷭ҇та̀ ѿ ме́ртвыхъ возвестѝ. но что̀ глаго́летъ писа́нїе; бли́зъ тѝ глаго́лъ є҆́сть во ᲂу҆стѣ́хъ твои́хъ, и҆ въ се́рдцѣ твое́мъ: си́рѣчь, глаго́лъ вѣ́ры, є҆го́же проповѣ́даемъ. ꙗ҆́кѡ а҆́ще и҆сповѣ́си ᲂу҆сты̀ твои́ми гдⷭ҇а і҆и҃са, и҆ вѣ́рꙋеши въ се́рдцѣ твое́мъ, ꙗ҆́кѡ бг҃ъ того̀ воздви́же и҆з̾ ме́ртвыхъ, спасе́шисѧ. се́рдцемъ бо вѣ́рꙋетсѧ въ пра́вдꙋ: ᲂу҆сты́ же и҆сповѣ́дꙋетсѧ во спасе́нїе. ",
}

add_apostol {
  ["номер"] = 104,
  ["комментарий"] = "Рим., 104 зач., X, 11 – XI, 2.",
  ["текст_ру"] = "Бра́тие, глаго́лет Писа́ние: всяк ве́руяй вонь не постыди́тся. Несть бо ра́знствия иуде́еви же и е́ллину: Той бо Бог всех, богатя́й во всех призыва́ющих Его́. Всяк бо, и́же а́ще призове́т и́мя Госпо́дне, спасе́тся. Ка́ко у́бо призову́т, в Него́же не ве́роваша? Ка́ко же уве́руют, Его́же не услы́шаша? Ка́ко же услы́шат без пропове́дающаго? Ка́ко же пропове́дят, а́ще не по́слани бу́дут? Я́коже есть пи́сано: коль красны́ но́ги благовеству́ющих мир, благовеству́ющих блага́я. Но не вси послу́шаша благовествова́ния. Иса́иа бо глаго́лет: Го́споди, кто ве́рова слу́ху на́шему? Те́мже у́бо ве́ра от слу́ха, слух же глаго́лом Бо́жиим. Но глаго́лю: еда́ не слы́шаша, те́мже у́бо, во всю зе́млю изы́де веща́ние их, и в концы́ вселе́нныя глаго́лы их. Но глаго́лю: еда́ не разуме́ Изра́иль? Пе́рвый Моисе́й глаго́лет: Аз раздражу́ вы не о язы́це, но о язы́це неразу́мне прогне́ваю вас. Иса́иа же дерза́ет и глаго́лет: обрето́хся не и́щущым Мене́, явле́н бых не вопроша́ющым о Мне. Ко Изра́илю же глаго́лет: весь день возде́х ру́це Мои́ к лю́дем непокори́вым и пререка́ющым. Глаго́лю у́бо: еда́ отри́ну Бог лю́ди Своя́? Да не бу́дет. И́бо и аз Изра́ильтянин есмь, от се́мене Авраа́мля, коле́на Вениами́нова. Не отри́ну Бог люде́й Свои́х, и́хже пре́жде разуме́. ",
  ["текст_цс"] = "Бра́тїе, глаго́летъ писа́нїе: всѧ́къ вѣ́рꙋѧй во́нь, не постыди́тсѧ. нѣ́сть бо ра́знствїѧ і҆ꙋде́еви же и҆ є҆́ллинꙋ: то́й бо бг҃ъ всѣ́хъ, богатѧ́й во всѣ́хъ призыва́ющихъ є҆го̀. всѧ́къ бо, и҆́же а҆́ще призове́тъ и҆́мѧ гдⷭ҇не, спасе́тсѧ. ка́кѡ ᲂу҆̀бо призовꙋ́тъ, въ него́же не вѣ́роваша; ка́кѡ же ᲂу҆вѣ́рꙋютъ, є҆гѡ́же не ᲂу҆слы́шаша; ка́кѡ же ᲂу҆слы́шатъ, без̾ проповѣ́дающагѡ; ка́кѡ же проповѣ́дѧтъ, а҆́ще не по́слани бꙋ́дꙋтъ; ꙗ҆́коже є҆́сть пи́сано: ко́ль красны̀ но́ги благовѣствꙋ́ющихъ ми́ръ, благовѣствꙋ́ющихъ бл҃га̑ѧ. но не всѝ послꙋ́шаша бл҃говѣствова́нїѧ: и҆са́їа бо глаго́летъ: гдⷭ҇и, кто̀ вѣ́рова слꙋ́хꙋ на́шемꙋ; тѣ́мже ᲂу҆́бѡ вѣ́ра ѿ слꙋ́ха: слꙋ́хъ же глаго́ломъ бж҃їимъ. но глаго́лю, є҆да̀ не слы́шаша; тѣ́мже ᲂу҆́бѡ во всю̀ зе́млю и҆зы́де вѣща́нїе и҆́хъ, и҆ въ концы̀ вселе́нныѧ глаго́лы и҆́хъ. но глаго́лю, є҆да̀ не разꙋмѣ̀ і҆и҃ль; пе́рвый мѡѷсе́й глаго́летъ: а҆́зъ раздражꙋ̀ вы̀ не ѡ҆ ꙗ҆зы́цѣ, но ѡ҆ ꙗ҆зы́цѣ неразꙋ́мнѣ прогнѣ́ваю ва́съ. и҆са́їа же дерза́етъ и҆ глаго́летъ: ѡ҆брѣто́хсѧ не и҆́щꙋщымъ менѐ, ꙗ҆вле́нъ бы́хъ не вопроша́ющымъ ѡ҆ мнѣ̀. ко і҆и҃лю же глаго́летъ: ве́сь де́нь воздѣ́хъ рꙋ́цѣ моѝ къ лю́демъ непокори́вымъ и҆ прерѣка́ющымъ. глаго́лю ᲂу҆̀бо: є҆да̀ ѿри́нꙋ бг҃ъ лю́ди своѧ̀; да не бꙋ́детъ: и҆́бо и҆ а҆́зъ і҆и҃льтѧнинъ є҆́смь, ѿ сѣ́мене а҆враа́млѧ, колѣ́на венїамі́нова. не ѿри́нꙋ бг҃ъ люде́й свои́хъ, и҆̀хже пре́жде разꙋмѣ̀. ",
}

add_apostol {
  ["номер"] = 105,
  ["комментарий"] = "Рим., 105 зач., XI, 2–12.",
  ["текст_ру"] = "Бра́тие, не ве́сте ли о Илии́, что глаго́лет Писа́ние, я́ко припове́дует Бо́гови на Изра́иля, глаго́ля: Го́споди, проро́ки Твоя́ изби́ша и олтари́ Твоя́ раскопа́ша, и аз оста́х еди́н, и и́щут ду́шу мою́ изъя́ти. Но что глаго́лет ему́ Боже́ственный отве́т? Оста́вих Себе́ седмь ты́сящ муже́й, и́же не преклони́ша коле́на пред Ваа́лом. Та́ко у́бо и в ны́нешнее вре́мя оста́нок по избра́нию благода́ти бысть. А́ще ли по благода́ти, то не от дел, зане́ благода́ть уже́ не быва́ет благода́ть. А́ще ли от дел, ктому́ несть благода́ть, зане́ бо де́ло уже́ несть де́ло. Что у́бо? Его́же иска́ше Изра́иль, сего́ не получи́, а избра́ние получи́. Про́чии же ослепи́шася, я́коже есть пи́сано: даде́ им Бог дух умиле́ния, о́чи не ви́дети и у́ши не слы́шати, да́же до дне́шняго дне. И Дави́д глаго́лет: да бу́дет трапе́за их в сеть и в лов, и в собла́зн и в воздая́ние им. Да помрача́тся о́чи их е́же не ви́дети, и хребе́т их вы́ну сляца́й. Глаго́лю у́бо: еда́ согреши́ша, да отпаду́т? Да не бу́дет. Но тех паде́нием спасе́ние язы́ком, во е́же раздражи́ти их. А́ще ли же прегреше́ние их бога́тство ми́ру, и отпаде́ние их бога́тство язы́ком, кольми́ па́че исполне́ние их? ",
  ["текст_цс"] = "Бра́тїе, не вѣ́сте ли ѡ҆ и҆лїѝ, что̀ глаго́летъ писа́нїе; ꙗ҆́кѡ приповѣ́дꙋетъ бг҃ови на і҆и҃лѧ, глаго́лѧ: гдⷭ҇и, проро́ки твоѧ̀ и҆зби́ша, и҆ ѻ҆лтарѝ твоѧ̀ раскопа́ша: и҆ а҆́зъ ѡ҆ста́хъ є҆ди́нъ, и҆ и҆́щꙋтъ дꙋ́шꙋ мою̀ [и҆з̾ѧ́ти]. но что̀ глаго́летъ є҆мꙋ̀ бж҃е́ственный ѿвѣ́тъ; ѡ҆ста́вихъ себѣ̀ се́дмь ты́сѧщъ мꙋже́й, и҆̀же не преклони́ша колѣ̑на пред̾ ваа́ломъ. та́кѡ ᲂу҆̀бо и҆ въ ны́нѣшнее вре́мѧ, ѡ҆ста́нокъ по и҆збра́нїю благода́ти бы́сть. а҆́ще ли по бл҃года́ти, то не ѿ дѣ́лъ: занѐ бл҃года́ть, ᲂу҆жѐ не быва́етъ благода́ть. а҆́ще ли ѿ дѣ́лъ, ктомꙋ̀ нѣ́сть благода́ть: зане́ бо дѣ́ло, ᲂу҆жѐ нѣ́сть дѣ́ло. что̀ ᲂу҆̀бо; є҆гѡ́же и҆ска́ше і҆и҃ль, сегѡ̀ не полꙋчѝ, а҆ и҆збра́нїе полꙋчѝ: про́чїи же ѡ҆слѣпи́шасѧ. ꙗ҆́коже є҆́сть пи́сано: дадѐ и҆̀мъ бг҃ъ дꙋ́хъ ᲂу҆миле́нїѧ, ѻ҆́чи не ви́дѣти, и҆ ᲂу҆́ши не слы́шати, да́же до дне́шнѧгѡ днѐ. и҆ дв҃дъ глаго́летъ: да бꙋ́детъ трапе́за и҆́хъ въ сѣ́ть и҆ въ ло́въ и҆ въ собла́знъ, и҆ въ воздаѧ́нїе и҆̀мъ. да помрача́тсѧ ѻ҆́чи и҆́хъ є҆́же не ви́дѣти, и҆ хребе́тъ и҆́хъ вы́нꙋ слѧца́й. глаго́лю ᲂу҆̀бо, є҆да̀ согрѣши́ша, да ѿпадꙋ́тъ; да не бꙋ́детъ: но тѣ́хъ паде́нїемъ, спасе́нїе ꙗ҆зы́кѡмъ, во є҆́же раздражи́ти и҆̀хъ. а҆́ще ли же прегрѣше́нїе и҆́хъ бога́тство мі́рꙋ, и҆ ѿпаде́нїе и҆́хъ бога́тство ꙗ҆зы́кѡмъ: кольмѝ па́че и҆сполне́нїе и҆́хъ; ",
}

add_apostol {
  ["номер"] = 106,
  ["комментарий"] = "Рим., 106 зач., XI, 13–24.",
  ["текст_ру"] = "Бра́тие, вам глаго́лю язы́ком, поне́же у́бо есмь аз язы́ком Апо́стол, слу́жбу мою́ прославля́ю. А́ще ка́ко раздражу́ мою́ плоть, и спасу́ не́кия от них? А́ще бо отложе́ние их, примире́ние ми́ру, что прия́тие, ра́зве жизнь из ме́ртвых? А́ще ли нача́ток свят, то и примеше́ние, и а́ще ко́рень свят, то и ве́тви. А́ще ли не́цыи от ве́твей отломи́шася, ты же, ди́вия ма́слина сый, прицепи́лся еси́ в них, и прича́стник ко́рене и ма́сти ма́слинныя был еси́. Не хвали́ся на ве́тви, а́ще ли же хва́лишися, не ты ко́рень но́сиши, но ко́рень тебе́. Рече́ши у́бо: отломи́шася ве́тви, да аз прицеплю́ся. До́бре, неве́рием отломи́шася, ты же ве́рою стои́ши. Не высокому́дрствуй, но бо́йся. А́ще бо Бог есте́ственных ве́твей не пощаде́, да не ка́ко и тебе́ не пощади́т. Виждь у́бо бла́гость и непощаде́ние Бо́жие: на отпа́дших у́бо непощаде́ние, а на тебе́ бла́гость Бо́жия, а́ще пребу́деши в бла́гости, а́ще ли же ни, то и ты отсе́чен бу́деши. И они́ же, а́ще не пребу́дут в неве́рствии, прицепя́тся, си́лен бо есть Бог па́ки прицепи́ти их. А́ще бо ты от есте́ственныя отсе́чен ди́вия ма́слины, и чрез естество́ прицепи́лся еси́ к до́брей ма́слине, кольми́ па́че си́и, и́же по естеству́, прицепя́тся свое́й ма́слине? ",
  ["текст_цс"] = "Бра́тїе, ва́мъ глаго́лю ꙗ҆зы́кѡмъ, поне́же ᲂу҆̀бо є҆́смь а҆́зъ ꙗ҆зы́кѡмъ а҆пⷭ҇лъ, слꙋ́жбꙋ мою̀ прославлѧ́ю: а҆́ще ка́кѡ раздражꙋ̀ мою̀ пло́ть, и҆ спасꙋ̀ нѣ̑кїѧ ѿ ни́хъ. а҆́ще бо ѿложе́нїе и҆́хъ, примире́нїе мі́рꙋ: что̀ прїѧ́тїе, ра́звѣ жи́знь и҆з̾ ме́ртвыхъ; а҆́ще ли нача́токъ ст҃ъ, то и҆ примѣше́нїе: и҆ а҆́ще ко́рень ст҃ъ, то и҆ вѣ̑тви. а҆́ще ли нѣ́цыи ѿ вѣ́твей ѿломи́шасѧ, ты́ же ди́вїѧ ма́слина сы́й, прицѣпи́лсѧ є҆сѝ въ ни́хъ, и҆ прича́стникъ ко́рене и҆ ма́сти ма́слинныѧ бы́лъ є҆сѝ. не хвали́сѧ на вѣ̑тви. а҆́ще ли же хва́лишисѧ, не ты̀ ко́рень но́сиши, но ко́рень тебѐ. рече́ши ᲂу҆́бѡ: ѿломи́шасѧ вѣ́тви, да а҆́зъ прицѣплю́сѧ. до́брѣ: невѣ́рїемъ ѿломи́шасѧ, ты́ же вѣ́рою стои́ши. не высокомꙋ́дрствꙋй, но бо́йсѧ. а҆́ще бо бг҃ъ є҆сте́ственныхъ вѣ́твей не пощадѣ̀: да не ка́кѡ и҆ тебѐ не пощади́тъ. ви́ждь ᲂу҆̀бо бл҃гость и҆ непощадѣ́нїе бж҃їе: на ѿпа́дшихъ ᲂу҆́бѡ непощадѣ́нїе, а҆ на тебѣ̀ бл҃гость бж҃їѧ, а҆́ще пребꙋ́деши въ бл҃гости: а҆́ще ли же нѝ, то и҆ ты̀ ѿсѣ́ченъ бꙋ́деши. и҆ ѻ҆ни́ же, а҆́ще не пребꙋ́дꙋтъ въ невѣ́рствїи, прицѣпѧ́тсѧ: си́ленъ бо є҆́сть бг҃ъ па́ки прицѣпи́ти и҆̀хъ. а҆́ще бо ты̀ ѿ є҆сте́ственныѧ ѿсѣ́ченъ ди́вїѧ ма́слины, и҆ чрез̾ є҆стество̀ прицѣпи́лсѧ є҆сѝ къ до́брѣй ма́слинѣ: кольмѝ па́че сі́и, и҆̀же по є҆стествꙋ̀, прицѣпѧ́тсѧ свое́й ма́слинѣ. ",
}

add_apostol {
  ["номер"] = 107,
  ["комментарий"] = "Рим., 107 зач., XI, 25–36.",
  ["текст_ру"] = "Бра́тие, не хощу́ вас не ве́дети та́йны сея́, да не бу́дете о себе́ му́дри, я́ко ослепле́ние от ча́сти Изра́илеви бысть, до́ндеже исполне́ние язы́ков вни́дет, и та́ко весь Изра́иль спасе́тся, я́коже есть пи́сано: прии́дет от Сио́на Избавля́яй, и отврати́т нече́стие от Иа́кова. И сей им от Мене́ заве́т, егда́ отиму́ грехи́ их. По благовествова́нию у́бо, врази́ вас ра́ди, по избра́нию же, возлю́блени оте́ц ра́ди. Нераска́янна бо дарова́ния и зва́ние Бо́жие. Я́коже бо и вы иногда́ проти́вистеся Бо́гови, ны́не же поми́ловани бы́сте сих противле́нием. Та́кожде и си́и ны́не проти́вишася ва́шей ми́лости, да и ти́и поми́ловани бу́дут. Затвори́ бо Бог всех в противле́ние, да всех поми́лует. О, глубина́ бога́тства и прему́дрости и ра́зума Бо́жия! Я́ко неиспы́тани су́дове Его́, и неизсле́довани путие́ Его́. Кто бо разуме́ ум Госпо́день, или́ кто сове́тник Ему́ бысть? Или́ кто пре́жде даде́ Ему́, и возда́стся Ему́, я́ко из Того́ и Тем и в Нем вся́ческая. Тому́ сла́ва во ве́ки. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, не хощꙋ̀ ва́съ не вѣ́дѣти та́йны сеѧ̀ [да не бꙋ́дете ѡ҆ себѣ̀ мꙋ́дри,] ꙗ҆́кѡ ѡ҆слѣпле́нїе ѿ ча́сти і҆и҃леви бы́сть, до́ндеже и҆сполне́нїе ꙗ҆зы́кѡвъ вни́детъ. и҆ та́кѡ ве́сь і҆и҃ль спасе́тсѧ, ꙗ҆́коже є҆́сть пи́сано: прїи́детъ ѿ сїѡ́на и҆збавлѧ́ѧй, и҆ ѿврати́тъ нече́стїе ѿ і҆а́кѡва. и҆ се́й и҆̀мъ ѿ менѐ завѣ́тъ, є҆гда̀ ѿимꙋ̀ грѣхѝ и҆́хъ. по благовѣствова́нїю ᲂу҆́бѡ, вразѝ ва́съ ра́ди: по и҆збра́нїю же, возлю́блени ѻ҆ц҃ъ ра́ди. нераска́ѧнна бо дарова̑нїѧ, и҆ зва́нїе бж҃їе. ꙗ҆́коже бо и҆ вы̀ и҆ногда̀ проти́вистесѧ бг҃ови, ны́нѣ же поми́ловани бы́сте си́хъ противле́нїемъ. та́кожде и҆ сі́и ны́нѣ проти́вишасѧ ва́шей ми́лости, да и҆ ті́и поми́ловани бꙋ́дꙋтъ. затвори́ бо бг҃ъ всѣ́хъ въ противле́нїе, да всѣ́хъ поми́лꙋетъ. ѽ глꙋбина̀ бога́тства, и҆ премꙋ́дрости, и҆ ра́зꙋма бж҃їѧ! ꙗ҆́кѡ неиспы́тани сꙋ́дове є҆гѡ̀, и҆ неизслѣ́довани пꙋтїѐ є҆гѡ̀. кто́ бо разꙋмѣ̀ ᲂу҆́мъ гдⷭ҇нь; и҆лѝ кто̀ совѣ́тникъ є҆мꙋ̀ бы́сть; и҆лѝ кто̀ пре́жде дадѐ є҆мꙋ̀, и҆ возда́стсѧ є҆мꙋ̀; ꙗ҆́кѡ и҆з̾ тогѡ̀, и҆ тѣ́мъ, и҆ въ не́мъ всѧ́чєскаѧ: томꙋ̀ сла́ва во вѣ́ки, а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 108,
  ["комментарий"] = "Рим., 108 зач., XII, 1–3.",
  ["текст_ру"] = "Бра́тие, молю́ вас щедро́тами Бо́жиими, предста́вите телеса́ ва́ша же́ртву жи́ву, свя́ту, благоуго́дну Бо́гови, слове́сное служе́ние ва́ше, и не сообразу́йтеся ве́ку сему́, но преобразу́йтеся обновле́нием ума́ ва́шего, во е́же искуша́ти вам, что есть во́ля Бо́жия, блага́я и уго́дная, и соверше́нная. Глаго́лю бо благода́тию да́вшеюся мне, вся́кому су́щему в вас не му́дрствовати па́че, е́же подоба́ет му́дрствовати, но му́дрствовати в целому́дрии, коему́ждо я́коже Бог раздели́л есть ме́ру ве́ры. ",
  ["текст_цс"] = "Бра́тїе, молю̀ ва́съ щедро́тами бж҃їими, предста́вите тѣлеса̀ ва́ша же́ртвꙋ жи́вꙋ, ст҃ꙋ, благоꙋго́днꙋ бг҃ови, слове́сное слꙋже́нїе ва́ше: и҆ не соѡбразꙋ́йтесѧ вѣ́кꙋ семꙋ̀, но преѡбразꙋ́йтесѧ ѡ҆бновле́нїемъ ᲂу҆ма̀ ва́шегѡ, во є҆́же и҆скꙋша́ти ва́мъ, что́ є҆сть во́лѧ бж҃їѧ, бл҃га́ѧ, и҆ ᲂу҆го́днаѧ, и҆ соверше́ннаѧ; глаго́лю ᲂу҆́бѡ бл҃года́тїю да́вшеюсѧ мнѣ̀, всѧ́комꙋ сꙋ́щемꙋ въ ва́съ, не мꙋ́дрствовати па́че, є҆́же подоба́етъ мꙋ́дрствовати: но мꙋ́дрствовати въ цѣломꙋ́дрїи, коемꙋ́ждо ꙗ҆́коже бг҃ъ раздѣли́лъ є҆́сть мѣ́рꙋ вѣ́ры. ",
}

add_apostol {
  ["номер"] = 109,
  ["комментарий"] = "Рим., 109 зач., XII, 4–5, 15–21.",
  ["текст_ру"] = "Бра́тие, я́коже во еди́ном телеси́ мно́ги у́ды и́мамы, у́ды же вси не то́жде и́мут де́лание, та́кожде мно́зи еди́но те́ло есмы́ о Христе́, а по еди́ному друг дру́гу у́ди. Ра́доватися с ра́дующимися, и пла́кати с пла́чущими. То́жде друг ко дру́гу му́дрствующе. Не высо́кая му́дрствующе, но смире́нными веду́щеся, не быва́йте му́дри о себе́. Ни еди́ному же зла за зло воздаю́ще, промышля́юще до́брая пред все́ми челове́ки. А́ще возмо́жно, е́же от вас, со все́ми челове́ки мир име́йте. Не себе́ отмща́юще, возлю́блении, но дади́те ме́сто гне́ву. Пи́сано бо есть: Мне отмще́ние, Аз возда́м, глаго́лет Госпо́дь. А́ще у́бо а́лчет враг твой, ухле́би его́, а́ще ли жа́ждет, напо́й его́. Сие́ бо творя́, у́глие о́гнено собира́еши на главу́ его́. Не побежде́н быва́й от зла, но побежда́й благи́м зло́е. ",
  ["текст_цс"] = "Бра́тїе, ꙗ҆́коже во є҆ди́номъ тѣлесѝ, мно́ги ᲂу҆́ды и҆́мамы, ᲂу҆́ды же всѝ не то́жде и҆́мꙋтъ дѣ́ланїе: та́кожде мно́зи є҆ди́но тѣ́ло є҆смы̀ ѡ҆ хрⷭ҇тѣ̀, а҆ по є҆ди́номꙋ дрꙋгъдрꙋ́гꙋ ᲂу҆́ди. ра́доватисѧ съ ра́дꙋющимисѧ, и҆ пла́кати съ пла́чꙋщими. то́жде дрꙋ́гъ ко дрꙋ́гꙋ мꙋ́дрствꙋюще, не высѡ́каѧ мꙋ́дрствꙋюще, но смире́нными ведꙋ́щесѧ, не быва́йте мꙋ́дри ѡ҆ себѣ̀. ни є҆ди́номꙋ же ѕла̀ за ѕло̀ воздаю́ще, промышлѧ́юще дѡ́браѧ пред̾ всѣ́ми чл҃вѣ́ки. а҆́ще возмо́жно, є҆́же ѿ ва́съ, со всѣ́ми человѣ́ки ми́ръ и҆мѣ́йте. не себѐ ѿмща́юще возлю́бленнїи, но дади́те мѣ́сто гнѣ́вꙋ: пи́сано бо є҆́сть: мнѣ̀ ѿмще́нїе, а҆́зъ возда́мъ, глаго́летъ гдⷭ҇ь. а҆́ще ᲂу҆̀бо а҆́лчетъ вра́гъ тво́й, ᲂу҆хлѣ́би є҆го̀: а҆́ще ли жа́ждетъ, напо́й є҆го̀. сїе́ бо творѧ̀, ᲂу҆́глїе ѻ҆́гнено собира́еши на главꙋ̀ є҆гѡ̀. не побѣжде́нъ быва́й ѿ ѕла̀, но побѣжда́й благи́мъ ѕло́е. ",
}

add_apostol {
  ["номер"] = 110,
  ["комментарий"] = "Рим., 110 зач., XII, 6–14.",
  ["текст_ру"] = "Бра́тие, иму́ще дарова́ния по благода́ти да́нней нам разли́чна, а́ще проро́чество, по ме́ре ве́ры, а́ще ли служе́ние, в служе́нии, а́ще учя́й, во уче́нии, а́ще утеша́яй, во утеше́нии, подава́яй, в простоте́, предстоя́й, со тща́нием, ми́луяй, с до́брым изволе́нием. Любы́ нелицеме́рна, ненави́дящи зло́е, прилепля́ющися благо́му. Братолю́бием друг ко дру́гу любе́зни, че́стию друг дру́га бо́льша творя́ще. Тща́нием не лени́ви, ду́хом горя́ще, Го́сподеви рабо́тающе. Упова́нием ра́дующеся, ско́рби терпя́ще, в моли́тве пребыва́юще. Тре́бованием святы́х приобща́ющеся, страннолю́бия держа́щеся. Благословля́йте гоня́щыя вы, благослови́те, а не клени́те. ",
  ["текст_цс"] = "Бра́тїе, и҆мꙋ́ще дарова̑нїѧ по бл҃года́ти да́ннѣй на́мъ разли́чна: а҆́ще проро́чество, по мѣ́рѣ вѣ́ры: а҆́ще ли слꙋже́нїе, въ слꙋже́нїи: а҆́ще ᲂу҆чѧ́й, во ᲂу҆че́нїи: а҆́ще ᲂу҆тѣша́ѧй, во ᲂу҆тѣше́нїи: подава́ѧй, въ простотѣ̀: предстоѧ́й, со тща́нїемъ: ми́лꙋѧй, съ до́брымъ и҆зволе́нїемъ. любы̀ нелицемѣ́рна, ненави́дѧщи ѕло́е, прилѣплѧ́ющисѧ бл҃го́мꙋ. братолю́бїемъ дрꙋ́гъ ко дрꙋ́гꙋ любе́зни, че́стїю дрꙋгъдрꙋ́га бо́льша творѧ́ще. тща́нїемъ не лѣни́ви, дх҃омъ горѧ́ще, гдⷭ҇ви рабо́тающе. ᲂу҆пова́нїемъ ра́дꙋющесѧ, скѡ́рби терпѧ́ще, въ мл҃твѣ пребыва́юще. тре́бованїємъ ст҃ы́хъ прїѡбща́ющесѧ, страннолю́бїѧ держа́щесѧ. бл҃гословлѧ́йте гонѧ́щыѧ вы̀: блгⷭ҇ви́те, а҆ не клени́те. ",
}

add_apostol {
  ["номер"] = 111,
  ["комментарий"] = "Рим., 111 зач., XIII, 1–10.",
  ["текст_ру"] = "Бра́тие, вся́ка душа́ власте́м предержа́щым да повину́ется, несть бо власть а́ще не от Бо́га, су́щыя же вла́сти от Бо́га учинены́ суть. Те́мже противля́яйся вла́сти, Бо́жию повеле́нию противля́ется, противля́ющиися же себе́ грех прие́млют. Кня́зи бо не суть боя́знь до́брым дело́м, но злым. Хо́щеши же ли не боя́тися вла́сти? Благо́е твори́, и име́ти бу́деши похвалу́ от него́. Бо́жий бо слуга́ есть, тебе́ во благо́е. А́ще ли зло́е твори́ши, бо́йся, не бо без ума́ мечь но́сит, Бо́жий бо слуга́ есть, отмсти́тель в гнев зло́е творя́щему. Те́мже потре́ба повинова́тися не то́кмо за гнев, но и за со́весть. Сего́ бо ра́ди и да́ни даете́, служи́тели бо Бо́жии суть, во и́стое сие́ пребыва́юще. Воздади́те у́бо всем до́лжная: ему́же у́бо уро́к, уро́к, а ему́же дань, дань, а ему́же страх, страх, и ему́же честь, честь. Ни еди́ному же ничи́мже до́лжни быва́йте, то́чию е́же люби́ти друг дру́га: любя́й бо дру́га, зако́н испо́лни. Е́же бо, не прелюбы́ сотвори́ши, не убие́ши, не укра́деши, не лжесвиде́тельствуеши, не похо́щеши, и а́ще ка́я и́на за́поведь, в сем словеси́ соверша́ется, во е́же возлю́биши и́скренняго твоего́, я́коже сам себе́. Любы́ и́скреннему зла не твори́т. Исполне́ние у́бо зако́на любы́ есть. ",
  ["текст_цс"] = "Бра́тїе, всѧ́ка дꙋша̀ власте́мъ предержа́щымъ да повинꙋ́етсѧ. нѣ́сть бо вла́сть а҆́ще не ѿ бг҃а: сꙋ́щыѧ же вла̑сти ѿ бг҃а ᲂу҆чинены̀ сꙋ́ть. тѣ́мже противлѧ́ѧйсѧ вла́сти, бж҃їю повелѣ́нїю противлѧ́етсѧ: противлѧ́ющїисѧ же, себѣ̀ грѣ́хъ прїе́млютъ. кнѧ́зи бо не сꙋ́ть боѧ́знь дѡ́брымъ дѣлѡ́мъ, но ѕлы̑мъ. хо́щеши же ли не боѧ́тисѧ вла́сти; бл҃го́е творѝ, и҆ и҆мѣ́ти бꙋ́деши похвалꙋ̀ ѿ негѡ̀. бж҃їй бо слꙋга̀ є҆́сть, тебѣ̀ во благо́е. а҆́ще ли ѕло́е твори́ши, бо́йсѧ: не бо без̾ ᲂу҆ма̀ ме́чь но́ситъ: бж҃їй бо слꙋга̀ є҆́сть, ѿмсти́тель въ гнѣ́въ ѕло́е творѧ́щемꙋ. тѣ́мже потре́ба повинова́тисѧ не то́кмѡ за гнѣ́въ, но и҆ за со́вѣсть. сегѡ́ бо ра́ди и҆ да̑ни даетѐ: слꙋжи́тели бо бж҃їи сꙋ́ть во и҆́стое сїѐ пребыва́юще. воздади́те ᲂу҆̀бо всѣ̑мъ дѡ́лжнаѧ: є҆мꙋ́же ᲂу҆́бѡ ᲂу҆ро́къ, ᲂу҆ро́къ: а҆ є҆мꙋ́же да́нь, да́нь: а҆ є҆мꙋ́же стра́хъ, стра́хъ: и҆ є҆мꙋ́же че́сть, че́сть. ни є҆ди́номꙋ же ничи́мже до́лжни быва́йте, то́чїю є҆́же люби́ти дрꙋгъдрꙋ́га: любѧ́й бо дрꙋ́га, зако́нъ и҆спо́лни. є҆́же бо, не прелюбы̀ сотвори́ши, не ᲂу҆бїе́ши, не ᲂу҆кра́деши, не лжесвидѣ́тельствꙋеши, не похо́щеши: и҆ а҆́ще ка́ѧ и҆́на за́повѣдь, въ се́мъ словесѝ соверша́етсѧ: во є҆́же возлю́биши и҆́скреннѧго твоего̀ ꙗ҆́коже са́мъ себѐ. любы̀ и҆́скреннемꙋ ѕла̀ не твори́тъ: и҆сполне́нїе ᲂу҆̀бо зако́на любы̀ є҆́сть. ",
}

add_apostol {
  ["номер"] = 112,
  ["комментарий"] = "Рим., 112 зач., XIII, 11 – XIV, 4.",
  ["текст_ру"] = "Бра́тие, ны́не ближа́йшее нам спасе́ние, не́жели егда́ ве́ровахом. Нощь у́бо пре́йде, а день прибли́жися: отложи́м у́бо дела́ те́мная, и облече́мся во ору́жие све́та. Я́ко во дни, благообра́зно да хо́дим, не козлогласова́нии и пия́нствы, не любодея́нии и студодея́нии, не рве́нием и за́вистию, но облецы́теся Го́сподем на́шим Иису́с Христо́м, и пло́ти уго́дия не твори́те в по́хоти. Изнемога́ющаго же в ве́ре прие́млите, не в сомне́ние помышле́ний. Ов бо ве́рует я́сти вся, а изнемога́яй зе́лия да яст. Яды́й не яду́щаго да не укоря́ет, и не яды́й яду́щаго да не осужда́ет, Бог бо его́ прия́т. Ты кто еси́ судя́й чужде́му рабу́? Своему́ Го́сподеви стои́т, или́ па́дает, ста́нет же, си́лен бо есть Бог поста́вити его́. ",
  ["текст_цс"] = "Бра́тїе, ны́нѣ ближа́йшее на́мъ спасе́нїе, не́жели є҆гда̀ вѣ́ровахомъ. но́щь ᲂу҆́бѡ пре́йде, а҆ де́нь прибли́жисѧ: ѿложи́мъ ᲂу҆̀бо дѣла̀ тє́мнаѧ, и҆ ѡ҆блече́мсѧ во ѻ҆рꙋ́жїе свѣ́та. ꙗ҆́кѡ во днѝ бл҃гоѻбра́знѡ да хо́димъ, не козлогласова́нїи и҆ пїѧ́нствы, не любодѣѧ́нїи и҆ стꙋдодѣѧ́нїи, не рве́нїемъ и҆ за́вистїю: но ѡ҆блецы́тесѧ гдⷭ҇емъ на́шимъ і҆и҃съ хрⷭ҇то́мъ, и҆ пло́ти ᲂу҆го́дїѧ не твори́те въ по́хоти. и҆знемога́ющаго же въ вѣ́рѣ прїе́млите, не въ сомнѣ́нїе помышле́нїй. ѻ҆́въ бо вѣ́рꙋетъ ꙗ҆́сти всѧ̑, а҆ и҆знемога́ѧй ѕє́лїѧ да ꙗ҆́стъ. ꙗ҆ды́й не ꙗ҆дꙋ́щаго да не ᲂу҆корѧ́етъ: и҆ не ꙗ҆ды́й ꙗ҆дꙋ́щаго да не ѡ҆сꙋжда́етъ: бг҃ъ бо є҆го̀ прїѧ́тъ. ты̀ кто̀ є҆сѝ сꙋдѧ́й чꙋжде́мꙋ рабꙋ̀; своемꙋ̀ гдⷭ҇еви стои́тъ, и҆лѝ па́даетъ, ста́нетъ же: си́ленъ бо є҆́сть бг҃ъ поста́вити є҆го̀. ",
}

add_apostol {
