  ["комментарий"] = "Рим., 117 зач., XV, 7–16.",
  ["текст_ру"] = "Бра́тие, прие́млите друг дру́га, я́коже и Христо́с прия́т вас во сла́ву Бо́жию. Глаго́лю же Христа́ Иису́са служи́теля бы́вша обре́зания по и́стине Бо́жией, во е́же утверди́ти обетова́ния отце́в. А язы́ком по ми́лости, просла́вити Бо́га, я́коже есть пи́сано: сего́ ра́ди испове́мся Тебе́ во язы́цех, Го́споди, и и́мени Твоему́ пою́. И па́ки глаго́лет: возвесели́теся, язы́цы, с людьми́ Его́. И па́ки: хвали́те Го́спода, вси язы́цы, и похвали́те Его́, вси лю́дие. И па́ки Иса́иа глаго́лет: бу́дет ко́рень Иессе́ов, и востая́й владе́ти над язы́ки, на Того́ язы́цы упова́ют. Бог же упова́ния да испо́лнит вас вся́кия ра́дости и ми́ра в ве́ре, избы́точествовати вам во упова́нии, си́лою Ду́ха Свята́го. Извеще́н же есмь, бра́тие моя́, и сам аз о вас, я́ко и са́ми вы по́лни есте́ бла́гости, испо́лнени вся́каго ра́зума, могу́ще и ины́я научи́ти. Де́рзее же писа́х вам, бра́тие моя́, от ча́сти, я́ко воспомина́я вам, за благода́ть да́нную ми от Бо́га, во е́же бы́ти ми служи́телю Иису́с Христо́ву во язы́цех, священноде́йствующу благовествова́ние Бо́жие, да бу́дет приноше́ние е́же от язы́к благоприя́тно и освяще́нно Ду́хом Святы́м. ",
  ["текст_цс"] = "Бра́тїе, прїе́млите дрꙋгъдрꙋ́га, ꙗ҆́коже и҆ хрⷭ҇то́съ прїѧ́тъ ва́съ во сла́вꙋ бж҃їю. глаго́лю же, хрⷭ҇та̀ і҆и҃са слꙋжи́телѧ бы́вша ѡ҆брѣ́занїѧ по и҆́стинѣ бж҃їей, во є҆́же ᲂу҆тверди́ти ѡ҆бѣтова̑нїѧ ѻ҆ц҃є́въ: а҆ ꙗ҆зы́кѡмъ по ми́лости, просла́вити бг҃а, ꙗ҆́коже є҆́сть пи́сано: сегѡ̀ ра́ди и҆сповѣ́мсѧ тебѣ̀ во ꙗ҆зы́цѣхъ гдⷭ҇и, и҆ и҆́мени твоемꙋ̀ пою̀. и҆ па́ки глаго́летъ: возвесели́тесѧ ꙗ҆зы́цы съ людьмѝ є҆гѡ̀. и҆ па́ки: хвали́те гдⷭ҇а всѝ ꙗ҆зы́цы, и҆ похвали́те є҆го̀ всѝ лю́дїе. и҆ па́ки и҆са́їа глаго́летъ: бꙋ́детъ ко́рень і҆ессе́овъ, и҆ востаѧ́й владѣ́ти над̾ ꙗ҆зы́ки, на того̀ ꙗ҆зы́цы ᲂу҆пова́ютъ. бг҃ъ же ᲂу҆пова́нїѧ, да и҆спо́лнитъ ва́съ всѧ́кїѧ ра́дости и҆ ми́ра въ вѣ́рѣ, и҆збы́точествовати ва́мъ во ᲂу҆пова́нїи, си́лою дх҃а ст҃а́гѡ. и҆звѣще́нъ же є҆́смь бра́тїе моѧ̀, и҆ са́мъ а҆́зъ ѡ҆ ва́съ, ꙗ҆́кѡ и҆ са́ми вы̀ по́лни є҆стѐ бла́гости, и҆спо́лнени всѧ́кагѡ ра́зꙋма, могꙋ́ще и҆ и҆ны́ѧ наꙋчи́ти. де́рзѣе же писа́хъ ва́мъ бра́тїе моѧ̀, ѿ ча́сти, ꙗ҆́кѡ воспомина́ѧ ва́мъ, за благода́ть да́ннꙋю мѝ ѿ бг҃а: во є҆́же бы́ти мѝ слꙋжи́телю і҆и҃съ хрⷭ҇то́вꙋ во ꙗ҆зы́цѣхъ, свѧщеннодѣ́йствꙋющꙋ благовѣствова́нїе бж҃їе, да бꙋ́детъ приноше́нїе є҆́же ѿ ꙗ҆зы̑къ благопрїѧ́тно, и҆ ѡ҆свѧще́нно дх҃омъ ст҃ы́мъ. ",
}

add_apostol {
  ["номер"] = 118,
  ["комментарий"] = "Рим., 118 зач., XV, 17–29.",
  ["текст_ру"] = "Бра́тие, и́мам похвалу́ о Христе́ Иису́се, я́же к Бо́гу. Не сме́ю бо глаго́лати что, и́хже не соде́я Христо́с мно́ю, в послуша́ние язы́ков, сло́вом и де́лом, в си́ле зна́мений и чуде́с, си́лою Ду́ха Бо́жия, я́коже ми от Иерусали́ма и о́крест да́же до Иллири́ка испо́лнити благовествова́ние Христо́во. Си́це же потща́хся благовести́ти, не иде́же именова́ся Христо́с, да не на чуже́м основа́нии сози́жду, но я́коже есть пи́сано: и́мже не возвести́ся о Нем, у́зрят, и и́же не слы́шаша, уразуме́ют. Те́мже и возбране́н бых мно́гажды приити́ к вам. Ны́не же ктому́ ме́ста не имы́й в страна́х сих, жела́ние же имы́й приити́ к вам от мно́гих лет, я́ко а́ще поиду́ во Испа́нию, прииду́ к вам. Упова́ю бо ми́мо гряды́й ви́дети вас и ва́ми проводи́тися та́мо, а́ще вас пре́жде от ча́сти насы́щуся. Ны́не же гряду́ во Иерусали́м, служя́й святы́м, благоволи́ша бо Македо́ниа и Аха́иа обще́ние не́кое сотвори́ти к ни́щым святы́м живу́щым во Иерусали́ме. Благоволи́ша бо, и до́лжни им суть. А́ще бо в духо́вных их прича́стники бы́ша язы́цы, до́лжни суть и в плотски́х послужи́ти им. Сие́ у́бо сконча́в, и запечатле́в им плод сей, поиду́ ва́ми во Испа́нию. Вем же, я́ко гряды́й к вам, во исполне́нии благослове́ния благове́стия Христо́ва прииду́. ",
  ["текст_цс"] = "Бра́тїе, и҆́мамъ похвалꙋ̀ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, ꙗ҆́же къ бг҃ꙋ. не смѣ́ю бо глаго́лати что̀, и҆́хже не содѣ́ѧ хрⷭ҇то́съ мно́ю, въ послꙋша́нїе ꙗ҆зы́кѡвъ, сло́вомъ и҆ дѣ́ломъ, въ си́лѣ зна́менїй и҆ чꙋде́съ, си́лою дх҃а бж҃їѧ: ꙗ҆́коже мѝ ѿ і҆ерꙋсали́ма и҆ ѻ҆́крестъ да́же до і҆ллѷрі́ка и҆спо́лнити благовѣствова́нїе хрⷭ҇то́во. си́це же потща́хсѧ благовѣсти́ти, не и҆дѣ́же и҆менова́сѧ хрⷭ҇то́съ, да не на чꙋже́мъ ѡ҆снова́нїи сози́ждꙋ: но ꙗ҆́коже є҆́сть пи́сано: и҆̀мже не возвѣсти́сѧ ѡ҆ не́мъ, ᲂу҆́зрѧтъ: и҆ и҆̀же не слы́шаша, ᲂу҆разꙋмѣ́ютъ. тѣ́мже и҆ возбране́нъ бы́хъ мно́гажды прїитѝ къ ва́мъ. ны́нѣ же ктомꙋ̀ мѣ́ста не и҆мы́й въ страна́хъ си́хъ, жела́нїе же и҆мы́й прїитѝ къ ва́мъ ѿ мно́гихъ лѣ́тъ: ꙗ҆́кѡ а҆́ще поидꙋ̀ во і҆спа́нїю, прїидꙋ̀ къ ва́мъ. ᲂу҆пова́ю бо ми́мѡ грѧды́й ви́дѣти ва́съ, и҆ ва́ми проводи́тисѧ та́мѡ, а҆́ще ва́съ пре́жде ѿ ча́сти насы́щꙋсѧ. ны́нѣ же грѧдꙋ̀ во і҆ерꙋсали́мъ, слꙋжѧ́й ст҃ы́мъ. бл҃говоли́ша бо македо́нїа и҆ а҆ха́їа ѡ҆бще́нїе нѣ́кое сотвори́ти къ ни́щымъ ст҃ы́мъ, живꙋ́щымъ во і҆ерꙋсали́мѣ. благоволи́ша бо, и҆ до́лжни и҆̀мъ сꙋ́ть: а҆́ще бо въ дꙋхо́вныхъ и҆́хъ прича́стники бы́ша ꙗ҆зы́цы, до́лжни сꙋ́ть и҆ въ плотски́хъ послꙋжи́ти и҆̀мъ. сїѐ ᲂу҆̀бо сконча́въ, и҆ запечатлѣ́въ и҆̀мъ пло́дъ се́й, поидꙋ̀ ва́ми во і҆спа́нїю. вѣ́мъ же, ꙗ҆́кѡ грѧды́й къ ва́мъ во и҆сполне́нїи благослове́нїѧ благовѣ́стїѧ хрⷭ҇то́ва прїидꙋ̀. ",
}

add_apostol {
  ["номер"] = 119,
  ["комментарий"] = "Рим., 119 зач., XV, 30–33.",
  ["текст_ру"] = "Бра́тие, молю́ вы Го́сподем на́шим Иису́с Христо́м и любо́вию Ду́ха, споспе́шствуйте ми в моли́твах о мне к Бо́гу, да изба́влюся от противля́ющихся во Иуде́и, и да слу́жба моя́, я́же во Иерусали́ме, благоприя́тна бу́дет святы́м. Да с ра́достию прииду́ к вам во́лею Бо́жиею и упоко́юся с ва́ми. Бог же ми́ра со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, молю́ вы гдⷭ҇емъ на́шимъ і҆и҃съ хрⷭ҇то́мъ, и҆ любо́вїю дх҃а, споспѣ́шствꙋйте мѝ въ мл҃твахъ ѡ҆ мнѣ̀ къ бг҃ꙋ: да и҆зба́влюсѧ ѿ противлѧ́ющихсѧ во і҆ꙋде́и, и҆ да слꙋ́жба моѧ̀ ꙗ҆́же во і҆ерꙋсали́мѣ благопрїѧ́тна бꙋ́детъ ст҃ы̑мъ. да съ ра́достїю прїидꙋ̀ къ ва́мъ во́лею бж҃їею, и҆ ᲂу҆поко́юсѧ съ ва́ми. бг҃ъ же ми́ра со всѣ́ми ва́ми, а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 120,
  ["комментарий"] = "Рим., 120 зач., XVI, 1–16.",
  ["текст_ру"] = "Бра́тие, вруча́ю вам Фи́ву, сестру́ на́шу, су́щу служи́тельницу це́ркве, я́же в Кегхре́ех, да прии́мете ю́ о Го́споде досто́йне святы́м, и споспе́шствуйте ей, о не́йже а́ще от вас потре́бует ве́щи, и́бо сия́ засту́пница мно́гим бысть, и самому́ мне. Целу́йте Приски́ллу и Аки́лу, споспе́шника моя́ о Христе́ Иису́се и́же по души́ мое́й своя́ вы́я положи́ша, и́хже не аз еди́н благодарю́, но и вся це́ркви язы́ческия, и дома́шнюю их це́рковь. Целу́йте Епене́та возлю́бленнаго ми, и́же есть нача́ток Аха́ии во Христа́. Целу́йте Мариа́мь, я́же мно́го труди́ся о нас. Целу́йте Андрони́ка и Иуни́ю, сро́дники моя́ и спле́нники моя́, и́же суть наро́читы во Апо́столех, и́же и пре́жде мене́ ве́роваша во Христа́. Целу́йте Ампли́а возлю́бленнаго ми о Го́споде. Целу́йте Урва́на споспе́шника на́шего о Христе́, и Стахи́а возлю́бленнаго ми. Целу́йте Апе́ллиа иску́сна о Христе́. Целу́йте су́щыя от Аристову́ла. Целу́йте Иродио́на сро́дника моего́. Целу́йте и́же от Нарки́сса су́щыя о Го́споде. Целу́йте Трифе́ну и Трифо́су тружда́ющыяся о Го́споде. Целу́йте Перси́ду возлю́бленную, я́же мно́го труди́ся о Го́споде. Целу́йте Ру́фа избра́ннаго о Го́споде, и ма́терь его́ и мою́. Целу́йте Асигкри́та, Фле́гонта, Е́рма, Патро́ва, Ерми́а, и су́щую с ни́ми бра́тию. Целу́йте Филоло́га и Иули́ю, Нире́а и сестру́ его́, и Олимпа́на, и су́щыя с ни́ми вся святы́я. Целу́йте друг дру́га лобза́нием святы́м. Целу́ют вы вся це́ркви Христо́вы. ",
  ["текст_цс"] = "Бра́тїе, врꙋча́ю ва́мъ фі́вꙋ сестрꙋ̀ на́шꙋ, сꙋ́щꙋ слꙋжи́тельницꙋ це́ркве, ꙗ҆́же въ кегхре́ехъ: да прїи́мете ю҆̀ ѡ҆ гдⷭ҇ѣ досто́йнѣ ст҃ы̑мъ, и҆ споспѣ́шствꙋйте є҆́й, ѡ҆ не́йже а҆́ще ѿ ва́съ потре́бꙋетъ ве́щи: и҆́бо сїѧ̀ застꙋ́пница мнѡ́гимъ бы́сть, и҆ самомꙋ̀ мнѣ̀. цѣлꙋ́йте прїскі́ллꙋ и҆ а҆кѵ́лꙋ, споспѣ̑шника моѧ̀ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: и҆́же по дꙋшѝ мое́й своѧ̀ вы́ѧ положи́ша: и҆̀хже не а҆́зъ є҆ди́нъ благодарю̀, но и҆ всѧ̀ це́ркви ꙗ҆зы́чєскїѧ: и҆ дома́шнюю и҆́хъ це́рковь. цѣлꙋ́йте є҆пене́та возлю́бленнаго мѝ, и҆́же є҆́сть нача́токъ а҆ха́їи во хрⷭ҇та̀. цѣлꙋ́йте марїа́мъ, ꙗ҆́же мно́гѡ трꙋди́сѧ ѡ҆ на́съ. цѣлꙋ́йте а҆ндроні́ка и҆ і҆ꙋні́ю, сро́дники моѧ̀ и҆ сплѣ́нники моѧ̀, и҆̀же сꙋ́ть наро́читы во а҆пⷭ҇лѣхъ, и҆̀же и҆ пре́жде менѐ вѣ́роваша во хрⷭ҇та̀. цѣлꙋ́йте а҆мплі́а возлю́бленнаго мѝ ѡ҆ гдⷭ҇ѣ. цѣлꙋ́йте ᲂу҆рва́на, споспѣ́шника на́шего ѡ҆ хрⷭ҇тѣ̀, и҆ стахѵ́а возлю́бленнаго мѝ. цѣлꙋ́йте а҆пе́ллїа и҆скꙋ́сна ѡ҆ хрⷭ҇тѣ̀. цѣлꙋ́йте сꙋ́щыѧ ѿ а҆рїстовꙋ́ла. цѣлꙋ́йте и҆родїѡ́на сро́дника моего̀. цѣлꙋ́йте и҆̀же ѿ наркі́сса, сꙋ́щыѧ ѡ҆ гдⷭ҇ѣ. цѣлꙋ́йте трѷфе́нꙋ и҆ трѷфѡ́сꙋ, трꙋжда́ющыѧсѧ ѡ҆ гдⷭ҇ѣ. цѣлꙋ́йте персі́дꙋ возлю́бленнꙋю, ꙗ҆́же мно́гѡ трꙋди́сѧ ѡ҆ гдⷭ҇ѣ. цѣлꙋ́йте рꙋ́фа и҆збра́ннаго ѡ҆ гдⷭ҇ѣ, и҆ мт҃рь є҆гѡ̀ и҆ мою̀. цѣлꙋ́йте а҆сѷгкрі́та, фле́гонта, є҆́рма, патро́ва, є҆рмі́а, и҆ сꙋ́щꙋю съ ни́ми бра́тїю. цѣлꙋ́йте фїлоло́га и҆ і҆ꙋлі́ю, нире́а и҆ сестрꙋ̀ є҆гѡ̀, и҆ ѻ҆лѷмпа́на, и҆ сꙋ́щыѧ съ ни́ми всѧ̀ ст҃ы́ѧ. цѣлꙋ́йте дрꙋ́гъ дрꙋ́га лобза́нїемъ ст҃ы́мъ. цѣлꙋ́ютъ вы̀ всѧ̀ цр҃кви хрⷭ҇то́вы. ",
}

