add_apostol {
  ["номер"] = 127,
  ["комментарий"] = "1 Кор., 127 зач., II, 9 – III, 8.",
  ["текст_ру"] = "Бра́тие, и́хже о́ко не ви́де и у́хо не слы́ша, и на се́рдце челове́ку не взыдо́ша, я́же угото́ва Бог лю́бящым Его́. Нам же Бог откры́л есть Ду́хом Свои́м: Дух бо вся испыту́ет, и глубины́ Бо́жия. Кто бо весть от челове́к, я́же в челове́це, то́чию дух челове́ка, живу́щий в нем? Та́кожде и Бо́жия никто́же весть, то́чию Дух Бо́жий. Мы же не дух ми́ра сего́ прия́хом, но Дух и́же от Бо́га, да ве́мы я́же от Бо́га дарова́нная нам, я́же и глаго́лем не в науче́ных челове́ческия прему́дрости словесе́х, но в науче́ных Ду́ха Свята́го, духо́вная духо́вными сразсужда́юще. Душе́вен же челове́к не прие́млет я́же Ду́ха Бо́жия: юро́дство бо ему́ есть, и не мо́жет разуме́ти, зане́ духо́вне востязу́ется. Духо́вный же востязу́ет у́бо вся, а сам той ни от еди́наго востязу́ется. Кто бо разуме́ ум Госпо́день, и́же изъясни́т и? Мы же ум Христо́в и́мамы. И аз, бра́тие, не мого́х вам глаго́лати я́ко духо́вным, но я́ко пло́тяным, я́ко младе́нцем о Христе́. Млеко́м вы напои́х, а не бра́шном, не у́бо можа́сте, но ни еще́ мо́жете ны́не, еще́ бо пло́тстии есте́. Иде́же бо в вас за́висти, и рве́ния, и ра́спри, не пло́тстии ли есте́ и по челове́ку хо́дите? Егда́ бо глаго́лет кто: аз у́бо есмь Па́влов, други́й же: аз Аполло́сов, не пло́тстии ли есте́? Кто у́бо есть Па́вел? Кто же ли Аполло́с? Но то́чию служи́теле, и́миже ве́ровасте, и кому́ждо я́коже Госпо́дь даде́. Аз насади́х, Аполло́с напои́, Бог же возрасти́. Те́мже ни насажда́яй есть что, ни напая́яй, но возраща́яй Бог. Насажда́яй же и напая́яй еди́но еста́, ки́йждо же свою́ мзду прии́мет по своему́ труду́. ",
  ["текст_цс"] = "Бра́тїе, и҆́хже ѻ҆́ко не ви́дѣ и҆ ᲂу҆́хо не слы́ша, и҆ на се́рдце, человѣ́кꙋ не взыдо́ша, ꙗ҆̀же ᲂу҆гото́ва бг҃ъ лю́бѧщымъ є҆го̀. на́мъ же бг҃ъ ѿкры́лъ є҆́сть дх҃омъ свои́мъ: дх҃ъ бо всѧ̑ и҆спытꙋ́етъ, и҆ глꙋбины̑ бж҃їѧ. кто́ бо вѣ́сть ѿ человѣ̑къ, ꙗ҆̀же въ человѣ́цѣ, то́чїю дх҃ъ чл҃вѣ́ка живꙋ́щїй въ не́мъ; та́коже и҆ бж҃їѧ никто́же вѣ́сть, то́чїю дх҃ъ бж҃їй. мы́ же не дꙋ́хъ мі́ра сегѡ̀ прїѧ́хомъ, но дх҃ъ и҆́же ѿ бг҃а, да вѣ́мы ꙗ҆̀же ѿ бг҃а дарова̑ннаѧ на́мъ. ꙗ҆́же и҆ глаго́лемъ, не въ наꙋче́ныхъ чл҃вѣ́ческїѧ премꙋ́дрости словесѣ́хъ, но въ наꙋче́ныхъ дх҃а ст҃а́гѡ, дꙋхѡ́внаѧ дꙋхо́вными сразсꙋжда́юще. дꙋше́венъ же человѣ́къ не прїе́млетъ ꙗ҆̀же дх҃а бж҃їѧ: ю҆ро́дство бо є҆мꙋ̀ є҆́сть, и҆ не мо́жетъ разꙋмѣ́ти, занѐ дꙋхо́внѣ востѧзꙋ́етсѧ. дꙋхо́вный же востѧзꙋ́етъ ᲂу҆́бѡ всѧ̑, а҆ са́мъ то́й ни ѿ є҆ди́нагѡ востѧзꙋ́етсѧ. кто́ бо разꙋмѣ̀ ᲂу҆́мъ гдⷭ҇нь, и҆́же и҆з̾ѧсни́тъ и҆̀; мы́ же ᲂу҆́мъ хрⷭ҇то́въ и҆́мамы. и҆ а҆́зъ бра́тїе, не мого́хъ ва́мъ глаго́лати ꙗ҆́кѡ дꙋхѡ́внымъ, но ꙗ҆́кѡ плѡ́тѧнымъ, ꙗ҆́кѡ младе́нцємъ ѡ҆ хрⷭ҇тѣ̀. млеко́мъ вы̀ напои́хъ, а҆ не бра́шномъ: не ᲂу҆́бѡ можа́сте, но ни є҆щѐ мо́жете ны́нѣ: є҆ще́ бо пло́тстїи є҆стѐ. и҆дѣ́же бо въ ва́съ за̑висти, и҆ рвє́нїѧ, и҆ ра̑спри, не пло́тстїи ли є҆стѐ, и҆ по человѣ́кꙋ хо́дите; є҆гда́ бо глаго́летъ кто̀: а҆́зъ ᲂу҆́бѡ є҆́смь па́ѵловъ: дрꙋгі́й же, а҆́зъ а҆поллѡ́совъ: не пло́тстїи ли є҆стѐ; кто̀ ᲂу҆́бѡ є҆́сть па́ѵелъ; кто́ же ли а҆поллѡ́съ; но то́чїю слꙋжи́телє, и҆́миже вѣ́ровасте, и҆ комꙋ́ждо ꙗ҆́коже гдⷭ҇ь дадѐ. а҆́зъ насади́хъ, а҆поллѡ́съ напоѝ: бг҃ъ же возрастѝ. тѣ́мже ни насажда́ѧй є҆́сть что̀, ни напаѧ́ѧй, но возраща́ѧй бг҃ъ. насажда́ѧй же и҆ напаѧ́ѧй, є҆ди́но є҆ста̀, кі́йждо же свою̀ мздꙋ̀ прїи́метъ по своемꙋ̀ трꙋдꙋ̀. ",
}

add_apostol {
  ["номер"] = 128,
  ["комментарий"] = "1 Кор., 128 зач., III, 9–17.",
  ["текст_ру"] = "Бра́тие, Бо́гу есмы́ поспе́шницы: Бо́жие тяжа́ние, Бо́жие зда́ние есте́. По благода́ти Бо́жией да́нней мне, я́ко прему́др архите́ктон основа́ние положи́х, ин же назида́ет, ки́йждо же да блюде́т, ка́ко назида́ет. Основа́ния бо ина́го никто́же мо́жет положи́ти па́че лежа́щаго, е́же есть Иису́с Христо́с. А́ще ли кто назида́ет на основа́нии сем зла́то, сребро́, ка́мение честно́е, дрова́, се́но, тро́стие, кого́ждо де́ло явле́но бу́дет, день бо яви́т, зане́ огне́м открыва́ется, и кого́ждо де́ло, яково́же есть, огнь иску́сит. И его́же а́ще де́ло пребу́дет, его́же назда́, мзду прии́мет. А его́же де́ло сгори́т, отщети́тся: сам же спасе́тся, та́кожде я́коже огне́м. Не ве́сте ли, я́ко храм Бо́жий есте́, и Дух Бо́жий живе́т в вас? А́ще кто Бо́жий храм растли́т, растли́т сего́ Бог, храм бо Бо́жий свят есть, и́же есте́ вы. ",
  ["текст_цс"] = "Бра́тїе, бг҃ꙋ є҆смы̀ поспѣ́шницы: бж҃їе тѧжа́нїе, бж҃їе зда́нїе є҆стѐ. по благода́ти бж҃їей да́ннѣй мнѣ̀, ꙗ҆́кѡ премꙋ́дръ а҆рхїте́ктѡнъ ѡ҆снова́нїе положи́хъ, и҆́нъ же назида́етъ: кі́йждо же да блюде́тъ, ка́кѡ назида́етъ. ѡ҆снова́нїѧ бо и҆на́гѡ никто́же мо́жетъ положи́ти па́че лежа́щагѡ, є҆́же є҆́сть і҆и҃съ хрⷭ҇то́съ. а҆́ще ли кто̀ назида́етъ на ѡ҆снова́нїи се́мъ, зла́то, сребро̀, ка́менїе честно́е: дрова̀, сѣ́но, тро́стїе: когѡ́ждо дѣ́ло ꙗ҆вле́но бꙋ́детъ, де́нь бо ꙗ҆ви́тъ, занѐ ѻ҆гне́мъ ѿкрыва́етсѧ, и҆ когѡ́ждо дѣ́ло ꙗ҆ково́же є҆́сть, ѻ҆́гнь и҆скꙋ́ситъ. и҆ є҆гѡ́же а҆́ще дѣ́ло пребꙋ́детъ, є҆го́же назда̀, мздꙋ̀ прїи́метъ. а҆ є҆гѡ́же дѣ́ло сгори́тъ, ѿтщети́тсѧ: са́мъ же спасе́тсѧ, та́кожде ꙗ҆́коже ѻ҆гне́мъ. не вѣ́сте ли, ꙗ҆́кѡ хра́мъ бж҃їй є҆стѐ, и҆ дх҃ъ бж҃їй живе́тъ въ ва́съ; а҆́ще кто̀ бж҃їй хра́мъ растли́тъ, растли́тъ сего̀ бг҃ъ: хра́мъ бо бж҃їй ст҃ъ є҆́сть, и҆́же є҆стѐ вы̀. ",
}

add_apostol {
