add_apostol {
  ["номер"] = 130,
  ["комментарий"] = "1 Кор., 130 зач., IV, 1–5.",
  ["текст_ру"] = "Бра́тие, та́ко нас да непщу́ет челове́к, я́ко слуги́ Христо́вы и строи́тели та́йнам Бо́жиим. А е́же про́чее и́щется в строи́телех, да ве́рен кто обря́щется. Мне же не вели́ко есть, да от вас истяжу́ся, или́ от челове́ческаго дне, но ни сам себе́ востязу́ю. Ничесо́же бо в себе́ свем, но ни о сем оправда́юся, востязу́яй же мя Госпо́дь есть. Те́мже пре́жде вре́мене ничто́же суди́те, до́ндеже прии́дет Госпо́дь, И́же во све́те приведе́т та́йная тмы и объяви́т сове́ты серде́чныя, и тогда́ похвала́ бу́дет кому́ждо от Бо́га. ",
  ["текст_цс"] = "Бра́тїе, та́кѡ на́съ да непщꙋ́етъ человѣ́къ, ꙗ҆́кѡ слꙋги̑ хрⷭ҇то́вы, и҆ строи́тели та́йнамъ бж҃їимъ. а҆ є҆́же про́чее и҆́щетсѧ въ строи́телехъ, да вѣ́ренъ кто̀ ѡ҆брѧ́щетсѧ. мнѣ́ же не вели́ко є҆́сть, да ѿ ва́съ и҆стѧжꙋ́сѧ, и҆лѝ ѿ человѣ́ческагѡ днѐ: но ни са́мъ себѐ востѧзꙋ́ю. ничесо́же бо себѐ свѣ́мъ: но ни ѡ҆ се́мъ ѡ҆правда́юсѧ: востѧзꙋ́ѧй же мѧ̀ гдⷭ҇ь є҆́сть. тѣ́мже пре́жде вре́мене ничто́же сꙋди́те, до́ндеже прїи́детъ гдⷭ҇ь, и҆́же во свѣ́тѣ приведе́тъ та̑йнаѧ тмы̀, и҆ ѡ҆б̾ѧви́тъ совѣ́ты сердє́чныѧ: и҆ тогда̀ похвала̀ бꙋ́детъ комꙋ́ждо ѿ бг҃а. ",
}

add_apostol {
  ["номер"] = 130,
  ["комментарий"] = "1 Кор., 130 зач., IV, 5-8.",
  ["текст_ру"] = "Бра́тие, пре́жде вре́мене ничто́же суди́те, до́ндеже прии́дет Госпо́дь, И́же во све́те приведе́т та́йная тмы и объяви́т сове́ты серде́чныя, и тогда́ похвала́ бу́дет кому́ждо от Бо́га. Сия́ же, бра́тие моя́, преобрази́х на себе́ и Аполло́са вас ра́ди, да от на́ю научите́ся не па́че напи́санных му́дрствовати, да не еди́н по еди́ному гордите́ся на друга́го. Кто бо тя разсужда́ет? Что же и́маши, его́же не́си прия́л? А́ще же и прия́л еси́, что хва́лишися я́ко не прие́м? Се сы́ти есте́, се обогати́стеся, без нас ца́рствовасте, и еще́ у́бо да воцарите́ся, да и мы бы́хом с ва́ми ца́рствовали. ",
