add_apostol {
  ["номер"] = 142,
  ["комментарий"] = "1 Кор., 142 зач., IX, 13–18.",
  ["текст_ру"] = "Бра́тие, не ве́сте ли, я́ко де́лающии свяще́нная от святи́лища ядя́т, и служа́щии олтарю́ со олтаре́м сделя́ются? Та́ко и Госпо́дь повеле́ пропове́дающым Благове́стие от благове́стия жи́ти. Аз же ни еди́но сотвори́х от сих. Не писа́х же сия́, да та́ко бу́дет о мне: до́брее бо мне па́че умре́ти, не́жели похвалу́ мою́ кто да испраздни́т. А́ще бо благовеству́ю, несть ми похвалы́, ну́жда бо ми належи́т. Го́ре же мне есть, а́ще не благовеству́ю. А́ще у́бо во́лею сие́ творю́, мзду и́мам: а́ще ли нево́лею, строе́ние ми есть предано́. Кая у́бо ми есть мзда? Да благовеству́яй без мзды положу́ Благове́стие Христо́во, во е́же не твори́ти ми по о́бласти мое́й в благовествова́нии. ",
  ["текст_цс"] = "Бра́тїе, не вѣ́сте ли, ꙗ҆́кѡ дѣ́лающїи свѧщє́ннаѧ, ѿ свѧти́лища ꙗ҆дѧ́тъ, и҆ слꙋжа́щїи ѻ҆лтарю̀, со ѻ҆лтаре́мъ сдѣлѧ́ютсѧ; та́кѡ и҆ гдⷭ҇ь повелѣ̀ проповѣ́дающымъ бл҃говѣ́стїе, ѿ бл҃говѣ́стїѧ жи́ти. а҆́зъ же ни є҆ди́но сотвори́хъ ѿ си́хъ: не писа́хъ же сїѧ̑, да та́кѡ бꙋ́детъ ѡ҆ мнѣ̀: до́брѣе бо мнѣ̀ па́че ᲂу҆мре́ти, не́жели похвалꙋ̀ мою̀ кто̀ да и҆спраздни́тъ. а҆́ще бо бл҃говѣствꙋ́ю, нѣ́сть мѝ похвалы̀: нꙋ́жда бо мѝ належи́тъ. го́ре же мнѣ̀ є҆́сть, а҆́ще не бл҃говѣствꙋ́ю. а҆́ще ᲂу҆́бѡ во́лею сїѐ творю̀, мздꙋ̀ и҆́мамъ: а҆́ще ли нево́лею, строе́нїе мѝ є҆́сть предано̀. ка́ѧ ᲂу҆́бѡ мѝ є҆́сть мзда̀; да благовѣствꙋ́ѧй без̾ мзды̀ положꙋ̀ благовѣ́стїе хрⷭ҇то́во, во є҆́же не твори́ти мѝ по ѻ҆́бласти мое́й въ благовѣствова́нїи. ",
}

add_apostol {
