  ["комментарий"] = "1 Кор., 147 зач., X, 28 – XI, 7.",
  ["текст_ру"] = "Бра́тие, а́ще кто вам рече́т: сие́ идоложе́ртвенно есть, не яди́те за о́ного пове́давшаго и со́весть, Госпо́дня бо земля́ и исполне́ние ея́. Со́весть же глаго́лю не свою́, но друга́го, вску́ю бо свобо́да моя́ су́дится от ины́я со́вести? А́ще аз благода́тию причаща́юся, почто́ хулу́ прие́млю, о не́мже аз благодарю́? А́ще у́бо я́сте, а́ще ли пиете́, а́ще ли и́но что творите́, вся в сла́ву Бо́жию твори́те. Безпреткнове́ни быва́йте иуде́ем и е́ллином, и це́ркви Бо́жией, я́коже и аз во всем всем угожда́ю, не иски́й своея́ по́льзы, но мно́гих, да спасу́тся. Подража́тели мне быва́йте, я́коже и аз Христу́. Хвалю́ же вы, бра́тие, я́ко вся моя́ по́мните, и я́коже преда́х вам, преда́ния держите́. Хощу́ же вас ве́дети, я́ко вся́кому му́жу глава́ Христо́с есть, глава́ же жене́ муж, глава́ же Христу́ Бог. Всяк муж, моли́тву де́яй или́ проро́чествуяй покры́тою главо́ю, срамля́ет главу́ свою́. И вся́ка жена́, моли́тву де́ющая или́ проро́чествующая открове́нною главо́ю, срамля́ет главу́ свою́: еди́но бо есть и то́жде остри́женней. А́ще у́бо не покрыва́ется жена́, да стриже́тся, а́ще ли же срам жене́ стри́щися или́ бри́тися, да покрыва́ется. Муж бо не до́лжен есть покрыва́ти главу́, о́браз и сла́ва Бо́жия сый, жена́ же сла́ва му́жу есть. ",
  ["текст_цс"] = "Бра́тїе, а҆́ще кто̀ ва́мъ рече́тъ: сїѐ і҆дѡложе́ртвенно є҆́сть: не ꙗ҆ди́те, за ѻ҆́ного повѣ́давшаго и҆ со́вѣсть: гдⷭ҇нѧ бо землѧ̀, и҆ и҆сполне́нїе є҆ѧ̀. со́вѣсть же глаго́лю не свою̀, но дрꙋга́гѡ: вскꙋ́ю бо свобо́да моѧ̀ сꙋ́дитсѧ ѿ и҆ны́ѧ со́вѣсти; а҆́ще а҆́зъ бл҃года́тїю причаща́юсѧ, почто̀ хꙋлꙋ̀ прїе́млю, ѡ҆ не́мже а҆́зъ благодарю̀; а҆́ще ᲂу҆̀бо ꙗ҆́сте, а҆́ще ли пїетѐ, а҆́ще ли и҆́но что̀ творитѐ, всѧ̑ въ сла́вꙋ бж҃їю твори́те. безпреткнове́ни быва́йте і҆ꙋде́ємъ, и҆ є҆́ллинѡмъ, и҆ це́ркви бж҃їей. ꙗ҆́коже и҆ а҆́зъ во все́мъ всѣ̑мъ ᲂу҆гожда́ю, не и҆скі́й своеѧ̀ по́льзы, но мно́гихъ, да спасꙋ́тсѧ. подража́тели мнѣ̀ быва́йте, ꙗ҆́коже и҆ а҆́зъ хрⷭ҇тꙋ̀. хвалю́ же вы̀ бра́тїе, ꙗ҆́кѡ всѧ̑ моѧ̀ по́мните, и҆ ꙗ҆́коже преда́хъ ва́мъ, преда̑нїѧ держитѐ. хощꙋ́ же ва́съ вѣ́дѣти, ꙗ҆́кѡ всѧ́комꙋ мꙋ́жꙋ глава̀, хрⷭ҇то́съ є҆́сть: глава́ же женѣ̀, мꙋ́жъ: глава́ же хрⷭ҇тꙋ̀, бг҃ъ. всѧ́къ мꙋ́жъ моли́твꙋ дѣ́ѧй, и҆лѝ проро́чествꙋѧй покры́тою главо́ю, срамлѧ́етъ главꙋ̀ свою̀. и҆ всѧ́ка жена̀ моли́твꙋ дѣ́ющаѧ, и҆лѝ проро́чествꙋющаѧ ѿкрове́нною главо́ю, срамлѧ́етъ главꙋ̀ свою̀: є҆ди́но бо є҆́сть и҆ то́жде є҆́же бы́ти ѡ҆стри́женнѣй. а҆́ще ᲂу҆́бѡ не покрыва́етсѧ жена̀, да стриже́тсѧ: а҆́ще ли же сра́мъ женѣ̀ стри́щисѧ и҆лѝ бри́тисѧ, да покрыва́етсѧ. мꙋ́жъ бо не до́лженъ є҆́сть покрыва́ти главꙋ̀, ѻ҆́бразъ и҆ сла́ва бж҃їѧ сы́й: жена́ же сла́ва мꙋ́жꙋ є҆́сть. ",
}

add_apostol {
  ["номер"] = 148,
  ["комментарий"] = "1 Кор., 148 зач., XI, 8–22.",
  ["текст_ру"] = "Бра́тие, несть муж от жены́, но жена́ от му́жа, и́бо не со́здан бысть муж жены́ ра́ди, но жена́ му́жа ра́ди. Сего́ ра́ди должна́ есть жена́ власть име́ти на главе́ А́нгел ра́ди. Оба́че ни муж без жены́, ни жена́ без му́жа, о Го́споде. Я́коже бо жена́ от му́жа, си́це и муж жено́ю, вся же от Бо́га. В вас саме́х суди́те, ле́по ли есть жене́ открове́нне Бо́гу моли́тися? Или́ и не са́мое естество́ учи́т вы, я́ко муж у́бо а́ще власы́ расти́т, безче́стие ему́ есть, жена́ же а́ще власы́ расти́т, сла́ва ей есть? Зане́ расте́ние власо́в вме́сто одея́ния дано́ бысть ей. А́ще ли кто мни́тся спо́рлив бы́ти, мы такова́го обы́чая не и́мамы, ниже́ це́ркви Бо́жия. Сие́ же завещава́я не хвалю́, я́ко не на лу́чшее, но на ху́дшее сбира́етеся. Пе́рвое у́бо, сходя́щымся вам в це́рковь, слы́шу в вас ра́спри су́щя, и часть не́кую сих ве́рую. Подоба́ет бо и ересе́м в вас бы́ти, да иску́снии явле́ни быва́ют в вас. Сходя́щымся у́бо вам вку́пе, несть Госпо́дскую ве́черю я́сти, ко́ждо бо свою́ ве́черю предваря́ет в снеде́ние, и ов у́бо а́лчет, ов же упива́ется. Еда́ бо домо́в не и́мате, во е́же я́сти и пи́ти? Или́ о це́ркви Бо́жией нерадите́ и срамля́ете не иму́щыя? Что вам реку́? Похвалю́ ли вы о сем? Не похвалю́. ",
  ["текст_цс"] = "Бра́тїе, нѣ́сть мꙋ́жъ ѿ жены̀, но жена̀ ѿ мꙋ́жа: и҆́бо не со́зданъ бы́сть мꙋ́жъ жены̀ ра́ди, но жена̀ мꙋ́жа ра́ди. сегѡ̀ ра́ди должна̀ є҆́сть жена̀ вла́сть и҆мѣ́ти на главѣ̀, а҆́гг҃лъ ра́ди. ѻ҆ба́че ни мꙋ́жъ без̾ жены̀, ни жена̀ без̾ мꙋ́жа ѡ҆ гдⷭ҇ѣ. ꙗ҆́коже бо жена̀ ѿ мꙋ́жа, си́це и҆ мꙋ́жъ жено́ю: всѧ̑ же ѿ бг҃а. въ ва́съ самѣ́хъ сꙋди́те: лѣ́по ли є҆́сть женѣ̀ ѿкрове́ннѣ бг҃ꙋ моли́тисѧ; и҆лѝ и҆ не са́мое є҆стество̀ ᲂу҆чи́тъ вы̀, ꙗ҆́кѡ мꙋ́жъ ᲂу҆́бѡ а҆́ще власы̀ расти́тъ, безче́стїе є҆мꙋ̀ є҆́сть. жена́ же а҆́ще власы̀ расти́тъ, сла́ва є҆́й є҆́сть: занѐ растѣ́нїе власѡ́въ, вмѣ́стѡ ѡ҆дѣѧ́нїѧ дано̀ бы́сть є҆́й. а҆́ще ли кто̀ мни́тсѧ спо́рливъ бы́ти, мы̀ такова́гѡ ѻ҆бы́чаѧ не и҆́мамы, нижѐ цр҃кви бж҃їѧ. сїе́ же завѣщава́ѧ, не хвалю̀, ꙗ҆́кѡ не на лꙋ́чшее, но на хꙋ́дшее сбира́етесѧ. пе́рвое ᲂу҆́бѡ, сходѧ́щымсѧ ва́мъ въ цр҃ковь, слы́шꙋ въ ва́съ ра̑спри сꙋ́щѧ, и҆ ча́сть нѣ́кꙋю си́хъ вѣ́рꙋю. подоба́етъ бо и҆ є҆ресє́мъ въ ва́съ бы́ти, да и҆скꙋ́снїи ꙗ҆вле́ни быва́ютъ въ ва́съ. сходѧ́щымсѧ ᲂу҆́бѡ ва́мъ вкꙋ́пѣ, нѣ́сть госпо́дскꙋю ве́черю ꙗ҆́сти: ко́ждо бо свою̀ ве́черю предварѧ́етъ въ снѣде́нїе: и҆ ѻ҆́въ ᲂу҆́бѡ а҆́лчетъ, ѻ҆́въ же ᲂу҆пива́етсѧ. є҆да́ бо домѡ́въ не и҆́мате, во є҆́же ꙗ҆́сти и҆ пи́ти; и҆лѝ ѡ҆ цр҃кви бж҃їей нерадитѐ, и҆ срамлѧ́ете не и҆мꙋ́щыѧ; что̀ ва́мъ рекꙋ̀; похвалю́ ли вы̀ ѡ҆ се́мъ; не похвалю̀. ",
}

add_apostol {
  ["номер"] = 149,
  ["комментарий"] = "1 Кор., 149 зач., XI, 23–32.",
  ["текст_ру"] = "Бра́тие, аз прия́х от Го́спода, е́же и преда́х вам, я́ко Госпо́дь Иису́с в нощь, в ню́же пре́дан быва́ше, прие́м хлеб, и благодари́в преломи́, и рече́: приими́те, яди́те, сие́ есть Те́ло Мое́, е́же за вы ломи́мое; сие́ твори́те в Мое́ воспомина́ние. Та́кожде и ча́шу по ве́чери, глаго́ля: сия́ ча́ша Но́вый Заве́т есть в Мое́й Кро́ви; сие́ твори́те, ели́жды а́ще пие́те, в Мое́ воспомина́ние. Ели́жды бо а́ще я́сте хлеб сей и ча́шу сию́ пие́те, смерть Госпо́дню возвеща́ете, до́ндеже у́бо прии́дет. Те́мже и́же а́ще яст хлеб сей или́ пие́т ча́шу Госпо́дню недосто́йне, пови́нен бу́дет Те́лу и Кро́ви Госпо́дни. Да искуша́ет же челове́к себе́, и та́ко от хле́ба да яст и от ча́ши да пие́т. Яды́й бо и пия́й недосто́йне, суд себе́ яст и пие́т, не разсужда́я те́ла Госпо́дня. Сего́ ра́ди в вас мно́зи не́мощни и неду́жливи, и спят дово́льни. А́ще бо бы́хом себе́ разсужда́ли, не бы́хом осужде́ни бы́ли. Суди́ми же, от Го́спода наказу́емся, да не с ми́ром осу́димся. ",
  ["текст_цс"] = "Бра́тїе, а҆́зъ прїѧ́хъ ѿ гдⷭ҇а, є҆́же и҆ преда́хъ ва́мъ: ꙗ҆́кѡ гдⷭ҇ь і҆и҃съ, въ но́щь, въ ню́же пре́данъ быва́ше, прїе́мъ хлѣ́бъ, и҆ благодари́въ, преломѝ, и҆ речѐ: прїими́те, ꙗ҆ди́те: сїѐ є҆́сть тѣ́ло моѐ, є҆́же за вы̀ ломи́мое: сїѐ твори́те въ моѐ воспомина́нїе. та́кожде и҆ ча́шꙋ по ве́чери, глаго́лѧ: сїѧ̀ ча́ша но́вый завѣ́тъ є҆́сть въ мое́й кро́ви: сїѐ твори́те, є҆ли́жды а҆́ще пїе́те, въ моѐ воспомина́нїе. є҆ли́жды бо а҆́ще ꙗ҆́сте хлѣ́бъ се́й, и҆ ча́шꙋ сїю̀ пїе́те, сме́рть гдⷭ҇ню возвѣща́ете, до́ндеже ᲂу҆́бѡ прїи́детъ. тѣ́мже и҆́же а҆́ще ꙗ҆́стъ хлѣ́бъ се́й, и҆лѝ пїе́тъ ча́шꙋ гдⷭ҇ню недосто́йнѣ, пови́ненъ бꙋ́детъ тѣ́лꙋ и҆ кро́ви гдⷭ҇ни. да и҆скꙋша́етъ же человѣ́къ себѐ, и҆ та́кѡ ѿ хлѣ́ба да ꙗ҆́стъ, и҆ ѿ ча́ши да пїе́тъ. ꙗ҆ды́й бо и҆ пїѧ́й недосто́йнѣ, сꙋ́дъ себѣ̀ ꙗ҆́стъ и҆ пїе́тъ, не разсꙋжда́ѧ тѣ́ла гдⷭ҇нѧ. сегѡ̀ ра́ди въ ва́съ мно́зи не́мощни и҆ недꙋ́жливи и҆ спѧ́тъ дово́льни. а҆́ще бо бы́хомъ себѐ разсꙋжда́ли, не бы́хомъ ѡ҆сꙋжде́ни бы́ли. сꙋди́ми же ѿ гдⷭ҇а, наказꙋ́емсѧ, да не съ мі́ромъ ѡ҆сꙋ́димсѧ. ",
