add_apostol {
  ["номер"] = 150,
  ["комментарий"] = "1 Кор., 150 зач., XI, 31 – XII, 6.",
  ["текст_ру"] = "Бра́тие, а́ще бы́хом са́ми себе́ разсужда́ли, не бы́хом осужде́ни бы́ли. Суди́ми же, от Го́спода наказу́емся, да не с ми́ром осу́димся. Те́мже, бра́тие моя́, сходя́щеся я́сти, друг дру́га жди́те. А́ще ли кто а́лчет, в дому́ да яст, да не в грех схо́дитеся. О про́чих же, егда́ прииду́, устро́ю. О духо́вных же, бра́тие, не хощу́ вас не ве́дети. Ве́сте, я́ко егда́ неве́рни бе́сте, ко и́долом безгла́сным я́ко ведо́ми ведо́стеся. Те́мже сказу́ю вам, я́ко никто́же, Ду́хом Бо́жиим глаго́ляй, рече́т ана́фема Иису́са, и никто́же мо́жет рещи́ Го́спода Иису́са, то́чию Ду́хом Святы́м. Разделе́ния же дарова́ний суть, а то́йжде Дух, и разделе́ния служе́ний суть, а то́йжде Госпо́дь, и разделе́ния действ суть, а то́йжде есть Бог, де́йствуяй вся во всех. ",
  ["текст_цс"] = "Бра́тїе, а҆́ще бы́хомъ са́ми себѐ разсꙋжда́ли, не бы́хомъ ѡ҆сꙋжде́ни бы́ли. сꙋди́ми же ѿ гдⷭ҇а, наказꙋ́емсѧ, да не съ мі́ромъ ѡ҆сꙋ́димсѧ. тѣ́мже бра́тїе моѧ̀, сходѧ́щесѧ ꙗ҆́сти, дрꙋгъдрꙋ́га жди́те. а҆́ще ли кто̀ а҆́лчетъ, въ домꙋ̀ да ꙗ҆́стъ, да не въ грѣ́хъ схо́дитесѧ. ѡ҆ про́чихъ же, є҆гда̀ прїидꙋ̀, ᲂу҆стро́ю. ѡ҆ дꙋхо́вныхъ же бра́тїе, не хощꙋ̀ ва́съ не вѣ́дѣти. вѣ́сте, ꙗ҆́кѡ є҆гда̀ невѣ́рни бѣ́сте, ко і҆́дѡлѡмъ безгла́снымъ ꙗ҆́кѡ ведо́ми ведо́стесѧ. тѣ́мже сказꙋ́ю ва́мъ, ꙗ҆́кѡ никто́же дх҃омъ бж҃їимъ глаго́лѧй, рече́тъ а҆на́ѳема і҆и҃са: и҆ никто́же мо́жетъ рещѝ гдⷭ҇а і҆и҃са, то́чїю дх҃омъ ст҃ы́мъ. раздѣлє́нїѧ же дарова́нїй сꙋ́ть, а҆ то́йжде дх҃ъ: и҆ раздѣлє́нїѧ слꙋже́нїй сꙋ́ть, а҆ то́йжде гдⷭ҇ь: и҆ раздѣлє́нїѧ дѣ́йствъ сꙋ́ть, а҆ то́йжде є҆́сть бг҃ъ, дѣ́йствꙋѧй всѧ̑ во всѣ́хъ. ",
}

add_apostol {
  ["номер"] = 151,
  ["комментарий"] = "1 Кор., 151 зач., XII, 7–11.",
  ["текст_ру"] = "Бра́тие, кому́ждо дае́тся явле́ние Ду́ха на по́льзу. О́вому бо Ду́хом дае́тся сло́во прему́дрости, ино́му же сло́во ра́зума, о то́мже Ду́се, друго́му же ве́ра, те́мже Ду́хом, ино́му же дарова́ния исцеле́ний, о то́мже Ду́се. Друго́му же де́йствия сил, ино́му же проро́чество, друго́му же разсужде́ния духово́м, ино́му же ро́ди язы́ков, друго́му же сказа́ния язы́ков. Вся же сия́ де́йствует еди́н и то́йжде Дух, разделя́я вла́стию коему́ждо я́коже хо́щет. ",
  ["текст_цс"] = "Бра́тїе, комꙋ́ждо дае́тсѧ ꙗ҆вле́нїе дх҃а на по́льзꙋ. ѻ҆́вомꙋ бо дх҃омъ дае́тсѧ сло́во премꙋ́дрости: и҆но́мꙋ же сло́во ра́зꙋма, ѡ҆ то́мже дс҃ѣ: дрꙋго́мꙋ же вѣ́ра, тѣ́мже дх҃омъ: и҆но́мꙋ же дарова̑нїѧ и҆сцѣле́нїй, ѡ҆ то́мже дс҃ѣ. дрꙋго́мꙋ же дѣ̑йствїѧ си́лъ, и҆но́мꙋ же прⷪ҇ро́чество, дрꙋго́мꙋ же разсꙋждє́нїѧ дꙋховѡ́мъ, и҆но́мꙋ же ро́ди ѧ҆зы́кѡвъ, дрꙋго́мꙋ же сказа̑нїѧ ѧ҆зы́кѡвъ. всѧ̑ же сїѧ̑ дѣ́йствꙋетъ є҆ди́нъ и҆ то́йжде дх҃ъ, раздѣлѧ́ѧ вла́стїю коемꙋ́ждо, ꙗ҆́коже хо́щетъ. ",
