add_apostol {
  ["номер"] = 152,
  ["комментарий"] = "1 Кор., 152 зач., XII, 12–26.",
  ["текст_ру"] = "Бра́тие, я́коже те́ло еди́но есть и у́ды и́мать мно́ги, вси же у́ды еди́наго те́ла, мно́зи су́ще, еди́но суть те́ло, та́ко и Христо́с. И́бо еди́нем Ду́хом мы вси во еди́но те́ло крести́хомся, а́ще иуде́и, а́ще е́ллини, или́ раби́, или́ свобо́дни, и вси еди́нем Ду́хом напои́хомся. И́бо те́ло несть еди́н уд, но мно́зи. А́ще рече́т нога́, я́ко несмь рука́, несмь от те́ла, еда́ сего́ ра́ди несть от те́ла? И а́ще рече́т у́хо, я́ко несмь о́ко, несмь от те́ла, еда́ сего́ ра́ди несть от те́ла? А́ще все те́ло о́ко, где слух? А́ще же все слух, где уха́ние? Ны́не же положи́ Бог у́ды, еди́наго коего́ждо их в телеси́, я́коже изво́ли. А́ще ли бы́ша вси еди́н уд, где те́ло? Ны́не же мно́зи у́бо у́дове, еди́но же те́ло. Не мо́жет же о́ко рещи́ руце́: не тре́бе ми еси́, или́ па́ки глава́ нога́ма: не тре́бе ми есте́. Но мно́го па́че, мня́щиися у́ди те́ла немощне́йши бы́ти, ну́жнейши суть, и и́хже мним безче́стнейших бы́ти те́ла, сим честь мно́жайшую прилага́ем. И неблагообра́знии на́ши благообра́зие мно́жайше и́мут, а благообра́знии на́ши не тре́бе и́мут. Но Бог раствори́ те́ло, худе́йшему бо́льшу дав честь, да не бу́дет ра́спри в телеси́, но да то́жде в себе́ пеку́тся у́ди. И а́ще стра́ждет еди́н уд, с ним стра́ждут вси у́ди, а́ще ли же сла́вится еди́н уд, с ним ра́дуются вси у́ди. ",
  ["текст_цс"] = "Бра́тїе, ꙗ҆́коже тѣ́ло є҆ди́но є҆́сть, и҆ ᲂу҆́ды и҆́мать мно́ги: вси́ же ᲂу҆́ды є҆ди́нагѡ тѣ́ла, мно́зи сꙋ́ще, є҆ди́но сꙋ́ть тѣ́ло, та́кѡ и҆ хрⷭ҇то́съ. и҆́бо є҆ди́нѣмъ дх҃омъ мы̀ всѝ во є҆ди́но тѣ́ло крⷭ҇ти́хомсѧ, а҆́ще і҆ꙋдє́и, а҆́ще є҆́ллини, и҆лѝ рабѝ, и҆лѝ свобо́дни: и҆ всѝ є҆ди́нѣмъ дх҃омъ напои́хомсѧ. и҆́бо тѣ́ло нѣ́сть є҆ди́нъ ᲂу҆́дъ, но мно́зи. а҆́ще рече́тъ нога̀, ꙗ҆́кѡ нѣ́смь рꙋка̀, нѣ́смь ѿ тѣ́ла: є҆да̀ сегѡ̀ ра́ди нѣ́сть ѿ тѣ́ла; и҆ а҆́ще рече́тъ ᲂу҆́хо, ꙗ҆́кѡ нѣ́смь ѻ҆́ко, нѣ́смь ѿ тѣ́ла: є҆да̀ сегѡ̀ ра́ди нѣ́сть ѿ тѣ́ла; а҆́ще всѐ тѣ́ло ѻ҆́ко, гдѣ̀ слꙋ́хъ; а҆́ще же всѐ слꙋ́хъ, гдѣ̀ ᲂу҆ха́нїе; ны́нѣ же положѝ бг҃ъ ᲂу҆́ды, є҆ди́наго коего́ждо и҆́хъ въ тѣлесѝ, ꙗ҆́коже и҆зво́ли. а҆́ще ли бы́ша всѝ є҆ди́нъ ᲂу҆́дъ, гдѣ̀ тѣ́ло; ны́нѣ же мно́зи ᲂу҆́бѡ ᲂу҆́дове, є҆ди́но же тѣ́ло. не мо́жетъ же ѻ҆́ко рещѝ рꙋцѣ̀: не тре́бѣ мѝ є҆сѝ. и҆лѝ па́ки глава̀ нога́ма, не тре́бѣ мѝ є҆стѐ. но мно́гѡ па́че мнѧ́щїисѧ ᲂу҆́ди тѣ́ла немощнѣ́йши бы́ти, нꙋ́жнѣйши сꙋ́ть: и҆ и҆̀хже мни́мъ безче́стнѣйшихъ бы́ти тѣ́ла, си́мъ че́сть мно́жайшꙋю прилага́емъ: и҆ неблагоѻбра́знїи на́ши, благоѻбра́зїе мно́жайше и҆́мꙋтъ: а҆ благоѻбра́знїи на́ши, не тре́бѣ и҆́мꙋтъ. но бг҃ъ растворѝ тѣ́ло, хꙋдѣ́йшемꙋ бо́льшꙋ да́въ че́сть: да не бꙋ́детъ ра́спри въ тѣлесѝ. но да то́жде въ себѣ̀ пекꙋ́тсѧ ᲂу҆́ди. и҆ а҆́ще стра́ждетъ є҆ди́нъ ᲂу҆́дъ, съ ни́мъ стра́ждꙋтъ всѝ ᲂу҆́ди: а҆́ще ли же сла́витсѧ є҆ди́нъ ᲂу҆́дъ, съ ни́мъ ра́дꙋютсѧ всѝ ᲂу҆́ди. ",
}

add_apostol {
  ["номер"] = 153,
  ["комментарий"] = "1 Кор., 153 зач., XII, 27 – XIII, 8.",
  ["текст_ру"] = "Бра́тие, вы есте́ те́ло Христо́во и у́ди от ча́сти. И о́вы у́бо положи́ Бог в Це́ркви, пе́рвее апо́столы, второ́е проро́ки, тре́тие учи́тели, пото́м же си́лы, та́же дарова́ния исцеле́ний, заступле́ния, правле́ния, ро́ди язы́ков. Еда́ вси апо́столи? Еда́ вси проро́цы? Еда́ вси учи́тели? Еда́ вси си́лы? Еда́ вси дарова́ния и́мут исцеле́ний? Еда́ вси язы́ки глаго́лют? Еда́ вси сказу́ют? Ревну́йте же дарова́ний бо́льших, и еще́ по превосхожде́нию путь вам показу́ю. А́ще язы́ки челове́ческими глаго́лю и а́нгельскими, любве́ же не и́мам, бых я́ко медь звеня́щи, или́ кимва́л звяца́яй. И а́ще и́мам проро́чество и вем та́йны вся, и весь ра́зум, и а́ще и́мам всю ве́ру, я́ко и го́ры преставля́ти, любве́ же не и́мам, ничто́же есмь. И а́ще разда́м вся име́ния моя́, и а́ще преда́м те́ло мое́, во е́же сжещи́ е́, любве́ же не и́мам, ника́я по́льза ми есть. Любы́ долготерпи́т, милосе́рдствует, любы́ не зави́дит, любы́ не превозно́сится, не горди́тся, ни безчи́нствует, не и́щет своя́ си, не раздража́ется, не мы́слит зла, не ра́дуется о непра́вде, ра́дуется же о и́стине; вся лю́бит, всему́ ве́ру е́млет, вся упова́ет, вся терпи́т. Любы́ николи́же отпа́дает. ",
  ["текст_цс"] = "Бра́тїе, вы̀ є҆стѐ тѣ́ло хрⷭ҇то́во, и҆ ᲂу҆́ди ѿ ча́сти. и҆ ѻ҆́вы ᲂу҆́бѡ положѝ бг҃ъ въ цр҃кви, пе́рвѣе а҆пⷭ҇лы, второ́е прⷪ҇ро́ки, тре́тїе ᲂу҆чи́тели: пото́мже си̑лы, та́же дарова̑нїѧ и҆сцѣле́нїй, застꙋплє́нїѧ, правлє́нїѧ, ро́ди ѧ҆зы́кѡвъ: є҆да̀ всѝ а҆пⷭ҇ли; є҆да̀ всѝ прⷪ҇ро́цы; є҆да̀ всѝ ᲂу҆чи́тели; є҆да̀ всѝ си̑лы; є҆да̀ всѝ дарова̑нїѧ и҆́мꙋтъ и҆сцѣле́нїй; є҆да̀ всѝ ѧ҆зы̑ки глаго́лютъ; є҆да̀ всѝ сказꙋ́ютъ; ревнꙋ́йте же дарова́нїй бо́льшихъ: и҆ є҆щѐ по превосхожде́нїю пꙋ́ть ва́мъ показꙋ́ю. а҆́ще ѧ҆зы̑ки человѣ́ческими глаго́лю и҆ а҆́гг҃льскими, любве́ же не и҆́мамъ, бы́хъ [ꙗ҆́кѡ] мѣ́дь звенѧ́щи, и҆лѝ кѷмва́лъ звѧца́ѧй. и҆ а҆́ще и҆́мамъ проро́чество, и҆ вѣ́мъ та̑йны всѧ̀, и҆ ве́сь ра́зꙋмъ: и҆ а҆́ще и҆́мамъ всю̀ вѣ́рꙋ, ꙗ҆́кѡ и҆ го́ры преставлѧ́ти, любве́ же не и҆́мамъ, ничто́же є҆́смь. и҆ а҆́ще разда́мъ всѧ̀ и҆мѣ̑нїѧ моѧ̀, и҆ а҆́ще преда́мъ тѣ́ло моѐ во є҆́же сжещѝ є҆̀, любве́ же не и҆́мамъ, ника́ѧ по́льза мѝ є҆́сть. любы̀ долготерпи́тъ, млⷭ҇рдствꙋетъ: любы̀ не зави́дитъ: любы̀ не превозно́ситсѧ, не горди́тсѧ: ни безчи́нствꙋетъ, не и҆́щетъ своѧ́ си, не раздража́етсѧ, не мы́слитъ ѕла̀: не ра́дꙋетсѧ ѡ҆ непра́вдѣ, ра́дꙋетсѧ же ѡ҆ и҆́стинѣ: всѧ̑ лю́битъ, всемꙋ̀ вѣ́рꙋ є҆́млетъ, всѧ̑ ᲂу҆пова́етъ, всѧ̑ терпи́тъ: любы̀ николи́же ѿпа́даетъ. ",
}

add_apostol {
  ["номер"] = 154,
  ["комментарий"] = "1 Кор., 154 зач., XIII, 4 – XIV, 5.",
  ["текст_ру"] = "Бра́тие, любы́ долготерпи́т, милосе́рдствует, любы́ не зави́дит, любы́ не превозно́сится, не горди́тся, не безчи́нствует, не и́щет своя́ си, не раздража́ется, не мы́слит зла, не ра́дуется о непра́вде, ра́дуется же о и́стине, вся лю́бит, всему́ ве́ру е́млет, вся упова́ет, вся терпи́т. Любы́ николи́же отпа́дает, а́ще же проро́чествия упраздня́тся, а́ще ли язы́цы умо́лкнут, а́ще ра́зум испраздни́тся. Отча́сти бо разумева́ем и от ча́сти проро́чествуем. Егда́ же прии́дет соверше́нное, тогда́ е́же от ча́сти упраздни́тся. Егда́ бех младе́нец, я́ко младе́нец глаго́лах, я́ко младе́нец му́дрствовах, я́ко младе́нец смышля́х, егда́ же бых муж, отверго́х младе́нческая. Ви́дим у́бо ны́не я́коже зерца́лом в гада́нии, тогда́ же лице́м к лицу́, ны́не разуме́ю от ча́сти, тогда́ же позна́ю, я́коже и позна́н бых. Ны́не же пребыва́ют ве́ра, наде́жда, любы́, три сия́, бо́льши же сих любы́. Держи́теся любве́, ревну́йте же духо́вным, па́че же да проро́чествуете. Глаго́ляй бо язы́ки, не челове́ком глаго́лет, но Бо́гу, никто́же бо слы́шит, ду́хом же глаго́лет та́йны. Проро́чествуяй же, челове́ком глаго́лет созида́ние и утеше́ние, и утвержде́ние. Глаго́ляй бо язы́ки себе́ зи́ждет, а проро́чествуяй це́рковь зи́ждет. Хощу́ же всех вас глаго́лати язы́ки, па́че же да прорица́ете, бо́лий бо проро́чествуяй, не́жели глаго́ляй язы́ки, ра́зве а́ще кто сказу́ет, да це́рковь созида́ние прие́млет. ",
  ["текст_цс"] = "Бра́тїе, любы̀ долготерпи́тъ, млⷭ҇рдствꙋетъ: любы̀ не зави́дитъ: любы̀ не превозно́ситсѧ, не горди́тсѧ: ни безчи́нствꙋетъ, не и҆́щетъ своѧ́ си, не раздража́етсѧ, не мы́слитъ ѕла̀: не ра́дꙋетсѧ ѡ҆ непра́вдѣ, ра́дꙋетсѧ же ѡ҆ и҆́стинѣ: всѧ̑ лю́битъ, всемꙋ̀ вѣ́рꙋ є҆́млетъ, всѧ̑ ᲂу҆пова́етъ, всѧ̑ терпи́тъ: любы̀ николи́же ѿпа́даетъ, а҆́ще же проро́чєствїѧ ᲂу҆празднѧ́тсѧ, а҆́ще ли ѧ҆зы́цы ᲂу҆мо́лкнꙋтъ, а҆́ще ра́зꙋмъ и҆спраздни́тсѧ. ѿча́сти бо разꙋмѣва́емъ, и҆ ѿ ча́сти проро́чествꙋемъ. є҆гда́ же прїи́детъ соверше́нное, тогда̀ є҆́же ѿ ча́сти, ᲂу҆праздни́тсѧ. є҆гда̀ бѣ́хъ млⷣнецъ, ꙗ҆́кѡ млⷣнецъ глаго́лахъ, ꙗ҆́кѡ младе́нецъ мꙋ́дрствовахъ, ꙗ҆́кѡ младе́нецъ смышлѧ́хъ: є҆гда́ же бы́хъ мꙋ́жъ, ѿверго́хъ млⷣнчєскаѧ. ви́димъ бо ны́нѣ ꙗ҆́коже зерца́ломъ въ гада́нїи тогда́ же лице́мъ къ лицꙋ̀: ны́нѣ разꙋмѣ́ю ѿ ча́сти тогда́ же позна́ю, ꙗ҆́коже и҆ позна́нъ бы́хъ. ны́нѣ же пребыва́ютъ вѣ́ра, наде́жда, любы̀, трѝ сїѧ̀: бо́льши же си́хъ, любы̀. держи́тесѧ любвѐ: ревнꙋ́йте же дꙋхѡ́внымъ, па́че же да проро́чествꙋете. глаго́лѧй бо ѧ҆зы́ки, не человѣ́кѡмъ глаго́летъ, но бг҃ꙋ: никто́же бо слы́шитъ, дх҃омъ же глаго́летъ та̑йны. проро́чествꙋѧй же, человѣ́кѡмъ глаго́летъ созида́нїе, и҆ ᲂу҆тѣше́нїе, и҆ ᲂу҆твержде́нїе. глаго́лѧй бо ѧ҆зы́ки, себѐ зи́ждетъ: а҆ проро́чествꙋѧй, цр҃ковь зи́ждетъ. хощꙋ́ же всѣ́хъ ва́съ глаго́лати ѧ҆зы́ки, па́че же да прорица́ете: бо́лїй бо проро́чествꙋѧй, не́жели глаго́лѧй ѧ҆зы́ки, ра́звѣ а҆́ще кто̀ сказꙋ́етъ, да цр҃ковь созида́нїе прїе́млетъ. ",
}

