  ["текст_ру"] = "Бра́тие, сказу́ю вам, Благовествова́ние, е́же благовести́х вам, е́же и прия́сте, в не́мже и стоите́, и́мже и спаса́етеся, ка́цем сло́вом благовести́х вам, а́ще содержите́, ра́зве а́ще не всуе ве́ровасте. Преда́х бо вам испе́рва, е́же и прия́х, я́ко Христо́с у́мре грех на́ших ра́ди, по Писа́нием, и я́ко погребе́н бысть, и я́ко воста́ в тре́тий день, по Писа́нием, и я́ко яви́ся Ки́фе, та́же единона́десятим. Пото́м же яви́ся бо́ле пяти́ сот бра́тиям еди́ною, от ни́хже мно́жайшии пребыва́ют досе́ле, не́цыи же и почи́ша. Пото́м же яви́ся Иа́кову, та́же Апо́столом всем. Последи́ же всех, я́ко не́коему и́звергу, яви́ся и мне. Аз бо есмь мний Апо́столов, и́же несмь досто́ин нарещи́ся Апо́стол, зане́ гони́х це́рковь Бо́жию. Благода́тию же Бо́жиею есмь, е́же есмь, и благода́ть Его́, я́же во мне, не тща бысть, но па́че всех их потруди́хся, не аз же, но благода́ть Бо́жия, я́же со мно́ю. А́ще у́бо аз, а́ще ли они́, та́ко пропове́дуем, и та́ко ве́ровасте. ",
  ["текст_цс"] = "Бра́тїе, сказꙋ́ю ва́мъ благовѣствова́нїе, є҆́же благовѣсти́хъ ва́мъ, є҆́же и҆ прїѧ́сте, въ не́мже и҆ стоитѐ: и҆́мже и҆ спаса́етесѧ, ка́цѣмъ сло́вомъ благовѣсти́хъ ва́мъ, а҆́ще содержитѐ, ра́звѣ а҆́ще не всꙋ́е вѣ́ровасте. преда́хъ бо ва́мъ и҆спе́рва, є҆́же и҆ прїѧ́хъ, ꙗ҆́кѡ хрⷭ҇то́съ ᲂу҆́мре грѣ̑хъ на́шихъ ра́ди, по писа́нїємъ, и҆ ꙗ҆́кѡ погребе́нъ бы́сть, и҆ ꙗ҆́кѡ воста̀ въ тре́тїй де́нь, по писа́нїємъ. и҆ ꙗ҆́кѡ ꙗ҆ви́сѧ ки́фѣ, та́же є҆динона́десѧтимъ. пото́мъ же ꙗ҆ви́сѧ бо́ле пѧтѝ сѡ́тъ бра́тїѧмъ є҆ди́ною, ѿ ни́хже мно́жайшїи пребыва́ютъ досе́лѣ, нѣ́цыи же и҆ почи́ша. пото́мъ же ꙗ҆ви́сѧ і҆а́кѡвꙋ: та́же а҆пⷭ҇лѡмъ всѣ́мъ. послѣди́ же всѣ́хъ, ꙗ҆́кѡ нѣ́коемꙋ и҆́звергꙋ, ꙗ҆ви́сѧ и҆ мнѣ̀. а҆́зъ бо є҆́смь мні́й а҆пⷭ҇лѡвъ, и҆́же нѣ́смь досто́инъ нарещи́сѧ а҆пⷭ҇лъ, занѐ гони́хъ цр҃ковь бж҃їю. бл҃года́тїю же бж҃їею є҆́смь, є҆́же є҆́смь, и҆ бл҃года́ть є҆гѡ̀, ꙗ҆́же во мнѣ̀, не тща̀ бы́сть, но па́че всѣ́хъ и҆́хъ потрꙋди́хсѧ: не а҆́зъ же, но благода́ть бж҃їѧ, ꙗ҆́же со мно́ю. а҆́ще ᲂу҆́бѡ а҆́зъ, а҆́ще ли ѻ҆нѝ, та́кѡ проповѣ́дꙋемъ, и҆ та́кѡ вѣ́ровасте. ",
}

add_apostol {
  ["номер"] = 159,
  ["комментарий"] = "1 Кор., 159 зач., XV, 12–19.",
  ["текст_ру"] = "Бра́тие, а́ще Христо́с пропове́дуется, я́ко из ме́ртвых воста́, ка́ко глаго́лют не́цыи в вас, я́ко воскресе́ния ме́ртвых несть? И а́ще воскресе́ния ме́ртвых несть, то ни Христо́с воста́. А́ще же Христо́с не воста́, тще у́бо пропове́дание на́ше, тща же и ве́ра ва́ша. Обрета́емся же и лжесвиде́теле Бо́жии, я́ко послушествова́хом на Бо́га, я́ко воскреси́ Христа́, Его́же не воскреси́, а́ще у́бо ме́ртвии не востаю́т, а́ще бо ме́ртвии не востаю́т, то ни Христо́с воста́. А́ще же Христо́с не воста́, су́етна ве́ра ва́ша, еще́ есте́ во гресе́х ва́ших. У́бо и уме́ршии о Христе́, погибо́ша. И а́ще в животе́ сем то́чию упова́юще есмы́ во Христа́ то́чию, окая́ннейши всех челове́к есмы́. ",
  ["текст_цс"] = "Бра́тїе, а҆́ще хрⷭ҇то́съ проповѣ́дꙋетсѧ, ꙗ҆́кѡ и҆з̾ ме́ртвыхъ воста̀, ка́кѡ глаго́лютъ нѣ́цыи въ ва́съ, ꙗ҆́кѡ воскрⷭ҇нїѧ ме́ртвыхъ нѣ́сть; и҆ а҆́ще воскрⷭ҇нїѧ ме́ртвыхъ нѣ́сть, то̀ ни хрⷭ҇то́съ воста̀. а҆́ще же хрⷭ҇то́съ не воста̀, тщѐ ᲂу҆̀бо проповѣ́данїе на́ше, тща́ же и҆ вѣ́ра ва́ша. ѡ҆брѣта́емсѧ же и҆ лжесвидѣ́телє бж҃їи, ꙗ҆́кѡ послꙋшествова́хомъ на бг҃а, ꙗ҆́кѡ воскресѝ хрⷭ҇та̀, є҆гѡ́же не воскресѝ, а҆́ще ᲂу҆́бѡ ме́ртвїи не востаю́тъ: а҆́ще бо ме́ртвїи не востаю́тъ, то̀ ни хрⷭ҇то́съ воста̀. а҆́ще же хрⷭ҇то́съ не воста̀, сꙋ́етна вѣ́ра ва́ша, є҆щѐ є҆стѐ во грѣсѣ́хъ ва́шихъ. ᲂу҆̀бо и҆ ᲂу҆ме́ршїи ѡ҆ хрⷭ҇тѣ̀, погибо́ша. и҆ а҆́ще въ животѣ̀ се́мъ ᲂу҆пова́юще є҆смы̀ во хрⷭ҇та̀ то́чїю, ѻ҆каѧ́ннѣйши всѣ́хъ человѣ̑къ є҆смы̀. ",
}

add_apostol {
  ["номер"] = 160,
  ["комментарий"] = "1 Кор., 160 зач., XV, 20-28.",
  ["текст_ру"] = "Бра́тие, Христо́с воста́ от ме́ртвых, нача́ток уме́ршым бысть. Поне́же бо челове́ком смерть бысть, и челове́ком воскресе́ние ме́ртвых. Я́коже бо о Ада́ме вси умира́ют, та́кожде и о Христе́ вси оживу́т, ко́ждо же во свое́м чину́: нача́ток Христо́с, пото́м же Христу́ ве́ровавшии в прише́ствии Его́. Та́же кончи́на, егда́ преда́ст Ца́рство Бо́гу и Отцу́, егда́ испраздни́т вся́ко нача́льство и вся́ку власть и си́лу. Подоба́ет бо Ему́ ца́рствовати, до́ндеже положи́т вся враги́ под нога́ма Свои́ма. После́дний же враг испраздни́тся смерть, вся бо покори́ под но́зе Его́, внегда́ же рещи́, я́ко вся покоре́на суть Ему́, я́ве я́ко ра́зве Поко́ршаго Ему́ вся. Егда́ же покори́т Ему́ вся́ческая, тогда́ и Сам Сын покори́тся Поко́ршему Ему́ вся́ческая, да бу́дет Бог вся́ческая во всех. ",
  ["текст_цс"] = "Бра́тїе, хрⷭ҇то́съ воста̀ ѿ ме́ртвыхъ, нача́токъ ᲂу҆ме́ршымъ бы́сть: поне́же бо чл҃вѣ́комъ сме́рть бы́сть, и҆ чл҃вѣ́комъ воскрⷭ҇нїе ме́ртвыхъ. ꙗ҆́коже бо ѡ҆ а҆да́мѣ всѝ ᲂу҆мира́ютъ, та́кожде и҆ ѡ҆ хрⷭ҇тѣ̀ всѝ ѡ҆живꙋ́тъ. ко́ждо же во свое́мъ чинꙋ̀: нача́токъ хрⷭ҇то́съ, пото́мъ же хрⷭ҇тꙋ̀ вѣ́ровавшїи, въ прише́ствїи є҆гѡ̀. та́же кончи́на, є҆гда̀ преда́стъ црⷭ҇тво бг҃ꙋ и҆ ѻ҆ц҃ꙋ̀: є҆гда̀ и҆спраздни́тъ всѧ́ко нача́льство, и҆ всѧ́кꙋ вла́сть и҆ си́лꙋ. подоба́етъ бо є҆мꙋ̀ ца́рствовати, до́ндеже положи́тъ всѧ̀ врагѝ под̾ нога́ма свои́ма. послѣ́днїй же вра́гъ и҆спраздни́тсѧ сме́рть: всѧ̑ бо покорѝ под̾ но́зѣ є҆гѡ̀, внегда́ же рещѝ, ꙗ҆́кѡ всѧ̑ покорє́на сꙋ́ть є҆мꙋ̀, ꙗ҆́вѣ ꙗ҆́кѡ ра́звѣ поко́ршагѡ є҆мꙋ̀ всѧ̑. є҆гда́ же покори́тъ є҆мꙋ̀ всѧ́чєскаѧ, тогда̀ и҆ са́мъ сн҃ъ покори́тсѧ поко́ршемꙋ є҆мꙋ̀ всѧ́чєскаѧ, да бꙋ́детъ бг҃ъ всѧ́чєскаѧ во всѣ́хъ. ",
}

add_apostol {
  ["номер"] = 161,
  ["комментарий"] = "1 Кор., 161 зач., XV, 29–38.",
  ["текст_ру"] = "Бра́тие, что сотворя́т крестя́щиися ме́ртвых ра́ди? А́ще отню́д ме́ртвии не востаю́т, что и креща́ются ме́ртвых ра́ди? Почто́ же и мы беды́ прие́млем на всяк час? По вся дни умира́ю, та́ко ми ва́ша похвала́, бра́тие, ю́же и́мам о Христе́ Иису́се Го́споде на́шем. А́ще бо по челове́ку со зве́рем боря́хся в Ефе́се ка́я ми по́льза, а́ще ме́ртвии не востаю́т? Да я́мы и пие́м, у́тре бо у́мрем. Не льсти́теся: тлят обы́чаи бла́ги бесе́ды злы. Истрезви́теся пра́ведно и не согреша́йте, неве́дение бо Бо́жие не́цыи и́мут, к сра́му вам глаго́лю. Но рече́т не́кто: ка́ко воста́нут ме́ртвии? Ко́им же те́лом прии́дут? Безу́мне, ты е́же се́еши, не оживе́т, а́ще не у́мрет. И е́же се́еши, не те́ло бу́дущее се́еши, но голо́ зе́рно, а́ще случи́тся, пшени́цы или́ ино́го от про́чих, Бог же дае́т ему́ те́ло, я́коже восхо́щет, и коему́ждо се́мени свое́ те́ло. ",
  ["текст_цс"] = "Бра́тїе, что̀ сотворѧ́тъ крестѧ́щїисѧ ме́ртвыхъ ра́ди; а҆́ще ѿню́дъ ме́ртвїи не востаю́тъ, что̀ и҆ креща́ютсѧ ме́ртвыхъ ра́ди; почто́ же и҆ мы̀ бѣды̑ прїе́млемъ на всѧ́къ ча́съ; по всѧ̀ днѝ ᲂу҆мира́ю, та́кѡ мѝ ва́ша похвала̀ бра́тїе, ю҆́же и҆́мамъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ гдⷭ҇ѣ на́шемъ. а҆́ще бо по человѣ́кꙋ со ѕвѣ́ремъ борѧ́хсѧ въ є҆фе́сѣ, ка́ѧ мѝ по́льза, а҆́ще ме́ртвїи не востаю́тъ; да ꙗ҆́мы и҆ пїе́мъ, ᲂу҆́трѣ бо ᲂу҆́мремъ. не льсти́тесѧ: тлѧ́тъ ѻ҆бы́чаи бла́ги бесѣ́ды ѕлы̑. и҆стрезви́тесѧ пра́веднѡ, и҆ не согрѣша́йте: невѣ́дѣнїе бо бж҃їе нѣ́цыи и҆́мꙋтъ: къ сра́мꙋ ва́мъ глаго́лю. но рече́тъ нѣ́кто: ка́кѡ воста́нꙋтъ ме́ртвїи; ко́имъ же тѣ́ломъ прїи́дꙋтъ; безꙋ́мне, ты̀ є҆́же сѣ́еши, не ѡ҆живе́тъ, а҆́ще не ᲂу҆́мретъ. и҆ є҆́же сѣ́еши, не тѣ́ло бꙋ́дꙋщее сѣ́еши, но голо̀ зе́рно, а҆́ще слꙋчи́тсѧ, пшени́цы и҆лѝ и҆но́го ѿ про́чихъ: бг҃ъ же дае́тъ є҆мꙋ̀ тѣ́ло, ꙗ҆́коже восхо́щетъ, и҆ коемꙋ́ждо сѣ́мени своѐ тѣ́ло. ",
}

add_apostol {
