  ["номер"] = 163,
  ["комментарий"] = "1 Кор., 163 зач., XV, 47–57.",
  ["текст_ру"] = "Бра́тие, пе́рвый челове́к от земли́ пе́рстен, вторы́й Челове́к Госпо́дь с небесе́. Яко́в пе́рстный, такови́ и пе́рстнии, и яко́в небе́сный, та́цы же и небе́снии. И я́коже облеко́хомся во о́браз пе́рстнаго, да облече́мся и во о́браз Небе́снаго. Сие́ же глаго́лю, бра́тие, я́ко плоть и кровь Ца́рствия Бо́жия насле́дити не мо́гут, ниже́ тле́ние нетле́ния насле́дствует. Се та́йну вам глаго́лю: вси бо не у́спнем, вси же измени́мся. Вско́ре, во мгнове́нии о́ка, в после́дней трубе́: востру́бит бо, и ме́ртвии воста́нут нетле́нни, и мы измени́мся. Подоба́ет бо тле́нному сему́ облещи́ся в нетле́ние, и ме́ртвенному сему́ облещи́ся в безсме́ртие. Егда́ же тле́нное сие́ облече́тся в нетле́ние, и сме́ртное сие́ облече́тся в безсме́ртие, тогда́ бу́дет сло́во напи́санное: поже́рта бысть смерть побе́дою. Где ти сме́рте, жа́ло; где ти а́де, побе́да? Жа́ло же сме́рти грех, си́ла же греха́ зако́н. Бо́гу же благодаре́ние, да́вшему нам побе́ду Го́сподем на́шим Иису́с Христо́м. ",
  ["текст_цс"] = "Бра́тїе, пе́рвый человѣ́къ ѿ землѝ пе́рстенъ, вторы́й чл҃вѣ́къ гдⷭ҇ь съ нб҃сѐ. ꙗ҆ко́въ пе́рстный, таковѝ и҆ пе́рстнїи: и҆ ꙗ҆ко́въ нбⷭ҇ный, та́цы же и҆ нбⷭ҇нїи. и҆ ꙗ҆́коже ѡ҆блеко́хомсѧ во ѻ҆́бразъ пе́рстнагѡ, да ѡ҆блече́мсѧ и҆ во ѻ҆́бразъ нбⷭ҇нагѡ. сїе́ же глаго́лю, бра́тїе, ꙗ҆́кѡ пло́ть и҆ кро́вь црⷭ҇твїѧ бж҃їѧ наслѣ́дити не мо́гꙋтъ, нижѐ тлѣ́нїе нетлѣ́нїѧ наслѣ́дствꙋетъ. сѐ та́йнꙋ ва́мъ глаго́лю: вси́ бо не ᲂу҆́спнемъ, вси́ же и҆змѣни́мсѧ, вско́рѣ, во мгнове́нїи ѻ҆́ка, въ послѣ́днѣй трꙋбѣ̀: вострꙋ́битъ бо, и҆ ме́ртвїи воста́нꙋтъ нетлѣ́нни, и҆ мы̀ и҆змѣни́мсѧ. подоба́етъ бо тлѣ́нномꙋ семꙋ̀ ѡ҆блещи́сѧ въ нетлѣ́нїе, и҆ ме́ртвенномꙋ семꙋ̀ ѡ҆блещи́сѧ въ безсме́ртїе. є҆гда́ же тлѣ́нное сїѐ ѡ҆блече́тсѧ въ нетлѣ́нїе, и҆ сме́ртное сїѐ ѡ҆блече́тсѧ въ безсме́ртїе, тогда̀ бꙋ́детъ сло́во напи́санное: поже́рта бы́сть сме́рть побѣ́дою. гдѣ́ ти сме́рте, жа́ло; гдѣ́ ти а҆́де, побѣ́да; жа́ло же сме́рти, грѣ́хъ: си́ла же грѣха̀, зако́нъ. бг҃ꙋ же благодаре́нїе, да́вшемꙋ на́мъ побѣ́дꙋ гдⷭ҇емъ на́шимъ і҆и҃съ хрⷭ҇то́мъ. ",
}

add_apostol {
  ["номер"] = 164,
  ["комментарий"] = "1 Кор., 164 зач., XV, 58 – XVI, 3.",
  ["текст_ру"] = "Бра́тие, тве́рди быва́йте, непосту́пни, избы́точествующе в де́ле Госпо́дни всегда́, ве́дяще, я́ко труд ваш несть тощь пред Го́сподем. О ми́лостыни же, я́же ко святы́м, я́коже устро́их це́рквам Галати́йским, та́ко и вы сотворя́йте. По еди́ней от суббо́т ко́ждо вас да полага́ет у себе́ сохраня́я, е́же а́ще что бла́го поспеши́тся, да не егда́ прииду́, тогда́ собра́ния быва́ют. Егда́ же прииду́, и́хже а́ще иску́сите посла́ньми, сих послю́ отнести́ благода́ть ва́шу во Иерусали́м. ",
  ["текст_цс"] = "Бра́тїе, тве́рди быва́йте, непостꙋ́пни, и҆збы́точествꙋюще въ дѣ́лѣ гдⷭ҇ни всегда̀: вѣ́дѧще, ꙗ҆́кѡ трꙋ́дъ ва́шъ нѣ́сть то́щъ пред̾ гдⷭ҇емъ. ѡ҆ ми́лостыни же, ꙗ҆́же ко ст҃ы̑мъ, ꙗ҆́коже ᲂу҆стро́ихъ цр҃квамъ галаті́йскимъ, та́кѡ и҆ вы̀ сотворѧ́йте. по є҆ди́нѣй ѿ сꙋббѡ́тъ ко́ждо ва́съ да полага́етъ ᲂу҆ себѐ, сохранѧ́ѧ є҆́же а҆́ще что̀ бл҃го поспѣши́тсѧ: да не є҆гда̀ прїидꙋ̀, тогда̀ собра̑нїѧ быва́ютъ. є҆гда́ же прїидꙋ̀, и҆̀хже а҆́ще и҆скꙋ́сите посла́ньми, си́хъ послю̀ ѿнестѝ блгⷣть ва́шꙋ во і҆ерꙋсали́мъ. ",
}

add_apostol {
