add_apostol {
  ["номер"] = 166,
  ["комментарий"] = "1 Кор., 166 зач., XVI, 13–24.",
  ["текст_ру"] = "Бра́тие, бо́дрствуйте, сто́йте в ве́ре, мужа́йтеся, утвержда́йтеся. Вся вам любо́вию да быва́ют. Молю́ же вы, бра́тие, ве́сте дом Стефани́нов, я́ко есть нача́ток Аха́ии, и в служе́ние святы́м учини́ша себе́, да и вы повину́йтеся таковы́м и вся́кому споспе́шствующу и тружда́ющуся. Возра́довахся же о прише́ствии Стефани́нове и Фуртуна́тове и Аха́икове, я́ко ва́ше лише́ние си́и испо́лниша. Поко́иша бо мой дух и ваш. Познава́йте у́бо таковы́я. Целу́ют вы це́ркви Аси́йския. Целу́ют вы о Го́споде мно́го Аки́ла и Приски́лла с дома́шнею их це́рковию. Целу́ют вы бра́тия вся. Целу́йте друг дру́га лобза́нием святы́м. Целова́ние мое́ю руко́ю Па́влею. А́ще кто не лю́бит Го́спода Иису́са Христа́, да бу́дет про́клят. Мара́н афа́. Благода́ть Го́спода на́шего Иису́са Христа́ с ва́ми, и любы́ моя́ со все́ми ва́ми о Христе́ Иису́се. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, бо́дрствꙋйте, сто́йте въ вѣ́рѣ, мꙋжа́йтесѧ ᲂу҆твержда́йтесѧ. всѧ̑ ва́мъ любо́вїю да быва́ютъ. молю́ же вы̀ бра́тїе: вѣ́сте до́мъ стефани́новъ, ꙗ҆́кѡ є҆́сть нача́токъ а҆ха́їи, и҆ въ слꙋже́нїе ст҃ы̑мъ ᲂу҆чини́ша себѐ: да и҆ вы̀ повинꙋ́йтесѧ таковы̑мъ, и҆ всѧ́комꙋ споспѣ́шствꙋющꙋ и҆ трꙋжда́ющꙋсѧ. возра́довахсѧ же ѡ҆ прише́ствїи стефани́новѣ, и҆ фꙋртꙋна́товѣ, и҆ а҆ха́їковѣ, ꙗ҆́кѡ ва́ше лише́нїе сі́и и҆спо́лниша. поко́иша бо мо́й дꙋ́хъ и҆ ва́шъ: познава́йте ᲂу҆̀бо таковы̑ѧ. цѣлꙋ́ютъ вы̀ цр҃кви а҆сі́йскїѧ. цѣлꙋ́ютъ вы̀ ѡ҆ гдⷭ҇ѣ мно́гѡ а҆кѵ́ла и҆ прїскі́лла, съ дома́шнею и҆́хъ цр҃ковїю. цѣлꙋ́ютъ вы̀ бра́тїѧ всѧ̀. цѣлꙋ́йте дрꙋгъдрꙋ́га лобза́нїемъ ст҃ы́мъ. цѣлова́нїе мое́ю рꙋко́ю па́ѵлею. а҆́ще кто̀ не лю́битъ гдⷭ҇а і҆и҃са хрⷭ҇та̀, да бꙋ́детъ про́клѧтъ: мара́н а҆ѳа̀. бл҃года́ть гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ съ ва́ми: и҆ любы̀ моѧ̀ со всѣ́ми ва́ми, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, а҆ми́нь. ",
}

add_apostol {
