  ["текст_цс"] = "Бра́тїе, бл҃гослове́нъ бг҃ъ, и҆ ѻ҆ц҃ъ гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, ѻ҆ц҃ъ щедро́тъ и҆ бг҃ъ всѧ́кїѧ ᲂу҆тѣ́хи: ᲂу҆тѣша́ѧй на́съ ѡ҆ всѧ́кой ско́рби на́шей, ꙗ҆́кѡ возмощѝ на́мъ ᲂу҆тѣ́шити сꙋ́щыѧ во всѧ́кой ско́рби, ᲂу҆тѣше́нїемъ, и҆́мже ᲂу҆тѣша́емсѧ са́ми ѿ бг҃а. занѐ ꙗ҆́коже и҆збы́точествꙋютъ страда̑нїѧ хрⷭ҇то́ва въ на́съ, та́кѡ хрⷭ҇то́мъ и҆збы́точествꙋетъ и҆ ᲂу҆тѣше́нїе на́ше. а҆́ще ли же скорби́мъ, ѡ҆ ва́шемъ ᲂу҆тѣше́нїи, и҆ спасе́нїи, дѣ́йствꙋющемсѧ въ терпѣ́нїи тѣ́хже страда́нїй, ꙗ҆̀же и҆ мы̀ стра́ждемъ: и҆ ᲂу҆пова́нїе на́ше и҆звѣ́стно ѡ҆ ва́съ. а҆́ще ли ᲂу҆тѣша́емсѧ, ѡ҆ ва́шемъ ᲂу҆тѣше́нїи и҆ спасе́нїи: вѣ́дѧще, занѐ ꙗ҆́коже ѻ҆́бщницы є҆стѐ страсте́мъ на́шымъ, та́кожде и҆ ᲂу҆тѣше́нїю. ",
}

add_apostol {
  ["номер"] = 168,
  ["комментарий"] = "2 Кор., 168 зач., I, 8–11.",
  ["текст_ру"] = "Бра́тие, не хощу́ вас не ве́дети о ско́рби на́шей, бы́вшей нам во Аси́и, я́ко по премно́гу и па́че си́лы отяготи́хомся, я́ко не наде́ятися нам и жи́ти. Но са́ми в себе́ осужде́ние сме́рти име́хом, да не наде́ющеся бу́дем на ся, но на Бо́га возставля́ющаго ме́ртвыя, И́же от толи́кия сме́рти изба́вил ны есть и избавля́ет, На́ньже и упова́хом, я́ко и еще́ изба́вит; поспеша́ющим и вам по нас моли́твою, да от мног лиц е́же в нас дарова́ние, мно́гими благодари́тся о вас. ",
  ["текст_цс"] = "Бра́тїе, не хощꙋ̀ ва́съ не вѣ́дѣти ѡ҆ ско́рби на́шей бы́вшей на́мъ во а҆сі́и, ꙗ҆́кѡ по премно́гꙋ и҆ па́че си́лы ѡ҆тѧготи́хомсѧ, ꙗ҆́кѡ не надѣ́ѧтисѧ на́мъ и҆ жи́ти. но са́ми въ себѣ̀ ѡ҆сꙋжде́нїе сме́рти и҆мѣ́хомъ, да не надѣ́ющесѧ бꙋ́демъ на сѧ̀, но на бг҃а возставлѧ́ющаго мє́ртвыѧ: и҆́же ѿ толи́кїѧ сме́рти и҆зба́вилъ ны̀ є҆́сть, и҆ и҆збавлѧ́етъ: на́ньже и҆ ᲂу҆пова́хомъ, ꙗ҆́кѡ и҆ є҆щѐ и҆зба́витъ. поспѣша́ющымъ и҆ ва́мъ по на́съ моли́твою: да ѿ мнѡ́гъ ли́цъ є҆́же въ на́съ дарова́нїе, мно́гими благодари́тсѧ ѡ҆ ва́съ. ",
}

add_apostol {
  ["номер"] = 169,
  ["комментарий"] = "2 Кор., 169 зач., I, 12–20.",
  ["текст_ру"] = "Бра́тие, похвале́ние на́ше сие́ есть, свиде́тельство со́вести на́шея, я́ко в простоте́ и чистоте́ Бо́жией, а не в му́дрости пло́ти, но благода́тию Бо́жиею жи́хом в ми́ре, мно́жае же у вас. Не ина́я бо пи́шем вам, но я́же чтете́ и разумева́ете, упова́ю же, я́ко и до конца́ уразуме́ете, я́коже и разуме́сте нас от ча́сти, я́ко похвале́ние вам есмы́, я́коже и вы нам, в день Го́спода на́шего Иису́са Христа́. И сим упова́нием хоте́х к вам приити́ пре́жде, да втору́ю благода́ть и́мате, и ва́ми проити́ в Македо́нию, и па́ки от Македо́нии приити́ к вам, и ва́ми проводи́тися во Иуде́ю. Сие́ же хотя́, еда́ что у́бо легкото́ю де́ях? Или́ я́же совещава́ю, по пло́ти совещава́ю, да бу́дет у мене́ е́же ей, ей, и е́же ни, ни. Ве́рен же Бог, я́ко сло́во на́ше, е́же к вам, не бысть ей и ни. И́бо Бо́жий Сын Иису́с Христо́с, и́же у вас на́ми пропове́данный, мно́ю и Силуа́ном и Тимофе́ем, не бысть ей и ни, но в Нем Само́м ей бысть. Ели́ка бо обетова́ния Бо́жия, в Том ей и в Том ами́нь, Бо́гу к сла́ве на́ми. ",
  ["текст_цс"] = "Бра́тїе, похвале́нїе на́ше сїѐ є҆́сть, свидѣ́тельство со́вѣсти на́шеѧ, ꙗ҆́кѡ въ простотѣ̀ и҆ чистотѣ̀ бж҃їей, а҆ не въ мꙋ́дрости пло́ти, но бл҃года́тїю бж҃їею жи́хомъ въ мі́рѣ, мно́жае же ᲂу҆ ва́съ. не и҆на̑ѧ бо пи́шемъ ва́мъ, но ꙗ҆̀же чтетѐ, и҆ разꙋмѣва́ете: ᲂу҆пова́ю же, ꙗ҆́кѡ и҆ до конца̀ ᲂу҆разꙋмѣ́ете: ꙗ҆́коже и҆ разꙋмѣ́сте на́съ ѿ ча́сти, ꙗ҆́кѡ похвале́нїе ва́мъ є҆смы̀, ꙗ҆́коже и҆ вы̀ на́мъ, въ де́нь гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀. и҆ си́мъ ᲂу҆пова́нїемъ хотѣ́хъ къ ва́мъ прїитѝ пре́жде, да вторꙋ́ю бл҃года́ть и҆́мате: и҆ ва́ми проитѝ въ македо́нїю, и҆ па́ки ѿ македо́нїи прїитѝ къ ва́мъ, и҆ ва́ми проводи́тисѧ во і҆ꙋде́ю. сїе́ же хотѧ̀, є҆да̀ что̀ ᲂу҆́бѡ легкото́ю дѣ́ѧхъ; и҆лѝ ꙗ҆̀же совѣщава́ю, по пло́ти совѣщава́ю; да бꙋ́детъ ᲂу҆ менѐ є҆́же є҆́й, є҆́й: и҆ є҆́же нѝ, нѝ. вѣ́ренъ же бг҃ъ, ꙗ҆́кѡ сло́во на́ше, є҆́же къ ва́мъ, не бы́сть є҆́й и҆ нѝ. и҆́бо бж҃їй сн҃ъ і҆и҃съ хрⷭ҇то́съ, и҆́же ᲂу҆ ва́съ на́ми проповѣ́данный, мно́ю и҆ сїлꙋа́номъ и҆ тїмоѳе́емъ, не бы́сть є҆́й и҆ нѝ: но въ не́мъ само́мъ є҆́й бы́сть. є҆ли̑ка бо ѡ҆бѣтова̑нїѧ бж҃їѧ, въ то́мъ є҆́й, и҆ въ то́мъ а҆ми́нь, бг҃ꙋ къ сла́вѣ на́ми. ",
}

add_apostol {
  ["номер"] = 170,
  ["комментарий"] = "2 Кор., 170 зач., I, 21 – II, 4.",
  ["текст_ру"] = "Бра́тие, известву́яй нас с ва́ми во Христа́ и пома́завый нас Бог, И́же и запечатле́вый нас, и да́вый обруче́ние Ду́ха в сердца́ на́ша. Аз же свиде́теля Бо́га призыва́ю на мою́ ду́шу, я́ко щадя́ вас, ктому́ не приидо́х в Кори́нф, не я́ко облада́ем ве́рою ва́шею, но я́ко споспе́шницы есмы́ ва́шей ра́дости: ве́рою бо стоите́. Суди́х же в себе́ сие́, не па́ки ско́рбию к вам приити́. А́ще бо аз скорбь творю́ вам, то кто есть веселя́яй мя, то́чию прие́мляй скорбь от мене́? И́бо писа́х вам сие́ и́стое, да не прише́д скорбь на скорбь прииму́, о ни́хже подоба́ше ми ра́доватися, наде́яся на вся вы, я́ко моя́ ра́дость всех вас есть. От печа́ли бо мно́гия и туги́ се́рдца написа́х вам мно́гими слеза́ми, не я́ко да оскорбите́ся, но любо́вь да позна́ете, ю́же и́мам изоби́льно к вам. ",
  ["текст_цс"] = "Бра́тїе, и҆звѣствꙋ́ѧй на́съ съ ва́ми во хрⷭ҇та̀, и҆ пома́завый на́съ, бг҃ъ: и҆́же и҆ запечатлѣ́вый на́съ, и҆ да́вый ѡ҆брꙋче́нїе дх҃а въ сердца̀ на́ша. а҆́зъ же свидѣ́телѧ бг҃а призыва́ю на мою̀ дꙋ́шꙋ, ꙗ҆́кѡ щадѧ̀ ва́съ ктомꙋ̀ не прїидо́хъ въ корі́нѳъ: не ꙗ҆́кѡ ѡ҆блада́емъ вѣ́рѣ ва́шей, но ꙗ҆́кѡ споспѣ́шницы є҆смы̀ ва́шей ра́дости: вѣ́рою бо стоитѐ. сꙋди́хъ же въ себѣ̀ сїѐ, не па́ки ско́рбїю къ ва́мъ прїитѝ. а҆́ще бо а҆́зъ ско́рбь творю̀ ва́мъ: то̀ кто̀ є҆́сть веселѧ́ѧй мѧ̀, то́чїю прїе́млѧй ско́рбь ѿ менѐ; и҆́бо писа́хъ ва́мъ сїѐ и҆́стое, да не прише́дъ ско́рбь на ско́рбь прїимꙋ̀, ѡ҆ ни́хже подоба́ше мѝ ра́доватисѧ, надѣ́ѧсѧ на всѧ̀ вы̀: ꙗ҆́кѡ моѧ̀ ра́дость всѣ́хъ ва́съ є҆́сть. ѿ печа́ли бо мно́гїѧ и҆ тꙋгѝ се́рдца написа́хъ ва́мъ мно́гими слеза́ми, не ꙗ҆́кѡ да ѡ҆скорбите́сѧ, но любо́вь да позна́ете, ю҆́же и҆́мамъ и҆з̾ѻби́льнѡ къ ва́мъ. ",
}

add_apostol {
