  ["комментарий"] = "2 Кор., 171 зач., II, 3–15.",
  ["текст_ру"] = "Бра́тие, моя́ ра́дость всех вас есть. От печа́ли бо мно́гия и туги́ се́рдца написа́х вам мно́гими слеза́ми, не я́ко да оскорбите́ся, но любо́вь да позна́ете, ю́же и́мам изоби́льно к вам. А́ще ли кто оскорби́л мене́, не мене́ оскорби́, но от ча́сти, да не отягчу́, всех вас. Дово́льно бо таково́му запреще́ние сие́, е́же от мно́гих. Те́мже сопроти́вное па́че вам дарова́ти и уте́шити, да не ка́ко мно́гою ско́рбию поже́рт бу́дет таковы́й. Те́мже молю́ вы, утверди́те к нему́ любо́вь. На сие́ бо и писа́х, да разуме́ю иску́сство ва́ше, а́ще во всем послушли́ви есте́. Ему́же а́ще что да́руете, и аз, и́бо аз а́ще что дарова́х, ему́же дарова́х, вас ра́ди, о лице́ Иису́с Христо́ве, да не оби́дими бу́дем от сатаны́, не не разумева́ем бо умышле́ний его́. Прише́д же в Троа́ду во благове́стие Христо́во, и две́ри отве́рзене ми бы́вшей о Го́споде, не име́х поко́я ду́ху моему́, не обре́тшу ми Ти́та бра́та моего́, но отре́кся им, изыдо́х в Македо́нию. Бо́гу же благодаре́ние, всегда́ победи́тели нас творя́щему о Христе́ Иису́се и воню́ ра́зума Его́ явля́ющу на́ми во вся́ком ме́сте. Я́ко Христо́во благоуха́ние есмы́ Бо́гови. ",
  ["текст_цс"] = "Бра́тїе, моѧ̀ ра́дость всѣ́хъ ва́съ є҆́сть. ѿ печа́ли бо мно́гїѧ и҆ тꙋгѝ се́рдца написа́хъ ва́мъ мно́гими слеза́ми, не ꙗ҆́кѡ да ѡ҆скорбите́сѧ, но любо́вь да позна́ете, ю҆́же и҆́мамъ и҆з̾ѻби́льнѡ къ ва́мъ. а҆́ще ли кто̀ ѡ҆скорби́лъ менѐ, не менѐ ѡ҆скорбѝ, но ѿ ча́сти, да не ѡ҆тѧгчꙋ̀, всѣ́хъ ва́съ. дово́льно бо таково́мꙋ запреще́нїе сїѐ, є҆́же ѿ мно́гихъ. тѣ́мже сопроти́вное па́че ва́мъ дарова́ти и҆ ᲂу҆тѣ́шити, да не ка́кѡ мно́гою ско́рбїю поже́ртъ бꙋ́детъ таковы́й. тѣ́мже молю́ вы, ᲂу҆тверди́те къ немꙋ̀ любо́вь. на сїе́ бо и҆ писа́хъ, да разꙋмѣ́ю и҆скꙋ́сство ва́ше, а҆́ще во все́мъ послꙋшли́ви є҆стѐ. є҆мꙋ́же а҆́ще что̀ да́рꙋете, и҆ а҆́зъ и҆́бо а҆́зъ а҆́ще что̀ дарова́хъ, є҆мꙋ́же дарова́хъ, ва́съ ра́ди ѡ҆ лицѣ̀ і҆и҃съ хрⷭ҇то́вѣ. да не ѡ҆би́дими бꙋ́демъ ѿ сатаны̀: не не разꙋмѣва́емъ бо ᲂу҆мышле́нїй є҆гѡ̀. прише́дъ же въ трѡа́дꙋ во благовѣ́стїе хрⷭ҇то́во, и҆ две́ри ѿве́рзенѣ мѝ бы́вшей ѡ҆ гдⷭ҇ѣ, не и҆мѣ́хъ поко́ѧ дꙋ́хꙋ моемꙋ̀, не ѡ҆брѣ́тшꙋ мѝ ті́та бра́та моегѡ̀: но ѿре́ксѧ и҆̀мъ, и҆зыдо́хъ въ македо́нїю. бг҃ꙋ же благодаре́нїе, всегда̀ побѣди́тели на́съ творѧ́щемꙋ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, и҆ воню̀ ра́зꙋма є҆гѡ̀ ꙗ҆влѧ́ющꙋ на́ми во всѧ́комъ мѣ́стѣ. ꙗ҆́кѡ хрⷭ҇то́во благоꙋха́нїе є҆смы̀ бг҃ови. ",
}

add_apostol {
  ["номер"] = 172,
  ["комментарий"] = "2 Кор., 172 зач., II, 14 – III, 3.",
  ["текст_ру"] = "Бра́тие, Бо́гу благодаре́ние, всегда́ победи́тели нас творя́щему о Христе́ Иису́се и воню́ ра́зума Его́ явля́ющу на́ми во вся́ком ме́сте. Я́ко Христо́во благоуха́ние есмы́ Бо́гови в спаса́емых и в погиба́ющих. О́вем у́бо воня́ сме́ртная в смерть, о́вем же воня́ живо́тная в живо́т. И к сим кто дово́лен? Не́смы бо, я́коже мно́зи, нечи́сто пропове́дающии сло́во Бо́жие, но я́ко от чистоты́, но я́ко от Бо́га, пред Бо́гом, во Христе́ глаго́лем. Зачина́ем ли па́ки нас саме́х извещава́ти вам? Или́ тре́буем, я́коже не́цыи, извещава́тельных посла́ний к вам, или́ от вас извести́тельных? Посла́ние бо на́ше вы есте́, напи́саное в сердца́х на́ших, зна́емое и прочита́емое от всех челове́к. Явля́еми, я́ко есте́ посла́ние Христо́во слу́женое на́ми, напи́сано не черни́лом, но Ду́хом Бо́га жи́ва, не на скрижа́лех ка́менных, но на скрижа́лех се́рдца пло́тяных. ",
  ["текст_цс"] = "Бра́тїе, бг҃ꙋ благодаре́нїе, всегда̀ побѣди́тели на́съ творѧ́щемꙋ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, и҆ воню̀ ра́зꙋма є҆гѡ̀ ꙗ҆влѧ́ющꙋ на́ми во всѧ́комъ мѣ́стѣ. ꙗ҆́кѡ хрⷭ҇то́во благоꙋха́нїе є҆смы̀ бг҃ови, въ спаса́емыхъ, и҆ въ погиба́ющихъ. ѻ҆́вѣмъ ᲂу҆́бѡ вонѧ̀ сме́ртнаѧ въ сме́рть: ѻ҆́вѣмъ же вонѧ̀ живо́тнаѧ въ живо́тъ. и҆ къ си́мъ кто̀ дово́ленъ; нѣ́смы бо, ꙗ҆́коже мно́зи, нечи́стѡ проповѣ́дающїи сло́во бж҃їе: но ꙗ҆́кѡ ѿ чистоты̀, но ꙗ҆́кѡ ѿ бг҃а, пред̾ бг҃омъ во хрⷭ҇тѣ̀ глаго́лемъ. зачина́емъ ли па́ки ꙗ҆̀же на́съ самѣ́хъ и҆звѣщава́ти ва́мъ; и҆лѝ тре́бꙋемъ, ꙗ҆́коже нѣ́цыи, и҆звѣщава́тельныхъ посла́нїй къ ва́мъ, и҆лѝ ѿ ва́съ и҆звѣсти́тельныхъ; посла́нїе бо на́ше вы̀ є҆стѐ, напи́саное въ сердца́хъ на́шихъ, зна́емое и҆ прочита́емое ѿ всѣ́хъ человѣ̑къ. ꙗ҆влѧ́еми, ꙗ҆́кѡ є҆стѐ посла́нїе хрⷭ҇то́во, слꙋ́женое на́ми, напи́сано не черни́ломъ, но дх҃омъ бг҃а жи́ва: не на скрижа́лѣхъ ка́менныхъ, но на скрижа́лѣхъ се́рдца пло́тѧныхъ. ",
}

add_apostol {
  ["номер"] = 173,
  ["комментарий"] = "2 Кор., 173 зач., III, 4–11.",
  ["текст_ру"] = "Бра́тие, наде́яние таково́ и́мамы Христо́м к Бо́гу, не я́ко дово́льни есмы́ от себе́ помы́слити что, я́ко от себе́, но дово́льство на́ше от Бо́га. И́же и удово́ли нас служи́тели бы́ти Но́ву Заве́ту, не пи́смени, но ду́ху: писмя́ бо убива́ет, а дух животвори́т. А́ще ли служе́ние сме́рти писмены́, образова́но в ка́менех, бысть в сла́ву, я́ко не мощи́ взира́ти сыно́м Изра́илевым на лице́ Моисе́ово, сла́вы ра́ди ли́ца его́ престаю́щия. Ка́ко не мно́жае па́че служе́ние ду́ха бу́дет в сла́ве? А́ще бо служе́ние осужде́ния, сла́ва, мно́го па́че избы́точествует служе́ние пра́вды в сла́ве. И́бо не просла́вися просла́вленное в ча́сти сей, за превосходя́щую сла́ву. А́ще бо престаю́щее, сла́вою, мно́го па́че пребыва́ющее, в сла́ве. ",
  ["текст_цс"] = "Бра́тїе, надѣ́ѧнїе таково̀ и҆́мамы хрⷭ҇то́мъ къ бг҃ꙋ: не ꙗ҆́кѡ дово́льни є҆смы̀ ѿ себѐ помы́слити что̀, ꙗ҆́кѡ ѿ себѐ, но дово́льство на́ше ѿ бг҃а. и҆́же и҆ ᲂу҆дово́ли на́съ слꙋжи́тели бы́ти но́вꙋ завѣ́тꙋ, не пи́смене, но дх҃ꙋ: писмѧ́ бо ᲂу҆бива́етъ, а҆ дх҃ъ животвори́тъ. а҆́ще ли слꙋже́нїе сме́рти писмены̀ ѡ҆бразова́но въ ка́менехъ, бы́сть въ сла́вꙋ, ꙗ҆́кѡ не мощѝ взира́ти сынѡ́мъ і҆и҃левымъ на лицѐ мѡѷсе́ово сла́вы ра́ди лица̀ є҆гѡ̀ престаю́щїѧ: ка́кѡ не мно́жае па́че слꙋже́нїе дх҃а бꙋ́детъ въ сла́вѣ; а҆́ще бо слꙋже́нїе ѡ҆сꙋжде́нїѧ, сла́ва: мно́гѡ па́че и҆збы́точествꙋетъ слꙋже́нїе пра́вды въ сла́вѣ. и҆́бо не просла́висѧ просла́вленное въ ча́сти се́й, за превосходѧ́щꙋю сла́вꙋ. а҆́ще бо престаю́щее, сла́вою: мно́гѡ па́че пребыва́ющее, въ сла́вѣ. ",
}

add_apostol {
