add_apostol {
  ["номер"] = 178,
  ["комментарий"] = "2 Кор., 178 зач., V, 1–10.",
  ["текст_ру"] = "Бра́тие, ве́мы я́ко а́ще земна́я на́ша хра́мина те́ла разори́тся, созда́ние от Бо́га и́мамы, хра́мину нерукотворе́ну, ве́чну на небесе́х. И́бо о сем воздыха́ем, в жили́ще на́ше небе́сное облещи́ся жела́юще, а́ще и обле́кшеся, не на́зи обря́щемся. И́бо су́щии в те́ле сем воздыха́ем отягча́еми, поне́же не хо́щем совлещи́ся, но пооблещи́ся, да поже́рто бу́дет ме́ртвенное живото́м. Сотвори́вый же нас в сие́ и́стое Бог, И́же и даде́ нам обруче́ние Ду́ха. Дерза́юще у́бо всегда́ и ве́дяще, я́ко живу́ще в те́ле отхо́дим от Го́спода: ве́рою бо хо́дим, а не виде́нием. Дерза́ем же и благоволи́м па́че отити́ от те́ла и вни́ти ко Го́споду. Те́мже и тщи́мся, а́ще входя́ще, а́ще отходя́ще, благоуго́дни Ему́ бы́ти. Всем бо яви́тися нам подоба́ет пред суди́щем Христо́вым. ",
  ["текст_цс"] = "Бра́тїе, вѣ́мы ꙗ҆́кѡ а҆́ще земна́ѧ на́ша хра́мина тѣ́ла разори́тсѧ, созда́нїе ѿ бг҃а и҆́мамы хра́минꙋ нерꙋкотворе́нꙋ, вѣ́чнꙋ на нб҃сѣ́хъ. и҆́бо ѡ҆ се́мъ воздыха́емъ, въ жили́ще на́ше нбⷭ҇ное ѡ҆блещи́сѧ жела́юще: а҆́ще и҆ ѡ҆бле́кшесѧ, не на́зи ѡ҆брѧ́щемсѧ. и҆́бо сꙋ́щїи въ тѣ́лѣ се́мъ, воздыха́емъ ѡ҆тѧгча́еми: поне́же не хо́щемъ совлещи́сѧ, но поѡблещи́сѧ: да поже́рто бꙋ́детъ ме́ртвенное живото́мъ. сотвори́вый же на́съ въ сїѐ и҆́стое бг҃ъ, и҆́же и҆ дадѐ на́мъ ѡ҆брꙋче́нїе дх҃а. дерза́юще ᲂу҆́бѡ всегда̀, и҆ вѣ́дѧще, ꙗ҆́кѡ живꙋ́ще въ тѣ́лѣ, ѿхо́димъ ѿ гдⷭ҇а: [вѣ́рою бо хо́димъ, а҆ не видѣ́нїемъ.] дерза́емъ же, и҆ благоволи́мъ па́че ѿитѝ ѿ тѣ́ла, и҆ вни́ти ко гдⷭ҇ꙋ. тѣ́мже и҆ тщи́мсѧ, а҆́ще входѧ́ще, а҆́ще ѿходѧ́ще, благоꙋго́дни є҆мꙋ̀ бы́ти. всѣ́мъ бо ꙗ҆ви́тисѧ на́мъ подоба́етъ пред̾ сꙋди́щемъ хрⷭ҇то́вымъ. ",
}

add_apostol {
  ["номер"] = 179,
  ["комментарий"] = "2 Кор., 179 зач., V, 10–15.",
  ["текст_ру"] = "Бра́тие, всем нам яви́тися подоба́ет пред суди́щем Христо́вым, да прии́мет ко́ждо, я́же с те́лом соде́ла, или́ бла́га, или́ зла. Ве́дуще у́бо страх Госпо́день, челове́ки увещава́ем, Бо́гови же явле́ни бы́хом, упова́ем же, я́ко и в со́вестех ва́ших явле́ни есмы́. Не па́ки бо себе́ хва́лим пред ва́ми, но вину́ дае́м вам похвале́нию по нас, да и́мате к хва́лящымся в лице́, а не в се́рдцы. А́ще бо изуми́хомся, Бо́гови, а́ще ли целому́дрствуем, вам. И́бо любы́ Бо́жия содержи́т нас, су́ждших сие́: я́ко а́ще Еди́н за всех у́мре, то у́бо вси умро́ша. Христо́с же за вся у́мре, да живу́щии не ктому́ себе́ живу́т, но уме́ршему за них и воскре́сшему. ",
  ["текст_цс"] = "Бра́тїе, всѣ́мъ на́мъ ꙗ҆ви́тисѧ подоба́етъ пред̾ сꙋди́щемъ хрⷭ҇то́вымъ да прїи́метъ ко́ждо ꙗ҆̀же съ тѣ́ломъ содѣ́ла, и҆лѝ бла̑га, и҆лѝ ѕла̑. вѣ́дꙋще ᲂу҆̀бо стра́хъ гдⷭ҇нь, человѣ́ки ᲂу҆вѣщава́емъ, бг҃ови же ꙗ҆вле́ни бы́хомъ: ᲂу҆пова́емъ же, ꙗ҆́кѡ и҆ въ со́вѣстехъ ва́шихъ ꙗ҆вле́ни є҆смы̀. не па́ки бо себѐ хва́лимъ пред̾ ва́ми, но винꙋ̀ дае́мъ ва́мъ похвале́нїю по на́съ, да и҆́мате къ хва́лѧщымсѧ въ лицѐ, а҆ не въ се́рдцы. а҆́ще бо и҆зꙋми́хомсѧ, бг҃ови: а҆́ще ли цѣломꙋ́дрствꙋемъ, ва́мъ. и҆́бо любы̀ бж҃їѧ содержи́тъ на́съ сꙋ́ждьшихъ сїѐ: ꙗ҆́кѡ а҆́ще є҆ди́нъ за всѣ́хъ ᲂу҆́мре, то̀ ᲂу҆̀бо всѝ ᲂу҆мро́ша. хрⷭ҇то́съ же за всѧ̑ ᲂу҆́мре, да живꙋ́щїи не ктомꙋ̀ себѣ̀ живꙋ́тъ: но ᲂу҆ме́ршемꙋ за ни́хъ и҆ воскре́сшемꙋ. ",
}

add_apostol {
  ["номер"] = 180,
  ["комментарий"] = "2 Кор., 180 зач., V, 15–21.",
  ["текст_ру"] = "Бра́тие, Христо́с за вся у́мре, да живу́щии не ктому́ себе́ живу́т, но уме́ршему за них и воскре́сшему. Те́мже и мы отны́не ни еди́наго ве́мы по пло́ти, а́ще же и разуме́хом по пло́ти Христа́, но ны́не ктому́ не разуме́ем. Те́мже а́ще ка́я о Христе́, нова́ тварь: дре́вняя мимоидо́ша, се бы́ша вся нова́. Вся́ческая же от Бо́га, примири́вшаго нас Себе́ Иису́с Христо́м и да́вшаго нам служе́ние примире́ния. Зане́ Бог бе во Христе́ мир примиря́я Себе́, не вменя́я им согреше́ний их и положи́в в нас сло́во примире́ния. По Христе́ у́бо мо́лим, я́ко Бо́гу моля́щу на́ми, мо́лимся у́бо по Христе́, примири́теся с Бо́гом. Не ве́девшаго бо греха́ по нас грех сотвори́, да мы бу́дем пра́вда Бо́жия о Нем. ",
  ["текст_цс"] = "Бра́тїе, хрⷭ҇то́съ за всѧ̑ ᲂу҆́мре, да живꙋ́щїи не ктомꙋ̀ себѣ̀ живꙋ́тъ: но ᲂу҆ме́ршемꙋ за ни́хъ и҆ воскре́сшемꙋ. тѣ́мже и҆ мы̀ ѿ ны́нѣ ни є҆ди́нагѡ вѣ́мы по пло́ти: а҆́ще же и҆ разꙋмѣ́хомъ по пло́ти хрⷭ҇та̀, но ны́нѣ ктомꙋ̀ не разꙋмѣ́емъ. тѣ́мже а҆́ще ка́ѧ ѡ҆ хрⷭ҇тѣ̀, нова̀ тва́рь: дрє́внѧѧ мимоидо́ша, сѐ бы́ша всѧ̑ нѡва̀. всѧ́чєскаѧ же ѿ бг҃а, примири́вшагѡ на́съ себѣ̀ і҆и҃съ хрⷭ҇то́мъ, и҆ да́вшагѡ на́мъ слꙋже́нїе примире́нїѧ. занѐ бг҃ъ бѣ̀ во хрⷭ҇тѣ̀ мі́ръ примирѧ́ѧ себѣ̀, не вмѣнѧ́ѧ и҆̀мъ согрѣше́нїй и҆́хъ: и҆ положи́въ въ на́съ сло́во примире́нїѧ. по хрⷭ҇тѣ̀ ᲂу҆́бѡ мо́лимъ, ꙗ҆́кѡ бг҃ꙋ молѧ́щꙋ на́ми: мо́лимсѧ ᲂу҆́бѡ по хрⷭ҇тѣ̀, примири́тесѧ съ бг҃омъ. не вѣ́дѣвшаго бо грѣха̀, по на́съ грѣ́хъ сотворѝ, да мы̀ бꙋ́демъ пра́вда бж҃їѧ ѡ҆ не́мъ. ",
}

