add_apostol {
  ["номер"] = 182,
  ["комментарий"] = "2 Кор., 182 зач., VI, 11–16.",
  ["текст_ру"] = "Бра́тие, уста́ на́ша отверзо́шася к вам, Кори́нфяне, се́рдце на́ше распространи́ся. Не те́сно вмеща́етеся в нас, утесня́етеся же во утро́бах ва́ших. То́жде возме́здие, я́коже ча́дом глаго́лю, распространи́теся и вы. Не быва́йте удо́бь прело́жни ко ино́му ярму́, я́коже неве́рнии. Ко́е бо прича́стие пра́вде к беззако́нию? Или́ ко́е обще́ние све́ту ко тьме? Ко́е же согла́сие Христо́ви с велиа́ром? Или́ ка́я часть ве́рну с неве́рным? Или́ ко́е сложе́ние це́ркви Бо́жией со и́долы? Вы бо есте́ це́ркви Бо́га жи́ва, я́коже рече́ Бог. ",
  ["текст_цс"] = "Бра́тїе, ᲂу҆ста̀ на́ша ѿверзо́шасѧ къ ва́мъ корі́нѳѧне, се́рдце на́ше распространи́сѧ. не тѣ́снѡ вмѣща́етесѧ въ на́съ, ᲂу҆тѣснѧ́етесѧ же во ᲂу҆тро́бахъ ва́шихъ. то́жде возме́здїе [ꙗ҆́коже ча́дѡмъ глаго́лю,] распространи́тесѧ и҆ вы̀. не быва́йте ᲂу҆до́бь прело́жни ко и҆но́мꙋ ꙗ҆рмꙋ̀, ꙗ҆́коже невѣ́рнїи: ко́е бо прича́стїе пра́вдѣ къ беззако́нїю; и҆лѝ ко́е ѻ҆бще́нїе свѣ́тꙋ ко тмѣ̀; ко́е же согла́сїе хрⷭ҇то́ви съ велїа́ромъ; и҆лѝ ка́ѧ ча́сть вѣ́рнꙋ съ невѣ́рнымъ; и҆лѝ ко́е сложе́нїе цр҃кви бж҃їей со і҆́дѡлы; вы́ бо є҆стѐ цр҃кви бг҃а жи́ва, ꙗ҆́коже речѐ бг҃ъ. ",
}

add_apostol {
