add_apostol {
  ["номер"] = 200,
  ["комментарий"] = "Гал., 200 зач., I, 11–19.",
  ["текст_ру"] = "Бра́тие, сказу́ю вам, Благовествова́ние благовеще́нное от мене́, я́ко несть по челове́ку. Ни бо аз от челове́ка прия́х е́, ниже́ научи́хся, но явле́нием Иису́с Христо́вым. Слы́шасте бо мое́ житие́ иногда́ в жидо́встве, я́ко попремно́гу гони́х Це́рковь Бо́жию и разруша́х ю́, и преспева́х в жидо́встве па́че мно́гих све́рстник мои́х в ро́де мое́м, и́злиха ревни́тель сый оте́ческих мои́х преда́ний. Егда́ же благоволи́ Бог, Избра́вый мя от чре́ва ма́тере моея́ и призва́вый благода́тию Свое́ю, яви́ти Сы́на Своего́ во мне, да благовеству́ю Его́ во язы́цех, а́бие не приложи́хся пло́ти и кро́ви, ни взыдо́х во Иерусали́м к пре́дним мене́ апо́столом, но идо́х во Арави́ю, и па́ки возврати́хся в Дама́ск. Пото́м же по трие́х ле́тех взыдо́х во Иерусали́м согля́дати Петра́, и пребы́х у него́ дний пятьна́десять. Ино́го же от апо́стол не ви́дех, то́кмо Иа́кова бра́та Госпо́дня. ",
  ["текст_цс"] = "Бра́тїе, сказꙋ́ю ва́мъ бл҃говѣствова́нїе бл҃говѣще́нное ѿ менѐ, ꙗ҆́кѡ нѣ́сть по человѣ́кꙋ. ни бо а҆́зъ ѿ человѣ́ка прїѧ́хъ є҆̀, нижѐ наꙋчи́хсѧ: но ꙗ҆вле́нїемъ і҆и҃съ хрⷭ҇то́вымъ. слы́шасте бо моѐ житїѐ и҆ногда̀ въ жидо́вствѣ, ꙗ҆́кѡ попремно́гꙋ гони́хъ це́рковь бж҃їю, и҆ разрꙋша́хъ ю҆̀: и҆ преспѣва́хъ въ жидо́вствѣ па́че мно́гихъ свє́рстникъ мои́хъ въ ро́дѣ мое́мъ, и҆́злиха ревни́тель сы́й ѻ҆те́ческихъ мои́хъ преда́нїй. є҆гда́ же благоволѝ бг҃ъ, и҆збра́вый мѧ̀ ѿ чре́ва ма́тере моеѧ̀, и҆ призва́вый бл҃года́тїю свое́ю, ꙗ҆ви́ти сн҃а своего̀ во мнѣ̀, да бл҃говѣствꙋ́ю є҆го̀ во ꙗ҆зы́цѣхъ: а҆́бїе не приложи́хсѧ пло́ти и҆ кро́ви, ни взыдо́хъ во і҆ерꙋсали́мъ къ прє́днимъ менѐ а҆по́столѡмъ: но и҆до́хъ во а҆раві́ю, и҆ па́ки возврати́хсѧ въ дама́скъ. пото́мъ же по трїе́хъ лѣ́тѣхъ взыдо́хъ во і҆ерꙋсали́мъ соглѧ́дати петра̀, и҆ пребы́хъ ᲂу҆ негѡ̀ дні́й пѧтьна́десѧть. и҆но́гѡ же ѿ а҆по́стѡлъ не ви́дѣхъ, то́кмѡ і҆а́кѡва бра́та гдⷭ҇нѧ. ",
}

add_apostol {
  ["номер"] = 201,
  ["комментарий"] = "Гал., 201 зач., II, 6–10.",
  ["текст_ру"] = "Бра́тие, от мня́щихся бы́ти что, якови́ не́когда бе́ша, ничто́же ми ра́знствует: лица́ Бог челове́ча не прие́млет. Мне бо мни́мии ничто́же привозложи́ша, но сопроти́вное, уразуме́вше, я́ко уве́рено ми бысть благове́стие необре́зания, я́коже Петру́ обре́зания. И́бо Споспе́шествовавый Петру́ в посла́ние обре́зания, поспе́шествова и мне во язы́ки. И позна́вше благода́ть да́нную ми, Иа́ков и Ки́фа и Иоа́нн, мни́мии столпи́ бы́ти, де́сная да́ша мне и Варна́ве обще́ния, да мы во язы́ки, они́ же во обре́зание, то́чию ни́щих да по́мнима, е́же и потща́хся сие́ и́стое сотвори́ти. ",
  ["текст_цс"] = "Бра́тїе, ѿ мнѧ́щихсѧ бы́ти что̀, [ꙗ҆ковѝ нѣ́когда бѣ́ша, ничто́же мѝ ра́знствꙋетъ: лица̀ бг҃ъ человѣ́ча не прїе́млетъ.] мнѣ́ бо мни́мїи ничто́же привозложи́ша: но сопроти́вное, ᲂу҆разꙋмѣ́вше, ꙗ҆́кѡ ᲂу҆вѣ́рено мѝ бы́сть бл҃говѣ́стїе неѡбрѣ́занїѧ, ꙗ҆́коже петрꙋ̀ ѡ҆брѣ́занїѧ. [и҆́бо споспѣ́шествовавый петрꙋ̀ въ посла́нїе ѡ҆брѣ́занїѧ, поспѣ́шествова и҆ мнѣ̀ во ꙗ҆зы́ки.] и҆ позна́вше бл҃года́ть да́ннꙋю мѝ, і҆а́кѡвъ, и҆ ки́фа, и҆ і҆ѡа́ннъ, мни́мїи столпѝ бы́ти, дє́снаѧ да́ша мнѣ̀ и҆ варна́вѣ ѻ҆бще́нїѧ, да мы̀ во ꙗ҆зы́ки, ѻ҆ни́ же во ѡ҆брѣ́занїе: то́чїю ни́щихъ да по́мнима, є҆́же и҆ потща́хсѧ сїѐ и҆́стое сотвори́ти. ",
}

add_apostol {
  ["номер"] = 202,
  ["комментарий"] = "Гал., 202 зач., II, 11–16.",
  ["текст_ру"] = "Бра́тие, егда́ прии́де Петр во Антиохи́ю, в лице́ ему́ проти́вустах, я́ко зазо́рен бе. Пре́жде бо да́же не приити́ не́ким от Иа́кова, с язы́ки ядя́ше, егда́ же приидо́ша, опря́ташеся и отлуча́шеся, боя́ся су́щих от обре́зания. И лицеме́ришася с ним и про́чии иуде́и, я́ко и Варна́ве приста́ти лицеме́рству их. Но егда́ ви́дех, я́ко не пра́во хо́дят ко и́стине Благовествова́ния, реко́х Петру́ пред все́ми: а́ще ты, иуде́й сый, язы́чески, а не иуде́йски живе́ши, почто́ язы́ки ну́диши иуде́йски жи́тельствовати? Мы естество́м иуде́и, а не от язы́к гре́шницы. Уве́девше же, я́ко не оправди́тся челове́к от дел зако́на, но то́кмо ве́рою Иису́с Христо́вою, и мы во Христа́ Иису́са ве́ровахом, да оправди́мся от ве́ры Христо́вы, а не от дел зако́на, зане́ не оправди́тся от дел зако́на вся́ка плоть. ",
  ["текст_цс"] = "Бра́тїе, є҆гда̀ прїи́де пе́тръ во а҆нтїохі́ю, въ лицѐ є҆мꙋ̀ проти́вꙋ ста́хъ, ꙗ҆́кѡ зазо́ренъ бѣ̀. пре́жде бо да́же не прїитѝ нѣ̑кимъ ѿ і҆а́кѡва, съ ꙗ҆зы́ки ꙗ҆дѧ́ше: є҆гда́ же прїидо́ша, ѡ҆прѧ́ташесѧ и҆ ѿлꙋча́шесѧ, боѧ́сѧ сꙋ́щихъ ѿ ѡ҆брѣ́занїѧ. и҆ лицемѣ́ришасѧ съ ни́мъ и҆ про́чїи і҆ꙋдє́и, ꙗ҆́кѡ и҆ варна́вѣ приста́ти лицемѣ́рствꙋ и҆́хъ. но є҆гда̀ ви́дѣхъ, ꙗ҆́кѡ не пра́вѡ хо́дѧтъ ко и҆́стинѣ бл҃говѣствова́нїѧ, реко́хъ петрꙋ̀ пред̾ всѣ́ми: а҆́ще ты̀ і҆ꙋде́й сы́й, ꙗ҆зы́чески а҆ не і҆ꙋде́йски живе́ши, почто̀ ꙗ҆зы́ки нꙋ́диши і҆ꙋде́йски жи́тельствовати; мы̀ є҆стество́мъ і҆ꙋдє́и, а҆ не ѿ ꙗ҆зы̑къ грѣ́шницы. ᲂу҆вѣ́дѣвше же, ꙗ҆́кѡ не ѡ҆правди́тсѧ человѣ́къ ѿ дѣ́лъ зако́на, но то́кмѡ вѣ́рою і҆и҃съ хрⷭ҇то́вою, и҆ мы̀ во хрⷭ҇та̀ і҆и҃са вѣ́ровахомъ, да ѡ҆правди́мсѧ ѿ вѣ́ры хрⷭ҇то́вы, а҆ не ѿ дѣ́лъ зако́на: занѐ не ѡ҆правди́тсѧ ѿ дѣ́лъ зако́на всѧ́ка пло́ть. ",
}

add_apostol {
  ["номер"] = 203,
  ["комментарий"] = "Гал., 203 зач., II, 16–20.",
  ["текст_ру"] = "Бра́тие, уве́девше я́ко не оправди́тся челове́к от дел зако́на, но то́кмо ве́рою Иису́с Христо́вою, и мы во Христа́ Иису́са ве́ровахом, да оправди́мся от ве́ры Христо́вы, а не от дел зако́на, зане́ не оправди́тся от дел зако́на вся́ка плоть. А́ще ли, и́щуще оправди́тися о Христе́, обрето́хомся и са́ми гре́шницы, Христо́с у́бо греху́ ли служи́тель? Да не бу́дет. А́ще бо, я́же разори́х, сия́ па́ки созида́ю, престу́пника себе́ представля́ю. Аз бо зако́ном зако́ну умро́х, да Бо́гови жив бу́ду. Христо́ви сраспя́хся. Живу́ же не ктому́ аз, но живе́т во мне Христо́с. А е́же ны́не живу́ во пло́ти, ве́рою живу́ Сы́на Бо́жия, возлюби́вшаго мене́ и преда́вшаго Себе́ по мне. ",
  ["текст_цс"] = "Бра́тїе, ᲂу҆вѣ́дѣвше ꙗ҆́кѡ не ѡ҆правди́тсѧ человѣ́къ ѿ дѣ́лъ зако́на, но то́кмѡ вѣ́рою і҆и҃съ хрⷭ҇то́вою, и҆ мы̀ во хрⷭ҇та̀ і҆и҃са вѣ́ровахомъ, да ѡ҆правди́мсѧ ѿ вѣ́ры хрⷭ҇то́вы, а҆ не ѿ дѣ́лъ зако́на: занѐ не ѡ҆правди́тсѧ ѿ дѣ́лъ зако́на всѧ́ка пло́ть. а҆́ще ли и҆́щꙋще ѡ҆правди́тисѧ ѡ҆ хрⷭ҇тѣ̀, ѡ҆брѣто́хомсѧ и҆ са́ми грѣ́шницы: хрⷭ҇то́съ ᲂу҆́бѡ грѣхꙋ́ ли слꙋжи́тель; да не бꙋ́детъ. а҆́ще бо ꙗ҆̀же разори́хъ, сїѧ̑ па́ки созида́ю, престꙋ́пника себѐ представлѧ́ю. а҆́зъ бо зако́номъ зако́нꙋ ᲂу҆мро́хъ, да бг҃ови жи́въ бꙋ́дꙋ: хрⷭ҇то́ви сраспѧ́хсѧ. живꙋ́ же не ктомꙋ̀ а҆́зъ, но живе́тъ во мнѣ̀ хрⷭ҇то́съ: а҆ є҆́же ны́нѣ живꙋ̀ во пло́ти, вѣ́рою живꙋ̀ сн҃а бж҃їѧ, возлюби́вшагѡ менѐ, и҆ преда́вшагѡ себѐ по мнѣ̀. ",
}

add_apostol {
  ["номер"] = 204,
  ["комментарий"] = "Гал., 204 зач., II, 21 – III, 7.",
  ["текст_ру"] = "Бра́тие, не отмета́ю благода́ти Бо́жия. А́ще бо зако́ном пра́вда, у́бо Христо́с ту́не у́мре. О, несмы́сленнии Гала́те, кто вы прельсти́л есть не покори́тися и́стине, и́мже пред очи́ма Иису́с Христо́с преднапи́сан бысть, в вас ра́спят? Сие́ еди́но хощу́ уве́дети от вас, от дел ли зако́на Ду́ха прия́сте, или́ от слу́ха ве́ры? Та́ко ли несмы́сленни есте́? Наче́нше ду́хом, ны́не пло́тию скончава́ете? Толи́ка пострада́сте ту́не, а́ще же и ту́не. Подая́й у́бо вам Ду́ха и де́йствуяй си́лы в вас, от дел ли зако́на, или́ от слу́ха ве́ры? Я́коже Авраа́м ве́рова Бо́гу, и вмени́ся ему́ в пра́вду. Разуме́йте у́бо, я́ко су́щии от ве́ры, си́и суть сы́нове Авраа́мли. ",
  ["текст_цс"] = "Бра́тїе, не ѿмета́ю бл҃года́ти бж҃їѧ: а҆́ще бо зако́номъ пра́вда, ᲂу҆̀бо хрⷭ҇то́съ тꙋ́не ᲂу҆́мре. ѽ несмы́сленнїи гала́тє, кто́ вы прельсти́лъ є҆́сть не покори́тисѧ и҆́стинѣ, и҆̀мже пред̾ ѻ҆чи́ма і҆и҃съ хрⷭ҇то́съ преднапи́санъ бы́сть, въ ва́съ ра́спѧтъ; сїѐ є҆ди́но хощꙋ̀ ᲂу҆вѣ́дѣти ѿ ва́съ, ѿ дѣ́лъ ли зако́на дх҃а прїѧ́сте, и҆лѝ ѿ слꙋ́ха вѣ́ры; та́кѡ ли несмы́сленни є҆стѐ: наче́нше дх҃омъ, ны́нѣ пло́тїю скончава́ете; толи̑ка пострада́сте тꙋ́не, а҆́ще же и҆ тꙋ́не. подаѧ́й ᲂу҆̀бо ва́мъ дх҃а, и҆ дѣ́йствꙋѧй си̑лы въ ва́съ, ѿ дѣ́лъ ли зако́на, и҆лѝ ѿ слꙋ́ха вѣ́ры; ꙗ҆́коже а҆враа́мъ вѣ́рова бг҃ꙋ, и҆ вмѣни́сѧ є҆мꙋ̀ въ пра́вдꙋ. разꙋмѣ́йте ᲂу҆̀бо, ꙗ҆́кѡ сꙋ́щїи ѿ вѣ́ры, сі́и сꙋ́ть сы́нове а҆враа́мли. ",
}

add_apostol {
  ["номер"] = 205,
  ["комментарий"] = "Гал., 205 зач., III, 8–12.",
  ["текст_ру"] = "Бра́тие, предуви́девше Писа́ние, я́ко от ве́ры оправда́ет язы́ки Бог, пре́жде благовествова́ Авраа́му, я́ко благословя́тся о тебе́ вси язы́цы. Те́мже су́щии от ве́ры, благословя́тся с ве́рным Авраа́мом. Ели́цы бо от дел зако́на суть, под кля́твою суть. Пи́сано бо есть: про́клят всяк, и́же не пребу́дет во всех пи́санных в кни́зе зако́нней, я́ко твори́ти я́. А я́ко в зако́не никто́же оправда́ется от Бо́га, я́ве, я́ко пра́ведный от ве́ры жив бу́дет. Зако́н же несть от ве́ры, но сотвори́вый та челове́к жив бу́дет в них. ",
  ["текст_цс"] = "Бра́тїе, пред̾ꙋви́дѣвше писа́нїе, ꙗ҆́кѡ ѿ вѣ́ры ѡ҆правда́етъ ꙗ҆зы́ки бг҃ъ, пре́жде бл҃говѣствова̀ а҆враа́мꙋ: ꙗ҆́кѡ бл҃гословѧ́тсѧ ѡ҆ тебѣ̀ всѝ ꙗ҆зы́цы. тѣ́мже сꙋ́щїи ѿ вѣ́ры благословѧ́тсѧ съ вѣ́рнымъ а҆враа́момъ. є҆ли́цы бо ѿ дѣ́лъ зако́на сꙋ́ть, под̾ клѧ́твою сꙋ́ть: пи́сано бо є҆́сть: про́клѧтъ всѧ́къ, и҆́же не пребꙋ́детъ во всѣ́хъ пи́санныхъ въ кни́зѣ зако́ннѣй, ꙗ҆́кѡ твори́ти ѧ҆̀. а҆ ꙗ҆́кѡ въ зако́нѣ никто́же ѡ҆правда́етсѧ ѿ бг҃а, ꙗ҆́вѣ, ꙗ҆́кѡ пра́ведный ѿ вѣ́ры жи́въ бꙋ́детъ. зако́нъ же нѣ́сть ѿ вѣ́ры: но сотвори́вый та̑ человѣ́къ жи́въ бꙋ́детъ въ ни́хъ. ",
}

add_apostol {
  ["номер"] = 206,
  ["комментарий"] = "Гал., 206 зач., 1 Кор., V, 6–8; Гал., III, 13–14.",
  ["текст_ру"] = "Бра́тие, мал квас все смеше́ние ква́сит. Очи́стите у́бо ве́тхий квас, да бу́дете но́во смеше́ние, я́коже есте́ безква́сни, и́бо Па́сха на́ша за ны пожре́н бысть, Христо́с. Те́мже да пра́зднуем, не в ква́се ве́тсе ни в ква́се зло́бы и лука́вства, но в безква́сиих чистоты́ и и́стины. Христо́с ны искупи́л есть от кля́твы зако́нныя, быв по нас кля́тва. Пи́сано бо есть: про́клят всяк ви́сяй на дре́ве. Да в язы́цех благослове́ние Авраа́мле бу́дет о Христе́ Иису́се да обетова́ние Ду́ха прии́мем ве́рою. ",
  ["текст_цс"] = "Бра́тїе, ма́лъ ква́съ всѐ смѣше́нїе ква́ситъ; ѡ҆чи́стите ᲂу҆̀бо ве́тхїй ква́съ, да бꙋ́дете но́во смѣше́нїе, ꙗ҆́коже є҆стѐ безква́сни: и҆́бо па́сха на́ша за ны̀ пожре́нъ бы́сть хрⷭ҇то́съ. тѣ́мже да пра́зднꙋемъ, не въ ква́сѣ ве́тсѣ, ни въ ква́сѣ ѕло́бы и҆ лꙋка́вства, но въ безква́сїихъ чистоты̀ и҆ и҆́стины. хрⷭ҇то́съ ны̀ и҆скꙋпи́лъ є҆́сть ѿ клѧ́твы зако́нныѧ, бы́въ по на́съ клѧ́тва: пи́сано бо є҆́сть: про́клѧтъ всѧ́къ ви́сѧй на дре́вѣ. да въ ꙗ҆зы́цѣхъ бл҃гослове́нїе а҆враа́мле бꙋ́детъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, да ѡ҆бѣтова́нїе дх҃а прїи́мемъ вѣ́рою. ",
