add_apostol {
  ["номер"] = 207,
  ["комментарий"] = "Гал., 207 зач., III, 15–22.",
  ["текст_ру"] = "Бра́тие, по челове́ку глаго́лю, оба́че челове́ку предутвержде́нна заве́та никто́же отмета́ет или́ приповелева́ет. Авраа́му же рече́ни бы́ша обе́ты, и се́мени его́. Не глаго́лет же: и се́менем, я́ко о мно́зех, но я́ко о еди́ном: и се́мени твоему́, и́же есть Христо́с. Сие́ же глаго́лю, заве́та предутвержде́нна от Бо́га во Христа́, и́же по ле́тех четы́риста и три́десятих бы́вый зако́н не отмета́ет, во е́же разори́ти обетова́ние. А́ще бо от зако́на насле́дие, не ктому́ уже́ от обетова́ния, Авраа́му же обетова́нием дарова́ Бог. Что у́бо зако́н? Преступле́ния ра́ди приложи́ся, до́ндеже прии́дет се́мя, ему́же обетова́ся, вчине́н А́нгелы, руко́ю хода́тая. Хода́тай же еди́наго несть, Бог же еди́н есть. Зако́н ли у́бо проти́ву обетова́нием Бо́жиим? Да не бу́дет. А́ще бо дан бысть зако́н моги́й оживи́ти, вои́стинну от зако́на бы была́ пра́вда. Но затвори́ Писа́ние всех под грехо́м, да обетова́ние от ве́ры Иису́с Христо́вы да́стся ве́рующым. ",
  ["текст_цс"] = "Бра́тїе, по человѣ́кꙋ глаго́лю ѻ҆ба́че чл҃вѣ́кꙋ пред̾ꙋтвержде́нна завѣ́та никто́же ѿмета́етъ, и҆лѝ приповелѣва́етъ. а҆враа́мꙋ же рече́ни бы́ша ѡ҆бѣ́ты, и҆ сѣ́мени є҆гѡ̀: не глаго́летъ же, и҆ сѣ́менємъ, ꙗ҆́кѡ ѡ҆ мно́зѣхъ, но ꙗ҆́кѡ ѡ҆ є҆ди́номъ, и҆ сѣ́мени твоемꙋ̀, и҆́же є҆́сть хрⷭ҇то́съ. сїе́ же глаго́лю, завѣ́та пред̾ꙋтвержде́нна ѿ бг҃а во хрⷭ҇та̀, и҆́же по лѣ́тѣхъ четы́риста и҆ три́десѧтихъ бы́вый зако́нъ не ѿмета́етъ, во є҆́же разори́ти ѡ҆бѣтова́нїе. а҆́ще бо ѿ зако́на наслѣ́дїе, не ктомꙋ̀ ᲂу҆жѐ ѿ ѡ҆бѣтова́нїѧ: а҆враа́мꙋ же ѡ҆бѣтова́нїемъ дарова̀ бг҃ъ. что̀ ᲂу҆̀бо зако́нъ; престꙋпле́нїѧ ра́ди приложи́сѧ, до́ндеже прїи́детъ сѣ́мѧ, є҆мꙋ́же ѡ҆бѣтова́сѧ, вчине́нъ а҆́гг҃лы рꙋко́ю хода́таѧ. хода́тай же є҆ди́нагѡ нѣ́сть: бг҃ъ же є҆ди́нъ є҆́сть. зако́нъ ли ᲂу҆̀бо проти́вꙋ ѡ҆бѣтова́нїємъ бж҃їимъ; да не бꙋ́детъ: а҆́ще бо да́нъ бы́сть зако́нъ могі́й ѡ҆живи́ти, вои́стиннꙋ ѿ зако́на бы была̀ пра́вда. но затворѝ писа́нїе всѧ̑ под̾ грѣхо́мъ, да ѡ҆бѣтова́нїе ѿ вѣ́ры і҆и҃съ хрⷭ҇то́вы да́стсѧ вѣ́рꙋющымъ. ",
}

add_apostol {
  ["номер"] = 208,
  ["комментарий"] = "Гал., 208 зач., III, 23–29.",
  ["текст_ру"] = "Бра́тие, пре́жде прише́ствия ве́ры, под зако́ном стрего́ми бе́хом, затворе́ни в хотя́щую ве́ру откры́тися. Те́мже зако́н пе́стун нам бысть во Христа́, да от ве́ры оправди́мся. Прише́дши же ве́ре, уже́ не под пе́стуном есмы́. Вси бо вы сы́нове Бо́жии есте́ ве́рою о Христе́ Иису́се: ели́цы бо во Христа́ крести́стеся, во Христа́ облеко́стеся. Несть иуде́й, ни е́ллин, несть раб, ни свобо́дь, несть му́жеский пол, ни же́нский, вси бо вы еди́но есте́ о Христе́ Иису́се. А́ще ли вы Христо́вы, у́бо Авраа́мле се́мя есте́, и по обетова́нию насле́дницы. ",
  ["текст_цс"] = "Бра́тїе, пре́жде прише́ствїѧ вѣ́ры, под̾ зако́номъ стрего́ми бѣ́хомъ, затворе́ни въ хотѧ́щꙋю вѣ́рꙋ ѿкры́тисѧ. тѣ́мже зако́нъ пѣ́стꙋнъ на́мъ бы́сть во хрⷭ҇та̀, да ѿ вѣ́ры ѡ҆правди́мсѧ. прише́дши же вѣ́рѣ, ᲂу҆жѐ не под̾ пѣ́стꙋномъ є҆смы̀. вси́ бо вы̀ сы́нове бж҃їи є҆стѐ вѣ́рою ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: є҆ли́цы бо во хрⷭ҇та̀ крⷭ҇ти́стесѧ, во хрⷭ҇та̀ ѡ҆блеко́стесѧ. нѣ́сть і҆ꙋде́й, ни є҆́ллинъ: нѣ́сть ра́бъ, ни свобо́дь: нѣ́сть мꙋ́жескїй по́лъ, ни же́нскїй: вси́ бо вы̀ є҆ди́но є҆стѐ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. а҆́ще ли вы̀ хрⷭ҇то́вы: ᲂу҆̀бо а҆враа́мле сѣ́мѧ є҆стѐ, и҆ по ѡ҆бѣтова́нїю наслѣ́дницы. ",
}

