  ["текст_ру"] = "Бра́тие, Бог бога́т сый в ми́лости, за премно́гую любо́вь Свою́, е́юже возлюби́ нас, и су́щих нас ме́ртвых прегреше́ньми, сооживи́ Христо́м, благода́тию есте́ спасе́ни, и с Ним воскреси́, и спосади́ на небе́сных во Христе́ Иису́се да яви́т в ве́цех гряду́щих презе́льное бога́тство благода́ти Своея́ благосты́нею на нас о Христе́ Иису́се. Благода́тию бо есте́ спасе́ни чрез ве́ру, и сие́ не от вас, Бо́жий дар, не от дел, да никто́же похва́лится. Того́ бо есмы́ творе́ние, созда́ни во Христе́ Иису́се на дела́ блага́я, я́же пре́жде угото́ва Бог, да в них хо́дим. ",
  ["текст_цс"] = "Бра́тїе, бг҃ъ бога́тъ сы́й въ млⷭ҇ти, за премно́гꙋю любо́вь свою̀, є҆́юже возлюбѝ на́съ: и҆ сꙋ́щихъ на́съ ме́ртвыхъ прегрѣше́ньми, соѡживѝ хрⷭ҇то́мъ: [бл҃года́тїю є҆стѐ спасе́ни:] и҆ съ ни́мъ воскресѝ, и҆ спосадѝ на нбⷭ҇ныхъ во хрⷭ҇тѣ̀ і҆и҃сѣ: да ꙗ҆ви́тъ въ вѣ́цѣхъ грѧдꙋ́щихъ преѕѣ́льное бога́тство бл҃года́ти своеѧ̀, бл҃госты́нею на на́съ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. бл҃года́тїю бо є҆стѐ спасе́ни чрез̾ вѣ́рꙋ: [и҆ сїѐ не ѿ ва́съ, бж҃їй да́ръ:] не ѿ дѣ́лъ, да никто́же похва́литсѧ. тогѡ́ бо є҆смы̀ творе́нїе, созда́ни ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ на дѣла̀ блага́ѧ, ꙗ҆̀же пре́жде ᲂу҆гото́ва бг҃ъ, да въ ни́хъ хо́димъ. ",
}

add_apostol {
  ["номер"] = 220,
  ["комментарий"] = "Еф., 220 зач., II, 11-13.",
  ["текст_ру"] = "Бра́тие, помина́йте, я́ко вы, и́же иногда́ язы́цы во пло́ти, глаго́лемии необре́зание от реко́маго обре́зания во пло́ти, рукотворе́ннаго, я́ко бе́сте во вре́мя о́но без Христа́, отчужде́ни жития́ Изра́илева и чу́жди от заве́т обетова́ния, упова́ния не иму́ще и безбо́жни в ми́ре. Ны́не же о Христе́ Иису́се, вы бы́вшии иногда́ дале́че, близ бы́сте Кро́вию Христо́вою. ",
  ["текст_цс"] = "Бра́тїе, помина́йте, ꙗ҆́кѡ вы̀, и҆̀же и҆ногда̀ ꙗ҆зы́цы во пло́ти, глаго́лемїи неѡбрѣ́занїе, ѿ реко́магѡ ѡ҆брѣ́занїѧ во пло́ти рꙋкотворе́ннагѡ: ꙗ҆́кѡ бѣ́сте во вре́мѧ ѻ҆́но без̾ хрⷭ҇та̀, ѿчꙋжде́ни житїѧ̀ і҆и҃лева, и҆ чꙋ́жди ѿ завѣ̑тъ ѡ҆бѣтова́нїѧ, ᲂу҆пова́нїѧ не и҆мꙋ́ще, и҆ безбо́жни въ мі́рѣ. ны́нѣ же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, вы̀ бы́вшїи и҆ногда̀ дале́че, бли́зъ бы́сте кро́вїю хрⷭ҇то́вою. ",
}

add_apostol {
  ["номер"] = 221,
  ["комментарий"] = "Еф., 221 зач., II, 14–22.",
  ["текст_ру"] = "Бра́тие, Христо́с есть мир наш, сотвори́вый обоя́ еди́но, и средосте́ние огра́ды разори́вый, вражду́ Пло́тию Свое́ю, зако́н за́поведей уче́ньми упраздни́в, да о́ба сози́ждет Собо́ю во еди́наго но́ваго челове́ка, творя́ мир, и примири́т обои́х во еди́ном те́ле Бо́гови кресто́м, уби́в вражду́ на нем. И прише́д благовести́ мир вам, да́льним и бли́жним, зане́ Тем и́мамы приведе́ние о́бои во еди́ном Ду́се ко Отцу́. Те́мже у́бо ктому́ не́сте стра́нни и прише́льцы, но сожи́теле святы́м и при́снии Бо́гу, назда́ни бы́вше на основа́нии Апо́стол и проро́к, су́щу краеуго́льну Самому́ Иису́су Христу́, о Не́мже вся́ко созда́ние составля́емо расте́т в це́рковь святу́ю о Го́споде, о Не́мже и вы созида́етеся в жили́ще Бо́жие Ду́хом. ",
  ["текст_цс"] = "Бра́тїе, хрⷭ҇то́съ є҆́сть ми́ръ на́шъ, сотвори́вый ѻ҆боѧ̑ є҆ди́но, и҆ средостѣ́нїе ѡ҆гра́ды разори́вый, враждꙋ̀ пло́тїю свое́ю, зако́нъ за́повѣдей ᲂу҆че́ньми ᲂу҆праздни́въ, да ѻ҆́ба сози́ждетъ собо́ю во є҆ди́наго но́ваго человѣ́ка, творѧ̀ ми́ръ: и҆ примири́тъ ѻ҆бои́хъ во є҆ди́номъ тѣ́лѣ бг҃ови крⷭ҇то́мъ, ᲂу҆би́въ враждꙋ̀ на не́мъ. и҆ прише́дъ, бл҃говѣстѝ ми́ръ ва́мъ, да̑льнимъ и҆ бли̑жнимъ: занѐ тѣ́мъ и҆́мамы приведе́нїе ѻ҆́бои во є҆ди́номъ дс҃ѣ ко ѻ҆ц҃ꙋ̀. тѣ́мже ᲂу҆́бѡ ктомꙋ̀ нѣ́сте стра́нни и҆ прише́льцы, но сожи́телє ст҃ы̑мъ, и҆ при́снїи бг҃ꙋ: назда́ни бы́вше на ѡ҆снова́нїи а҆по́стѡлъ и҆ прорѡ́къ, сꙋ́щꙋ краеꙋго́льнꙋ самомꙋ̀ і҆и҃сꙋ хрⷭ҇тꙋ̀, ѡ҆ не́мже всѧ́ко созда́нїе составлѧ́емо расте́тъ въ цр҃ковь ст҃ꙋ́ю ѡ҆ гдⷭ҇ѣ: ѡ҆ не́мже и҆ вы̀ созида́етесѧ въ жили́ще бж҃їе дх҃омъ. ",
}

add_apostol {
  ["номер"] = 222,
  ["комментарий"] = "Еф., 222 зач., II, 19 – III, 7.",
  ["текст_ру"] = "Бра́тие, ктому́ не́сте стра́нни и прише́льцы, но сожи́теле святы́м и при́снии Бо́гу, назда́ни бы́вше на основа́нии Апо́стол и проро́к, су́щу краеуго́льну Самому́ Иису́су Христу́, о не́мже вся́ко созда́ние составля́емо расте́т в це́рковь святу́ю о Го́споде, о Не́мже и вы созида́етеся в жили́ще Бо́жие Ду́хом. Сего́ ра́ди аз Па́вел, ю́зник Иису́с Христо́в о вас язы́цех, похвалю́ся. А́ще у́бо слы́шасте смотре́ние благода́ти Бо́жия да́нныя мне в вас, я́ко по открове́нию сказа́ ми ся та́йна, я́коже преднаписа́х вма́ле. О не́мже мо́жете чту́ще разуме́ти ра́зум мой в та́йне Христо́ве, я́же во ине́х ро́дех не сказа́ся сыно́м челове́ческим, я́коже ны́не откры́ся святы́м Его́ Апо́столом и проро́ком Ду́хом Святы́м, я́ко бы́ти язы́ком снасле́дником и стеле́сником и сприча́стником обетова́ния Его́ о Христе́ Иису́се благовествова́нием, ему́же бых служи́тель по да́ру благода́ти Бо́жия, да́нныя мне по де́йству си́лы Его́. ",
  ["текст_цс"] = "Бра́тїе, ктомꙋ̀ нѣ́сте стра́нни и҆ прише́льцы, но сожи́телє ст҃ы̑мъ, и҆ при́снїи бг҃ꙋ: назда́ни бы́вше на ѡ҆снова́нїи а҆по́стѡлъ и҆ прорѡ́къ, сꙋ́щꙋ краеꙋго́льнꙋ самомꙋ̀ і҆и҃сꙋ хрⷭ҇тꙋ̀, ѡ҆ не́мже всѧ́ко созда́нїе составлѧ́емо расте́тъ въ цр҃ковь ст҃ꙋ́ю ѡ҆ гдⷭ҇ѣ: ѡ҆ не́мже и҆ вы̀ созида́етесѧ въ жили́ще бж҃їе дх҃омъ. сегѡ̀ ра́ди а҆́зъ па́ѵелъ, ю҆́зникъ і҆и҃съ хрⷭ҇то́въ, ѡ҆ ва́съ ꙗ҆зы́цѣхъ похвалю́сѧ: а҆́ще ᲂу҆́бѡ слы́шасте смотре́нїе бл҃года́ти бж҃їѧ да́нныѧ мнѣ̀ въ ва́съ, ꙗ҆́кѡ по ѿкрове́нїю сказа́ ми сѧ та́йна, ꙗ҆́коже преднаписа́хъ вма́лѣ. ѡ҆ не́мже мо́жете чтꙋ́ще разꙋмѣ́ти ра́зꙋмъ мо́й въ та́йнѣ хрⷭ҇то́вѣ: ꙗ҆́же во и҆нѣ́хъ ро́дѣхъ не сказа́сѧ сынѡ́мъ человѣ́чєскимъ, ꙗ҆́коже ны́нѣ ѿкры́сѧ свѧты́мъ є҆гѡ̀ а҆пⷭ҇толѡмъ и҆ проро́кѡмъ дх҃омъ ст҃ы́мъ: ꙗ҆́кѡ бы́ти ꙗ҆зы́кѡмъ снаслѣ́дникѡмъ, и҆ стѣле́сникѡмъ, и҆ сприча́стникѡмъ ѡ҆бѣтова́нїѧ є҆гѡ̀ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, благовѣствова́нїемъ: є҆мꙋ́же бы́хъ слꙋжи́тель по да́рꙋ бл҃года́ти бж҃їѧ, да́нныѧ мнѣ̀ по дѣ́йствꙋ си́лы є҆гѡ̀. ",
}

add_apostol {
  ["номер"] = 223,
  ["комментарий"] = "Еф., 223 зач., III, 8–21.",
  ["текст_ру"] = "Бра́тие, мне ме́ньшему всех святы́х дана́ бысть благода́ть сия́, во язы́цех благовести́ти неизсле́дованное бога́тство Христо́во, и просвети́ти всех, что есть смотре́ние та́йны сокрове́нныя от веко́в в Бо́зе, созда́вшем вся́ческая Иису́с Христо́м, да ска́жется ны́не нача́лом и власте́м на небе́сных Це́рковию многоразли́чная прему́дрость Бо́жия, по предложе́нию век, е́же сотвори́ о Христе́ Иису́се Го́споде на́шем, о Не́мже и́мамы дерзнове́ние и приведе́ние в наде́янии ве́рою Его́. Те́мже молю́ вы не стужа́ти си в ско́рбех мои́х о вас, я́же есть сла́ва ва́ша. Сего́ ра́ди преклоня́ю коле́на моя́ ко Отцу́ Го́спода на́шего Иису́са Христа́, из Него́же вся́ко оте́чество на небесе́х и на земли́ имену́ется, да даст вам по бога́тству сла́вы Своея́, си́лою утверди́тися Ду́хом Его́ во вну́треннем челове́це, всели́тися Христу́ ве́рою в сердца́ ва́ша: в любви́ вкорене́ни и основа́ни, да возмо́жете разуме́ти со все́ми святы́ми, что широта́, и долгота́, и глубина́, и высота́, разуме́ти же преспе́ющую ра́зум любо́вь Христо́ву, да испо́лнитеся во вся́ко исполне́ние Бо́жие. Могу́щему же па́че вся твори́ти по преизбы́точествию, и́хже про́сим или́ разуме́ем, по си́ле де́йствуемей в нас, Тому́ сла́ва в Це́ркви о Христе́ Иису́се во вся ро́ды ве́ка веко́в. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, мнѣ̀ ме́ньшемꙋ всѣ́хъ ст҃ы́хъ дана̀ бы́сть бл҃года́ть сїѧ̀, во ꙗ҆зы́цѣхъ благовѣсти́ти неизслѣ́дованное бога́тство хрⷭ҇то́во, и҆ просвѣти́ти всѣ́хъ: что̀ є҆́сть смотре́нїе та́йны сокрове́нныѧ ѿ вѣкѡ́въ въ бз҃ѣ, созда́вшемъ всѧ́чєскаѧ і҆и҃съ хрⷭ҇то́мъ. да ска́жетсѧ ны́нѣ нача́лѡмъ и҆ властє́мъ на нбⷭ҇ныхъ це́рковїю, многоразли́чнаѧ премꙋ́дрость бж҃їѧ, по предложе́нїю вѣ̑къ, ꙗ҆̀же сотворѝ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ гдⷭ҇ѣ на́шемъ: ѡ҆ не́мже и҆́мамы дерзнове́нїе, и҆ приведе́нїе въ надѣ́ѧнїи, вѣ́рою є҆гѡ̀. тѣ́мже молю́ вы, не стꙋжа́ти сѝ въ ско́рбехъ мои́хъ ꙗ҆̀же ѡ҆ ва́съ, ꙗ҆́же є҆́сть сла́ва ва́ша. сегѡ̀ ра́ди преклонѧ́ю кѡлѣ́на моѧ̀ ко ѻ҆ц҃ꙋ̀ гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, и҆з̾ негѡ́же всѧ́ко ѻ҆те́чество на небесѣ́хъ и҆ на землѝ и҆менꙋ́етсѧ: да да́стъ ва́мъ по бога́тствꙋ сла́вы своеѧ̀, си́лою ᲂу҆тверди́тисѧ дх҃омъ є҆гѡ̀, во внꙋ́треннѣмъ человѣ́цѣ, всели́тисѧ хрⷭ҇тꙋ̀ вѣ́рою въ сердца̀ ва́ша, въ любвѝ вкорене́ни и҆ ѡ҆снова́ни: да возмо́жете разꙋмѣ́ти со всѣ́ми ст҃ы́ми, что̀ широта̀, и҆ долгота̀, и҆ глꙋбина̀, и҆ высота̀: разꙋмѣ́ти же преспѣ́ющꙋю ра́зꙋмъ любо́вь хрⷭ҇то́вꙋ, да и҆спо́лнитесѧ во всѧ́ко и҆сполне́нїе бж҃їе. могꙋ́щемꙋ же па́че всѧ̑ твори́ти по преизбы́точествїю, и҆̀хже про́симъ, и҆лѝ разꙋмѣ́емъ, по си́лѣ дѣ́йствꙋемѣй въ на́съ: томꙋ̀ сла́ва въ це́ркви ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, во всѧ̀ ро́ды вѣ́ка вѣкѡ́въ, а҆ми́нь. ",
}

add_apostol {
