  ["номер"] = 224,
  ["комментарий"] = "Еф., 224 зач., IV, 7-13.",
  ["текст_ру"] = "Бра́тие, еди́ному кому́ждо нас даде́ся благода́ть по ме́ре дарова́ния Христо́ва. Те́мже глаго́лет: возше́д на высоту́, плени́л еси́ плен, и даде́ дая́ния челове́ком. А е́же взы́де, что есть, то́чию я́ко и сни́де пре́жде в до́льнейшыя страны́ земли́? Сше́дый, Той есть и возше́дый превы́ше всех небе́с, да испо́лнит вся́ческая. И Той дал есть о́вы у́бо Апо́столы, о́вы же проро́ки, о́вы же Благове́стники, о́вы же па́стыри и учи́тели, к соверше́нию святы́х, в де́ло служе́ния, в созида́ние Те́ла Христо́ва, до́ндеже дости́гнем вси во едине́ние ве́ры и позна́ния Сы́на Бо́жия, в му́жа соверше́нна, в ме́ру во́зраста исполне́ния Христо́ва. ",
  ["текст_цс"] = "Бра́тїе, є҆ди́номꙋ комꙋ́ждо на́съ даде́сѧ благода́ть по мѣ́рѣ дарова́нїѧ хрⷭ҇то́ва. тѣ́мже глаго́летъ: возше́дъ на высотꙋ̀, плѣни́лъ є҆сѝ плѣ́нъ, и҆ дадѐ даѧ̑нїѧ человѣ́кѡмъ. а҆ є҆́же, взы́де, что̀ є҆́сть, а҆́ще не то́чїю, ꙗ҆́кѡ и҆ сни́де пре́жде въ до́льнѣйшыѧ страны̑ землѝ; сше́дый, то́й є҆́сть и҆ возше́дый превы́ше всѣ́хъ небе́съ, да и҆спо́лнитъ всѧ́чєскаѧ. и҆ то́й да́лъ є҆́сть, ѻ҆́вы ᲂу҆́бѡ а҆по́столы, ѻ҆́вы же проро́ки, ѻ҆́вы же благовѣ́стники, ѻ҆́вы же па́стыри и҆ ᲂу҆чи́тели, къ соверше́нїю ст҃ы́хъ, въ дѣ́ло слꙋже́нїѧ, въ созида́нїе тѣ́ла хрⷭ҇то́ва: до́ндеже дости́гнемъ всѝ во є҆дине́нїе вѣ́ры, и҆ позна́нїѧ сн҃а бж҃їѧ, въ мꙋ́жа соверше́нна, въ мѣ́рꙋ во́зраста и҆сполне́нїѧ хрⷭ҇то́ва. ",
}

add_apostol {
  ["номер"] = 225,
  ["комментарий"] = "Еф., 225 зач., IV, 14–19.",
  ["текст_ру"] = "Бра́тие, да не быва́ем ктому́ младе́нцы, вла́ющеся и скита́ющеся вся́ким ве́тром уче́ния, во лжи челове́честей, в кова́рстве ко́зней льще́ния. И́стинствующе же в любви́, да возрасти́м в Него́ вся́ческая, И́же есть глава́ Христо́с, из Него́же все те́ло, составля́емо и счинева́емо прили́чне вся́цем осяза́нием подая́ния, по де́йству в ме́ре еди́ныя коея́ждо ча́сти, возраще́ние те́ла твори́т в созда́ние сама́го себе́ любо́вию. Сие́ у́бо глаго́лю и послушеству́ю о Го́споде, ктому́ не ходи́ти вам, я́коже и про́чии язы́цы хо́дят в суете́ ума́ их, помраче́ни смы́слом, су́ще отчужде́ни от жи́зни Бо́жия, за неве́жество су́щее в них, за окамене́ние серде́ц их, и́же в неча́яние вло́жшеся, преда́ша себе́ студодея́нию, в де́лание вся́кия нечистоты́ в лихоима́нии. ",
  ["текст_цс"] = "Бра́тїе, да не быва́емъ ктомꙋ̀ младе́нцы, вла́ющесѧ и҆ скита́ющесѧ всѧ́кимъ вѣ́тромъ ᲂу҆че́нїѧ, во лжѝ человѣ́честѣй, въ кова́рствѣ ко́зней льще́нїѧ. и҆́стинствꙋюще же въ любвѝ, да возрасти́мъ въ него̀ всѧ́чєскаѧ, и҆́же є҆́сть глава̀ хрⷭ҇то́съ: и҆з̾ негѡ́же всѐ тѣ́ло составлѧ́емо и҆ счинѣва́емо прили́чнѣ, всѧ́цѣмъ ѡ҆сѧза́нїемъ подаѧ́нїѧ по дѣ́йствꙋ въ мѣ́рѣ є҆ди́ныѧ коеѧ́ждо ча́сти, возраще́нїе тѣ́ла твори́тъ, въ созда́нїе сама́гѡ себѐ любо́вїю. сїѐ ᲂу҆́бѡ глаго́лю, и҆ послꙋшествꙋ́ю ѡ҆ гдⷭ҇ѣ, ктомꙋ̀ не ходи́ти ва́мъ, ꙗ҆́коже и҆ про́чїи ꙗ҆зы́цы хо́дѧтъ, въ сꙋетѣ̀ ᲂу҆ма̀ и҆́хъ, помраче́ни смы́сломъ, сꙋ́ще ѿчꙋжде́ни ѿ жи́зни бж҃їѧ, за невѣ́жество сꙋ́щее въ ни́хъ, за ѡ҆камене́нїе серде́цъ и҆́хъ: и҆́же въ неча́ѧнїе вло́жшесѧ, преда́ша себѐ стꙋдодѣѧ́нїю, въ дѣ́ланїе всѧ́кїѧ нечистоты̀ въ лихоима́нїи. ",
}

add_apostol {
