  ["комментарий"] = "Еф., 226 зач., IV, 17–25.",
  ["текст_ру"] = "Бра́тие, сие́ глаго́лю и послушеству́ю о Го́споде, ктому́ не ходи́ти вам, я́коже и про́чии язы́цы хо́дят в суете́ ума́ их, помраче́ни смы́слом, су́ще отчужде́ни от жи́зни Бо́жия, за неве́жество су́щее в них, за окамене́ние серде́ц их, и́же в неча́яние вло́жшеся, преда́ша себе́ студодея́нию, в де́лание вся́кия нечистоты́ в лихоима́нии. Вы же не та́ко позна́сте Христа́. А́ще у́бо слы́шасте Его́ и о Нем научи́стеся, я́коже есть и́стина о Иису́се: отложи́ти вам, по пе́рвому житию́, ве́тхаго челове́ка, тле́ющаго в по́хотех преле́стных, обновля́тися же ду́хом ума́ ва́шего, и облещи́ся в но́ваго челове́ка, созда́ннаго по Бо́гу в пра́вде и в преподо́бии и́стины. Те́мже отло́жше лжу, глаго́лите и́стину ки́йждо ко и́скреннему своему́. ",
  ["текст_цс"] = "Бра́тїе, сїѐ глаго́лю, и҆ послꙋшествꙋ́ю ѡ҆ гдⷭ҇ѣ, ктомꙋ̀ не ходи́ти ва́мъ, ꙗ҆́коже и҆ про́чїи ꙗ҆зы́цы хо́дѧтъ, въ сꙋетѣ̀ ᲂу҆ма̀ и҆́хъ, помраче́ни смы́сломъ, сꙋ́ще ѿчꙋжде́ни ѿ жи́зни бж҃їѧ, за невѣ́жество сꙋ́щее въ ни́хъ, за ѡ҆камене́нїе серде́цъ и҆́хъ: и҆́же въ неча́ѧнїе вло́жшесѧ, преда́ша себѐ стꙋдодѣѧ́нїю, въ дѣ́ланїе всѧ́кїѧ нечистоты̀ въ лихоима́нїи. вы́ же не та́кѡ позна́сте хрⷭ҇та̀. а҆́ще ᲂу҆́бѡ слы́шасте є҆го̀ и҆ ѡ҆ не́мъ наꙋчи́стесѧ, ꙗ҆́коже є҆́сть и҆́стина ѡ҆ і҆и҃сѣ: ѿложи́ти ва́мъ по пе́рвомꙋ житїю̀ ве́тхаго человѣ́ка, тлѣ́ющаго въ по́хотехъ преле́стныхъ: ѡ҆бновлѧ́тисѧ же дꙋ́хомъ ᲂу҆ма̀ ва́шегѡ: и҆ ѡ҆блещи́сѧ въ но́ваго человѣ́ка, созда́ннаго по бг҃ꙋ въ пра́вдѣ, и҆ въ преподо́бїи и҆́стины. тѣ́мже ѿло́жше лжꙋ̀, глаго́лите и҆́стинꙋ кі́йждо ко и҆́скреннемꙋ своемꙋ̀. ",
}

add_apostol {
  ["номер"] = 227,
  ["комментарий"] = "Еф., 227 зач., IV, 25–32.",
  ["текст_ру"] = "Бра́тие, отло́жше лжу, глаго́лите и́стину ки́йждо ко и́скреннему своему́. Зане́ есмы́ друг дру́гу у́дове. Гне́вайтеся и не согреша́йте, со́лнце да не за́йдет в гне́ве ва́шем, ниже́ дади́те ме́ста диа́волу. Крады́й ктому́ да не кра́дет, но па́че да тружда́ется, де́лая свои́ма рука́ма благо́е, да и́мать подая́ти тре́бующему. Вся́ко сло́во гни́ло да не исхо́дит из уст ва́ших, но то́чию е́же есть бла́го к созда́нию ве́ры, да даст благода́ть слы́шащим. И не оскорбля́йте Ду́ха Свята́го Бо́жия, о Не́мже зна́менастеся в день избавле́ния. Вся́ка го́ресть, и гнев, и я́рость, и кличь, и хула́ да во́змется от вас, со вся́кою зло́бою. Быва́йте же друг ко дру́гу бла́зи, милосе́рди, проща́юще друг дру́гу, я́коже и Бог во Христе́ прости́л есть вам. ",
  ["текст_цс"] = "Бра́тїе, ѿло́жше лжꙋ̀ глаго́лите и҆́стинꙋ кі́йждо ко и҆́скреннемꙋ своемꙋ̀: занѐ є҆смы̀ дрꙋгъдрꙋ́гꙋ ᲂу҆́дове. гнѣ́вайтесѧ, и҆ не согрѣша́йте: со́лнце да не за́йдетъ въ гнѣ́вѣ ва́шемъ: нижѐ дади́те мѣ́ста дїа́волꙋ. крады́й, ктомꙋ̀ да не кра́детъ: но па́че да трꙋжда́етсѧ дѣ́лаѧ свои́ма рꙋка́ма благо́е, да и҆́мать подаѧ́ти тре́бꙋющемꙋ. всѧ́ко сло́во гни́ло да не и҆схо́дитъ и҆з̾ ᲂу҆́стъ ва́шихъ: но то́чїю є҆́же є҆́сть бла́го, къ созда́нїю вѣ́ры, да да́стъ благода́ть слы́шащымъ. и҆ не ѡ҆скорблѧ́йте дх҃а ст҃а́гѡ бж҃їѧ, ѡ҆ не́мже зна́менастесѧ въ де́нь и҆збавле́нїѧ. всѧ́ка го́ресть, и҆ гнѣ́въ, и҆ ꙗ҆́рость, и҆ кли́чь, и҆ хꙋла̀, да во́зметсѧ ѿ ва́съ со всѧ́кою ѕло́бою. быва́йте же дрꙋ́гъ ко дрꙋ́гꙋ бла́зи, милосе́рди, проща́юще дрꙋгъдрꙋ́гꙋ, ꙗ҆́коже и҆ бг҃ъ во хрⷭ҇тѣ̀ прости́лъ є҆́сть ва́мъ. ",
}

add_apostol {
