  ["комментарий"] = "Еф., 228 зач., V, 1–8.",
  ["текст_ру"] = "Бра́тие, быва́йте подража́тели Бо́гу, я́коже ча́да возлю́бленная, и ходи́те в любви́, я́коже и Христо́с возлюби́л есть нас, и предаде́ Себе́ за ны приноше́ние и же́ртву Бо́гу в воню́ благоуха́ния. Блуд же и вся́ка нечистота́, и лихои́мство ниже́ да имену́ется в вас, я́коже подоба́ет святы́м, и скверносло́вие, и буесло́вие, или́ кощу́ны, и я́же неподо́бная, но па́че благодаре́ние. Сие́ бо да есте́ ве́дуще, я́ко всяк блудни́к, или́ нечи́ст, или́ лихои́мец, и́же есть идолослужи́тель, не и́мать достоя́ния в Ца́рствии Христа́ и Бо́га. Никто́же вас да льстит су́етными словесы́, сих бо ра́ди гряде́т гнев Бо́жий на сы́ны непокори́выя. Не быва́йте у́бо соприча́стницы сим. Бе́сте бо иногда́ тма, ны́не же свет о Го́споде. ",
  ["текст_цс"] = "Бра́тїе, быва́йте подража́тели бг҃ꙋ, ꙗ҆́коже ча́да возлю́блєннаѧ: и҆ ходи́те въ любвѝ ꙗ҆́коже и҆ хрⷭ҇то́съ возлюби́лъ є҆́сть на́съ, и҆ предадѐ себѐ за ны̀ приноше́нїе и҆ же́ртвꙋ бг҃ꙋ, въ воню̀ благоꙋха́нїѧ. блꙋ́дъ же, и҆ всѧ́ка нечистота̀, и҆ лихои́мство, нижѐ да и҆менꙋ́етсѧ въ ва́съ, ꙗ҆́коже подоба́етъ свѧты̑мъ: и҆ скверносло́вїе, и҆ бꙋесло́вїе, и҆ кощꙋ́ны, и҆ ꙗ҆̀же неподѡ́бнаѧ, но па́че бл҃годаре́нїе. сїе́ бо да є҆стѐ вѣ́дꙋще, ꙗ҆́кѡ всѧ́къ блꙋдни́къ, и҆лѝ нечи́стъ, и҆лѝ лихои́мецъ, и҆́же є҆́сть і҆дѡлослꙋжи́тель, не и҆́мать достоѧ́нїѧ въ црⷭ҇твїи хрⷭ҇та̀ и҆ бг҃а. никто́же ва́съ да льсти́тъ сꙋ́етными словесы̀: си́хъ бо ра́ди грѧде́тъ гнѣ́въ бж҃їй на сы́ны непокори́выѧ. не быва́йте ᲂу҆́бѡ соприча́стницы си̑мъ. бѣ́сте бо и҆ногда̀ тма̀, ны́нѣ же свѣ́тъ ѡ҆ гдⷭ҇ѣ. ",
}

add_apostol {
