  ["текст_ру"] = "Бра́тие, благодаря́ще всегда́ о всех о и́мени Го́спода на́шего Иису́са Христа́ Бо́гу и Отцу́, повину́ющеся друг дру́гу в стра́се Бо́жии. Жены́, свои́м муже́м повину́йтеся, я́коже Го́споду, зане́ муж глава́ есть жены́, я́коже и Христо́с глава́ Це́ркве, и Той есть Спаси́тель те́ла. Но я́коже Це́рковь повину́ется Христу́, та́кожде и жены́ свои́м муже́м во всем. Му́жие, люби́те своя́ жены́, я́коже и Христо́с возлюби́ Це́рковь, и Себе́ предаде́ за ню, да освяти́т ю́, очи́стив ба́нею водно́ю в глаго́ле. ",
  ["текст_цс"] = "Бра́тїе, бл҃годарѧ́ще всегда̀ ѡ҆ всѣ́хъ, ѡ҆ и҆́мени гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, бг҃ꙋ и҆ ѻ҆ц҃ꙋ̀: повинꙋ́ющесѧ дрꙋгъдрꙋ́гꙋ въ стра́сѣ бж҃їи. жєны̀, свои́мъ мꙋжє́мъ повинꙋ́йтесѧ, ꙗ҆́коже гдⷭ҇ꙋ: занѐ мꙋ́жъ глава̀ є҆́сть жены̀, ꙗ҆́коже и҆ хрⷭ҇то́съ глава̀ цр҃кве, и҆ то́й є҆́сть сп҃си́тель тѣ́ла. но ꙗ҆́коже цр҃ковь повинꙋ́етсѧ хрⷭ҇тꙋ̀, та́кожде и҆ жєны̀ свои́мъ мꙋжє́мъ во все́мъ. мꙋ́жїе, люби́те своѧ̀ жєны̀, ꙗ҆́коже и҆ хрⷭ҇то́съ возлюбѝ цр҃ковь, и҆ себѐ предадѐ за ню̀: да ѡ҆свѧти́тъ ю҆̀, ѡ҆чи́стивъ ба́нею водно́ю въ глаго́лѣ. ",
}

add_apostol {
  ["номер"] = 230,
  ["комментарий"] = "Еф., 230 зач., V, 20–33.",
  ["текст_ру"] = "Бра́тие, благодаря́ще всегда́ о всех о и́мени Го́спода на́шего Иису́са Христа́ Бо́гу и Отцу́, повину́ющеся друг дру́гу в стра́се Бо́жии. Жены́, свои́м му́жем повину́йтеся, я́коже Го́споду, зане́ муж глава́ есть жены́, я́коже и Христо́с глава́ Це́ркве, и Той есть Спаси́тель те́ла. Но я́коже Це́рковь повину́ется Христу́, та́кожде и жены́ свои́м муже́м во всем. Му́жие, люби́те своя́ жены́, я́коже и Христо́с возлюби́ Це́рковь, и Себе́ предаде́ за ню, да освяти́т ю́, очи́стив ба́нею водно́ю в глаго́ле. Да предста́вит ю́ Себе́ сла́вну Це́рковь, не иму́щу скве́рны, или́ поро́ка, или́ не́что от таковы́х, но да есть свята́ и непоро́чна. Та́ко до́лжни суть му́жие люби́ти своя́ жены́, я́ко своя́ телеса́: любя́й бо свою́ жену́, себе́ сама́го лю́бит. Никто́же бо когда́ свою́ плоть возненави́де, но пита́ет и гре́ет ю́, я́коже и Госпо́дь Це́рковь, зане́ у́ди есмы́ те́ла Его́, от пло́ти Его́, и от косте́й Его́. Сего́ ра́ди оста́вит челове́к отца́ своего́ и ма́терь, и прилепи́тся к жене́ свое́й, и бу́дета два в плоть еди́ну. Та́йна сия́ вели́ка есть, аз же глаго́лю во Христа́ и во Це́рковь. Оба́че и вы по еди́ному, ки́йждо свою́ жену́ си́це да лю́бит, я́коже и себе́, а жена́ да бои́тся своего́ му́жа. ",
  ["текст_цс"] = "Бра́тїе, бл҃годарѧ́ще всегда̀ ѡ҆ всѣ́хъ, ѡ҆ и҆́мени гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, бг҃ꙋ и҆ ѻ҆ц҃ꙋ̀: повинꙋ́ющесѧ дрꙋгъдрꙋ́гꙋ въ стра́сѣ бж҃їи. жєны̀, свои́мъ мꙋжє́мъ повинꙋ́йтесѧ, ꙗ҆́коже гдⷭ҇ꙋ: занѐ мꙋ́жъ глава̀ є҆́сть жены̀, ꙗ҆́коже и҆ хрⷭ҇то́съ глава̀ цр҃кве, и҆ то́й є҆́сть сп҃си́тель тѣ́ла. но ꙗ҆́коже цр҃ковь повинꙋ́етсѧ хрⷭ҇тꙋ̀, та́кожде и҆ жєны̀ свои́мъ мꙋжє́мъ во все́мъ. мꙋ́жїе, люби́те своѧ̀ жєны̀, ꙗ҆́коже и҆ хрⷭ҇то́съ возлюбѝ цр҃ковь, и҆ себѐ предадѐ за ню̀: да ѡ҆свѧти́тъ ю҆̀, ѡ҆чи́стивъ ба́нею водно́ю въ глаго́лѣ. да предста́витъ ю҆̀ себѣ̀ сла́внꙋ цр҃ковь, не и҆мꙋ́щꙋ скве́рны, и҆лѝ поро́ка, и҆лѝ нѣ́что ѿ таковы́хъ: но да є҆́сть ст҃а̀ и҆ непоро́чна. та́кѡ до́лжни сꙋ́ть мꙋ́жїе люби́ти своѧ̀ жєны̀, ꙗ҆́кѡ своѧ̀ тѣлеса̀: любѧ́й бо свою̀ женꙋ̀, себѐ сама́го лю́битъ. никто́же бо когда̀ свою̀ пло́ть возненави́дѣ: но пита́етъ, и҆ грѣ́етъ ю҆̀, ꙗ҆́коже и҆ гдⷭ҇ь цр҃ковь. занѐ ᲂу҆́ди є҆смы̀ тѣ́ла є҆гѡ̀, ѿ пло́ти є҆гѡ̀, и҆ ѿ косте́й є҆гѡ̀. сегѡ̀ ра́ди ѡ҆ста́витъ человѣ́къ ѻ҆тца̀ своего̀ и҆ ма́терь, и҆ прилѣпи́тсѧ къ женѣ̀ свое́й, и҆ бꙋ́дета два̀ въ пло́ть є҆ди́нꙋ. та́йна сїѧ̀ вели́ка є҆́сть: а҆́зъ же глаго́лю во хрⷭ҇та̀, и҆ во цр҃ковь. ѡ҆ба́че и҆ вы̀, по є҆ди́номꙋ кі́йждо свою̀ женꙋ̀ си́це да лю́битъ, ꙗ҆́коже и҆ себѐ: а҆ жена̀ да бои́тсѧ своегѡ̀ мꙋ́жа. ",
}

