add_apostol {
  ["номер"] = 233,
  ["комментарий"] = "Еф., 233 зач., VI, 10–17.",
  ["текст_ру"] = "Бра́тие, возмога́йте о Го́споде и в держа́ве кре́пости Его́, облецы́теся во вся ору́жия Бо́жия, я́ко возмощи́ вам ста́ти проти́ву ко́знем диа́вольским, я́ко несть на́ша брань к кро́ви и пло́ти, но к нача́лом и ко власте́м и к миродержи́телем тмы ве́ка сего́, к духово́м зло́бы поднебе́сным. Сего́ ра́ди приими́те вся ору́жия Бо́жия, да возмо́жете проти́витися в день лют и вся соде́явше ста́ти. Ста́ните у́бо препоя́сани чресла́ ва́ша и́стиною, и обо́лкшеся в броня́ пра́вды, и обу́вше но́зе во угото́вание благовествова́ния ми́ра, над все́ми же восприи́мше щит ве́ры, в не́мже возмо́жете вся стре́лы лука́ваго разжже́нныя угаси́ти. И шлем спасе́ния восприими́те, и мечь духо́вный, и́же есть глаго́л Бо́жий. ",
  ["текст_цс"] = "Бра́тїе, возмога́йте ѡ҆ гдⷭ҇ѣ, и҆ въ держа́вѣ крѣ́пости є҆гѡ̀: ѡ҆блецы́тесѧ во всѧ̀ ѻ҆рꙋ́жїѧ бж҃їѧ, ꙗ҆́кѡ возмощѝ ва́мъ ста́ти проти́вꙋ ко́знемъ дїа́вольскимъ. ꙗ҆́кѡ нѣ́сть на́ша бра́нь къ кро́ви и҆ пло́ти: но къ нача́лѡмъ и҆ ко властє́мъ, и҆ къ мїродержи́телємъ тмы̀ вѣ́ка сегѡ̀, къ дꙋховѡ́мъ ѕло́бы поднебє́снымъ. сегѡ̀ ра́ди прїими́те всѧ̀ ѻ҆рꙋ́жїѧ бж҃їѧ, да возмо́жете проти́витисѧ въ де́нь лю́тъ, и҆ всѧ̑ содѣ́ѧвше ста́ти. ста́ните ᲂу҆̀бо препоѧ́сани чресла̀ ва́ша и҆́стиною, и҆ ѡ҆бо́лкшесѧ въ бронѧ̀ пра́вды, и҆ ѡ҆бꙋ́вше но́зѣ во ᲂу҆гото́ванїе бл҃говѣствова́нїѧ ми́ра: над̾ всѣ́ми же воспрїи́мше щи́тъ вѣ́ры: въ не́мже возмо́жете всѧ̀ стрѣ́лы лꙋка́вагѡ разжжє́нныѧ ᲂу҆гаси́ти. и҆ шле́мъ спасе́нїѧ воспрїими́те, и҆ ме́чь дх҃о́вный, и҆́же є҆́сть глаго́лъ бж҃їй. ",
}

