  ["номер"] = 234,
  ["комментарий"] = "Еф., 234 зач., VI, 18–24.",
  ["текст_ру"] = "Бра́тие, вся́кою моли́твою и моле́нием моля́щеся на вся́ко вре́мя ду́хом, и в сие́ и́стое бдя́ще во вся́ком терпе́нии и моли́тве о всех святы́х и о мне, да да́стся ми сло́во во отверзе́ние уст мои́х, с дерзнове́нием сказа́ти та́йну благовествова́ния, о не́мже посо́льствую во у́зах, да в нем дерза́ю, я́коже подоба́ет ми глаго́лати. Да уве́сте же и вы, я́же о мне, что де́лаю, вся ска́жет вам Тихи́к, возлю́бленный брат и ве́рен служи́тель о Го́споде, его́же посла́х к вам на сие́ и́стое, да уве́сте, я́же о нас, и да уте́шит сердца́ ва́ша. Мир бра́тии и любо́вь с ве́рою от Бо́га Отца́ и Го́спода Иису́са Христа́. Благода́ть со все́ми лю́бящими Го́спода на́шего Иису́са Христа́ в неистле́нии. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, всѧ́кою моли́твою и҆ моле́нїемъ, молѧ́щесѧ на всѧ́кое вре́мѧ дх҃омъ: и҆ въ сїѐ и҆́стое бдѧ́ще во всѧ́комъ терпѣ́нїи и҆ мл҃твѣ, ѡ҆ всѣ́хъ ст҃ы́хъ, и҆ ѡ҆ мнѣ̀, да да́стсѧ мѝ сло́во во ѿверзе́нїе ᲂу҆́стъ мои́хъ, съ дерзнове́нїемъ сказа́ти та́йнꙋ благовѣствова́нїѧ: ѡ҆ не́мже посо́льствꙋю во ᲂу҆́захъ, да въ не́мъ дерза́ю, ꙗ҆́коже подоба́етъ мѝ глаго́лати. да ᲂу҆вѣ́сте же и҆ вы̀ ꙗ҆̀же ѡ҆ мнѣ̀, что̀ дѣ́лаю: всѧ̑ ска́жетъ ва́мъ тѷхі́къ возлю́бленный бра́тъ, и҆ вѣ́ренъ слꙋжи́тель ѡ҆ гдⷭ҇ѣ: є҆го́же посла́хъ къ ва́мъ на сїѐ и҆́стое, да ᲂу҆вѣ́сте ꙗ҆́же ѡ҆ на́съ, и҆ да ᲂу҆тѣ́шитъ сердца̀ ва́ша. ми́ръ бра́тїи, и҆ любо́вь съ вѣ́рою, ѿ бг҃а ѻ҆ц҃а̀ и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀. бл҃года́ть со всѣ́ми лю́бѧщими гдⷭ҇а на́шего і҆и҃са хрⷭ҇та̀ въ неистлѣ́нїи. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 235,
  ["комментарий"] = "Флп., 235 зач., I, 1–7.",
  ["текст_ру"] = "Па́вел и Тимофе́й, раби́ Иису́с Христо́вы, всем святы́м о Христе́ Иису́се су́щым в Фили́ппех, с епи́скопы и диа́коны, благода́ть вам и мир от Бо́га Отца́ на́шего и Го́спода Иису́са Христа́. Благодарю́ Бо́га моего́ о всей па́мяти ва́шей, всегда́ во вся́кой моли́тве мое́й за всех вас с ра́достию моли́тву мою́ творя́, о обще́нии ва́шем в благовествова́ние от пе́рваго дне да́же и доны́не, наде́явся на сие́ и́стое, я́ко начны́й де́ло бла́го в вас соверши́т е́ да́же до дне Иису́с Христо́ва. Я́коже есть пра́ведно мне сие́ му́дрствовати о всех вас, за е́же име́ти ми в се́рдце вас, во у́зах мои́х и во отве́те и извеще́нии благове́стия, соо́бщников ми благода́ти всех вас су́щих. ",
  ["текст_цс"] = "Па́ѵелъ и҆ тїмоѳе́й, рабѝ і҆и҃съ хрⷭ҇то́вы, всѣ́мъ ст҃ы̑мъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, сꙋ́щымъ въ фїлі́ппѣхъ, съ є҆пⷭ҇кпы и҆ дїа́коны: благода́ть ва́мъ и҆ ми́ръ ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀. благодарю̀ бг҃а моего̀ ѡ҆ все́й па́мѧти ва́шей, всегда̀ во всѧ́кой моли́твѣ мое́й за всѣ́хъ ва́съ, съ ра́достїю моли́твꙋ мою̀ творѧ̀. ѡ҆ ѻ҆бще́нїи ва́шемъ въ благовѣствова́нїе, ѿ пе́рвагѡ днѐ да́же и҆ до ны́нѣ: надѣ́ѧвсѧ на сїѐ и҆́стое, ꙗ҆́кѡ начны́й дѣ́ло бла́го въ ва́съ, соверши́тъ є҆̀, да́же до днѐ і҆и҃съ хрⷭ҇то́ва. ꙗ҆́коже є҆́сть пра́ведно мнѣ̀ сїѐ мꙋ́дрствовати ѡ҆ всѣ́хъ ва́съ, за є҆́же и҆мѣ́ти мѝ въ се́рдцѣ ва́съ, во ᲂу҆́захъ мои́хъ, и҆ во ѿвѣ́тѣ, и҆ и҆звѣще́нїи благовѣ́стїѧ, соѻ́бщники мѝ благода́ти всѣ́хъ ва́съ сꙋ́щихъ. ",
}

add_apostol {
  ["номер"] = 236,
  ["комментарий"] = "Флп., 236 зач., I, 8–14.",
  ["текст_ру"] = "Бра́тие, свиде́тель ми есть Бог, я́ко люблю́ всех вас по ми́лости Иису́с Христо́ве. И о сем молю́ся, да любо́вь ва́ша еще́ па́че и па́че избы́точествует в ра́зуме и во вся́ком чу́вствии, во е́же искуша́ти вам лу́чшая, да бу́дете чи́сти и непреткнове́нни в день Христо́в, испо́лнени плодо́в пра́вды Иису́с Христо́м, в сла́ву и похвалу́ Бо́жию. Разуме́ти же хощу́ вам, бра́тие, я́ко я́же о мне па́че во успе́х благовествова́ния приидо́ша, я́ко у́зам мои́м явле́нным о Христе́ бы́вшым во всем суди́щи и в про́чих всех, и мно́жайшии бра́тиям о Го́споде, наде́явшымся о у́зах мои́х, па́че дерза́ти без стра́ха сло́во Бо́жие глаго́лати. ",
  ["текст_цс"] = "Бра́тїе, свидѣ́тель мѝ є҆́сть бг҃ъ, ꙗ҆́кѡ люблю̀ всѣ́хъ ва́съ, по ми́лости і҆и҃съ хрⷭ҇то́вѣ. и҆ ѡ҆ се́мъ молю́сѧ, да любо́вь ва́ша є҆щѐ па́че и҆ па́че и҆збы́точествꙋетъ въ ра́зꙋмѣ, и҆ во всѧ́комъ чꙋ́вствїи. во є҆́же и҆скꙋша́ти ва́мъ лꙋ̑чшаѧ, да бꙋ́дете чи́сти, и҆ непреткнове́нни въ де́нь хрⷭ҇то́въ, и҆спо́лнени плодѡ́въ пра́вды і҆и҃съ хрⷭ҇то́мъ, въ сла́вꙋ и҆ похвалꙋ̀ бж҃їю. разꙋмѣ́ти же хощꙋ̀ ва́мъ бра́тїе, ꙗ҆́кѡ ꙗ҆̀же ѡ҆ мнѣ̀, па́че во ᲂу҆спѣ́хъ бл҃говѣствова́нїѧ прїидо́ша. ꙗ҆́кѡ ᲂу҆́замъ мои́мъ ꙗ҆влє́ннымъ ѡ҆ хрⷭ҇тѣ̀ бы́вшымъ во все́мъ сꙋди́щи, и҆ въ про́чїихъ всѣ́хъ. и҆ мно́жайшымъ бра́тїѧмъ ѡ҆ гдⷭ҇ѣ, надѣ́ѧвшымсѧ ѡ҆ ᲂу҆́захъ мои́хъ, па́че дерза́ти без̾ стра́ха сло́во бж҃їе глаго́лати. ",
}

add_apostol {
  ["номер"] = 237,
  ["комментарий"] = "Флп., 237 зач., I, 12–20.",
  ["текст_ру"] = "Бра́тие, разуме́ти вам хощу́, я́ко я́же о мне па́че во успе́х благовествова́ния приидо́ша, я́ко у́зам мои́м явле́нным о Христе́ бы́вшым во всем суди́щи и в про́чиих всех, и мно́жайшии бра́тия о Го́споде, наде́явшиися о у́зах мои́х, па́че дерза́ти без стра́ха сло́во Бо́жие глаго́лати. Не́цыи у́бо по за́висти и ре́вности, друзи́и же и за благоволе́ние Христа́ пропове́дают. О́ви у́бо от рве́ния Христа́ возвеща́ют нечи́сте, мня́ще печа́ль нанести́ у́зам мои́м, о́ви же от любве́, ве́дяще, я́ко во отве́те благовествова́ния лежу́. Что у́бо? Оба́че вся́цем о́бразом, а́ще вино́ю, а́ще и́стиною Христо́с пропове́даемь есть, и о сем ра́дуюся, но и возра́дуюся. Вем бо, я́ко сие́ сбу́дется ми во спасе́ние ва́шею моли́твою и подая́нием Ду́ха Иису́с Христо́ва, по ча́янию и упова́нию моему́. ",
  ["текст_цс"] = "Бра́тїе, разꙋмѣ́ти ва́мъ хощꙋ̀ ꙗ҆́кѡ ꙗ҆̀же ѡ҆ мнѣ̀, па́че во ᲂу҆спѣ́хъ бл҃говѣствова́нїѧ прїидо́ша. ꙗ҆́кѡ ᲂу҆́замъ мои́мъ ꙗ҆влє́ннымъ ѡ҆ хрⷭ҇тѣ̀ бы́вшымъ во все́мъ сꙋди́щи, и҆ въ про́чїихъ всѣ́хъ. и҆ мно́жайшымъ бра́тїѧмъ ѡ҆ гдⷭ҇ѣ, надѣ́ѧвшымсѧ ѡ҆ ᲂу҆́захъ мои́хъ, па́че дерза́ти без̾ стра́ха сло́во бж҃їе глаго́лати. нѣ́цыи ᲂу҆́бѡ по за́висти и҆ ре́вности, дрꙋзі́и же и҆ за благоволе́нїе, хрⷭ҇та̀ проповѣ́даютъ. ѻ҆́ви ᲂу҆́бѡ ѿ рве́нїѧ хрⷭ҇та̀ возвѣща́ютъ нечи́стѣ, мнѧ́ще печа́ль нанестѝ ᲂу҆́замъ мои́мъ: ѻ҆́ви же ѿ любвѐ, вѣ́дѧще ꙗ҆́кѡ во ѿвѣ́тѣ благовѣствова́нїѧ лежꙋ̀. что̀ ᲂу҆́бѡ; ѻ҆ба́че всѧ́цѣмъ ѻ҆́бразомъ, а҆́ще вино́ю, а҆́ще и҆́стиною, хрⷭ҇то́съ проповѣ́даемь є҆́сть: и҆ ѡ҆ се́мъ ра́дꙋюсѧ, но и҆ возра́дꙋюсѧ. вѣ́мъ бо, ꙗ҆́кѡ сїѐ сбꙋ́детсѧ мѝ во спасе́нїе ва́шею моли́твою, и҆ подаѧ́нїемъ дх҃а і҆и҃съ хрⷭ҇то́ва, по ча́ѧнїю и҆ ᲂу҆пова́нїю моемꙋ̀. ",
}

add_apostol {
  ["номер"] = 238,
  ["комментарий"] = "Флп., 238 зач., I, 20–27.",
  ["текст_ру"] = "Бра́тие, ни о еди́ном постыжу́ся, но во вся́ком дерзнове́нии, я́коже всегда́, и ны́не возвели́чится Христо́с в те́ле мое́м, а́ще живото́м, а́ще ли сме́ртию. Мне бо е́же жи́ти, Христо́с, и е́же умре́ти, приобре́тение есть. А́ще ли е́же жи́ти ми те́лом, сие́ мне плод дела́, и что изво́лю, не вем. Обдержи́мь же есмь от обою́, жела́ние имы́й разреши́тися и со Христо́м бы́ти, мно́го па́че лу́чше, а е́же пребыва́ти во пло́ти, ну́жднейше есть вас ра́ди. И сие́ изве́стне вем, я́ко бу́ду и спребу́ду вам всем в ваш успе́х и ра́дость ве́ры, я́ко да похвала́ ва́ша избы́точествует о Христе́ Иису́се во мне, мои́м прише́ствием па́ки к вам. То́чию досто́йне благовествова́нию Христо́ву жи́тельствуйте. ",
  ["текст_цс"] = "Бра́тїе, ни ѡ҆ є҆ди́номъ постыжꙋ́сѧ, но во всѧ́комъ дерзнове́нїи, ꙗ҆́коже всегда̀, и҆ ны́нѣ возвели́читсѧ хрⷭ҇то́съ въ тѣ́лѣ мое́мъ, а҆́ще живото́мъ, а҆́ще ли сме́ртїю. мнѣ́ бо є҆́же жи́ти хрⷭ҇то́съ: и҆ є҆́же ᲂу҆мре́ти, прїѡбрѣ́тенїе є҆́сть. а҆́ще ли є҆́же жи́ти мѝ тѣ́ломъ, сїе́ ми пло́дъ дѣ́ла, и҆ что̀ и҆зво́лю, не вѣ́мъ. ѡ҆бдержи́мь же є҆́смь ѿ ѻ҆бою̀, жела́нїе и҆мы́й разрѣши́тисѧ, и҆ со хрⷭ҇то́мъ бы́ти, мно́гѡ па́че лꙋ́чше: а҆ є҆́же пребыва́ти во пло́ти, нꙋ́жднѣйше є҆́сть ва́съ ра́ди. и҆ сїѐ и҆звѣ́стнѣ вѣ́мъ, ꙗ҆́кѡ бꙋ́дꙋ, и҆ спребꙋ́дꙋ ва́мъ всѣ́мъ въ ва́шъ ᲂу҆спѣ́хъ, и҆ ра́дость вѣ́ры. ꙗ҆́кѡ да похвала̀ ва́ша и҆збы́точествꙋетъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ во мнѣ̀, мои́мъ прише́ствїемъ па́ки къ ва́мъ. то́чїю досто́йнѣ благовѣствова́нїю хрⷭ҇то́вꙋ жи́тельствꙋйте. ",
}

add_apostol {
  ["номер"] = 239,
  ["комментарий"] = "Флп., 239 зач., I, 27 – II, 4.",
  ["текст_ру"] = "Бра́тие, досто́йне благовествова́нию Христо́ву жи́тельствуйте, да а́ще прише́д и ви́дев вас, а́ще и не сый у вас, услы́шу я́же о вас, я́ко и́стиною стоите́ во еди́ном ду́се и единоду́шне сподвиза́ющеся по ве́ре Благовествова́ния во́лею, и не коле́блющеся ни о еди́ном же от сопроти́вных, е́же тем у́бо есть явле́ние поги́бели, вам же спасе́ния, и сие́ от Бо́га. Я́ко вам дарова́ся, е́же о Христе́, не то́кмо е́же в Него́ ве́ровати, но и е́же по Нем страда́ти, то́йже по́двиг иму́ще, яко́в же во мне ви́десте и ны́не слы́шите о мне. А́ще у́бо ко́е утеше́ние о Христе́, или́ а́ще ка́я уте́ха любве́, а́ще ко́е обще́ние ду́ха, а́ще ко́е милосе́рдие и щедро́ты, испо́лните мою́ ра́дость, да то́жде му́дрствуете, ту́же любо́вь иму́ще, единоду́шни, единому́дренни, ничто́же по рве́нию или́ тщесла́вию, но смиреному́дрием друг дру́га че́стию бо́льша себе́ творя́ще. Не свои́х си ки́йждо, но и дру́жних ки́йждо смотря́йте. ",
  ["текст_цс"] = "Бра́тїе, досто́йнѣ благовѣствова́нїю хрⷭ҇то́вꙋ жи́тельствꙋйте, да а҆́ще прише́дъ и҆ ви́дѣвъ ва́съ, а҆́ще и҆ не сы́й ᲂу҆ ва́съ, ᲂу҆слы́шꙋ ꙗ҆̀же ѡ҆ ва́съ, ꙗ҆́кѡ и҆́стиною стоитѐ во є҆ди́номъ дс҃ѣ, и҆ є҆динодꙋ́шнѣ сподвиза́ющесѧ, по вѣ́рѣ благовѣствова́нїѧ во́лею, и҆ не коле́блющесѧ ни ѡ҆ є҆ди́номъ же ѿ сопроти́вныхъ: є҆́же тѣ̑мъ ᲂу҆́бѡ є҆́сть ꙗ҆вле́нїе поги́бели, ва́мъ же спасе́нїѧ, и҆ сїѐ ѿ бг҃а. ꙗ҆́кѡ ва́мъ дарова́сѧ є҆́же ѡ҆ хрⷭ҇тѣ̀, не то́кмѡ є҆́же въ него̀ вѣ́ровати, но и҆ є҆́же по не́мъ страда́ти: то́йже по́двигъ и҆мꙋ́ще, ꙗ҆ко́въ же во мнѣ̀ ви́дѣсте, и҆ ны́нѣ слы́шите ѡ҆ мнѣ̀. а҆́ще ᲂу҆̀бо ко́е ᲂу҆тѣше́нїе ѡ҆ хрⷭ҇тѣ̀, и҆лѝ а҆́ще ка́ѧ ᲂу҆тѣ́ха любвѐ, а҆́ще ко́е ѻ҆бще́нїе дх҃а, а҆́ще ко́е милосе́рдїе и҆ щедрѡ́ты: и҆спо́лните мою̀ ра́дость да то́жде мꙋ́дрствꙋете, тꙋ́же любо́вь и҆мꙋ́ще, є҆динодꙋ́шни, є҆диномꙋ́дренни: ничто́же по рве́нїю, и҆лѝ тщесла́вїю, но смиреномꙋ́дрїемъ дрꙋгъдрꙋ́га че́стїю бо́льша себѐ творѧ́ще. не свои́хъ сѝ кі́йждо, но и҆ дрꙋ́жнихъ кі́йждо смотрѧ́йте. ",
}

add_apostol {
  ["номер"] = 240,
  ["комментарий"] = "Флп., 240 зач., II, 5–11.",
  ["текст_ру"] = "Бра́тие, сие́ да му́дрствуется в вас, е́же и во Христе́ Иису́се, И́же во о́бразе Бо́жии сый, не восхище́нием непщева́ бы́ти ра́вен Бо́гу. Но Себе́ ума́лил, зрак раба́ прии́м, в подо́бии челове́честем быв, и о́бразом обре́теся я́коже челове́к. Смири́л Себе́, послушли́в быв да́же до сме́рти, сме́рти же кре́стныя. Те́мже и Бог Его́ превознесе́ и дарова́ Ему́ и́мя, е́же па́че вся́каго и́мене, да о и́мени Иису́сове вся́ко коле́но поклони́тся небе́сных и земны́х и преиспо́дних, и всяк язы́к испове́сть, я́ко Госпо́дь Иису́с Христо́с в сла́ву Бо́га Отца́. ",
  ["текст_цс"] = "Бра́тїе, сїѐ да мꙋ́дрствꙋетсѧ въ ва́съ, є҆́же и҆ во хрⷭ҇тѣ̀ і҆и҃сѣ, и҆́же во ѻ҆́бразѣ бж҃їи сы́й, не восхище́нїемъ непщева̀ бы́ти ра́венъ бг҃ꙋ. но себѐ ᲂу҆ма́лилъ, зра́къ раба̀ прїи́мъ, въ подо́бїи человѣ́честѣмъ бы́въ и҆ ѻ҆́бразомъ ѡ҆брѣ́тесѧ ꙗ҆́коже человѣ́къ. смири́лъ себѐ, послꙋшли́въ бы́въ да́же до сме́рти, сме́рти же крⷭ҇тныѧ. тѣ́мже и҆ бг҃ъ є҆го̀ превознесѐ, и҆ дарова̀ є҆мꙋ̀ и҆́мѧ, є҆́же па́че всѧ́кагѡ и҆́мене: да ѡ҆ и҆́мени і҆и҃совѣ всѧ́ко колѣ́но поклони́тсѧ, нбⷭ҇ныхъ, и҆ земны́хъ, и҆ преиспо́днихъ: и҆ всѧ́къ ѧ҆зы́къ и҆сповѣ́сть ꙗ҆́кѡ гдⷭ҇ь і҆и҃съ хрⷭ҇то́съ, въ сла́вꙋ бг҃а ѻ҆ц҃а̀. ",
}

add_apostol {
  ["номер"] = 241,
  ["комментарий"] = "Флп., 241 зач., II, 12–16.",
  ["текст_ру"] = "Бра́тие, я́коже всегда́ послу́шасте мене́, не я́коже в прише́ствии мое́м то́чию, но ны́не мно́го па́че во отше́ствии мое́м, со стра́хом и тре́петом свое́ спасе́ние содева́йте. Бог бо есть де́йствуяй в вас и е́же хоте́ти и е́же де́яти о благоволе́нии. Вся твори́те без ропта́ния и размышле́ния, да бу́дете непоро́чни и це́ли, ча́да Бо́жия непоро́чна посреде́ ро́да стропти́ва и развраще́на, в ни́хже явля́етеся я́коже свети́ла в ми́ре, сло́во живо́тно предержа́ще, в похвалу́ мне в день Христо́в. ",
