}

add_apostol {
  ["номер"] = 242,
  ["комментарий"] = "Флп., 242 зач., II, 16–23.",
  ["текст_ру"] = "Бра́тие, не вотще́ теко́х, ни вотще́ труди́хся. Но а́ще и жрен быва́ю о же́ртве и слу́жбе ве́ры ва́шея, ра́дуюся и сра́дуюся всем вам, та́кожде и вы ра́дуйтеся и сра́дуйте ми ся. Упова́ю же о Го́споде Иису́се Тимофе́а вско́ре посла́ти к вам, да и аз благоду́шствую, уве́дев я́же о вас. Ни еди́наго бо и́мам равноду́шна, и́же при́снее о вас попече́тся, вси бо свои́х си и́щут, а не я́же Христа́ Иису́са. Иску́сство же его́ зна́ете, зане́ я́коже отцу́ ча́до, со мно́ю порабо́тал в благове́стии. Сего́ же у́бо упова́ю посла́ти а́бие, по внегда́ уве́м я́же о мне. ",
  ["текст_цс"] = "Бра́тїе, не вотщѐ теко́хъ, ни вотщѐ трꙋди́хсѧ. но а҆́ще и҆ жре́нъ быва́ю, ѡ҆ же́ртвѣ и҆ слꙋ́жбѣ вѣ́ры ва́шеѧ ра́дꙋюсѧ, и҆ сра́дꙋюсѧ всѣ̑мъ ва́мъ: та́кожде и҆ вы̀ ра́дꙋйтесѧ, и҆ сра́дꙋйте ми сѧ. ᲂу҆пова́ю же ѡ҆ гдⷭ҇ѣ і҆и҃сѣ, тїмоѳе́а вско́рѣ посла́ти къ ва́мъ, да и҆ а҆́зъ благодꙋ́шствꙋю, ᲂу҆вѣ́дѣвъ ꙗ҆̀же ѡ҆ ва́съ: ни є҆ди́нагѡ бо и҆́мамъ равнодꙋ́шна, и҆́же при́снѣе ѡ҆ ва́съ попече́тсѧ: вси́ бо свои́хъ сѝ и҆́щꙋтъ, а҆ не ꙗ҆̀же хрⷭ҇та̀ і҆и҃са. и҆скꙋ́сство же є҆гѡ̀ зна́ете, занѐ, ꙗ҆́коже ѻ҆ц҃ꙋ̀ ча́до, со мно́ю порабо́талъ въ благовѣ́стїи. сего́ же ᲂу҆̀бо ᲂу҆пова́ю посла́ти а҆́бїе, по внегда̀ ᲂу҆вѣ́мъ ꙗ҆̀же ѡ҆ мнѣ̀. ",
}

add_apostol {
  ["номер"] = 243,
  ["комментарий"] = "Флп., 243 зач., II, 24–30.",
  ["текст_ру"] = "Бра́тие, наде́юся о Го́споде, я́ко и сам ско́ро прииду́ к вам. Потре́бнее же возмне́х Епафроди́та бра́та и споспе́шника и сво́инника моего́, ва́шего же посла́нника и служи́теля потре́бе мое́й, посла́ти к вам, поне́же жела́нием жела́ше ви́дети всех вас, и тужа́ше, зане́ слы́шасте, я́ко боле́. И́бо боле́ близ сме́рти, но Бог поми́лова его́, не его́ же то́кмо, но и мене́, да не скорбь на скорбь прииму́. Скоре́е у́бо посла́х его́, да ви́девше его́ па́ки, возра́дуетеся, и аз безпеча́лен пребу́ду. Приими́те у́бо его́ о Го́споде со вся́кою ра́достию, и таковы́я че́стны име́йте, зане́ за де́ло Христо́во да́же до сме́рти прибли́жися, пону́див себе́ вседу́шно, да испо́лнит ва́ше лише́ние, е́же к мое́й слу́жбе. ",
  ["текст_цс"] = "Бра́тїе, надѣ́юсѧ ѡ҆ гдⷭ҇ѣ ꙗ҆́кѡ и҆ са́мъ ско́рѡ прїидꙋ̀ къ ва́мъ. потре́бнѣе же возмнѣ́хъ, є҆пафроді́та бра́та, и҆ споспѣ́шника и҆ сво́инника моего̀, ва́шего же посла́нника, и҆ слꙋжи́телѧ потре́бѣ мое́й, посла́ти къ ва́мъ. поне́же жела́нїемъ жела́ше ви́дѣти всѣ́хъ ва́съ: и҆ тꙋжа́ше, занѐ слы́шасте, ꙗ҆́кѡ болѣ̀. и҆́бо болѣ̀ близ̾ сме́рти: но бг҃ъ поми́лова є҆го̀, не є҆го́ же то́кмѡ, но и҆ менѐ, да не ско́рбь на ско́рбь прїимꙋ̀. скорѣ́е ᲂу҆̀бо посла́хъ є҆го̀, да ви́дѣвше є҆го̀ па́ки, возра́дꙋетесѧ, и҆ а҆́зъ безпеча́ленъ пребꙋ́дꙋ. прїими́те ᲂу҆̀бо є҆го̀ ѡ҆ гдⷭ҇ѣ со всѧ́кою ра́достїю, и҆ таковы́ѧ че́стны и҆мѣ́йте: занѐ за дѣ́ло хрⷭ҇то́во да́же до сме́рти прибли́жисѧ: понꙋ́дивъ себѐ вседꙋ́шнѡ, да и҆спо́лнитъ ва́ше лише́нїе, є҆́же къ мое́й слꙋ́жбѣ. ",
}

add_apostol {
  ["номер"] = 244,
  ["комментарий"] = "Флп., 244 зач., III, 1–8.",
  ["текст_ру"] = "Бра́тие, ра́дуйтеся о Го́споде. Та́яжде бо писа́ти вам, мне у́бо неле́ностно, вам же тве́рдо. Блюди́теся от псов, блюди́теся от злых де́лателей, блюди́теся от сече́ния неве́рных. Мы бо есмы́ обре́зание, и́же ду́хом Бо́гу слу́жим и хва́лимся о Христе́ Иису́се, а не в пло́ти наде́емся. И́бо и аз име́ю наде́яние во пло́ти. А́ще кто ин мнит наде́ятися во пло́ти, аз па́че, обре́зан осмодне́вно, от ро́да Изра́илева, коле́на Вениами́нова, евре́ин от евре́й, по зако́ну фарисе́й, по ре́вности гони́х Це́рковь Бо́жию, по пра́вде зако́нней быв непоро́чен. Но я́же ми бя́ху приобре́тения, сия́ вмени́х Христа́ ра́ди тщету́. Но у́бо вменя́ю вся тщету́ бы́ти за превосходя́щее ра́зума Христа́ Иису́са Го́спода моего́, Его́же ра́ди всех отщети́хся, и вменя́ю вся уме́ты бы́ти, да Христа́ приобря́щу. ",
  ["текст_цс"] = "Бра́тїе, ра́дꙋйтесѧ ѡ҆ гдⷭ҇ѣ: та̑ѧжде бо писа́ти ва́мъ мнѣ̀ ᲂу҆́бѡ нелѣ́ностно, ва́мъ же тве́рдо. блюди́тесѧ ѿ псѡ́въ, блюди́тесѧ ѿ ѕлы́хъ дѣ́лателей, блюди́тесѧ ѿ сѣче́нїѧ невѣ́рныхъ. мы́ бо є҆смы̀ ѡ҆брѣ́занїе, и҆̀же дх҃омъ бг҃ꙋ слꙋ́жимъ, и҆ хва́лимсѧ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, а҆ не въ пло́ти надѣ́емсѧ. и҆́бо и҆ а҆́зъ и҆мѣ́ю надѣ́ѧнїе во пло́ти: а҆́ще кто̀ и҆́нъ мни́тъ надѣ́ѧтисѧ во пло́ти, а҆́зъ па́че. ѡ҆брѣ́занъ ѻ҆смодне́внѡ, ѿ ро́да і҆и҃лева, колѣ́на венїамі́нова, є҆вре́инъ ѿ є҆врє́й: по зако́нꙋ фарїсе́й, по ре́вности гони́хъ цр҃ковь бж҃їю, по пра́вдѣ зако́ннѣй бы́въ непоро́ченъ. но ꙗ҆̀же мѝ бѧ́хꙋ прїѡбрѣ́тєнїѧ, сїѧ̑ вмѣни́хъ хрⷭ҇та̀ ра́ди тщетꙋ̀. но ᲂу҆̀бо вмѣнѧ́ю всѧ̑ тщетꙋ̀ бы́ти, за превосходѧ́щее ра́зꙋма хрⷭ҇та̀ і҆и҃са гдⷭ҇а моегѡ̀. є҆гѡ́же ра́ди всѣ́хъ ѿтщети́хсѧ, и҆ вмѣнѧ́ю всѧ̑ ᲂу҆ме́ты бы́ти, да хрⷭ҇та̀ прїѡбрѧ́щꙋ. ",
