add_apostol {
  ["номер"] = 247,
  ["комментарий"] = "Флп., 247 зач., IV, 4-9.",
  ["текст_ру"] = "Бра́тие, ра́дуйтеся всегда́ о Го́споде, и па́ки реку́, ра́дуйтеся. Кро́тость ва́ша разу́мна да бу́дет всем челове́ком. Госпо́дь близ. Ни о че́мже пецы́теся, но во всем моли́твою и моле́нием со благодаре́нием проше́ния ва́ша да сказу́ются к Бо́гу. И мир Бо́жий, превосходя́й всяк ум, да соблюде́т сердца́ ва́ша и разуме́ния ва́ша о Христе́ Иису́се. Про́чее же, бра́тие моя́, ели́ка суть и́стинна, ели́ка че́стна, ели́ка пра́ведна, ели́ка пречи́ста, ели́ка прелюбе́зна, ели́ка доброхва́льна, а́ще ка́я доброде́тель, и а́ще ка́я похвала́, сия́ помышля́йте. И́мже и научи́стеся, и прия́сте, и слы́шасте, и ви́десте во мне, сия́ твори́те, и Бог ми́ра бу́дет с ва́ми. ",
  ["текст_цс"] = "Бра́тїе, ра́дꙋйтесѧ всегда̀ ѡ҆ гдⷭ҇ѣ: и҆ па́ки рекꙋ̀, ра́дꙋйтесѧ. кро́тость ва́ша разꙋ́мна да бꙋ́детъ всѣ́мъ человѣ́кѡмъ. гдⷭ҇ь бли́зъ. ни ѡ҆ че́мже пецы́тесѧ, но во все́мъ моли́твою и҆ моле́нїемъ со бл҃годаре́нїемъ, прошє́нїѧ ва́ша да сказꙋ́ютсѧ къ бг҃ꙋ. и҆ ми́ръ бж҃їй превосходѧ́й всѧ́къ ᲂу҆́мъ, да соблюде́тъ сердца̀ ва́ша и҆ разꙋмѣ̑нїѧ ва́ша, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. про́чее же бра́тїе моѧ̀, є҆ли̑ка сꙋ́ть и҆́стинна, є҆ли̑ка чє́стна, є҆ли̑ка пра́вєдна, є҆ли̑ка пречи̑ста, є҆ли̑ка прелюбє́зна, є҆ли̑ка доброхва̑льна, а҆́ще ка́ѧ добродѣ́тель, и҆ а҆́ще ка́ѧ похвала̀, сїѧ̑ помышлѧ́йте. и҆̀мже и҆ наꙋчи́стесѧ, и҆ прїѧ́сте, и҆ слы́шасте, и҆ ви́дѣсте во мнѣ̀, сїѧ̑ твори́те, и҆ бг҃ъ ми́ра бꙋ́детъ съ ва́ми. ",
}

add_apostol {
