  ["комментарий"] = "Кол., 249 зач., I, 3-6.",
  ["текст_ру"] = "Бра́тие, благода́ть вам и мир от Бо́га Отца́ на́шего, и Го́спода Иису́са Христа́. Благодари́м Бо́га и Отца́ Го́спода на́шего Иису́са Христа́, всегда́ о вас моля́щеся, слы́шавше ве́ру ва́шу, я́же о Христе́ Иису́се и любо́вь, ю́же и́мате ко всем святы́м, за упова́ние отложе́нное вам на небесе́х, е́же пре́жде слы́шасте в словеси́ и́стины благовествова́ния, су́щаго в вас, я́коже и во всем ми́ре: и есть плодоно́сно и расти́мо, я́коже и в вас, от него́же дне слы́шасте и разуме́сте благода́ть Бо́жию во и́стине. ",
  ["текст_цс"] = "Бра́тїе, бл҃года́ть ва́мъ и҆ ми́ръ ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀, благодари́мъ бг҃а и҆ ѻ҆ц҃а̀ гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, всегда̀ ѡ҆ ва́съ молѧ́щесѧ: слы́шавше вѣ́рꙋ ва́шꙋ, ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, и҆ любо́вь ю҆́же и҆́мате ко всѣ́мъ ст҃ы̑мъ: за ᲂу҆пова́нїе ѿложе́нное ва́мъ на небесѣ́хъ, є҆́же пре́жде слы́шасте въ словесѝ и҆́стины бл҃говѣствова́нїѧ, сꙋ́щагѡ въ ва́съ, ꙗ҆́коже и҆ во все́мъ мі́рѣ: и҆ є҆́сть плодоно́сно и҆ расти́мо, ꙗ҆́коже и҆ въ ва́съ, ѿ негѡ́же днѐ слы́шасте, и҆ разꙋмѣ́сте бл҃года́ть бж҃їю во и҆́стинѣ. ",
}

add_apostol {
  ["номер"] = 250,
  ["комментарий"] = "Кол., 250 зач., I, 12–18.",
  ["текст_ру"] = "Бра́тие, благодаря́ще Бо́га и Отца́, призва́вшаго вас в прича́стие насле́дия святы́х во све́те. И́же изба́ви нас от вла́сти те́мныя и преста́ви в Ца́рство Сы́на любве́ Своея́, о Не́мже и́мамы избавле́ние Кро́вию Его́ и оставле́ние грехо́в. И́же есть о́браз Бо́га неви́димаго, перворожде́н всея́ тва́ри. Я́ко о Нем создана́ бы́ша вся́ческая, я́же на небеси́, и я́же на земли́, ви́димая и неви́димая, а́ще престо́ли, а́ще госпо́дствия, а́ще нача́ла, а́ще вла́сти, вся́ческая Тем и о Нем созда́шася. И Той есть пре́жде всех, и вся́ческая в Нем состоя́тся. И Той есть глава́ те́лу Це́ркве, И́же есть нача́ток, перворожде́н из ме́ртвых, я́ко да бу́дет во всех Той пе́рвенствуя. ",
  ["текст_цс"] = "Бра́тїе, благодарѧ́ще бг҃а и҆ ѻ҆ц҃а̀, призва́вшаго ва́съ въ прича́стїе наслѣ́дїѧ ст҃ы́хъ во свѣ́тѣ: и҆́же и҆зба́ви на́съ ѿ вла́сти те́мныѧ, и҆ преста́ви въ црⷭ҇тво сн҃а любвѐ своеѧ̀: ѡ҆ не́мже и҆́мамы и҆збавле́нїе кро́вїю є҆гѡ̀, и҆ ѡ҆ставле́нїе грѣхѡ́въ: и҆́же є҆́сть ѻ҆́бразъ бг҃а неви́димагѡ, перворожде́нъ всеѧ̀ тва́ри. ꙗ҆́кѡ ѡ҆ не́мъ создана̀ бы́ша всѧ́чєскаѧ, ꙗ҆̀же на небесѝ, и҆ ꙗ҆̀же на землѝ, ви̑димаѧ, и҆ неви̑димаѧ: а҆́ще престо́ли, а҆́ще гдⷭ҇ьствїѧ, а҆́ще нача̑ла, а҆́ще вла̑сти, всѧ́чєскаѧ тѣ́мъ и҆ ѡ҆ не́мъ созда́шасѧ. и҆ то́й є҆́сть пре́жде всѣ́хъ, и҆ всѧ́чєскаѧ ѡ҆ не́мъ состоѧ́тсѧ. и҆ то́й є҆́сть глава̀ тѣ́лꙋ це́ркве, и҆́же є҆́сть нача́токъ, перворожде́нъ и҆з̾ ме́ртвыхъ, ꙗ҆́кѡ да бꙋ́детъ во всѣ́хъ то́й пе́рвенствꙋѧ. ",
}

add_apostol {
  ["номер"] = 251,
  ["комментарий"] = "Кол., 251 зач., I, 18–23.",
  ["текст_ру"] = "Бра́тие, Христо́с есть глава́ те́лу Це́ркве, И́же есть нача́ток, перворожде́н из ме́ртвых, я́ко да бу́дет во всех Той пе́рвенствуя. Я́ко в Нем благоизво́ли всему́ исполне́нию всели́тися, и Тем примири́ти вся́ческая к Себе́, умиротвори́в Кро́вию креста́ Его́, чрез Него́, а́ще земна́я, а́ще ли небе́сная. И вас, иногда́ су́щих очужде́нных и враго́в помышле́ньми в де́лех лука́вых, ны́не же примири́ в те́ле Пло́ти Его́ сме́ртию Его́, предста́вити вас свя́ты и непоро́чны и непови́нны пред Собо́ю, а́ще у́бо пребыва́ете в ве́ре основа́ни и тве́рди, и неподви́жими от упова́ния благовествова́ния, е́же слы́шасте, пропове́данное всей тва́ри поднебе́сней, ему́же бых аз Па́вел служи́тель. ",
  ["текст_цс"] = "Бра́тїе, хрⷭ҇то́съ є҆́сть глава̀ тѣ́лꙋ це́ркве, и҆́же є҆́сть нача́токъ, перворожде́нъ и҆з̾ ме́ртвыхъ, ꙗ҆́кѡ да бꙋ́детъ во всѣ́хъ то́й пе́рвенствꙋѧ. ꙗ҆́кѡ въ не́мъ благоизво́ли всемꙋ̀ и҆сполне́нїю всели́тисѧ. и҆ тѣ́мъ примири́ти всѧ́чєскаѧ къ себѣ̀, ᲂу҆миротвори́въ кро́вїю крⷭ҇та̀ є҆гѡ̀ чрез̾ него̀, а҆́ще земна̑ѧ, а҆́ще ли небє́снаѧ. и҆ ва́съ и҆ногда̀ сꙋ́щихъ ѡ҆чꙋжде́ныхъ, и҆ врагѡ́въ помышле́ньми въ дѣ́лѣхъ лꙋка́выхъ, ны́нѣ же примирѝ въ тѣ́лѣ пло́ти є҆гѡ̀ сме́ртїю є҆гѡ̀, предста́вити ва́съ ст҃ы, и҆ непоро́чны и҆ непови́нны пред̾ собо́ю. а҆́ще ᲂу҆̀бо пребыва́ете въ вѣ́рѣ ѡ҆снова́ни и҆ тве́рди, и҆ неподви́жими ѿ ᲂу҆пова́нїѧ благовѣствова́нїѧ, є҆́же слы́шасте, проповѣ́даное все́й тва́ри поднебе́снѣй, є҆мꙋ́же бы́хъ а҆́зъ па́ѵелъ слꙋжи́тель. ",
}

add_apostol {
  ["номер"] = 252,
  ["комментарий"] = "Кол., 252 зач., I, 24–29.",
  ["текст_ру"] = "Бра́тие, ны́не ра́дуюся во страда́ниих мои́х о вас, я́ко исполня́ю лише́ние скорбе́й Христо́вых во пло́ти мое́й за Те́ло Его́, е́же есть Це́рковь. Е́йже бых аз служи́тель по смотре́нию Бо́жию, да́нному мне в вас, испо́лнити сло́во Бо́жие, та́йну сокрове́нную от век и от родо́в, ны́не же яви́ся святы́м Его́, И́мже восхоте́ Бог сказа́ти, ко́е бога́тство сла́вы та́йны сея́ во язы́цех, и́же есть Христо́с в вас, упова́ние сла́вы, Его́же мы пропове́дуем, наказу́юще вся́каго челове́ка и уча́ще вся́кой прему́дрости, да предста́вим вся́каго челове́ка соверше́нна о Христе́ Иису́се, в Не́мже и тружда́юся и подвиза́юся по де́йству Его́ де́йствуемому во мне си́лою. ",
  ["текст_цс"] = "Бра́тїе, ны́нѣ ра́дꙋюсѧ во страда́нїихъ мои́хъ ѡ҆ ва́съ, ꙗ҆́кѡ и҆сполнѧ́ю лише́нїе скорбе́й хрⷭ҇то́выхъ во пло́ти мое́й, за тѣ́ло є҆гѡ̀, є҆́же є҆́сть це́рковь: є҆́йже бы́хъ а҆́зъ слꙋжи́тель, по смотре́нїю бж҃їю да́нномꙋ мнѣ̀ въ ва́съ, и҆спо́лнити сло́во бж҃їе: та́йнꙋ сокрове́ннꙋю ѿ вѣ́къ и҆ ѿ родѡ́въ, ны́нѣ же ꙗ҆ви́сѧ свѧты̑мъ є҆гѡ̀. и҆̀мже восхотѣ̀ бг҃ъ сказа́ти, ко́е бога́тство сла́вы та́йны сеѧ̀ во ꙗ҆зы́цѣхъ, и҆́же є҆́сть хрⷭ҇то́съ въ ва́съ, ᲂу҆пова́нїе сла́вы: є҆го́же мы̀ проповѣ́дꙋемъ, наказꙋ́юще всѧ́каго человѣ́ка, и҆ ᲂу҆ча́ще всѧ́кой премꙋ́дрости: да предста́вимъ всѧ́каго человѣ́ка соверше́нна ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: въ не́мже и҆ трꙋжда́юсѧ и҆ подвиза́юсѧ по дѣ́йствꙋ є҆гѡ̀, дѣ́йствꙋемомꙋ во мнѣ̀ си́лою. ",
}

add_apostol {
  ["номер"] = 253,
  ["комментарий"] = "Кол., 253 зач., II, 1–7.",
  ["текст_ру"] = "Бра́тие, хощу́ вас ве́дети, коли́к по́двиг и́мам о вас и о су́щих в Лаодики́и и во Иерапо́ли, и ели́цы не ви́деша ли́ца моего́ во пло́ти, да уте́шатся сердца́ их, сне́мшихся в любви́ и во вся́ком бога́тстве извеще́ния ра́зума, в позна́ние та́йны Бо́га и Отца́ и Христа́, в Не́мже суть вся сокро́вища прему́дрости и ра́зума сокрове́нна. Сие́ же глаго́лю, да никто́же вас прельсти́т в словопре́нии. А́ще бо и пло́тию отстою́, но ду́хом с ва́ми есмь, ра́дуяся и ви́дя ваш чин и утвержде́ние ва́шея ве́ры, я́же во Христа́. Я́коже у́бо прия́сте Христа́ Иису́са Го́спода, та́коже в Нем ходи́те, укорене́ни и назда́ни в Нем и изве́ствовани ве́рою, я́коже научи́стеся, избы́точествующе в ней благодаре́нием. ",
  ["текст_цс"] = "Бра́тїе, хощꙋ̀ ва́съ вѣ́дѣти, коли́къ по́двигъ и҆́мамъ ѡ҆ ва́съ, и҆ ѡ҆ сꙋ́щихъ въ лаодїкі́и, и҆ во і҆ерапо́ли, и҆ є҆ли́цы не ви́дѣша лица̀ моегѡ̀ во пло́ти, да ᲂу҆тѣ́шатсѧ сердца̀ и҆́хъ, сне́мшихсѧ въ любвѝ, и҆ во всѧ́комъ бога́тствѣ и҆звѣще́нїѧ ра́зꙋма, въ позна́нїе та́йны бг҃а и҆ ѻ҆ц҃а̀, и҆ хрⷭ҇та̀: въ не́мже сꙋ́ть всѧ̀ сокрѡ́вища премꙋ́дрости, и҆ ра́зꙋма сокровє́нна. сїе́ же глаго́лю, да никто́же ва́съ прельсти́тъ въ словопрѣ́нїи. а҆́ще бо и҆ пло́тїю ѿстою̀, но дꙋ́хомъ съ ва́ми є҆́смь, ра́дꙋѧсѧ, и҆ ви́дѧ ва́шъ чи́нъ, и҆ ᲂу҆твержде́нїе ва́шеѧ вѣ́ры ꙗ҆́же во хрⷭ҇та̀. ꙗ҆́коже ᲂу҆̀бо прїѧ́сте хрⷭ҇та̀ і҆и҃са гдⷭ҇а, та́коже въ не́мъ ходи́те, ᲂу҆корене́ни, и҆ назда́ни въ не́мъ, и҆ и҆звѣ́ствовани вѣ́рою, ꙗ҆́коже наꙋчи́стесѧ, и҆збы́точествꙋюще въ не́й благодаре́нїемъ. ",
}

add_apostol {
  ["номер"] = 254,
  ["комментарий"] = "Кол., 254 зач., II, 8–12.",
  ["текст_ру"] = "Бра́тие, блюди́теся, да никто́же вас бу́дет прельща́я филосо́фиею и тще́тною ле́стию, по преда́нию челове́ческому, по стихи́ам ми́ра, а не по Христе́. Я́ко в том живе́т вся́ко исполне́ние Божества́ теле́сне. И да бу́дете в Нем испо́лнени, и́же есть глава́ вся́кому нача́лу и вла́сти; о Не́мже и обре́зани бы́сте обре́занием нерукотворе́нным, в совлече́нии те́ла грехо́внаго пло́ти, во обре́зании Христо́ве, спогре́бшеся Ему́ креще́нием; о Не́мже и совоста́сте ве́рою, де́йством Бо́га, воскреси́вшаго Его́ из ме́ртвых. ",
  ["текст_цс"] = "Бра́тїе, блюди́тесѧ, да никто́же ва́съ бꙋ́детъ прельща́ѧ фїлосо́фїею, и҆ тще́тною ле́стїю, по преда́нїю человѣ́ческомꙋ, по стїхі́амъ мі́ра, а҆ не по хрⷭ҇тѣ̀: ꙗ҆́кѡ въ то́мъ живе́тъ всѧ́ко и҆сполне́нїе бж҃ества̀ тѣле́снѣ: и҆ да бꙋ́дете въ не́мъ и҆спо́лнени, и҆́же є҆́сть глава̀ всѧ́комꙋ нача́лꙋ и҆ вла́сти: ѡ҆ не́мже и҆ ѡ҆брѣ́зани бы́сте ѡ҆брѣ́занїемъ нерꙋкотворе́ннымъ, въ совлече́нїи тѣ́ла грѣхо́внагѡ пло́ти, во ѡ҆брѣ́занїи хрⷭ҇то́вѣ, спогре́бшесѧ є҆мꙋ̀ креще́нїемъ: ѡ҆ не́мже и҆ совоста́сте вѣ́рою, дѣ́йствомъ бг҃а, воскреси́вшагѡ є҆го̀ и҆з̾ ме́ртвыхъ. ",
}

add_apostol {
  ["номер"] = 255,
  ["комментарий"] = "Кол., 255 зач., II, 13–20.",
  ["текст_ру"] = "Бра́тие, Бог вы ме́ртвы су́щя в прегреше́ниих и в необре́зании пло́ти ва́шея, сооживи́л есть со Христо́м, дарова́в нам вся прегреше́ния, истреби́в е́же на нас рукописа́ние уче́ньми, е́же бе сопроти́вно нам, и то взят от среды́, пригвозди́в е́ на Кресте́, совле́к нача́ла и вла́сти, изведе́ в позо́р дерзнове́нием, изобличи́в их в Себе́. Да никто́же у́бо вас осужда́ет о яде́нии, или́ о питии́, или́ о ча́сти пра́здника, или́ о новоме́сячиих, или́ о суббо́тах, я́же суть стень гряду́щих, те́ло же Христо́во. Никто́же вас да прельща́ет изволе́нным ему́ смиреному́дрием и слу́жбою А́нгельскою, я́же не уве́де учя́, без ума́ дмя́ся от ума́ пло́ти своея́, а не держя́ главы́, из нея́же все те́ло, соста́вы и соу́зы подае́мо и сне́млемо, расти́т возраще́ние Бо́жие. А́ще у́бо умро́сте со Христо́м от стихи́й ми́ра, почто́ а́ки живу́ще в ми́ре стяза́етеся? ",
  ["текст_цс"] = "Бра́тїе, бг҃ъ вы̀ мє́ртвы сꙋ́щѧ въ прегрѣше́нїихъ, и҆ въ неѡбрѣ́занїи пло́ти ва́шеѧ, соѡживи́лъ є҆́сть со хрⷭ҇то́мъ, дарова́въ на́мъ всѧ̀ прегрѣшє́нїѧ: и҆стреби́въ є҆́же на на́съ рꙋкописа́нїе ᲂу҆че́ньми, є҆́же бѣ̀ сопроти́вно на́мъ, и҆ то̀ взѧ́тъ ѿ среды̀, пригвозди́въ є҆̀ на крⷭ҇тѣ̀: совле́къ нача̑ла и҆ вла̑сти, и҆зведѐ въ позо́ръ дерзнове́нїемъ, и҆з̾ѡбличи́въ и҆̀хъ въ себѣ̀ да никто́же ᲂу҆̀бо ва́съ ѡ҆сꙋжда́етъ ѡ҆ ꙗ҆де́нїи, и҆лѝ ѡ҆ питїѝ, и҆лѝ ѡ҆ ча́сти пра́здника, и҆лѝ ѡ҆ новомѣ́сѧчїихъ, и҆лѝ ѡ҆ сꙋббѡ́тахъ: ꙗ҆̀же сꙋ́ть стѣ́нь грѧдꙋ́щихъ, тѣ́ло же хрⷭ҇то́во. никто́же ва́съ да прельща́етъ и҆зволе́ннымъ є҆мꙋ̀ смиреномꙋ́дрїемъ, и҆ слꙋ́жбою а҆́гг҃льскою, ꙗ҆̀же не ᲂу҆вѣ́дѣ ᲂу҆чѧ̀, без̾ ᲂу҆ма̀ дмѧ́сѧ ѿ ᲂу҆ма̀ пло́ти своеѧ̀: и҆ не держѧ̀ главы̀, и҆з̾ неѧ́же всѐ тѣ́ло, соста́вы и҆ соꙋ́зы подае́мо, и҆ сне́млемо, расти́тъ возраще́нїе бж҃їе. а҆́ще ᲂу҆̀бо ᲂу҆мро́сте со хрⷭ҇то́мъ ѿ стїхі́й мі́ра почто̀ а҆́ки живꙋ́ще въ мі́рѣ стѧза́етесѧ; ",
}

add_apostol {
  ["номер"] = 256,
  ["комментарий"] = "Кол., 256 зач., II, 20 – III, 3.",
  ["текст_ру"] = "Бра́тие, а́ще умро́сте со Христо́м от стихи́й ми́ра, почто́ а́ки живу́ще в ми́ре стяза́етеся? Не косни́ся, ниже́ вкуси́, ни осяжи́; я́же суть вся во истле́ние употребле́нием, по за́поведем и уче́нием челове́ческим; я́же суть сло́во у́бо иму́ще прему́дрости в самово́льней слу́жбе, и смиреному́дрии и непощаде́нии те́ла, не в че́сти ко́ей к сы́тости пло́ти. А́ще у́бо воскресну́сте со Христо́м, вы́шних ищи́те, иде́же есть Христо́с одесну́ю Бо́га седя́; го́рняя му́дрствуйте, а не земна́я. Умро́сте бо, и живо́т ваш сокрове́н есть со Христо́м в Бо́зе. ",
