add_apostol {
  ["номер"] = 258,
  ["комментарий"] = "Кол., 258 зач., III, 12–16.",
  ["текст_ру"] = "Бра́тие, облецы́теся у́бо, я́коже избра́ннии Бо́жии, свя́ти и возлю́бленни, во утро́бы щедро́т, бла́гость, смиреному́дрие, кро́тость и долготерпе́ние, прие́млюще друг дру́га и проща́юще себе́, а́ще кто на кого́ и́мать порече́ние, я́коже и Христо́с прости́л есть вам, та́ко и вы. Над все́ми же си́ми стяжи́те любо́вь, я́же есть соу́з соверше́нства. И мир Бо́жий да водворя́ется в сердца́х ва́ших, во́ньже и зва́ни бы́сте во еди́ном те́ле, и благода́рни быва́йте. Сло́во Христо́во да вселя́ется в вас бога́тно, во вся́кой прему́дрости, уча́ще и вразумля́юще себе́ саме́х во псалме́х и пе́ниих и пе́снех духо́вных, во благода́ти пою́ще в сердца́х ва́ших Го́сподеви. ",
  ["текст_цс"] = "Бра́тїе, ѡ҆блецы́тесѧ ᲂу҆̀бо [ꙗ҆́коже и҆збра́ннїи бж҃їи, ст҃и, и҆ возлю́бленни,] во ᲂу҆трѡ́бы щедро́тъ, бл҃гость, смиреномꙋ́дрїе, кро́тость, и҆ долготерпѣ́нїе: прїе́млюще дрꙋгъдрꙋ́га, и҆ проща́юще себѣ̀, а҆́ще кто̀ на кого̀ и҆́мать порече́нїе: ꙗ҆́коже и҆ хрⷭ҇то́съ прости́лъ є҆́сть ва́мъ, та́кѡ и҆ вы̀. над̾ всѣ́ми же си́ми стѧжи́те любо́вь, ꙗ҆́же є҆́сть соꙋ́зъ соверше́нства. и҆ ми́ръ бж҃їй да водворѧ́етсѧ въ сердца́хъ ва́шихъ, во́ньже и҆ зва́ни бы́сте во є҆ди́номъ тѣ́лѣ: и҆ благода́рни быва́йте. сло́во хрⷭ҇то́во да вселѧ́етсѧ въ ва́съ бога́тнѡ, во всѧ́кой премꙋ́дрости, ᲂу҆ча́ще и҆ вразꙋмлѧ́юще себѐ самѣ́хъ во ѱалмѣ́хъ, и҆ пѣ́нїихъ и҆ пѣ́снехъ дꙋхо́вныхъ, ѡ҆ благода́ти пою́ще въ сердца́хъ ва́шихъ гдⷭ҇ви. ",
}

add_apostol {
  ["номер"] = 259,
  ["комментарий"] = "Кол., 259 зач., III, 17 – IV, 1.",
  ["текст_ру"] = "Бра́тие, все е́же а́ще что твори́те сло́вом или́ делом, вся во и́мя Го́спода Иису́са Христа́, благодаря́ще Бо́га и Отца́ Тем. Жены́, повину́йтеся свои́м муже́м, я́коже подоба́ет о Го́споде. Му́жие, люби́те жены́ ва́ша, и не огорча́йтеся к ним. Ча́да, послу́шайте роди́телей свои́х во всем, сие́ бо уго́дно есть Го́сподеви. Отцы́, не раздража́йте чад ва́ших, да не уныва́ют. Раби́, послу́шайте по всему́ плотски́х госпо́дий ва́ших, не пред очи́ма то́чию рабо́тающе а́ки человекоуго́дницы, но в простоте́ се́рдца, боя́щеся Бо́га. И вся́ко, е́же а́ще что творите́, от души́ де́лайте, я́коже Го́споду, а не челове́ком, ве́дяще, я́ко от Го́спода прии́мете воздая́ние достоя́ния, Го́споду бо Христу́ рабо́таете. А оби́дяй восприи́мет, е́же оби́де, и несть лица́ обинове́ния. Госпо́дие, пра́вду и уравне́ние рабо́м подава́йте, ве́дяще, я́ко и вы и́мате Го́спода на небесе́х. ",
  ["текст_цс"] = "Бра́тїе, всѐ є҆́же а҆́ще что̀ творитѐ сло́вомъ, и҆лѝ дѣ́ломъ, всѧ̑ во и҆́мѧ гдⷭ҇а і҆и҃са хрⷭ҇та̀, благодарѧ́ще бг҃а и҆ ѻ҆ц҃а̀ тѣ́мъ. жєны̀, повинꙋ́йтесѧ свои́мъ мꙋжє́мъ, ꙗ҆́коже подоба́етъ ѡ҆ гдⷭ҇ѣ. мꙋ́жїе, люби́те жєны̀ ва́шѧ, и҆ не ѡ҆горча́йтесѧ къ ни́мъ. ча́да, послꙋ́шайте роди́телей свои́хъ во все́мъ: сїе́ бо ᲂу҆го́дно є҆́сть гдⷭ҇ви. ѻ҆ц҃ы̀, не раздража́йте ча̑дъ ва́шихъ, да не ᲂу҆ныва́ютъ. рабѝ, послꙋ́шайте по всемꙋ̀ плотски́хъ госпо́дїй ва́шихъ, не пред̾ ѻ҆чи́ма то́чїю рабо́тающе а҆́ки чл҃вѣкоꙋго́дницы, но въ простотѣ̀ се́рдца, боѧ́щесѧ бг҃а. и҆ всѧ́ко, є҆́же а҆́ще что̀ творитѐ, ѿ дꙋшѝ дѣ́лайте, ꙗ҆́коже гдⷭ҇ꙋ, а҆ не человѣ́кѡмъ: вѣ́дѧще, ꙗ҆́кѡ ѿ гдⷭ҇а прїи́мете воздаѧ́нїе достоѧ́нїѧ: гдⷭ҇ꙋ бо хрⷭ҇тꙋ̀ рабо́таете. а҆ ѡ҆би́дѧй, воспрїи́метъ є҆́же ѡ҆би́дѣ, и҆ нѣ́сть лица̀ ѡ҆бинове́нїѧ. госпо́дїе, пра́вдꙋ и҆ ᲂу҆равне́нїе рабѡ́мъ подава́йте, вѣ́дѧще, ꙗ҆́кѡ и҆ вы̀ и҆́мате гдⷭ҇а на нб҃сѣ́хъ. ",
