  ["текст_ру"] = "Бра́тие, в прему́дрости ходи́те ко вне́шним, вре́мя искупу́юще. Сло́во ва́ше да быва́ет всегда́ во благода́ти, со́лию растворе́но, ве́дети, ка́ко подоба́ет вам еди́ному кому́ждо отвещава́ти. А я́же о мне, вся ска́жет вам Тихи́к, возлю́бленный брат и ве́рен служи́тель, и срабо́тник о Го́споде, его́же посла́х к вам на се и́стое, я́ко да разуме́ет я́же о вас и уте́шит сердца́ ва́ша, со Они́симом, ве́рным и возлю́бленным бра́том на́шим, и́же есть от вас, вся вам ска́жут, я́же зде. Целу́ет вы Лука́ врачь возлю́бленный, и Дима́с. Целова́ние мое́ю руко́ю Па́влею. Помина́йте моя́ у́зы. Благода́ть со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, въ премꙋ́дрости ходи́те ко внѣ́шнимъ, вре́мѧ и҆скꙋпꙋ́юще. сло́во ва́ше да быва́етъ всегда̀ во благода́ти, со́лїю растворе́но, вѣ́дѣти, ка́кѡ подоба́етъ ва́мъ є҆ди́номꙋ комꙋ́ждо ѿвѣщава́ти. а҆ ꙗ҆̀же ѡ҆ мнѣ̀, всѧ̑ ска́жетъ ва́мъ тѷхі́къ возлю́бленный бра́тъ, и҆ вѣ́ренъ слꙋжи́тель, и҆ срабо́тникъ ѡ҆ гдⷭ҇ѣ. є҆го́же посла́хъ къ ва́мъ на сѐ и҆́стое, ꙗ҆́кѡ да разꙋмѣ́етъ ꙗ҆̀же ѡ҆ ва́съ, и҆ ᲂу҆тѣ́шитъ сердца̀ ва́ша, со ѻ҆ни́сїмомъ вѣ́рнымъ, и҆ возлю́бленнымъ бра́томъ на́шимъ, и҆́же є҆́сть ѿ ва́съ: всѧ̑ ва́мъ ска́жꙋтъ ꙗ҆̀же здѣ̀. цѣлꙋ́етъ вы̀ лꙋка̀ вра́чь возлю́бленный, и҆ дима́съ. цѣлова́нїе мое́ю рꙋко́ю па́ѵлею. помина́йте моѧ̀ ᲂу҆́зы. бл҃года́ть со всѣ́ми ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 261,
  ["комментарий"] = "Кол., 261 зач., IV, 10–18.",
  ["текст_ру"] = "Бра́тие, целу́ет вы Ариста́рх спле́нник мой, и Ма́рко анепсе́й Варна́вин, о не́мже прия́сте за́поведи, а́ще прии́дет к вам, приими́те его́, и Иису́с нарече́нный Иу́ст, су́щии от обре́зания: си́и еди́ни споспе́шницы во Ца́рство Бо́жие, и́же бы́ша ми утеше́ние. Целу́ет вы Епафра́с, и́же от вас, раб Иису́са Христа́, всегда́ подвиза́яйся о вас в моли́твах, да бу́дете соверше́ни и испо́лнени во вся́кой во́ли Бо́жией. Свиде́тельствую бо о нем, я́ко и́мать ре́вность мно́гу и боле́знь о вас и о су́щих в Лаодики́и и во Иерапо́ли. Целу́ет вы Лука́ врачь возлю́бленный, и Дима́с. Целу́йте бра́тию су́щую в Лаодики́и, и Нимфа́на, и дома́шнюю его́ це́рковь. И егда́ прочте́тся посла́ние сие́ у вас, сотвори́те, да и в Лаодики́йстей це́ркви прочте́но бу́дет, и напи́саное от Лаодики́и да и вы прочте́те. И рцы́те Архи́ппу: блюди́ служе́ние, е́же прия́л еси́ о Го́споде, да доверши́ши е́. Целова́ние мое́ю руко́ю Па́влею. Помина́йте моя́ у́зы. Благода́ть со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, цѣлꙋ́етъ вы̀ а҆рїста́рхъ сплѣ́нникъ мо́й, и҆ ма́рко а҆неѱе́й варна́винъ, ѡ҆ не́мже прїѧ́сте за́пѡвѣди: а҆́ще же прїи́детъ къ ва́мъ, прїими́те є҆го̀: и҆ і҆исꙋ́съ нарече́нный і҆ꙋ́стъ, сꙋ́щїи ѿ ѡ҆брѣ́занїѧ: сі́и є҆ди́ни споспѣ́шницы во црⷭ҇тво бж҃їе, и҆̀же бы́ша мѝ ᲂу҆тѣше́нїе. цѣлꙋ́етъ вы̀ є҆пафра́съ, и҆́же ѿ ва́съ, ра́бъ і҆и҃са хрⷭ҇та̀, всегда̀ подвиза́ѧйсѧ ѡ҆ ва́съ въ моли́твахъ, да бꙋ́дете соверше́ни и҆ и҆спо́лнени во всѧ́кой во́ли бж҃їей. свидѣ́тельствꙋю бо ѡ҆ не́мъ, ꙗ҆́кѡ и҆́мать ре́вность мно́гꙋ, и҆ болѣ́знь ѡ҆ ва́съ, и҆ ѡ҆ сꙋ́щихъ въ лаодїкі́и, и҆ во і҆ерапо́ли. цѣлꙋ́етъ вы̀ лꙋка̀ вра́чь возлю́бленный, и҆ дима́съ. цѣлꙋ́йте бра́тїю сꙋ́щꙋю въ лаодїкі́и, и҆ нѷмфа́на, и҆ дома́шнюю є҆гѡ̀ цр҃ковь. и҆ є҆гда̀ прочте́тсѧ посла́нїе сїѐ ѿ ва́съ, сотвори́те, да и҆ въ лаодїкі́йстѣй цр҃кви прочте́но бꙋ́детъ, и҆ напи́санное ѿ лаодїкі́и, да и҆ вы̀ прочте́те. и҆ рцы́те а҆рхі́ппꙋ: блюдѝ слꙋже́нїе, є҆́же прїѧ́лъ є҆сѝ ѡ҆ гдⷭ҇ѣ, да доверши́ши є҆̀. цѣлова́нїе мое́ю рꙋко́ю па́ѵлею. помина́йте моѧ̀ ᲂу҆́зы. бл҃года́ть со всѣ́ми ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 262,
  ["комментарий"] = "1 Сол., 262 зач., I, 1–5.",
  ["текст_ру"] = "Па́вел и Силуа́н, и Тимофе́й це́ркви Солу́нстей о Бо́зе Отце́ и Го́споде Иису́се Христе́: благода́ть вам и мир от Бо́га Отца́ на́шего и Го́спода Иису́са Христа́. Благодари́м Бо́га всегда́ о всех вас, помина́ние ва́ше творя́ще в моли́твах на́ших, непреста́нно помина́юще ва́ше де́ло ве́ры, и труд любве́, и терпе́ние упова́ния Го́спода на́шего Иису́са Христа́, пред Бо́гом и Отце́м на́шим, ве́дяще, бра́тие возлю́бленная, от Бо́га избра́ние ва́ше, я́ко благовествова́ние на́ше не бысть к вам в сло́ве то́чию, но и си́лою, и Ду́хом Святы́м, и во извеще́нии мно́зе, я́коже и ве́сте, какови́ бы́хом в вас ра́ди вас. ",
  ["текст_цс"] = "Па́ѵелъ и҆ сїлꙋа́нъ и҆ тїмоѳе́й, цр҃кви солꙋ́нстѣй, ѡ҆ бз҃ѣ ѻ҆ц҃ѣ̀, и҆ гдⷭ҇ѣ і҆и҃сѣ хрⷭ҇тѣ̀: бл҃года́ть ва́мъ и҆ ми́ръ ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀. благодари́мъ бг҃а всегда̀ ѡ҆ всѣ́хъ ва́съ, помина́нїе ва́ше творѧ́ще въ моли́твахъ на́шихъ: непреста́ннѡ помина́юще ва́ше дѣ́ло вѣ́ры, и҆ трꙋ́дъ любвѐ, и҆ терпѣ́нїе ᲂу҆пова́нїѧ гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, пред̾ бг҃омъ и҆ ѻ҆ц҃е́мъ на́шимъ. вѣ́дѧще бра́тїе возлю́бленнаѧ, ѿ бг҃а и҆збра́нїе ва́ше: ꙗ҆́кѡ благовѣствова́нїе на́ше не бы́сть къ ва́мъ въ сло́вѣ то́чїю, но и҆ си́лою, и҆ дх҃омъ ст҃ы́мъ, и҆ во и҆звѣще́нїи мно́зѣ: ꙗ҆́коже и҆ вѣ́сте, каковѝ бы́хомъ въ ва́съ, ра́ди ва́съ. ",
}

add_apostol {
  ["номер"] = 263,
  ["комментарий"] = "1 Сол., 263 зач., I, 6–10.",
  ["текст_ру"] = "Бра́тие, вы подо́бницы бы́сте нам и Го́споду, прие́мше сло́во в ско́рби мно́зе с ра́достию Ду́ха Свята́го, я́ко бы́ти вам о́браз всем ве́рующым в Македо́нии и Аха́ии. От вас бо промче́ся сло́во Госпо́дне не то́кмо в Македо́нии и Аха́ии, но и во вся́ко ме́сто ве́ра ва́ша, я́же к Бо́гу, изы́де, я́ко не тре́бовати нам глаго́лати что. Ти́и бо о нас возвеща́ют, како́в вход име́хом к вам, и ка́ко обрати́стеся к Бо́гу от и́дол, рабо́тати Бо́гу жи́ву и и́стинну и жда́ти Сы́на Его́ с небе́с, Его́же воскреси́ из ме́ртвых, Иису́са, избавля́ющаго нас от гне́ва гряду́щаго. ",
  ["текст_цс"] = "Бра́тїе, вы̀ подо́бницы бы́сте на́мъ и҆ гдⷭ҇ꙋ, прїе́мше сло́во въ ско́рби мно́зѣ, съ ра́достїю дх҃а ст҃а́гѡ: ꙗ҆́кѡ бы́ти ва́мъ ѻ҆́бразъ всѣ́мъ вѣ́рꙋющымъ въ македо́нїи и҆ а҆ха́їи. ѿ ва́съ бо промче́сѧ сло́во гдⷭ҇не, не то́кмѡ въ македо́нїи и҆ а҆ха́їи: но и҆ во всѧ́ко мѣ́сто вѣ́ра ва́ша, ꙗ҆́же къ бг҃ꙋ, и҆зы́де: ꙗ҆́кѡ не тре́бовати на́мъ глаго́лати что̀. ті́и бо ѡ҆ на́съ возвѣща́ютъ, како́въ вхо́дъ и҆мѣ́хомъ къ ва́мъ, и҆ ка́кѡ ѡ҆брати́стесѧ къ бг҃ꙋ ѿ і҆́дѡлъ, рабо́тати бг҃ꙋ жи́вꙋ и҆ и҆́стиннꙋ: и҆ жда́ти сн҃а є҆гѡ̀ съ нб҃съ, є҆го́же воскресѝ и҆з̾ ме́ртвыхъ, і҆и҃са и҆збавлѧ́ющаго на́съ ѿ гнѣ́ва грѧдꙋ́щагѡ. ",
}

add_apostol {
  ["номер"] = 264,
  ["комментарий"] = "1 Сол., 264 зач., II, 1–8.",
  ["текст_ру"] = "Бра́тие, ве́сте вход наш и́же к вам, я́ко не вотще́ бысть, но предпострада́вше и досажде́ни бы́вше, я́коже ве́сте, в Фили́ппех, дерзну́хом о Бо́зе на́шем глаго́лати к вам благовествова́ние Бо́жие со мно́гим по́двигом. Утеше́ние бо на́ше не от пре́лести, ни от нечистоты́, ни ле́стию, но я́коже искуси́хомся от Бо́га ве́рни бы́ти прия́ти благовествова́ние, та́ко глаго́лем, не а́ки челове́ком угожда́юще, но Бо́гу искуша́ющему сердца́ на́ша. Никогда́же бо в словеси́ ласка́ния бы́хом к вам, я́коже ве́сте, ниже́ вино́ю лихоима́ния, Бог свиде́тель! Ни и́щуще от челове́к сла́вы, ни от вас, ни от ине́х, могу́ще в тяготе́ бы́ти, я́коже Христо́вы Апо́столи, но бы́хом ти́си посреде́ вас, я́коже дои́лица гре́ет своя́ ча́да. Та́ко жела́юще вас, благоволи́хом пода́ти вам не то́чию благовествова́ние Бо́жие, но и ду́шы своя́, зане́же возлю́блени бы́сте нам. ",
  ["текст_цс"] = "Бра́тїе, вѣ́сте вхо́дъ на́шъ и҆́же къ ва́мъ, ꙗ҆́кѡ не вотщѐ бы́сть: но предпострада́вше и҆ досажде́ни бы́вше, ꙗ҆́коже вѣ́сте, въ фїлі́ппѣхъ, дерзнꙋ́хомъ ѡ҆ бз҃ѣ на́шемъ, глаго́лати къ ва́мъ благовѣствова́нїе бж҃їе со мно́гимъ по́двигомъ. ᲂу҆тѣше́нїе бо на́ше, не ѿ пре́лести, нѝ ѿ нечистоты̀, ни ле́стїю: но ꙗ҆́коже и҆скꙋси́хомсѧ ѿ бг҃а вѣ́рни бы́ти прїѧ́ти благовѣствова́нїе, та́кѡ глаго́лемъ, не а҆́ки человѣ́кѡмъ ᲂу҆гожда́юще, но бг҃ꙋ и҆скꙋша́ющемꙋ сердца̀ на́ша. никогда́же бо въ словесѝ ласка́нїѧ бы́хомъ къ ва́мъ, ꙗ҆́коже вѣ́сте, нижѐ вино́ю лихоима́нїѧ: бг҃ъ свидѣ́тель. ни и҆́щꙋще ѿ человѣ̑къ сла́вы, ни ѿ ва́съ, ни ѿ и҆нѣ́хъ: могꙋ́ще въ тѧготѣ̀ бы́ти, ꙗ҆́коже хрⷭ҇то́вы а҆пⷭ҇толи, но бы́хомъ ти́си посредѣ̀ ва́съ, ꙗ҆́коже дои́лица грѣ́етъ своѧ̀ ча̑да: та́кѡ жела́юще ва́съ, благоволи́хомъ пода́ти ва́мъ не то́чїю благовѣствова́нїе бж҃їе, но и҆ дꙋ́шы своѧ̀: зане́же возлю́блени бы́сте на́мъ. ",
