add_apostol {
  ["номер"] = 265,
  ["комментарий"] = "1 Сол., 265 зач., II, 9–14.",
  ["текст_ру"] = "Бра́тие, по́мните труд наш и по́двиг: нощь бо и день де́лающе, да не отяготи́ти ни еди́наго от вас, пропове́дахом вам благовествова́ние Бо́жие. Вы свиде́тели и Бог, я́ко преподо́бно и пра́ведно, и непоро́чно вам ве́рующым бы́хом, я́коже ве́сте, зане́ еди́наго кого́ждо вас, я́коже оте́ц ча́да своя́, моля́ще и утеша́юще вас, и свиде́тельствующе вам ходи́ти досто́йно Бо́гу, призва́вшему вы во Свое́ Ца́рство и сла́ву. Сего́ ра́ди и мы благодари́м Бо́га непреста́нно, я́ко прие́мше сло́во слы́шания Бо́жия от нас, прия́сте не а́ки сло́во челове́ческо, но я́коже есть вои́стинну сло́во Бо́жие, е́же и де́йствуется в вас ве́рующих. Вы бо подо́бницы бы́сте, бра́тие, це́рквам Бо́жиим су́щым во Иуде́и о Христе́ Иису́се. ",
  ["текст_цс"] = "Бра́тїе, по́мните трꙋ́дъ на́шъ, и҆ по́двигъ: но́щь бо и҆ де́нь дѣ́лающе, ꙗ҆́кѡ не ѡ҆тѧготи́ти ни є҆ди́нагѡ ѿ ва́съ, проповѣ́дахомъ ва́мъ бл҃говѣствова́нїе бж҃їе. вы̀ свидѣ́тели, и҆ бг҃ъ, ꙗ҆́кѡ преподо́бнѡ и҆ пра́веднѡ и҆ непоро́чнѡ ва́мъ вѣ́рꙋющымъ бы́хомъ: ꙗ҆́коже вѣ́сте, занѐ є҆ди́наго кого́ждо ва́съ, ꙗ҆́коже ѻ҆ц҃ъ ча̑да своѧ̀, молѧ́ще и҆ ᲂу҆тѣша́юще ва́съ, и҆ свидѣ́тельствꙋюще ва́мъ ходи́ти досто́йнѡ бг҃ꙋ, призва́вшемꙋ вы̀ во своѐ црⷭ҇тво и҆ сла́вꙋ. сегѡ̀ ра́ди и҆ мы̀ бл҃годари́мъ бг҃а непреста́ннѡ, ꙗ҆́кѡ прїе́мше сло́во слы́шанїѧ бж҃їѧ ѿ на́съ, прїѧ́сте не а҆́ки сло́во человѣ́ческо, но [ꙗ҆́коже є҆́сть вои́стиннꙋ] сло́во бж҃їе, є҆́же и҆ дѣ́йствꙋетсѧ въ ва́съ вѣ́рꙋющихъ. вы́ бо подо́бницы бы́сте бра́тїе, цр҃квамъ бж҃їимъ сꙋ́щымъ во і҆ꙋде́и, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. ",
