  ["текст_ру"] = "Бра́тие, вы подо́бницы бы́сте це́рквам Бо́жиим су́щым во Иуде́и о Христе́ Иису́се. Зане́ та́яжде и вы пострада́сте от свои́х сплеме́нник, я́коже и ти́и от иуде́й, уби́вших и Го́спода Иису́са и Его́ проро́ки, и нас изгна́вших, и Бо́гу не угоди́вших, и всем челове́ком проти́вящихся, и возбраня́ющих нам глаго́лати язы́ком, да спасу́тся, во е́же испо́лнити им грехи́ своя́ всегда́, пости́же же на них гнев до конца́. Мы же, бра́тие, осироте́вше от вас ко вре́мени часа́ лице́м, а не се́рдцем, ли́шше тща́хомся лице́ ва́ше ви́дети мно́гим жела́нием. Те́мже хоте́хом приити́ к вам, аз у́бо Па́вел, еди́ною и два́жды, и возбрани́ нам сатана́. Кто бо нам упова́ние или́ ра́дость, или́ вене́ц похвале́ния? Не и вы ли пред Го́сподем на́шим Иису́с Христо́м во прише́ствии Его́? ",
  ["текст_цс"] = "Бра́тїе, вы̀ подо́бницы бы́сте цр҃квамъ бж҃їимъ сꙋ́щымъ во і҆ꙋде́и, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. занѐ та̑ѧжде и҆ вы̀ пострада́сте ѿ свои́хъ сплемє́нникъ, ꙗ҆́коже и҆ ті́и ѿ і҆ꙋдє́й: и҆ ᲂу҆би́вшихъ гдⷭ҇а і҆и҃са, и҆ є҆гѡ̀ проро́ки, и҆ на́съ и҆згна́вшихъ, и҆ бг҃ꙋ неꙋгоди́вшихъ, и҆ всѣ́мъ человѣ́кѡмъ проти́вѧщихсѧ: и҆ возбранѧ́ющихъ на́мъ глаго́лати ꙗ҆зы́кѡмъ, да спасꙋ́тсѧ, во є҆́же и҆спо́лнити и҆̀мъ грѣхѝ своѧ̀ всегда̀: пости́же же на ни́хъ гнѣ́въ до конца̀. мы́ же бра́тїе ѡ҆сиротѣ́вше ѿ ва́съ ко вре́мени часа̀, лице́мъ а҆ не се́рдцемъ, ли́шше тща́хомсѧ лицѐ ва́ше ви́дѣти мно́гимъ жела́нїемъ. тѣ́мже хотѣ́хомъ прїитѝ къ ва́мъ, а҆́зъ ᲂу҆́бѡ па́ѵелъ є҆ди́ною и҆ два́жды, и҆ возбранѝ на́мъ сатана̀. кто́ бо на́мъ ᲂу҆пова́нїе, и҆лѝ ра́дость, и҆лѝ вѣне́цъ похвале́нїѧ, не и҆ вы́ ли пред̾ гдⷭ҇емъ на́шимъ і҆и҃съ хрⷭ҇то́мъ, во прише́ствїи є҆гѡ̀; ",
}

add_apostol {
  ["номер"] = 267,
  ["комментарий"] = "1 Сол., 267 зач., II, 20 – III, 8.",
  ["текст_ру"] = "Бра́тие, вы есте́ сла́ва на́ша и ра́дость. Те́мже уже́ не терпя́ще, благоволи́хом оста́тися во Афи́нех еди́ни, и посла́хом Тимофе́а, бра́та на́шего и служи́теля Бо́жия и споспе́шника на́шего во благове́стии Христо́ве, утверди́ти вас и уте́шити о ве́ре ва́шей, я́ко ни еди́ному смуща́тися в ско́рбех сих, са́ми бо ве́сте, я́ко на сие́ и́стое лежи́м. И́бо егда́ у вас бе́хом, предреко́хом вам, я́ко и́мамы скорбе́ти, е́же и бысть, и ве́сте. Сего́ ра́ди и аз ктому́ не терпя́, посла́х разуме́ти ве́ру ва́шу, да не ка́ко искуси́л вы бу́дет искуша́яй, и вотще́ бу́дет труд наш. Ны́не же прише́дшу Тимофе́ю к нам от вас и благовести́вшу нам ве́ру ва́шу и любо́вь, и я́ко и́мате па́мять о нас бла́гу, всегда́ жела́юще нас ви́дети, я́коже и мы вас. Сего́ ра́ди уте́шихомся, бра́тие, о вас, во вся́кой ско́рби и ну́жде на́шей, ва́шею ве́рою. Я́ко мы ны́не жи́ви есмы́, а́ще вы стоите́ о Го́споде. ",
  ["текст_цс"] = "Бра́тїе, вы̀ є҆стѐ сла́ва на́ша и҆ ра́дость. тѣ́мже ᲂу҆жѐ не терпѧ́ще, благоволи́хомъ ѡ҆ста́тисѧ во а҆ѳи́нѣхъ є҆ди́ни. и҆ посла́хомъ тїмоѳе́а бра́та на́шего, и҆ слꙋжи́телѧ бж҃їѧ, и҆ споспѣ́шника на́шего во благовѣ́стїи хрⷭ҇то́вѣ, ᲂу҆тверди́ти ва́съ и҆ ᲂу҆тѣ́шити ѡ҆ вѣ́рѣ ва́шей: ꙗ҆́кѡ ни є҆ди́номꙋ смꙋща́тисѧ въ ско́рбехъ си́хъ: са́ми бо вѣ́сте, ꙗ҆́кѡ на сїѐ и҆́стое лежи́мъ. и҆́бо є҆гда̀ ᲂу҆ ва́съ бѣ́хомъ, предреко́хомъ ва́мъ, ꙗ҆́кѡ и҆́мамы скорбѣ́ти, є҆́же и҆ бы́сть, и҆ вѣ́сте. сегѡ̀ ра́ди и҆ а҆́зъ ктомꙋ̀ не терпѧ̀, посла́хъ разꙋмѣ́ти вѣ́рꙋ ва́шꙋ, да не ка́кѡ и҆скꙋси́лъ вы̀ бꙋ́детъ и҆скꙋша́ѧй, и҆ вотщѐ бꙋ́детъ трꙋ́дъ на́шъ. ны́нѣ же прише́дшꙋ тїмоѳе́ю къ на́мъ ѿ ва́съ, и҆ благовѣсти́вшꙋ на́мъ вѣ́рꙋ ва́шꙋ и҆ любо́вь, и҆ ꙗ҆́кѡ и҆́мате па́мѧть ѡ҆ на́съ бла́гꙋ, всегда̀ жела́юще на́съ ви́дѣти, ꙗ҆́коже и҆ мы̀ ва́съ. сегѡ̀ ра́ди ᲂу҆тѣ́шихомсѧ бра́тїе ѡ҆ ва́съ, во всѧ́кой ско́рби и҆ нꙋ́ждѣ на́шей, ва́шею вѣ́рою. ꙗ҆́кѡ мы̀ ны́нѣ жи́ви є҆смы̀, а҆́ще вы̀ стоитѐ ѡ҆ гдⷭ҇ѣ. ",
}

add_apostol {
  ["номер"] = 268,
  ["комментарий"] = "1 Сол., 268 зач., III, 9–13.",
  ["текст_ру"] = "Бра́тие, ко́е благодаре́ние Бо́гу мо́жем возда́ти о вас, о вся́кой ра́дости, е́юже ра́дуемся вас ра́ди пред Бо́гом на́шим, нощь и день преизли́ха моля́щеся ви́дети лице́ ва́ше и соверши́ти лише́ние ве́ры ва́шея? Сам же Бог и Оте́ц наш и Госпо́дь наш Иису́с Христо́с да испра́вит путь наш к вам. Вас же Госпо́дь да умно́жит и да избы́точествит любо́вию друг ко дру́гу и ко всем, я́коже и мы к вам, во е́же утверди́ти сердца́ ва́ша непоро́чна в святы́ни пред Бо́гом и Отце́м на́шим, в прише́ствие Го́спода на́шего Иису́са Христа́ со все́ми святы́ми Его́. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, ко́е благодаре́нїе бг҃ꙋ мо́жемъ возда́ти ѡ҆ ва́съ, ѡ҆ всѧ́кой ра́дости, є҆́юже ра́дꙋемсѧ ва́съ ра́ди, пред̾ бг҃омъ на́шимъ; но́щь и҆ де́нь преизли́ха молѧ́щесѧ ви́дѣти лицѐ ва́ше, и҆ соверши́ти лише́нїе вѣ́ры ва́шеѧ. са́мъ же бг҃ъ и҆ ѻ҆ц҃ъ на́шъ и҆ гдⷭ҇ь на́шъ і҆и҃съ хрⷭ҇то́съ, да и҆спра́витъ пꙋ́ть на́шъ къ ва́мъ. ва́съ же гдⷭ҇ь да ᲂу҆мно́житъ, и҆ да и҆збы́точествитъ любо́вїю дрꙋ́гъ ко дрꙋ́гꙋ, и҆ ко всѣ́мъ, ꙗ҆́коже и҆ мы̀ къ ва́мъ: во є҆́же ᲂу҆тверди́ти сердца̀ ва́ша непорѡ́чна въ ст҃ы́ни, пред̾ бг҃омъ и҆ ѻ҆ц҃е́мъ на́шимъ, въ прише́ствїе гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ со всѣ́ми ст҃ы́ми є҆гѡ̀. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 269,
  ["комментарий"] = "1 Сол., 269 зач., IV, 1–12.",
  ["текст_ру"] = "Бра́тие, про́сим вы и мо́лим о Христе́ Иису́се да я́коже прия́сте от нас, ка́ко подоба́ет вам ходи́ти и угожда́ти Бо́гови, я́коже и ходи́те, да избы́точествуете па́че, ве́сте бо, какова́ повеле́ния да́хом вам Го́сподем Иису́сом. Сия́ бо есть во́ля Бо́жия, свя́тость ва́ша, храни́ти себе́ саме́х от блуда́, и ве́дети кому́ждо от вас свой сосу́д стяжава́ти во святы́ни и че́сти, а не в стра́сти по́хотней, я́коже и язы́цы не ве́дящии Бо́га. И е́же не преступа́ти и лихои́мствовати в ве́щи бра́та своего́, зане́ мсти́тель есть Госпо́дь о всех сих, я́коже и пре́жде реко́хом к вам и засвиде́тельствовахом. Не призва́ бо нас Бог на нечистоту́, но во свя́тость. Те́мже у́бо отмета́яй не челове́ка отмета́ет, но Бо́га, да́вшаго Дух Свой Святы́й в нас. О братолю́бии же, не тре́буете, да пи́шется к вам, са́ми бо вы Бо́гом уче́ни есте́, е́же люби́ти друг дру́га, и́бо творите́ то ко всей бра́тии, су́щей во всей Македо́нии. Мо́лим же вы, бра́тие, избы́точествовати па́че, и любе́зно прилежа́ти, е́же безмо́лвствовати и де́яти своя́ и де́лати свои́ми рука́ма, я́коже повеле́хом вам, да хо́дите благообра́зно ко вне́шним и ни еди́наго же тре́бовати. ",
  ["текст_цс"] = "Бра́тїе, про́симъ вы̀ и҆ мо́лимъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: да ꙗ҆́коже прїѧ́сте ѿ на́съ, ка́кѡ подоба́етъ ва́мъ ходи́ти и҆ ᲂу҆гожда́ти бг҃ови, та́кожде и҆ ходи́те, да и҆збы́точествꙋете па́че: вѣ́сте бо какова̀ повелѣ̑нїѧ да́хомъ ва́мъ, гдⷭ҇емъ і҆и҃сомъ. сїѧ́ бо є҆́сть во́лѧ бж҃їѧ, ст҃ость ва́ша, храни́ти себѐ самѣ́хъ ѿ блꙋда̀: и҆ вѣ́дѣти комꙋ́ждо ѿ ва́съ сво́й сосꙋ́дъ стѧжава́ти во ст҃ы́ни и҆ че́сти: а҆ не въ стра́сти по́хотнѣй, ꙗ҆́коже и҆ ꙗ҆зы́цы не вѣ́дѧщїи бг҃а. и҆ є҆́же не престꙋпа́ти и҆ лихои́мствовати въ ве́щи бра́та своегѡ̀: занѐ мсти́тель є҆́сть гдⷭ҇ь ѡ҆ всѣ́хъ си́хъ, ꙗ҆́коже и҆ пре́жде реко́хомъ къ ва́мъ, и҆ засвидѣ́тельствовахомъ. не призва́ бо на́съ бг҃ъ на нечистотꙋ̀, но во ст҃ость. тѣ́мже ᲂу҆́бѡ ѿмета́ѧй, не человѣ́ка ѿмета́етъ, но бг҃а, да́вшаго дх҃ъ сво́й ст҃ы́й въ на́съ. ѡ҆ братолю́бїи же, не тре́бꙋете, да пи́шетсѧ къ ва́мъ: са́ми бо вы̀ бг҃омъ ᲂу҆че́ни є҆стѐ, є҆́же люби́ти дрꙋгъдрꙋ́га: и҆́бо творитѐ то̀ ко все́й бра́тїи, сꙋ́щей во все́й македо́нїи. мо́лимъ же вы̀ бра́тїе, и҆збы́точествовати па́че, и҆ любе́знѡ прилѣжа́ти є҆́же безмо́лвствовати, и҆ дѣ́ѧти своѧ̑, и҆ дѣ́лати свои́ми рꙋка́ми, ꙗ҆́коже повелѣ́хомъ ва́мъ: да хо́дите бл҃гоѻбра́знѡ ко внѣ́шнимъ, и҆ ни є҆ди́нагѡ же тре́бовати. ",
}

add_apostol {
  ["номер"] = 270,
  ["комментарий"] = "1 Сол., 270 зач., IV, 13–17.",
  ["текст_ру"] = "Бра́тие, не хощу́ вас неве́дети о уме́рших, да не скорбите́, я́коже и про́чии не иму́щии упова́ния. А́ще бо ве́руем, я́ко Иису́с у́мре и воскре́се та́ко и Бог уме́ршия во Иису́се приведе́т с Ним. Сие́ бо вам глаго́лем сло́вом Госпо́дним, я́ко мы живу́щии, оста́вшии в прише́ствие Госпо́дне, не и́мамы предвари́ти уме́рших. Я́ко Сам Госпо́дь в повеле́нии, во гла́се Арха́нгелове и в трубе́ Бо́жии сни́дет с небесе́, и ме́ртвии о Христе́ воскре́снут пе́рвее. Пото́м же мы, живу́щии оста́вшии, ку́пно с ни́ми восхище́ни бу́дем на о́блацех в сре́тение Госпо́дне на возду́се и та́ко всегда́ с Го́сподем бу́дем. ",
  ["текст_цс"] = "Бра́тїе, не хощꙋ̀ ва́съ невѣ́дѣти ѡ҆ ᲂу҆ме́ршихъ, да не скорбитѐ, ꙗ҆́коже и҆ про́чїи не и҆мꙋ́щїи ᲂу҆пова́нїѧ. а҆́ще бо вѣ́рꙋемъ, ꙗ҆́кѡ і҆и҃съ ᲂу҆́мре и҆ воскре́се, та́кѡ и҆ бг҃ъ ᲂу҆ме́ршыѧ ѡ҆ і҆и҃сѣ приведе́тъ съ ни́мъ. сїе́ бо ва́мъ глаго́лемъ сло́вомъ гдⷭ҇нимъ: ꙗ҆́кѡ мы̀ живꙋ́щїи ѡ҆ста́вшїи въ прише́ствїе гдⷭ҇не, не и҆́мамы предвари́ти ᲂу҆ме́ршихъ. ꙗ҆́кѡ са́мъ гдⷭ҇ь въ повелѣ́нїи, во гла́сѣ а҆рха́гг҃ловѣ, и҆ въ трꙋбѣ̀ бж҃їи сни́детъ съ нб҃сѐ, и҆ ме́ртвїи ѡ҆ хрⷭ҇тѣ̀ воскре́снꙋтъ пе́рвѣе. пото́мъ же мы̀ живꙋ́щїи ѡ҆ста́вшїи, кꙋ́пнѡ съ ни́ми восхище́ни бꙋ́демъ на ѻ҆́блацѣхъ, въ срѣ́тенїе гдⷭ҇не на воздꙋ́сѣ: и҆ та́кѡ всегда̀ съ гдⷭ҇емъ бꙋ́демъ. ",
}

add_apostol {
  ["номер"] = 271,
  ["комментарий"] = "1 Сол., 271 зач., V, 1–8.",
  ["текст_ру"] = "Бра́тие, о ле́тех и о времене́х не тре́бе есть вам писа́ти. Са́ми бо вы изве́стно ве́сте, я́ко день Госпо́день, я́коже тать в нощи́, та́ко прии́дет. Егда́ бо реку́т: мир и утвержде́ние, тогда́ внеза́пу нападе́т на них всегуби́тельство, я́коже боле́знь во чре́ве иму́щей, и не и́мут избежа́ти. Вы же, бра́тие, не́сте во тме, да день вас я́коже тать пости́гнет. Вси бо вы сы́нове све́та есте́, и сы́нове дне, не́смы но́щи, ниже́ тмы. Те́мже у́бо да не спим, я́коже и про́чии, но да бо́дрствуим и трезви́мся. Спя́щии бо, в нощи́ спят, и упива́ющиися в нощи́ упива́ются. Мы же, сы́нове су́ще дне, да трезви́мся, обо́лкшеся в броню́ ве́ры и любве́, и шлем упова́ния спасе́ния. ",
  ["текст_цс"] = "Бра́тїе, ѡ҆ лѣ́тѣхъ и҆ ѡ҆ временѣ́хъ не тре́бѣ є҆́сть ва́мъ писа́ти. са́ми бо вы̀ и҆звѣ́стнѡ вѣ́сте, ꙗ҆́кѡ де́нь гдⷭ҇нь, ꙗ҆́коже та́ть въ нощѝ, та́кѡ прїи́детъ. є҆гда́ бо рекꙋ́тъ ми́ръ и҆ ᲂу҆твержде́нїе, тогда̀ внеза́пꙋ нападе́тъ на ни́хъ всегꙋби́тельство, ꙗ҆́коже и҆ болѣ́знь во чре́вѣ и҆мꙋ́щей: и҆ не и҆́мꙋтъ и҆збѣжа́ти. вы́ же бра́тїе, нѣ́сте во тмѣ̀, да де́нь ва́съ ꙗ҆́коже та́ть пости́гнетъ. вси́ бо вы̀ сы́нове свѣ́та є҆стѐ, и҆ сы́нове днѐ: нѣ́смы но́щи, нижѐ тмы̀. тѣ́мже ᲂу҆́бѡ да не спи́мъ ꙗ҆́коже и҆ про́чїи, но да бо́дрствꙋимъ и҆ трезви́мсѧ: спѧ́щїи бо, въ нощѝ спѧ́тъ, и҆ ᲂу҆пива́ющїисѧ, въ нощѝ ᲂу҆пива́ютсѧ. мы́ же сы́нове сꙋ́ще днѐ, да трезви́мсѧ, ѡ҆бо́лкшесѧ въ броню̀ вѣ́ры и҆ любвѐ, и҆ шле́мъ ᲂу҆пова́нїѧ спасе́нїѧ. ",
}

add_apostol {
  ["номер"] = 272,
  ["комментарий"] = "1 Сол., 272 зач., V, 9–13, 24–28.",
  ["текст_ру"] = "Бра́тие, не положи́ нас Бог в гнев, но в получе́ние спасе́ния Го́сподем на́шим Иису́с Христо́м, уме́ршим за нас, да а́ще бдим, а́ще ли спим, ку́пно с Ним и оживе́м. Сего́ ра́ди утеша́йте друг дру́га, и созида́йте ко́йждо бли́жняго, я́коже и творите́. Мо́лим же вы, бра́тие, зна́йте тружда́ющихся у вас, и настоя́телей ва́ших о Го́споде, и наказу́ющих вы, и име́йте я́ по преизли́ха в любви́ за де́ло их, ми́рствуйте в себе́. Ве́рен Призва́вый вас, И́же и сотвори́т. Бра́тие, моли́теся о нас. Целу́йте бра́тию всю лобза́нием святы́м. Заклина́ю вы Го́сподем, прочести́ посла́ние сие́ пред все́ю свято́ю бра́тиею. Благода́ть Го́спода на́шего Иису́са Христа́ с ва́ми. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, не положѝ на́съ бг҃ъ въ гнѣ́въ, но въ полꙋче́нїе спасе́нїѧ, гдⷭ҇емъ на́шимъ і҆и҃съ хрⷭ҇то́мъ, ᲂу҆ме́ршимъ за на́съ: да а҆́ще бди́мъ, а҆́ще ли спи́мъ, кꙋ́пнѡ съ ни́мъ и҆ ѡ҆живе́мъ. сегѡ̀ ра́ди ᲂу҆тѣша́йте дрꙋгъдрꙋ́га, и҆ созида́йте ко́йждо бли́жнѧго, ꙗ҆́коже и҆ творитѐ. мо́лимъ же вы̀ бра́тїе, зна́йте трꙋжда́ющихсѧ ᲂу҆ ва́съ, и҆ настоѧ́телей ва́шихъ ѡ҆ гдⷭ҇ѣ, и҆ наказꙋ́ющихъ вы̀. и҆ и҆мѣ́йте ѧ҆̀ по преизли́ха въ любвѝ, за дѣ́ло и҆́хъ ми́рствꙋйте въ себѣ̀. вѣ́ренъ призва́вый ва́съ, и҆́же и҆ сотвори́тъ. бра́тїе, моли́тесѧ и҆ ѡ҆ на́съ. цѣлꙋ́йте бра́тїю всю̀ лобза́нїемъ ст҃ы́мъ. заклина́ю вы̀ гдⷭ҇емъ, прочестѝ посла́нїе сїѐ пред̾ все́ю ст҃о́ю бра́тїею. бл҃года́ть гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ съ ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 273,
  ["комментарий"] = "1 Сол., 273 зач., V, 14–23.",
  ["текст_ру"] = "Бра́тие, мо́лим вы: вразумля́йте безчи́нныя, утеша́йте малоду́шныя, заступа́йте немощны́я, долготерпи́те ко всем. Блюди́те, да никто́же зла за зло кому́ возда́ст, но всегда́ до́брое гони́те, и друг ко дру́гу, и ко всем. Всегда́ ра́дуйтеся, непреста́нно моли́теся, о всем благодари́те, сия́ бо есть во́ля Бо́жия о Христе́ Иису́се в вас. Ду́ха не угаша́йте, проро́чествия не уничижа́йте. Вся же искуша́юще, до́брая держи́те. От вся́кия ве́щи злы́я отгреба́йтеся. Сам же Бог ми́ра да освяти́т вы всесоверше́нны о всем, и всесоверше́н ваш дух, и душа́, и те́ло непоро́чно в прише́ствие Го́спода на́шего Иису́са Христа́ да сохрани́тся. ",
  ["текст_цс"] = "Бра́тїе, мо́лимъ вы̀, вразꙋмлѧ́йте безчи̑нныѧ, ᲂу҆тѣша́йте малодꙋ́шныѧ, застꙋпа́йте немощны́ѧ, долготерпи́те ко всѣ́мъ. блюди́те, да никто́же ѕла̀ за ѕло̀ комꙋ̀ возда́стъ: но всегда̀ до́брое гони́те, и҆ дрꙋ́гъ ко дрꙋ́гꙋ, и҆ ко всѣ́мъ. всегда̀ ра́дꙋйтесѧ: непреста́ннѡ моли́тесѧ. ѡ҆ все́мъ благодари́те: сїѧ́ бо є҆́сть во́лѧ бж҃їѧ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ въ ва́съ. дх҃а не ᲂу҆гаша́йте: проро́чествїѧ не ᲂу҆ничижа́йте: всѧ̑ же и҆скꙋша́юще, дѡ́браѧ держи́те. ѿ всѧ́кїѧ ве́щи ѕлы́ѧ ѿгреба́йтесѧ. са́мъ же бг҃ъ ми́ра да ѡ҆свѧти́тъ вы̀, всесоверше́ны ѡ҆ все́мъ: и҆ всесоверше́нъ ва́шъ дх҃ъ, и҆ дꙋша̀, и҆ тѣ́ло непоро́чно, въ прише́ствїе гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ да сохрани́тсѧ. ",
}

add_apostol {
  ["номер"] = 274,
  ["комментарий"] = "2 Сол., 274 зач., I, 1–10.",
  ["текст_ру"] = "Па́вел и Силуа́н, и Тимофе́й, це́ркви Солу́нстей, о Бо́зе Отце́ на́шем и Го́споде Иису́се Христе́, благода́ть вам и мир от Бо́га Отца́ на́шего, и Го́спода Иису́са Христа́. Благодари́ти до́лжни есмы́ Бо́га всегда́ о вас, бра́тие, я́коже досто́йно есть, я́ко превозраста́ет ве́ра ва́ша, и мно́жится любо́вь еди́наго коего́ждо всех вас друг ко дру́гу, я́ко саме́м нам хвали́тися о вас в це́рквах Бо́жиих, о терпе́нии ва́шем и ве́ре во всех гоне́ниих ва́ших и ско́рбех, и́хже прие́млете, показа́ние пра́веднаго суда́ Бо́жия, во е́же сподо́битися вам Ца́рствия Бо́жия, его́же ра́ди и стра́ждете. А́ще у́бо пра́ведно у Бо́га, возда́ти скорбь оскорбля́ющым вас, а вам оскорбля́емым отра́ду с на́ми, во открове́нии Го́спода Иису́са с небесе́, со А́нгелы си́лы Своея́, во огни́ пла́менне даю́щаго отмще́ние не ве́дущым Бо́га и не послу́шающым благовествова́ния Го́спода на́шего Иису́са Христа́. И́же му́ку прии́мут, поги́бель ве́чную, от лица́ Госпо́дня и от сла́вы кре́пости Его́, егда́ прии́дет просла́витися во святы́х Свои́х и ди́вен бы́ти во всех ве́ровавших, я́ко уве́рися свиде́тельство на́ше в вас в день он. ",
  ["текст_цс"] = "Па́ѵелъ и҆ сїлꙋа́нъ и҆ тїмоѳе́й, цр҃кви солꙋ́нстѣй, ѡ҆ бз҃ѣ ѻ҆ц҃ѣ̀ на́шемъ, и҆ гдⷭ҇ѣ і҆и҃сѣ хрⷭ҇тѣ̀: бл҃года́ть ва́мъ и҆ ми́ръ, ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀. бл҃годари́ти до́лжни є҆смы̀ бг҃а всегда̀ ѡ҆ ва́съ бра́тїе, ꙗ҆́коже досто́йно є҆́сть, ꙗ҆́кѡ превозраста́етъ вѣ́ра ва́ша, и҆ мно́житсѧ любо́вь є҆ди́нагѡ коегѡ́ждо всѣ́хъ ва́съ дрꙋ́гъ ко дрꙋ́гꙋ: ꙗ҆́кѡ самѣ́мъ на́мъ хвали́тисѧ ѡ҆ ва́съ въ цр҃квахъ бж҃їихъ, ѡ҆ терпѣ́нїи ва́шемъ, и҆ вѣ́рѣ, во всѣ́хъ гоне́нїихъ ва́шихъ и҆ ско́рбехъ, и҆̀хже прїе́млете: показа́нїе пра́веднагѡ сꙋда̀ бж҃їѧ, во є҆́же сподо́битисѧ ва́мъ црⷭ҇твїѧ бж҃їѧ, є҆гѡ́же ра́ди и҆ стра́ждете. а҆́ще ᲂу҆́бѡ пра́ведно ᲂу҆ бг҃а, возда́ти ско́рбь ѡ҆скорблѧ́ющымъ ва́съ: а҆ ва́мъ ѡ҆скорблѧ́ємымъ ѿра́дꙋ съ на́ми, во ѿкрове́нїи гдⷭ҇а і҆и҃са съ нб҃сѐ, со а҆́гг҃лы си́лы своеѧ̀, во ѻ҆гнѝ пла́меннѣ даю́щагѡ ѿмще́нїе невѣ́дꙋщымъ бг҃а, и҆ не послꙋ́шающымъ благовѣствова́нїѧ гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀. и҆́же мꙋ́кꙋ прїи́мꙋтъ, поги́бель вѣ́чнꙋю, ѿ лица̀ гдⷭ҇нѧ, и҆ ѿ сла́вы крѣ́пости є҆гѡ̀: є҆гда̀ прїи́детъ просла́витисѧ во ст҃ы́хъ свои́хъ, и҆ ди́венъ бы́ти во всѣ́хъ вѣ́ровавшихъ. ꙗ҆́кѡ ᲂу҆вѣ́рисѧ свидѣ́тельство на́ше въ ва́съ въ де́нь ѻ҆́нъ. ",
}

add_apostol {
