add_apostol {
  ["номер"] = 275,
  ["комментарий"] = "2 Сол., 275 зач., II, 1–12.",
  ["текст_ру"] = "Бра́тие, мо́лим вы о прише́ствии Го́спода на́шего Иису́са Христа́ и на́шем собра́нии о Нем, не ско́ро подвиза́тися вам от ума́, ни ужаса́тися ниже́ ду́хом, ниже́ сло́вом, ни посла́нием а́ки от нас по́сланным, я́ко уже́ настои́т день Христо́в. Да никто́же вас прельсти́т ни по еди́ному же о́бразу, я́ко а́ще не прии́дет отступле́ние пре́жде, и откры́ется челове́к беззако́ния, сын поги́бели, проти́вник и превознося́йся па́че вся́каго глаго́лемаго Бо́га или́ чти́лища, я́коже ему́ се́сти в це́ркви Бо́жией а́ки Бо́гу, показу́ющу себе́, я́ко Бог есть. Не по́мните ли, я́ко еще́ живы́й у вас, сия́ глаго́лах вам? И ны́не одержа́щее ве́сте, во е́же яви́тися ему́ в свое́ ему́ вре́мя. Та́йна бо уже́ де́ется беззако́ния, то́чию держя́й ны́не до́ндеже от среды́ бу́дет, и тогда́ яви́тся беззако́нник, его́же Госпо́дь Иису́с убие́т ду́хом уст Свои́х, и упраздни́т явле́нием прише́ствия Своего́, его́же есть прише́ствие по де́йству сатанину́ во вся́кой си́ле и зна́мениих и чудесе́х ло́жных, и во вся́кой льсти непра́вды в погиба́ющих, зане́ любве́ и́стины не прия́ша, во е́же спасти́ся им. И сего́ ра́ди по́слет им Бог де́йство льсти, во е́же ве́ровати им лжи, да суд прии́мут вси неве́ровавшии и́стине, но благоволи́вше в непра́вде. ",
  ["текст_цс"] = "Бра́тїе, мо́лимъ вы̀, ѡ҆ прише́ствїи гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, и҆ на́шемъ собра́нїи ѡ҆ не́мъ, не ско́рѡ подвиза́тисѧ ва́мъ ѿ ᲂу҆ма̀, ни ᲂу҆жаса́тисѧ, нижѐ дх҃омъ, нижѐ сло́вомъ, ни посла́нїемъ а҆́ки ѿ на́съ по́сланнымъ, ꙗ҆́кѡ ᲂу҆жѐ настои́тъ де́нь хрⷭ҇то́въ. да никто́же ва́съ прельсти́тъ ни по є҆ди́номꙋ же ѻ҆́бразꙋ: ꙗ҆́кѡ а҆́ще не прїи́детъ ѿстꙋпле́нїе пре́жде, и҆ ѿкры́етсѧ человѣ́къ беззако́нїѧ, сы́нъ поги́бели, проти́вникъ, и҆ превозносѧ́йсѧ па́че всѧ́кагѡ глаго́лемагѡ бо́га и҆лѝ чти́лища: ꙗ҆́коже є҆мꙋ̀ сѣ́сти въ цр҃кви бж҃їей а҆́ки бо́гꙋ, показꙋ́ющꙋ себѐ ꙗ҆́кѡ бо́гъ є҆́сть. не по́мните ли, ꙗ҆́кѡ є҆щѐ живы́й ᲂу҆ ва́съ, сїѧ̑ глаго́лахъ ва́мъ; и҆ ны́нѣ ѡ҆держа́щее вѣ́сте, во є҆́же ꙗ҆ви́тисѧ є҆мꙋ̀ въ своѐ є҆мꙋ̀ вре́мѧ. та́йна бо ᲂу҆жѐ дѣ́етсѧ беззако́нїѧ, то́чїю держѧ́й ны́нѣ, до́ндеже ѿ среды̀ бꙋ́детъ: и҆ тогда̀ ꙗ҆ви́тсѧ беззако́нникъ, є҆го́же гдⷭ҇ь і҆и҃съ ᲂу҆бїе́тъ дх҃омъ ᲂу҆́стъ свои́хъ, и҆ ᲂу҆праздни́тъ ꙗ҆вле́нїемъ прише́ствїѧ своегѡ̀: є҆гѡ́же є҆́сть прише́ствїе по дѣ́йствꙋ сатанинꙋ̀, во всѧ́кой си́лѣ, и҆ зна́менїихъ и҆ чꙋдесѣ́хъ ло́жныхъ: и҆ во всѧ́кой льстѝ непра́вды въ погиба́ющихъ, занѐ любвѐ и҆́стины не прїѧ́ша во є҆́же спасти́сѧ и҆̀мъ. и҆ сегѡ̀ ра́ди по́слетъ и҆̀мъ бг҃ъ дѣ́йство льстѝ, во є҆́же вѣ́ровати и҆̀мъ лжѝ: да сꙋ́дъ прїи́мꙋтъ всѝ невѣ́ровавшїи и҆́стинѣ, но благоволи́вше въ непра́вдѣ. ",
}

add_apostol {
  ["номер"] = 276,
  ["комментарий"] = "2 Сол., 276 зач., II, 13 – III, 5.",
  ["текст_ру"] = "Бра́тие, мы до́лжни есмы́ благодари́ти Бо́га всегда́ о вас, бра́тие возлю́бленная от Го́спода, я́ко избра́л есть вас Бог от нача́ла во спасе́ние во святы́ни Ду́ха и ве́ры и́стины, в не́же призва́ вас благовествова́нием на́шим, в получе́ние сла́вы Го́спода на́шего Иису́са Христа́. Те́мже у́бо, бра́тие, сто́йте и держи́те преда́ния, и́мже научи́стеся или́ сло́вом, или́ посла́нием на́шим. Сам же Госпо́дь наш Иису́с Христо́с, и Бог и Оте́ц наш, возлюби́вый нас, и да́вый утеше́ние ве́чно, и упова́ние бла́го в благода́ти, да уте́шит сердца́ ва́ша, и да утверди́т во вся́ком сло́ве и де́ле бла́зе. Про́чее же моли́теся о нас, бра́тие, да сло́во Госпо́дне тече́т и сла́вится, я́коже и в вас, и да изба́вимся от злых и лука́вых челове́к, не всех бо есть ве́ра. Ве́рен есть Госпо́дь, И́же утверди́т вы и сохрани́т от лука́ваго. Упова́ем же на Го́спода о вас, я́ко я́же повелева́ем вам, и творите́ и сотворите́. Госпо́дь же да испра́вит сердца́ ва́ша в любо́вь Бо́жию и в терпе́ние Христо́во. ",
  ["текст_цс"] = "Бра́тїе, мы̀ до́лжни є҆смы̀ благодари́ти бг҃а всегда̀ ѡ҆ ва́съ, бра́тїе возлю́блєннаѧ ѿ гдⷭ҇а: ꙗ҆́кѡ и҆збра́лъ є҆́сть ва́съ бг҃ъ ѿ нача́ла во спасе́нїе, во ст҃ы́ни дх҃а и҆ вѣ́ры и҆́стины: въ не́же призва̀ ва́съ бл҃говѣствова́нїемъ на́шимъ, въ полꙋче́нїе сла́вы гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀. тѣ́мже ᲂу҆́бѡ бра́тїе, сто́йте, и҆ держи́те преда̑нїѧ, и҆̀мже наꙋчи́стесѧ, и҆лѝ сло́вомъ, и҆лѝ посла́нїемъ на́шимъ. са́мъ же гдⷭ҇ь на́шъ і҆и҃съ хрⷭ҇то́съ, и҆ бг҃ъ и҆ ѻ҆ц҃ъ на́шъ, возлюби́вый на́съ, и҆ да́вый ᲂу҆тѣше́нїе вѣ́чно, и҆ ᲂу҆пова́нїе бла́го въ бл҃года́ти: да ᲂу҆тѣ́шитъ сердца̀ ва́ша, и҆ да ᲂу҆тверди́тъ ва́съ во всѧ́комъ сло́вѣ и҆ дѣ́лѣ бла́зѣ. про́чее же моли́тесѧ ѡ҆ на́съ бра́тїе, да сло́во гдⷭ҇не тече́тъ и҆ сла́витсѧ, ꙗ҆́коже и҆ въ ва́съ: и҆ да и҆зба́вимсѧ ѿ ѕлы́хъ и҆ лꙋка́выхъ человѣ̑къ: не всѣ́хъ бо є҆́сть вѣ́ра. вѣ́ренъ є҆́сть гдⷭ҇ь, и҆́же ᲂу҆тверди́тъ вы̀, и҆ сохрани́тъ ѿ лꙋка́вагѡ. ᲂу҆пова́емъ же на гдⷭ҇а ѡ҆ ва́съ, ꙗ҆́кѡ ꙗ҆̀же повелѣва́емъ ва́мъ, и҆ творитѐ, и҆ сотворитѐ. гдⷭ҇ь же да и҆спра́витъ сердца̀ ва́ша въ любо́вь бж҃їю, и҆ въ терпѣ́нїе хрⷭ҇то́во. ",
}

add_apostol {
  ["номер"] = 277,
  ["комментарий"] = "2 Сол., 277 зач., III, 6–18.",
  ["текст_ру"] = "Бра́тие, повелева́ем вам о и́мени Го́спода на́шего Иису́са Христа́, отлуча́тися вам от вся́каго бра́та безчи́нно ходя́ща, а не по преда́нию, е́же прия́ша от нас. Са́ми бо ве́сте, ка́ко ле́по есть вам подо́битися нам, я́ко не безчи́нновахом у вас, ни ту́не хлеб ядо́хом у кого́, но в труде́ и по́двизе, нощь и день де́лающе, да не отягчи́м никого́же от вас. Не я́ко не и́мамы вла́сти, но я́ко да себе́ о́браз да́мы вам, во е́же уподо́битися нам. И́бо егда́ бе́хом у вас, сие́ завещава́хом вам: я́ко а́ще кто не хо́щет де́лати ниже́ да яст. Слы́шим бо не́кия безчи́нно ходя́щыя у вас, ничто́же де́лающыя, но лука́вно обходя́щыя. Таковы́м запреща́ем и мо́лим о Го́споде на́шем Иису́се Христе́, да с безмо́лвием де́лающе, свой хлеб ядя́т. Вы же, бра́тие, не стужа́йте си до́брое творя́ще. А́ще ли же кто не послу́шает словесе́ на́шего посла́нием, сего́ назна́менуйте и не примеша́йтеся ему́, да посрами́тся. И не а́ки врага́ име́йте его́, но наказу́йте я́коже бра́та. Сам же Госпо́дь ми́ра да даст вам мир всегда́ во вся́ком о́бразе. Госпо́дь со все́ми ва́ми. Целова́ние мое́ю руко́ю Па́влею, е́же есть зна́мение во вся́ком посла́нии, си́це пишу́: благода́ть Го́спода на́шего Иису́са Христа́ со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Бра́тїе, повелѣва́емъ ва́мъ ѡ҆ и҆́мени гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, ѿлꙋча́тисѧ ва́мъ ѿ всѧ́кагѡ бра́та, безчи́ннѡ ходѧ́ща, а҆ не по преда́нїю, є҆́же прїѧ́ша ѿ на́съ. са́ми бо вѣ́сте, ка́кѡ лѣ́по є҆́сть ва́мъ подо́битисѧ на́мъ, ꙗ҆́кѡ не безчи́нновахомъ ᲂу҆ ва́съ, ни тꙋ́не хлѣ́бъ ꙗ҆до́хомъ ᲂу҆ когѡ̀: но въ трꙋдѣ̀ и҆ по́двизѣ, но́щь и҆ де́нь дѣ́лающе, да не ѡ҆тѧгчи́мъ никогѡ́же ѿ ва́съ. не ꙗ҆́кѡ не и҆́мамы вла́сти, но ꙗ҆́кѡ да себѐ ѻ҆́бразъ да́мы ва́мъ, во є҆́же ᲂу҆подо́битисѧ на́мъ. и҆́бо є҆гда̀ бѣ́хомъ ᲂу҆ ва́съ, сїѐ завѣщава́хомъ ва́мъ: ꙗ҆́кѡ а҆́ще не хо́щетъ кто̀ дѣ́лати, нижѐ да ꙗ҆́стъ. слы́шимъ бо нѣ́кїѧ безчи́ннѡ ходѧ́щыѧ ᲂу҆ ва́съ, ничто́же дѣ́лающыѧ, но лꙋка́внѡ ѡ҆бходѧ́щыѧ. таковы̑мъ запреща́емъ, и҆ мо́лимъ ѡ҆ гдⷭ҇ѣ на́шемъ і҆и҃сѣ хрⷭ҇тѣ̀, да съ безмо́лвїемъ дѣ́лающе сво́й хлѣ́бъ ꙗ҆дѧ́тъ. вы́ же бра́тїе, не стꙋжа́йте сѝ до́брое творѧ́ще. а҆́ще ли же кто̀ не послꙋ́шаетъ словесѐ на́шегѡ, посла́нїемъ сего̀ назна́менꙋйте, и҆ не примѣша́йтесѧ є҆мꙋ̀, да посрами́тсѧ. и҆ не а҆́ки врага̀ и҆мѣ́йте є҆го̀, но наказꙋ́йте ꙗ҆́коже бра́та. са́мъ же гдⷭ҇ь ми́ра, да да́стъ ва́мъ ми́ръ всегда̀, во всѧ́комъ ѻ҆́бразѣ. гдⷭ҇ь со всѣ́ми ва́ми. цѣлова́нїе мое́ю рꙋко́ю па́ѵлею, є҆́же є҆́сть зна́менїе, во всѧ́комъ посла́нїи, си́це пишꙋ̀: бл҃года́ть гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ со всѣ́ми ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 278,
  ["комментарий"] = "1 Тим., 278 зач., I, 1–7.",
  ["текст_ру"] = "Па́вел, посла́нник Иису́с Христо́в по повеле́нию Бо́га Спа́са на́шего и Го́спода Иису́са Христа́ упова́ния на́шего, Тимофе́ю при́сному ча́ду в ве́ре, благода́ть, ми́лость, мир от Бо́га Отца́ на́шего и Христа́ Иису́са Го́спода на́шего. Я́коже умоли́х тя пребы́ти во Ефе́се иды́й в Македо́нию, да завеща́еши не́ким не и́нако учи́ти, ниже́ внима́ти ба́снем и родосло́вием безконе́чным, я́же стяза́ния творя́т па́че, не́жели Бо́жие строе́ние, е́же в ве́ре. Коне́ц же завеща́ния есть любы́ от чи́ста се́рдца и со́вести бла́ги и ве́ры нелицеме́рныя, и́хже не́цыи погреши́вше, уклони́шася в суесло́вия, хотя́ще бы́ти законоучи́теле, не разуме́юще ни я́же глаго́лют, ни о ни́хже утвержда́ют. ",
  ["текст_цс"] = "Па́ѵелъ посла́нникъ і҆и҃съ хрⷭ҇то́въ, по повелѣ́нїю бг҃а, сп҃са на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀, ᲂу҆пова́нїѧ на́шегѡ: тїмоѳе́ю при́сномꙋ ча́дꙋ въ вѣ́рѣ, бл҃года́ть, ми́лость, ми́ръ, ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ хрⷭ҇та̀ і҆и҃са гдⷭ҇а на́шегѡ. ꙗ҆́коже ᲂу҆моли́хъ тѧ̀ пребы́ти во є҆фе́сѣ, и҆ды́й въ македо́нїю, да завѣща́еши нѣ̑кимъ, не и҆́накѡ ᲂу҆чи́ти, нижѐ внима́ти ба́снемъ и҆ родосло́вїємъ безконє́чнымъ: ꙗ҆̀же стѧза̑нїѧ творѧ́тъ па́че, не́жели бж҃їе строе́нїе, є҆́же въ вѣ́рѣ. коне́цъ же завѣща́нїѧ є҆́сть, любы̀ ѿ чи́ста се́рдца, и҆ со́вѣсти бла́ги, и҆ вѣ́ры нелицемѣ́рныѧ, и҆́хже нѣ́цыи погрѣши́вше, ᲂу҆клони́шасѧ въ сꙋеслѡ́вїѧ: хотѧ́ще бы́ти законоꙋчи́тели, не разꙋмѣ́юще ни ꙗ҆̀же глаго́лютъ, ни ѡ҆ ни́хже ᲂу҆твержда́ютъ. ",
}

add_apostol {
  ["номер"] = 279,
  ["комментарий"] = "1 Тим., 279 зач., I, 8–14.",
  ["текст_ру"] = "Ча́до Тимофе́е, ве́мы я́ко добр зако́н есть, а́ще кто его́ зако́нне твори́т, ве́дый сие́, я́ко пра́веднику зако́н не лежи́т, но беззако́нным и непокори́вым, нечести́вым же и гре́шником, непра́ведным и скве́рным, отца́ и ма́тере досади́телем, мужеуби́йцам, блуднико́м, мужело́жником, разбо́йником, клеветнико́м, скотоло́жником, лжи́вым, клятвопресту́пником, и а́ще что и́но здра́вому уче́нию проти́вится, по благове́стию сла́вы блаже́ннаго Бо́га, е́же мне уве́рено бысть. И благодарю́ укрепля́ющаго мя Христа́ Иису́са Го́спода на́шего, я́ко ве́рна мя непщева́, положи́в мя в слу́жбу, бы́вша мя иногда́ ху́льника и гони́теля и досади́теля, но поми́лован бых, я́ко неве́дый сотвори́х в неве́рствии, упреумно́жися же благода́ть Го́спода на́шего Иису́са Христа́ с ве́рою и любо́вию я́же о Христе́ Иису́се. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, вѣ́мы ꙗ҆́кѡ до́бръ зако́нъ є҆́сть, а҆́ще кто̀ є҆го̀ зако́ннѣ твори́тъ, вѣ́дый сїѐ, ꙗ҆́кѡ пра́ведникꙋ зако́нъ не лежи́тъ, но беззакѡ́ннымъ, и҆ непокори̑вымъ, нечести̑вымъ же и҆ грѣ́шникѡмъ, непра́вєднымъ, и҆ сквє́рнымъ, ѻ҆тца̀ и҆ ма́тере досади́телємъ, мꙋжеꙋбі́йцамъ, блꙋдникѡ́мъ, мꙋжело́жникѡмъ, разбо́йникѡмъ, клеветникѡ́мъ, скотоло́жникѡмъ, лжи̑вымъ, клѧтвопрестꙋ́пникѡмъ, и҆ а҆́ще что̀ и҆́но здра́вомꙋ ᲂу҆че́нїю проти́витсѧ, по благовѣ́стїю сла́вы блаже́ннагѡ бг҃а, є҆́же мнѣ̀ ᲂу҆вѣ́рено бы́сть. и҆ благодарю̀ ᲂу҆крѣплѧ́ющаго мѧ̀ хрⷭ҇та̀ і҆и҃са гдⷭ҇а на́шего: ꙗ҆́кѡ вѣ́рна мѧ̀ непщева̀, положи́въ мѧ̀ въ слꙋ́жбꙋ, бы́вша мѧ̀ и҆ногда̀ хꙋ́льника, и҆ гони́телѧ, и҆ досади́телѧ: но поми́лованъ бы́хъ, ꙗ҆́кѡ не вѣ́дый сотвори́хъ въ невѣ́рствїи: ᲂу҆преꙋмно́жисѧ же благода́ть гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, съ вѣ́рою, и҆ любо́вїю ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. ",
}

