add_apostol {
  ["номер"] = 281,
  ["комментарий"] = "1 Тим., 281 зач., I, 18–20; II, 8–15.",
  ["текст_ру"] = "Ча́до Тимофе́е, сие́ завеща́ние предаю́ тебе́ по бы́вших на тя пре́жде проро́чествиих, да во́инствуеши в них до́брое во́инство, име́я ве́ру и благу́ю со́весть, ю́же не́цыи отри́нувше, от ве́ры отпадо́ша. От ни́хже есть Имене́й и Алекса́ндр, и́хже преда́х сатане́, я́ко да нака́жутся не ху́лити. Хощу́ у́бо, да моли́твы творя́т му́жие на вся́ком ме́сте, возде́юще преподо́бныя ру́ки без гне́ва и размышле́ния. Та́кожде и жены́ во украше́нии ле́потном, со стыде́нием и целому́дрием да украша́ют себе́ не в плете́ниих, ни зла́том, или́ би́сером, или́ ри́зами многоце́нными, но е́же подоба́ет жена́м обещава́ющымся благоче́стию, делесы́ благи́ми. Жена́ в безмо́лвии да учи́тся со вся́ким покоре́нием. Жене́ же учи́ти не повелева́ю, ни владе́ти му́жем, но бы́ти в безмо́лвии. Ада́м бо пре́жде со́здан бысть, пото́м же Е́ва. И Ада́м не прельсти́ся, жена́ же прельсти́вшися, в преступле́нии бысть. Спасе́тся же чадоро́дия ра́ди, а́ще пребу́дет в ве́ре и любви́, и во святы́ни с целому́дрием. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, сїѐ завѣща́нїе предаю̀ тебѣ̀ по бы́вшихъ на тѧ̀ пре́жде проро́чествїихъ, да во́инствꙋеши въ ни́хъ до́брое во́инство, и҆мѣ́ѧ вѣ́рꙋ, и҆ бл҃гꙋ́ю со́вѣсть, ю҆́же нѣ́цыи ѿри́нꙋвше, ѿ вѣ́ры ѿпадо́ша. ѿ ни́хже є҆́сть ѵ҆мене́й, и҆ а҆леѯа́ндръ, и҆̀хже преда́хъ сатанѣ̀, ꙗ҆́кѡ да нака́жꙋтсѧ не хꙋ́лити. хощꙋ̀ ᲂу҆̀бо, да моли̑твы творѧ́тъ мꙋ́жїе на всѧ́комъ мѣ́стѣ, воздѣ́юще преподѡ́бныѧ рꙋ́ки без̾ гнѣ́ва и҆ размышле́нїѧ. та́кожде и҆ жєны̀ во ᲂу҆краше́нїи лѣ́потномъ, со стыдѣ́нїемъ и҆ цѣломꙋ́дрїемъ, да ᲂу҆краша́ютъ себѐ, не въ плете́нїихъ, ни зла́томъ и҆лѝ би́серомъ, и҆лѝ ри́зами многоцѣ́нными: но [є҆́же подоба́етъ жена́мъ, ѡ҆бѣщава́ющымсѧ благоче́стїю] дѣлесы̀ благи́ми. жена̀ въ безмо́лвїи да ᲂу҆чи́тсѧ со всѧ́кимъ покоре́нїемъ. женѣ́ же ᲂу҆чи́ти не повелѣва́ю, ни владѣ́ти мꙋ́жемъ, но бы́ти въ безмо́лвїи. а҆да́мъ бо пре́жде со́зданъ бы́сть, пото́мъ же є҆́ѵа. и҆ а҆да́мъ не прельсти́сѧ, жена́ же прельсти́вшисѧ, въ престꙋпле́нїи бы́сть. спасе́тсѧ же чадоро́дїѧ ра́ди, а҆́ще пребꙋ́детъ въ вѣ́рѣ, и҆ любвѝ, и҆ во свѧты́ни съ цѣломꙋ́дрїемъ. ",
}

add_apostol {
  ["номер"] = 282,
  ["комментарий"] = "1 Тим., 282 зач., II, 1–7.",
  ["текст_ру"] = "Ча́до Тимофе́е, молю́ пре́жде всех твори́ти моли́твы, моле́ния, проше́ния, благодаре́ния за вся челове́ки, за царя́ и за вся, и́же во вла́сти суть, да ти́хое и безмо́лвное житие́ поживе́м во вся́ком благоче́стии и чистоте́. Сие́ бо добро́ и прия́тно пред Спаси́телем на́шим Бо́гом, И́же всем челове́ком хо́щет спасти́ся и в ра́зум и́стины приити́. Еди́н бо есть Бог, и еди́н хода́тай Бо́га и челове́ков, челове́к Христо́с Иису́с, да́вый Себе́ избавле́ние за всех, свиде́тельство времены́ свои́ми, в не́же поста́влен бых аз пропове́дник и Апо́стол, и́стину глаго́лю о Христе́, не лгу, учи́тель язы́ков в ве́ре и и́стине. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, молю̀ пре́жде всѣ́хъ твори́ти моли̑твы, молє́нїѧ, прошє́нїѧ, бл҃годарє́нїѧ за всѧ̀ человѣ́ки: за цр҃ѧ̀, и҆ за всѧ̀ и҆̀же во вла́сти сꙋ́ть: да ти́хое и҆ безмо́лвное житїѐ поживе́мъ, во всѧ́комъ бл҃гоче́стїи и҆ чистотѣ̀. сїе́ бо добро̀ и҆ прїѧ́тно пред̾ сп҃си́телемъ на́шимъ бг҃омъ, и҆́же всѣ́мъ чл҃вѣ́кѡмъ хо́щетъ спасти́сѧ, и҆ въ ра́зꙋмъ и҆́стины прїитѝ. є҆ди́нъ бо є҆́сть бг҃ъ, и҆ є҆ди́нъ хода́тай бг҃а и҆ чл҃вѣ́кѡвъ, чл҃вѣ́къ хрⷭ҇то́съ і҆и҃съ: да́вый себѐ и҆збавле́нїе за всѣ́хъ, свидѣ́тельство времены̀ свои́ми. въ не́же поста́вленъ бы́хъ а҆́зъ проповѣ́дникъ и҆ а҆пⷭ҇лъ: [и҆́стинꙋ глаго́лю ѡ҆ хрⷭ҇тѣ̀, не лгꙋ̀,] ᲂу҆чи́тель ꙗ҆зы́кѡвъ въ вѣ́рѣ и҆ и҆́стинѣ. ",
}

add_apostol {
  ["номер"] = 283,
  ["комментарий"] = "1 Тим., 283 зач., III, 1–13.",
  ["текст_ру"] = "Ча́до Тимофе́е, ве́рно сло́во: а́ще кто епи́скопства хо́щет, добра́ де́ла жела́ет. Подоба́ет у́бо епи́скопу бы́ти непоро́чну, еди́ныя жены́ му́жу, тре́звену, целому́дру, благогове́йну, че́стну, страннолюби́ву, учи́тельну, не пия́нице, не би́йце, не сварли́ву, не мшелои́мцу, но кро́тку, не зави́стливу, не сребролю́бцу, свой дом до́бре пра́вящу, ча́да иму́щу в послуша́нии со вся́кою чистото́ю. А́ще же кто своего́ до́му не уме́ет пра́вити, ка́ко о Це́ркви Бо́жией прилежа́ти возмо́жет? Не новокреще́нну, да не разгорде́вся в суд впаде́т и в сеть диа́волю. Подоба́ет же ему́ и свиде́тельство добро́ име́ти от вне́шних, да не в поноше́ние впаде́т и в сеть неприя́знену. Диа́коном та́кожде чи́стым, не двоязы́чным, не вину́ мно́гу внима́ющым, не скверностяжа́тельным, иму́щым та́инство ве́ры в чи́стей со́вести. И си́и у́бо да искуша́ются пре́жде, пото́м же да слу́жат, непоро́чни су́ще. Жена́м та́кожде чи́стым, не клевети́вым, не нава́дницам, тре́звенным, ве́рным о всем. Диа́кони да быва́ют еди́ныя жены́ му́жие, ча́да до́бре заступа́юще и своя́ до́мы. И́бо служи́вшии до́бре степе́нь себе́ добр сниска́ют и мно́гое дерзнове́ние в ве́ре, я́же о Христе́ Иису́се. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, вѣ́рно сло́во, а҆́ще кто̀ є҆пі́скопства хо́щетъ, добра̀ дѣ́ла жела́етъ. подоба́етъ же є҆пⷭ҇кпꙋ бы́ти непоро́чнꙋ, є҆ди́ныѧ жены̀ мꙋ́жꙋ, тре́звенꙋ, цѣломꙋ́дрꙋ, бл҃гоговѣ́йнꙋ, че́стнꙋ, страннолюби́вꙋ, ᲂу҆чи́тельнꙋ, не пїѧ́ницѣ, не бі́йцѣ, не сварли́вꙋ, не мшелои́мцꙋ, но кро́ткꙋ, не зави́стливꙋ, не сребролю́бцꙋ: сво́й до́мъ до́брѣ пра́вѧщꙋ, ча̑да и҆мꙋ́щꙋ въ послꙋша́нїи со всѧ́кою чистото́ю. [а҆́ще же кто̀ своегѡ̀ до́мꙋ не ᲂу҆мѣ́етъ пра́вити, ка́кѡ ѡ҆ цр҃кви бж҃їей прилѣжа́ти возмо́жетъ;] не новокреще́ннꙋ, да не разгордѣ́всѧ въ сꙋ́дъ впаде́тъ и҆ въ сѣ́ть дїа́волю. подоба́етъ же є҆мꙋ̀ и҆ свидѣ́тельство добро̀ и҆мѣ́ти ѿ внѣ́шнихъ, да не въ поноше́нїе впаде́тъ, и҆ въ сѣ́ть непрїѧ́зненꙋ. дїа́конѡмъ та́кожде чи́стымъ, не двоѧзы́чнымъ, не вїнꙋ̀ мно́гꙋ внима́ющымъ, не скверностѧжа́тєльнымъ: и҆мꙋ́щымъ та́инство вѣ́ры въ чи́стѣй со́вѣсти. и҆ сі́и ᲂу҆́бѡ да и҆скꙋша́ютсѧ пре́жде, пото́мъ же да слꙋ́жатъ непоро́чни сꙋ́ще. жена́мъ та́кожде чи́стымъ, не клевети́вымъ, не нава́дницамъ, тре́звеннымъ, вѣ́рнымъ ѡ҆ все́мъ. дїа́кони да быва́ютъ є҆ди́ныѧ жены̀ мꙋ́жи, ча̑да до́брѣ застꙋпа́юще, и҆ своѧ̀ до́мы. и҆́бо слꙋжи́вшїи до́брѣ, степе́нь себѣ̀ до́бръ сниска́ютъ, и҆ мно́гое дерзнове́нїе въ вѣ́рѣ, ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. ",
}

