  ["комментарий"] = "2 Тим., 290 зач., I, 1–2, 8–18.",
  ["текст_ру"] = "Па́вел, Апо́стол Иису́с Христо́в во́лею Бо́жиею, по обетова́нию жи́зни, я́же о Христе́ Иису́се Тимофе́ю возлю́бленному ча́ду благода́ть, ми́лость, мир от Бо́га Отца́ и Христа́ Иису́са Го́спода на́шего. Не постыди́ся у́бо стра́стию Го́спода на́шего Иису́са Христа́, ни мно́ю ю́зником Его́, но спостражди́ благовествова́нию Христо́ву по си́ле Бо́га, спа́сшаго нас и призва́вшаго зва́нием святы́м, не по дело́м на́шым, но по Своему́ благоволе́нию и благода́ти да́нней нам о Христе́ Иису́се пре́жде лет ве́чных, я́вльшися же ны́не просвеще́нием Спаси́теля на́шего Иису́са Христа́, разруши́вшаго у́бо смерть и возсия́вшаго жизнь и нетле́ние благовествова́нием, в не́же поста́влен бых аз пропове́дник и Апо́стол и учи́тель язы́ков. Ея́же ра́ди вины́ и сия́ стражду́, но не стыжду́ся. Вем бо, Ему́же ве́ровах, и извести́хся, я́ко си́лен есть преда́ние мое́ сохрани́ти в день он. О́браз име́й здра́вых слове́с, и́хже от мене́ слы́шал еси́, в ве́ре и любви́, я́же о Христе́ Иису́се. До́брое завеща́ние соблюди́ Ду́хом Святы́м живу́щим в нас. Ве́си ли сие́, я́ко отврати́шася от мене́ вси, и́же от Аси́и, от ни́хже есть Фиге́лл и Ермоге́н. Да даст же ми́лость Госпо́дь Ониси́форову дому́, я́ко мно́гажды мя упоко́и и вери́г мои́х не постыде́ся, но прише́д в Рим, то́щнее взыска́ мя и обре́те. Да даст ему́ Госпо́дь обрести́ ми́лость от Го́спода в день он, и ели́ко во Ефе́се послужи́ ми, до́брее ты ве́си. ",
  ["текст_цс"] = "Па́ѵелъ а҆пⷭ҇лъ і҆и҃съ хрⷭ҇то́въ, во́лею бж҃їею, по ѡ҆бѣтова́нїю жи́зни, ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: тїмоѳе́ю возлю́бленномꙋ ча́дꙋ бл҃года́ть, млⷭ҇ть, ми́ръ, ѿ бг҃а ѻ҆ц҃а̀ и҆ хрⷭ҇та̀ і҆и҃са гдⷭ҇а на́шегѡ. не постыди́сѧ ᲂу҆́бѡ стра́стїю гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, ни мно́ю ю҆́зникомъ є҆гѡ̀: но спостраждѝ бл҃говѣствова́нїю хрⷭ҇то́вꙋ, по си́лѣ бг҃а, спа́сшагѡ на́съ, и҆ призва́вшагѡ зва́нїемъ ст҃ы́мъ, не по дѣлѡ́мъ на́шымъ, но по своемꙋ̀ благоволе́нїю, и҆ бл҃года́ти да́ннѣй на́мъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, пре́жде лѣ́тъ вѣ́чныхъ: ꙗ҆́вльшисѧ же ны́нѣ просвѣще́нїемъ сп҃си́телѧ на́шегѡ і҆и҃са хрⷭ҇та̀, разрꙋши́вшагѡ ᲂу҆́бѡ сме́рть, и҆ возсїѧ́вшагѡ жи́знь и҆ нетлѣ́нїе благовѣствова́нїемъ: въ не́же поста́вленъ бы́хъ а҆́зъ проповѣ́дникъ и҆ а҆по́столъ, и҆ ᲂу҆чи́тель ꙗ҆зы́кѡвъ. є҆ѧ́же ра́ди вины̀ и҆ сїѧ̑ страждꙋ̀, но не стыждꙋ́сѧ: вѣ́мъ бо, є҆мꙋ́же вѣ́ровахъ, и҆ и҆звѣсти́хсѧ, ꙗ҆́кѡ си́ленъ є҆́сть преда́нїе моѐ сохрани́ти въ де́нь ѻ҆́нъ. ѻ҆́бразъ и҆мѣ́й здра́выхъ слове́съ, и҆̀хже ѿ менѐ слы́шалъ є҆сѝ въ вѣ́рѣ и҆ любвѝ, ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. до́брое завѣща́нїе соблюдѝ, дх҃омъ ст҃ы́мъ живꙋ́щимъ въ на́съ. вѣ́си ли сїѐ, ꙗ҆́кѡ ѿврати́шасѧ ѿ менѐ всѝ и҆̀же ѿ а҆сі́и, ѿ ни́хже є҆́сть фѷге́ллъ и҆ є҆рмоге́нъ; да да́стъ же ми́лость гдⷭ҇ь ѻ҆нисі́форовꙋ до́мꙋ, ꙗ҆́кѡ мно́гажды мѧ̀ ᲂу҆поко́и и҆ вери́гъ мои́хъ не постыдѣ́сѧ: но прише́дъ въ ри́мъ, то́щнѣе взыска́ мѧ и҆ ѡ҆брѣ́те. да да́стъ є҆мꙋ̀ гдⷭ҇ь ѡ҆брѣстѝ ми́лость ѿ гдⷭ҇а въ де́нь ѻ҆́нъ: и҆ є҆ли́кѡ во є҆фе́сѣ послꙋжи́ ми, до́брѣе ты̀ вѣ́си. ",
}

add_apostol {
  ["номер"] = 290,
  ["комментарий"] = "2 Тим., 290 зач., I, 3-9.",
  ["текст_ру"] = "Ча́до Тимофе́е, благодарю́ Бо́га, Ему́же служу́ от прароди́телей чи́стою со́вестию, я́ко непреста́нную и́мам о тебе́ па́мять в моли́твах мои́х день и нощь, жела́я ви́дети тя, помина́я сле́зы твоя́, да ра́дости испо́лнюся, воспомина́ние прие́мля о су́щей в тебе́ нелицеме́рней ве́ре, я́же всели́ся пре́жде в ба́бу твою́ Лои́ду и в ма́терь твою́ Евники́ю: изве́стен же есмь, я́ко и в тебе́. Ея́же ра́ди вины́ воспомина́ю тебе́ возгрева́ти дар Бо́жий живу́щий в тебе́ возложе́нием руку́ мое́ю. Не бо даде́ нам Бог ду́ха стра́ха, но си́лы и любве́, и целому́дрия. Не постыди́ся у́бо стра́стию Го́спода на́шего Иису́са Христа́, ни мно́ю ю́зником Его́, но спостражди́ благовествова́нию Христо́ву по си́ле Бо́га, спа́сшаго нас и призва́вшаго зва́нием святы́м, не по дело́м на́шым, но по Своему́ благоволе́нию и благода́ти да́нней нам о Христе́ Иису́се. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, благодарю̀ бг҃а, є҆мꙋ́же слꙋжꙋ̀ ѿ прароди́телей чи́стою со́вѣстїю, ꙗ҆́кѡ непреста́ннꙋю и҆́мамъ ѡ҆ тебѣ̀ па́мѧть въ моли́твахъ мои́хъ, де́нь и҆ но́щь: жела́ѧ ви́дѣти тѧ̀, помина́ѧ сле́зы твоѧ̀, да ра́дости и҆спо́лнюсѧ: воспомина́нїе прїе́млѧ ѡ҆ сꙋ́щей въ тебѣ̀ нелицемѣ́рнѣй вѣ́рѣ, ꙗ҆́же всели́сѧ пре́жде въ ба́бꙋ твою̀ лѡі́дꙋ, и҆ въ ма́терь твою̀ є҆ѵнїкі́ю: и҆звѣ́стенъ же є҆́смь, ꙗ҆́кѡ и҆ въ тебѐ. є҆ѧ́же ра́ди вины̀ воспомина́ю тебѣ̀, возгрѣва́ти да́ръ бж҃їй, живꙋ́щїй въ тебѣ̀ возложе́нїемъ рꙋкꙋ̀ мое́ю. не бо̀ дадѐ на́мъ бг҃ъ дх҃ъ стра́ха, но си́лы и҆ любвѐ и҆ цѣломꙋ́дрїѧ. не постыди́сѧ ᲂу҆́бѡ стра́стїю гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀, ни мно́ю ю҆́зникомъ є҆гѡ̀: но спостраждѝ бл҃говѣствова́нїю хрⷭ҇то́вꙋ, по си́лѣ бг҃а, спа́сшагѡ на́съ, и҆ призва́вшагѡ зва́нїемъ ст҃ы́мъ, не по дѣлѡ́мъ на́шымъ, но по своемꙋ̀ благоволе́нїю, и҆ бл҃года́ти да́ннѣй на́мъ ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. ",
}

