add_apostol {
  ["номер"] = 292,
  ["комментарий"] = "2 Тим., 292 зач., II, 1–10.",
  ["текст_ру"] = "Ча́до Тимофе́е, возмога́й во благода́ти, я́же о Христе́ Иису́се и я́же слы́шал еси́ от мене́ мно́гими свиде́тели, сия́ преда́ждь ве́рным челове́ком, и́же дово́льни бу́дут и ины́х научи́ти. Ты у́бо злопостражди́ я́ко добр во́ин Иису́с Христо́в. Никто́же бо во́ин быва́я обязу́ется ку́плями жите́йскими, да воево́де уго́ден бу́дет. А́ще же и постра́ждет кто, не венча́ется, а́ще не зако́нно му́чен бу́дет. Тружда́ющемуся де́лателю пре́жде подоба́ет от плода́ вкуси́ти. Разуме́й, я́же глаго́лю: да даст у́бо тебе́ Госпо́дь ра́зум о всем. Помина́й Го́спода Иису́са Христа́ воста́вшаго от ме́ртвых, от се́мене Дави́дова, по благовествова́нию моему́, в не́мже злостражду́ да́же до уз, я́ко злоде́й, но сло́во Бо́жие не вя́жется. Сего́ ра́ди вся терплю́ избра́нных ра́ди, да и ти́и спасе́ние улуча́т е́же о Христе́ Иису́се со сла́вою ве́чною. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, возмога́й ѡ҆ благода́ти, ꙗ҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: и҆ ꙗ҆̀же слы́шалъ є҆сѝ ѿ менѐ мно́гими свидѣ́тели, сїѧ̑ преда́ждь вѣ̑рнымъ человѣ́кѡмъ, и҆̀же дово́льни бꙋ́дꙋтъ и҆ и҆ны́хъ наꙋчи́ти. ты̀ ᲂу҆̀бо ѕлопостраждѝ ꙗ҆́кѡ до́бръ во́инъ і҆и҃съ хрⷭ҇то́въ. никто́же бо во́инъ быва́ѧ ѡ҆бѧзꙋ́етсѧ кꙋ́плѧми жите́йскими, да воево́дѣ ᲂу҆го́денъ бꙋ́детъ. а҆́ще же и҆ постра́ждетъ кто̀, не вѣнча́етсѧ, а҆́ще не зако́ннѡ мꙋ́ченъ бꙋ́детъ. трꙋжда́ющемꙋсѧ дѣ́лателю пре́жде подоба́етъ ѿ плода̀ вкꙋси́ти. разꙋмѣ́й ꙗ҆̀же глаго́лю: да да́стъ ᲂу҆́бѡ тебѣ̀ гдⷭ҇ь ра́зꙋмъ ѡ҆ все́мъ. помина́й гдⷭ҇а і҆и҃са хрⷭ҇та̀ воста́вшаго ѿ ме́ртвыхъ, ѿ сѣ́мене дв҃дова, по бл҃говѣствова́нїю моемꙋ̀: въ не́мже ѕлостраждꙋ̀ да́же до ᲂу҆́зъ, ꙗ҆́кѡ ѕлодѣ́й: но сло́во бж҃їе не вѧ́жетсѧ. сегѡ̀ ра́ди всѧ̑ терплю̀ и҆збра́нныхъ ра́ди, да и҆ ті́и спасе́нїе ᲂу҆лꙋча́тъ є҆́же ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ, со сла́вою вѣ́чною. ",
}

