  ["текст_ру"] = "Ча́до Тимофе́е, потщи́ся ско́ро приити́ ко мне. Дима́с бо мене́ оста́ви, возлюби́в ны́нешний век, и и́де в Солу́нь, Кри́скент в Галати́ю, Тит в Далма́тию, Лука́ еди́н есть со мно́ю. Ма́рка пое́м приведи́ с собо́ю, есть бо ми благопотре́бен в слу́жбу. Тихи́ка же посла́х во Ефе́с. Фело́н, его́же оста́вих в Троа́де у Ка́рпа, гряды́й принеси́, и кни́ги, па́че же ко́жаныя. Алекса́ндр кова́чь мно́га ми зла сотвори́, да возда́ст ему́ Госпо́дь по дело́м его́, от него́же и ты себе́ блюди́, зело́ бо проти́вится словесе́м на́шым. В пе́рвый мой отве́т никто́же бысть со мно́ю, но вси мя оста́виша, да не вмени́тся им. Госпо́дь же мне предста́ и укрепи́ мя, да мно́ю пропове́дание изве́стно бу́дет, и услы́шат вси язы́цы, и изба́влен бых от уст львов. И изба́вит мя Госпо́дь от вся́каго дела́ лука́ва и спасе́т во Ца́рствие Свое́ Небе́сное, Ему́же сла́ва во ве́ки веко́в. Ами́нь. Целу́й Приски́ллу и Аки́лу и Ониси́форов дом. Ера́ст оста́ в Кори́нфе, Трофи́ма же оста́вих в Мили́те боля́ща. Потщи́ся пре́жде зимы́ приити́. Целу́ют тя Евву́л и Пуд, и Лин, и Клавди́а, и бра́тия вся. Госпо́дь Иису́с Христо́с со ду́хом твои́м. Благода́ть с ва́ми. Ами́нь. ",
  ["текст_цс"] = "Ча́до тїмоѳе́е, потщи́сѧ ско́рѡ прїитѝ ко мнѣ̀: дима́съ бо менѐ ѡ҆ста́ви, возлюби́въ ны́нѣшнїй вѣ́къ, и҆ и҆́де въ солꙋ́нь: кри́скентъ въ галаті́ю, ті́тъ въ далма́тїю. лꙋка̀ є҆ди́нъ є҆́сть со мно́ю. ма́рка пое́мъ приведѝ съ собо́ю: є҆́сть бо мѝ благопотре́бенъ въ слꙋ́жбꙋ. тѷхі́ка же посла́хъ во є҆фе́съ. фелѡ́нъ, є҆го́же ѡ҆ста́вихъ въ трѡа́дѣ ᲂу҆ ка́рпа, грѧды́й принесѝ, и҆ кни̑ги, па́че же кѡ́жаныѧ. а҆леѯа́ндръ кова́чь мнѡ́га мѝ ѕла̀ сотворѝ, да возда́стъ є҆мꙋ̀ гдⷭ҇ь по дѣлѡ́мъ є҆гѡ̀: ѿ негѡ́же и҆ ты̀ себѐ блюдѝ, ѕѣлѡ́ бо проти́витсѧ словесє́мъ на́шымъ. въ пе́рвый мо́й ѿвѣ́тъ никто́же бы́сть со мно́ю, но вси́ мѧ ѡ҆ста́виша: да не вмѣни́тсѧ и҆̀мъ. гдⷭ҇ь же мнѣ̀ предста̀, и҆ ᲂу҆крѣпи́ мѧ, да мно́ю проповѣ́данїе и҆звѣ́стно бꙋ́детъ, и҆ ᲂу҆слы́шатъ всѝ ꙗ҆зы́цы: и҆ и҆зба́вленъ бы́хъ ѿ ᲂу҆́стъ львѡ́въ. и҆ и҆зба́витъ мѧ̀ гдⷭ҇ь ѿ всѧ́кагѡ дѣ́ла лꙋка́ва, и҆ спасе́тъ во црⷭ҇твїе своѐ нбⷭ҇ное: є҆мꙋ́же сла́ва во вѣ́ки вѣкѡ́въ, а҆ми́нь. цѣлꙋ́й прїскі́ллꙋ и҆ а҆кѵ́лꙋ, и҆ ѻ҆нисі́форовъ до́мъ. є҆ра́стъ ѡ҆ста̀ въ корі́нѳѣ, трофі́ма же ѡ҆ста́вихъ въ мїли́тѣ болѧ́ща. потщи́сѧ пре́жде зимы̀ прїитѝ. цѣлꙋ́ютъ тѧ̀ є҆ѵвꙋ́лъ, и҆ пꙋ́дъ, и҆ лі́нъ, и҆ клаѵді́а, и҆ бра́тїѧ всѧ̀. гдⷭ҇ь і҆и҃съ хрⷭ҇то́съ со дх҃омъ твои́мъ: бл҃года́ть съ ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 300,
  ["комментарий"] = "Тит., 300 зач., I, 1–4; II, 15 – III, 3, 12–13, 15.",
  ["текст_ру"] = "Па́вел, раб Бо́жий, Апо́стол же Иису́с Христо́в, по ве́ре избра́нных Бо́жиих и ра́зуму и́стины, я́же по благоче́стию, о упова́нии жи́зни ве́чныя, ю́же обетова́ нело́жный Бог пре́жде лет ве́чных, яви́ же во времена́ своя́ сло́во Свое́ пропове́данием, е́же мне поруче́но бысть по повеле́нию Спаси́теля на́шего Бо́га, Ти́ту, при́сному ча́ду по о́бщей ве́ре, благода́ть, ми́лость, мир от Бо́га Отца́ и Го́спода Иису́са Христа́ Спа́са на́шего. Сия́ глаго́ли, и моли́, и облича́й со вся́ким повеле́нием, да никто́же тя преоби́дит. Воспомина́й тем нача́льствующым и владе́ющым повинова́тися и покаря́тися, и ко вся́кому де́лу бла́гу гото́вым бы́ти: ни еди́наго ху́лити, не сварли́вым бы́ти, но ти́хим, вся́ку явля́ющым кро́тость ко всем челове́ком. Бе́хом бо иногда́ и мы несмы́сленни, и непокори́ви, и прельще́ни, рабо́тающе похоте́м и сласте́м разли́чным, в зло́бе и за́висти живу́ще, ме́рзцы су́ще и ненави́дяще друг дру́га. Егда́ послю́ Арте́му к тебе́ или́ Тихи́ка, потщи́ся приити́ ко мне в Никопо́ль, ту бо суди́х озиме́ти. Зи́ну зако́нника и Аполло́са ско́ро предпосли́, и да ничто́же и́ма ску́дно бу́дет. Целу́ют тя со мно́ю су́щии вси. Целу́й лю́бящыя ны в ве́ре. Благода́ть со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Па́ѵелъ ра́бъ бж҃їй, а҆пⷭ҇лъ же і҆и҃съ хрⷭ҇то́въ, по вѣ́рѣ и҆збра́нныхъ бж҃їихъ, и҆ ра́зꙋмꙋ и҆́стины, ꙗ҆́же по благоче́стїю: ѡ҆ ᲂу҆пова́нїи жи́зни вѣ́чныѧ, ю҆́же ѡ҆бѣтова̀ нело́жный бг҃ъ, пре́жде лѣ́тъ вѣ́чныхъ: ꙗ҆ви́ же во времена̀ своѧ̀ сло́во своѐ проповѣ́данїемъ, є҆́же мнѣ̀ порꙋче́но бы́сть, по повелѣ́нїю сп҃си́телѧ на́шегѡ бг҃а: ті́тꙋ при́сномꙋ ча́дꙋ по ѻ҆́бщей вѣ́рѣ, благода́ть, ми́лость, ми́ръ ѿ бг҃а ѻ҆ц҃а̀, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀, сп҃са на́шегѡ. сїѧ̑ глаго́ли, и҆ молѝ, и҆ ѡ҆блича́й со всѧ́кимъ повелѣ́нїемъ, да никто́же тѧ̀ преѡби́дитъ. воспомина́й тѣ̑мъ, нача́льствꙋющымъ и҆ владѣ́ющымъ, повинова́тисѧ и҆ покорѧ́тисѧ, и҆ ко всѧ́комꙋ дѣ́лꙋ бла́гꙋ готѡ́вымъ бы́ти: ни є҆ди́нагѡ хꙋ́лити, не сварли̑вымъ бы́ти, но ти̑химъ, всѧ́кꙋ ꙗ҆влѧ́ющымъ кро́тость ко всѣ́мъ человѣ́кѡмъ. бѣ́хомъ бо и҆ногда̀ и҆ мы̀ несмы́сленни, и҆ непокори́ви, и҆ прельще́ни, рабо́тающе похоте́мъ, и҆ сласте́мъ разли́чнымъ, въ ѕло́бѣ и҆ за́висти живꙋ́ще, ме́рзцы сꙋ́ще, и҆ ненави́дѧще дрꙋгъдрꙋ́га. є҆гда̀ послю̀ а҆рте́мꙋ къ тебѣ̀, и҆лѝ тѷхі́ка, потщи́сѧ прїитѝ ко мнѣ̀ въ нїкопо́ль: тꙋ́ бо сꙋди́хъ ѡ҆зимѣ́ти. зи́нꙋ зако́нника и҆ а҆поллѡ́са, ско́рѡ предпослѝ, и҆ да ничто́же и҆́ма скꙋ́дно бꙋ́детъ. цѣлꙋ́ютъ тѧ̀ со мно́ю сꙋ́щїи всѝ, цѣлꙋ́й лю́бѧщыѧ ны̀ въ вѣ́рѣ: бл҃года́ть со всѣ́ми ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 300,
  ["комментарий"] = "Тит., 300 зач., I, 5 - II, 1.",
  ["текст_ру"] = "Ча́до Ти́те, сего́ ра́ди оста́вих тя в Кри́те, да недоконча́нная испра́виши и устро́иши по всем градо́м пресви́теры, я́коже тебе́ аз повеле́х. А́ще кто есть непоро́чен, еди́ныя жены́ муж, ча́да имы́й ве́рна, не во укоре́нии блуда́, или́ непокори́ва. Подоба́ет бо епи́скопу без поро́ка бы́ти, я́коже Бо́жию строи́телю: не себе́ угожда́ющу, не де́рзу, не напра́сливу, не гневли́ву, не пия́нице, не би́йце, не скверностяжа́тельну, но страннолюби́ву, благолю́бцу, целому́дренну, пра́ведну, преподо́бну, воздержа́тельну, держа́щемуся ве́рнаго словесе́ по уче́нию, да си́лен бу́дет и утеша́ти во здра́вем уче́нии, и проти́вящыяся облича́ти. Суть бо мно́зи непокори́ви, суесло́вцы и умо́м прельще́ни, наипа́че же су́щии от обре́зания, и́хже подоба́ет уста́ загражда́ти, и́же вся до́мы развраща́ют, уча́ще я́же не подоба́ет, скве́рнаго ра́ди прибы́тка. Рече́ же не́кто от них, свой им проро́к: Кри́тяне при́сно лжи́ви, зли́и зве́рие, утро́бы пра́здныя. Свиде́тельство сие́ и́стинно есть. Ея́же ра́ди вины́ облича́й их неща́дно, да здра́ви бу́дут в ве́ре, не внима́юще иуде́йским ба́снем, ни за́поведем челове́к отвраща́ющихся от и́стины. Вся у́бо чи́ста чи́стым, оскверне́ным же и неве́рным ничто́же чи́сто, но оскверни́ся их и ум и со́весть. Бо́га испове́дуют ве́дети, а де́лы отме́щутся Его́, ме́рзцы су́ще и непокори́ви и на вся́кое де́ло благо́е неиску́сни. Ты же глаго́ли, я́же подоба́ет здра́вому уче́нию. ",
  ["текст_цс"] = "Ча́до ті́те, сегѡ̀ ра́ди ѡ҆ста́вихъ тѧ̀ въ кри́тѣ, да недоконча̑ннаѧ и҆спра́виши, и҆ ᲂу҆стро́иши по всѣ́мъ градѡ́мъ пресвѵ́теры, ꙗ҆́коже тебѣ̀ а҆́зъ повелѣ́хъ. а҆́ще кто̀ є҆́сть непоро́ченъ, є҆ди́ныѧ жены̀ мꙋ́жъ, ча̑да и҆мы́й вѣ́рна, не во ᲂу҆коре́нїи блꙋда̀, и҆лѝ непокори́ва. подоба́етъ бо є҆пⷭ҇кпꙋ без̾ поро́ка бы́ти ꙗ҆́коже бж҃їю строи́телю: не себѣ̀ ᲂу҆гожда́ющꙋ, не де́рзꙋ, не напра́сливꙋ, не гнѣвли́вꙋ, не пїѧ́ницѣ, не бі́йцѣ, не скверностѧжа́тельнꙋ: но страннолюби́вꙋ, благолю́бцꙋ, цѣломꙋ́дреннꙋ, пра́веднꙋ, преподо́бнꙋ, воздержа́тельнꙋ: держа́щемꙋсѧ вѣ́рнагѡ словесѐ по ᲂу҆че́нїю, да си́ленъ бꙋ́детъ и҆ ᲂу҆тѣша́ти во здра́вѣмъ ᲂу҆че́нїи, и҆ проти́вѧщыѧсѧ ѡ҆блича́ти. сꙋ́ть бо мно́зи непокори́ви, сꙋесло́вцы, и҆ ᲂу҆мо́мъ прельще́ни, и҆ наипа́че сꙋ́щїи ѿ ѡ҆брѣ́занїѧ: и҆́хже подоба́етъ ᲂу҆ста̀ загражда́ти: и҆̀же всѧ̀ до́мы развраща́ютъ, ᲂу҆ча́ще ꙗ҆̀же не подоба́етъ, скве́рнагѡ ра́ди прибы́тка. рече́ же нѣ́кто ѿ ни́хъ сво́й и҆̀мъ проро́къ: кри́тѧне при́снѡ лжи́ви, ѕлі́и ѕвѣ́рїе, ᲂу҆трѡ́бы пра́здныѧ. свидѣ́тельство сїѐ и҆́стинно є҆́сть. є҆ѧ́же ра́ди вины̀ ѡ҆блича́й и҆̀хъ неща́днѡ, да здра́ви бꙋ́дꙋтъ въ вѣ́рѣ: не внима́юще і҆ꙋде́йскимъ ба́снемъ, ни за́повѣдемъ человѣ̑къ, ѿвраща́ющихсѧ ѿ и҆́стины. всѧ̑ ᲂу҆́бѡ чи́ста чи̑стымъ: ѡ҆сквернє́нымъ же и҆ невѣ̑рнымъ ничто́же чи́сто: но ѡ҆скверни́сѧ и҆́хъ и҆ ᲂу҆́мъ и҆ со́вѣсть. бг҃а и҆сповѣ́дꙋютъ вѣ́дѣти, а҆ дѣ́лы ѿме́щꙋтсѧ є҆гѡ̀, ме́рзцы сꙋ́ще, и҆ непокори́ви, и҆ на всѧ́ко дѣ́ло благо́е неискꙋ́сни. ты́ же глаго́ли, ꙗ҆̀же подоба́етъ здра́вомꙋ ᲂу҆че́нїю. ",
}

add_apostol {
  ["номер"] = 301,
  ["комментарий"] = "Тит., 301 зач., I, 15 – II, 10.",
  ["текст_ру"] = "Ча́до Ти́те, вся чи́ста чи́стым, оскверне́ным же и неве́рным ничто́же чи́сто, но оскверни́ся их и ум и со́весть. Бо́га испове́дуют ве́дети, а де́лы отме́щутся Его́, ме́рзцы су́ще и непокори́ви, и на вся́кое де́ло благо́е неиску́сни. Ты же глаго́ли, я́же подоба́ет здра́вому уче́нию: ста́рцем тре́звенным бы́ти, че́стным, целому́дренным, здра́вствующым ве́рою, любо́вию, терпе́нием. Ста́рицам та́кожде во украше́нии святоле́пным, не клевети́вым, не вину́ мно́гу порабоще́нным, доброучи́тельным, я́ко да уцелому́дрят ю́ныя, мужелю́бицам бы́ти, чадолю́бицам, целому́дренным, чи́стым, до́мы до́бре пра́вящым, благи́м, покаря́ющымся свои́м муже́м, да не сло́во Бо́жие ху́лится. Ю́ношы та́кожде моли́ целому́дрствовати. О всем же сам себе́ подава́я о́браз до́брых дел, во уче́нии незави́стное, че́стность, нетле́ние, сло́во здра́вое, незазо́рное. Да проти́вный посрами́тся, ничто́же име́я глаго́лати о нас уко́рно. Рабы́, свои́м господе́м повинова́тися, во всем благоуго́дным бы́ти, не прекосло́вным, не кра́дущым, но ве́ру вся́ку явля́ющым бла́гу, да уче́ние Спаси́теля на́шего Бо́га украша́ют во всем. ",
  ["текст_цс"] = "Ча́до ті́те, всѧ̑ чи́ста чи̑стымъ: ѡ҆сквернє́нымъ же и҆ невѣ̑рнымъ ничто́же чи́сто: но ѡ҆скверни́сѧ и҆́хъ и҆ ᲂу҆́мъ и҆ со́вѣсть. бг҃а и҆сповѣ́дꙋютъ вѣ́дѣти, а҆ дѣ́лы ѿме́щꙋтсѧ є҆гѡ̀, ме́рзцы сꙋ́ще, и҆ непокори́ви, и҆ на всѧ́ко дѣ́ло благо́е неискꙋ́сни. ты́ же глаго́ли, ꙗ҆̀же подоба́етъ здра́вомꙋ ᲂу҆че́нїю. ста́рцємъ тре́звєнымъ бы́ти, чє́стнымъ, цѣломꙋ́дрєннымъ, здра́вствꙋющымъ вѣ́рою, любо́вїю, терпѣ́нїемъ. ста́рицамъ та́коже во ᲂу҆краше́нїи ст҃олѣ̑пнымъ, не клевети̑вымъ, не вїнꙋ̀ мно́гꙋ порабощє́ннымъ, доброꙋчи́тельнымъ: ꙗ҆́кѡ да ᲂу҆цѣломꙋ́дрѧтъ ю҆́ныѧ, мꙋжелю́бицамъ бы́ти, чадолю́бицамъ, цѣломꙋ́дрєннымъ, чи̑стымъ, до́мы до́брѣ пра́вѧщымъ, благи̑мъ, покарѧ́ющымсѧ свои́мъ мꙋжє́мъ, да не сло́во бж҃їе хꙋ́литсѧ. ю҆́ношы та́кожде молѝ цѣломꙋ́дрствовати. ѡ҆ все́мъ же са́мъ себѐ подава́ѧ ѻ҆́бразъ до́брыхъ дѣ́лъ, во ᲂу҆че́нїи незави́стное, че́стность, нетлѣ́нїе, сло́во здра́вое, незазо́рное, да проти́вный посрами́тсѧ, ничто́же и҆мѣ́ѧ глаго́лати ѡ҆ на́съ ᲂу҆ко́рно. рабы̑, свои́мъ господє́мъ повинова́тисѧ, во все́мъ благоꙋгѡ́днымъ бы́ти, не прекослѡ́внымъ, не кра́дꙋщымъ: но вѣ́рꙋ всѧ́кꙋ ꙗ҆влѧ́ющымъ бла́гꙋ, да ᲂу҆че́нїе сп҃си́телѧ на́шегѡ бг҃а ᲂу҆краша́ютъ во все́мъ. ",
}

add_apostol {
  ["номер"] = 302,
  ["комментарий"] = "Тит., 302 зач., II, 11–14; III, 4–7.",
  ["текст_ру"] = "Ча́до Ти́те, яви́ся благода́ть Бо́жия спаси́тельная всем челове́ком, наказу́ющи нас, да отве́ргшеся нече́стия и мирски́х похоте́й, целому́дренно, и пра́ведно, и благоче́стно поживе́м в ны́нешнем ве́це, жду́ще блаже́ннаго упова́ния и явле́ния сла́вы Вели́каго Бо́га и Спа́са на́шего Иису́са Христа́. И́же дал есть Себе́ за ны, да изба́вит ны от вся́каго беззако́ния и очи́стит Себе́ лю́ди избра́нны, ревни́тели до́брым дело́м. Егда́ же благода́ть и человеколю́бие яви́ся Спа́са на́шего Бо́га, не от дел пра́ведных, и́хже сотвори́хом мы, но по Свое́й Его́ ми́лости, спасе́ нас ба́нею пакибытия́ и обновле́нием Ду́ха Свята́го, Его́же излия́ на нас оби́льно Иису́с Христо́м, Спаси́телем на́шим, да оправди́вшеся благода́тию Его́, насле́дницы бу́дем по упова́нию жи́зни ве́чныя. ",
  ["текст_цс"] = "Ча́до ті́те, ꙗ҆ви́сѧ бл҃года́ть бж҃їѧ сп҃си́тельнаѧ всѣ́мъ человѣ́кѡмъ, наказꙋ́ющи на́съ, да ѿве́ргшесѧ нече́стїѧ и҆ мїрски́хъ похоте́й, цѣломꙋ́дреннѡ и҆ пра́веднѡ, и҆ благоче́стнѡ поживе́мъ въ ны́нѣшнѣмъ вѣ́цѣ. ждꙋ́ще блаже́ннагѡ ᲂу҆пова́нїѧ, и҆ ꙗ҆вле́нїѧ сла́вы вели́кагѡ бг҃а и҆ сп҃са на́шегѡ і҆и҃са хрⷭ҇та̀. и҆́же да́лъ є҆́сть себѐ за ны̀, да и҆зба́витъ ны̀ ѿ всѧ́кагѡ беззако́нїѧ, и҆ ѡ҆чи́ститъ себѣ̀ лю́ди и҆збра́нны, ревни́тели дѡ́брымъ дѣлѡ́мъ. є҆гда́ же бл҃года́ть и҆ человѣколю́бїе ꙗ҆ви́сѧ сп҃са на́шегѡ бг҃а: не ѿ дѣ́лъ пра́ведныхъ, и҆̀хже сотвори́хомъ мы̀, но по свое́й є҆гѡ̀ ми́лости, спасѐ на́съ ба́нею пакибытїѧ̀, и҆ ѡ҆бновле́нїемъ дх҃а ст҃а́гѡ, є҆го́же и҆злїѧ̀ на на́съ ѻ҆би́льнѡ і҆и҃съ хрⷭ҇то́мъ, сп҃си́телемъ на́шимъ: да ѡ҆правди́вшесѧ блгⷣтїю є҆гѡ̀, наслѣ́дницы бꙋ́демъ по ᲂу҆пова́нїю жи́зни вѣ́чныѧ. ",
}

add_apostol {
  ["номер"] = 302,
  ["комментарий"] = "Тит., 302 зач., III, 8-15.",
  ["текст_ру"] = "Ча́до Ти́те, ве́рно сло́во, и о сих хощу́ тя извеща́ти, да пеку́тся до́брым дело́м прилежа́ти ве́ровавшии Бо́гу, сия́ суть поле́зна челове́ком и добра́. Бу́их же стяза́ний и родосло́вий и рве́ний и сва́ров зако́нных отступа́й: суть бо неполе́зны и су́етны. Еретика́ челове́ка по пе́рвом и второ́м наказа́нии отрица́йся, ве́дый, я́ко разврати́ся таковы́й, и согреша́ет, и есть самоосужде́н. Егда́ послю́ Арте́му к тебе́ или́ Тихи́ка, потщи́ся приити́ ко мне в Никопо́ль, ту бо суди́х озиме́ти. Зи́ну зако́нника и Аполло́са ско́ро предпосли́, и да ничто́же и́ма ску́дно бу́дет. Да уча́тся же и на́ши до́брым дело́м прилежа́ти в ну́жная тре́бования, да не бу́дут безпло́дни. Целу́ют тя со мно́ю су́щии вси. Целу́й лю́бящыя ны в ве́ре. Благода́ть со все́ми ва́ми. Ами́нь. ",
  ["текст_цс"] = "Ча́до ті́те, вѣ́рно сло́во, и҆ ѡ҆ си́хъ хощꙋ̀ тѧ̀ і҆звѣща́ти, да пекꙋ́тсѧ дѡ́брымъ дѣлѡ́мъ прилѣжа́ти вѣ́ровавшїи бг҃ꙋ: сїѧ̑ сꙋ́ть полє́зна человѣ́кѡмъ и҆ дѡбра̀. бꙋ́ихъ же стѧза́нїй и҆ родосло́вїй и҆ рве́нїй, и҆ сва́рѡвъ зако́нныхъ ѿстꙋпа́й: сꙋ́ть бо неполе́зны и҆ сꙋ́етны. є҆ретїка̀ человѣ́ка, по пе́рвомъ и҆ второ́мъ наказа́нїи ѿрица́йсѧ: вѣ́дый, ꙗ҆́кѡ разврати́сѧ таковы́й, и҆ согрѣша́етъ и҆ є҆́сть самоѡсꙋжде́нъ. є҆гда̀ послю̀ а҆рте́мꙋ къ тебѣ̀, и҆лѝ тѷхі́ка, потщи́сѧ прїитѝ ко мнѣ̀ въ нїкопо́ль: тꙋ́ бо сꙋди́хъ ѡ҆зимѣ́ти. зи́нꙋ зако́нника и҆ а҆поллѡ́са, ско́рѡ предпослѝ, и҆ да ничто́же и҆́ма скꙋ́дно бꙋ́детъ. да ᲂу҆ча́тсѧ же и҆ на́ши дѡ́брымъ дѣлѡ́мъ прилѣжа́ти въ нꙋ́жнаѧ тре́бѡванїѧ, да не бꙋ́дꙋтъ безпло́дни. цѣлꙋ́ютъ тѧ̀ со мно́ю сꙋ́щїи всѝ, цѣлꙋ́й лю́бѧщыѧ ны̀ въ вѣ́рѣ: бл҃года́ть со всѣ́ми ва́ми. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 302,
  ["комментарий"] = "Флм., 302 зач., I, 1–25.",
  ["текст_ру"] = "Па́вел, ю́зник Иису́с Христо́в, и Тимофе́й брат, Филимо́ну возлю́бленному и споспе́шнику на́шему, и Апфи́и сестре́ возлю́бленней, и Архи́ппу сово́инственнику на́шему, и дома́шней твое́й це́ркви, благода́ть вам и мир от Бо́га Отца́ на́шего, и Го́спода Иису́са Христа́. Благодарю́ Бо́га моего́, всегда́ па́мять о тебе́ творя́ в моли́твах мои́х, слы́шав любо́вь твою́ и ве́ру, ю́же и́маши ко Го́споду Иису́су и ко всем святы́м. Я́ко да обще́ние твоея́ ве́ры де́йственно бу́дет в ра́зуме вся́каго бла́га, е́же в вас, о Христе́ Иису́се. Ра́дость бо и́мам мно́гу и утеше́ние о любви́ твое́й, я́ко утро́бы святы́х почи́ша тобо́ю, бра́те. Сего́ ра́ди мно́гое дерзнове́ние име́я во Христе́ повелева́ти тебе́, е́же потре́бно есть, любве́ же ра́ди па́че молю́, тако́в сый я́коже Па́вел ста́рец, ны́не же и ю́зник Иису́са Христа́, молю́ тя о мое́м ча́де, его́же роди́х во у́зах мои́х Они́сима, иногда́ тебе́ непотре́бнаго, ны́не же тебе́ и мне благопотре́бна, его́же возпосла́х тебе́, ты же его́, си́речь мою́ утро́бу, приими́. Его́же аз хоте́х у себе́ держа́ти, да в тебе́ ме́сто послу́жит ми во у́зах благовествова́ния. Без твоея́ же во́ли ничто́же восхоте́х сотвори́ти, да не а́ки по ну́жди благо́е твое́ бу́дет, но по во́ли. Не́гли бо ра́ди сего́ разлучи́ся на час, да ве́чна того́ прии́меши, не ктому́ а́ки раба́, но вы́ше раба́, бра́та возлю́бленна, па́че же мне, кольми́ же па́че тебе́, и по пло́ти и о Го́споде. А́ще у́бо и́маши мене́ о́бщника, приими́ сего́ я́коже мене́. А́ще же в чесо́м оби́де тебе́, или́ до́лжен есть, мне сие́ вмени́. Аз Па́вел написа́х руко́ю мое́ю, аз возда́м, да не реку́ тебе́, я́ко и сам себе́ ми еси́ до́лжен. Ей, бра́те, аз да получу́ е́же прошу́ у тебе́ о Го́споде: упоко́й мою́ утро́бу о Го́споде. Наде́явся послуша́нию твоему́ написа́х тебе́, ве́дый, я́ко и па́че, е́же глаго́лю, сотвори́ши. Ку́пно же и угото́ви ми оби́тель: упова́ю бо, я́ко моли́твами ва́шими дарова́н бу́ду вам. Целу́ет тя Епафра́с, спле́нник мой о Христе́ Иису́се, Ма́рко, Ариста́рх, Дима́с, Лука́, споспе́шницы мои́. Благода́ть Го́спода на́шего Иису́са Христа́ со ду́хом ва́шим. Ами́нь. ",
  ["текст_цс"] = "Па́ѵелъ ю҆́зникъ і҆и҃съ хрⷭ҇то́въ и҆ тїмоѳе́й бра́тъ фїлимо́нꙋ возлю́бленномꙋ и҆ споспѣ́шникꙋ на́шемꙋ, и҆ а҆пфі́и сестрѣ̀ возлю́бленнѣй, и҆ а҆рхі́ппꙋ сово́инственникꙋ на́шемꙋ, и҆ дома́шнѣй твое́й цр҃кви: бл҃года́ть ва́мъ и҆ ми́ръ ѿ бг҃а ѻ҆ц҃а̀ на́шегѡ, и҆ гдⷭ҇а і҆и҃са хрⷭ҇та̀. бл҃годарю̀ бг҃а моего̀, всегда̀ па́мѧть ѡ҆ тебѣ̀ творѧ̀ въ моли́твахъ мои́хъ, слы́шавъ любо́вь твою̀ и҆ вѣ́рꙋ, ю҆́же и҆́маши ко гдⷭ҇ꙋ і҆и҃сꙋ, и҆ ко всѣ̑мъ ст҃ы́мъ: ꙗ҆́кѡ да ѻ҆бще́нїе твоеѧ̀ вѣ́ры дѣ́йственно бꙋ́детъ, въ ра́зꙋмѣ всѧ́кагѡ бла́га є҆́же въ ва́съ, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ. ра́дость бо и҆́мамъ мно́гꙋ, и҆ ᲂу҆тѣше́нїе ѡ҆ любвѝ твое́й, ꙗ҆́кѡ ᲂу҆трѡ́бы ст҃ы́хъ почи́ша тобо́ю, бра́те. сегѡ̀ ра́ди мно́гое дерзнове́нїе и҆мѣ́ѧ во хрⷭ҇тѣ̀ повелѣва́ти тебѣ̀, є҆́же потре́бно є҆́сть: любве́ же ра́ди па́че молю̀, тако́въ сы́й, ꙗ҆́коже па́ѵелъ ста́рецъ, ны́нѣ же и҆ ю҆́зникъ і҆и҃са хрⷭ҇та̀: молю́ тѧ ѡ҆ мое́мъ ча́дѣ, є҆го́же роди́хъ во ᲂу҆́захъ мои́хъ ѻ҆ни́сїма: и҆ногда̀ тебѣ̀ непотре́бнаго, ны́нѣ же тебѣ̀ и҆ мнѣ̀ бл҃гопотре́бна: є҆го́же возпосла́хъ тѝ, ты́ же є҆го̀, си́рѣчь мою̀ ᲂу҆тро́бꙋ, прїимѝ. є҆го́же а҆́зъ хотѣ́хъ ᲂу҆ себѐ держа́ти, да въ тебѐ мѣ́сто послꙋ́житъ мѝ во ᲂу҆́захъ благовѣствова́нїѧ. без̾ твоеѧ́ же во́ли ничто́же восхотѣ́хъ сотвори́ти: да не а҆́ки по нꙋ́жди бл҃го́е твоѐ бꙋ́детъ, но по во́ли. не́гли бо ра́ди сегѡ̀ разлꙋчи́сѧ на ча́съ, да вѣ́чна того̀ прїи́меши: не ктомꙋ̀ а҆́ки раба̀, но вы́ше раба̀, бра́та возлю́бленна, па́че же мнѣ̀, кольми́ же па́че тебѣ̀, и҆ по пло́ти, и҆ ѡ҆ гдⷭ҇ѣ. а҆́ще ᲂу҆́бѡ и҆́маши менѐ ѻ҆́бщника, прїимѝ сего̀ ꙗ҆́коже менѐ. а҆́ще же въ чесо́мъ ѡ҆би́дѣ тебѐ, и҆лѝ до́лженъ є҆́сть, мнѣ̀ сїѐ вмѣнѝ. а҆́зъ па́ѵелъ написа́хъ рꙋко́ю мое́ю, а҆́зъ возда́мъ: да не рекꙋ̀ тебѣ̀, ꙗ҆́кѡ и҆ са́мъ себе́ ми є҆сѝ до́лженъ. є҆́й, бра́те, а҆́зъ да полꙋчꙋ̀, є҆́же прошꙋ̀ ᲂу҆ тебѐ ѡ҆ гдⷭ҇ѣ: ᲂу҆поко́й мою̀ ᲂу҆тро́бꙋ ѡ҆ гдⷭ҇ѣ. надѣ́ѧвсѧ послꙋша́нїю твоемꙋ̀ написа́хъ тебѣ̀, вѣ́дый, ꙗ҆́кѡ и҆ па́че є҆́же глаго́лю, сотвори́ши. кꙋ́пнѡ же и҆ ᲂу҆гото́ви мѝ ѻ҆би́тель: ᲂу҆пова́ю бо, ꙗ҆́кѡ моли́твами ва́шими дарова́нъ бꙋ́дꙋ ва́мъ. цѣлꙋ́етъ тѧ̀ є҆пафра́съ сплѣ́нникъ мо́й, ѡ҆ хрⷭ҇тѣ̀ і҆и҃сѣ: ма́рко, а҆рїста́рхъ, дима́съ, лꙋка̀, споспѣ́шницы моѝ. бл҃года́ть гдⷭ҇а на́шегѡ і҆и҃са хрⷭ҇та̀ со дх҃омъ ва́шимъ. а҆ми́нь. ",
}

add_apostol {
  ["номер"] = 303,
  ["комментарий"] = "Евр., 303 зач., I, 1–12.",
  ["текст_ру"] = "Многоча́стне и многообра́зне дре́вле Бог, глаго́лавый отце́м во проро́цех. В после́док дний сих глаго́ла нам в Сы́не, Его́же положи́ насле́дника всем, И́мже и ве́ки сотвори́. И́же Сый сия́ние сла́вы и о́браз Ипоста́си Его́, нося́ же вся́ческая глаго́лом си́лы Своея́, Собо́ю очище́ние сотвори́в грехо́в на́ших, се́де одесну́ю Престо́ла вели́чествия на высо́ких. Толи́ко лу́чший быв А́нгел, ели́ко пресла́внее па́че их насле́дствова и́мя. Кому́ бо рече́ когда́ от А́нгел: Сын Мой еси́ Ты, Аз днесь роди́х Тя? И па́ки: Аз бу́ду Ему́ во Отца́, и Той бу́дет Мне в Сы́на. Егда́ же па́ки вво́дит Перворо́днаго во вселе́нную, глаго́лет: и да покло́нятся Ему́ вси А́нгели Бо́жии. И ко А́нгелом у́бо глаго́лет: творя́й А́нгелы Своя́ ду́хи и слуги́ Своя́ огнь паля́щ. К Сы́ну же: престо́л Твой, Бо́же, в век ве́ка, жезл пра́вости, жезл Ца́рствия Твоего́. Возлюби́л еси́ пра́вду и возненави́дел еси́ беззако́ние, сего́ ра́ди пома́за Тя, Бо́же, Бог Твой еле́ем ра́дости па́че прича́стник Твои́х. И па́ки: в нача́ле Ты, Го́споди, зе́млю основа́л еси́, и дела́ руку́ Твое́ю суть небеса́. Та поги́бнут, Ты же пребыва́еши, и вся, я́коже ри́за, обетша́ют, и я́ко оде́жду, свие́ши их, и изменя́тся; Ты же то́йжде еси́, и лета́ Твоя́ не оскуде́ют. ",
  ["текст_цс"] = "Многоча́стнѣ и҆ многоѻбра́знѣ дре́вле бг҃ъ глаго́лавый ѻ҆ц҃є́мъ во проро́цѣхъ, въ послѣ́докъ дні́й си́хъ глаго́ла на́мъ въ сн҃ѣ, є҆го́же положѝ наслѣ́дника всѣ̑мъ, и҆́мже и҆ вѣ́ки сотворѝ. и҆́же сы́й сїѧ́нїе сла́вы, и҆ ѻ҆́бразъ ѵ҆поста́си є҆гѡ̀: носѧ́ же всѧ́чєскаѧ глаго́ломъ си́лы своеѧ̀, собо́ю ѡ҆чище́нїе сотвори́въ грѣхѡ́въ на́шихъ, сѣ́де ѡ҆деснꙋ́ю престо́ла вели́чествїѧ на высо́кихъ. толи́кѡ лꙋ́чшїй бы́въ а҆́гг҃лъ, є҆ли́кѡ пресла́внѣе па́че и҆́хъ наслѣ́дствова и҆́мѧ. комꙋ́ бо речѐ когда̀ ѿ а҆́гг҃лъ: сн҃ъ мо́й є҆сѝ ты̀, а҆́зъ дне́сь роди́хъ тѧ̀; и҆ па́ки: а҆́зъ бꙋ́дꙋ є҆мꙋ̀ во ѻ҆ц҃а̀, и҆ то́й бꙋ́детъ мнѣ̀ въ сн҃а; є҆гда́ же па́ки вво́дитъ перворо́днаго во вселе́ннꙋю, глаго́летъ: и҆ да покло́нѧтсѧ є҆мꙋ̀ всѝ а҆́гг҃ли бж҃їи. и҆ ко а҆́гг҃лѡмъ ᲂу҆́бѡ глаго́летъ: творѧ́й а҆́гг҃лы своѧ̀ дх҃и, и҆ слꙋги̑ своѧ̀ ѻ҆́гнь палѧ́щь. къ сн҃ꙋ же: престо́лъ тво́й бж҃е, въ вѣ́къ вѣ́ка: же́злъ пра́вости, же́злъ ца́рствїѧ твоегѡ̀. возлюби́лъ є҆сѝ пра́вдꙋ, и҆ возненави́дѣлъ є҆сѝ беззако́нїе: сегѡ̀ ра́ди пома́за тѧ̀ бж҃е, бг҃ъ тво́й, є҆ле́емъ ра́дости, па́че прича̑стникъ твои́хъ. и҆ па́ки: въ нача́лѣ ты̀ гдⷭ҇и зе́млю ѡ҆снова́лъ є҆сѝ, и҆ дѣла̀ рꙋкꙋ̀ твое́ю сꙋ́ть нб҃са̀: та̑ поги́бнꙋтъ, ты́ же пребыва́еши, и҆ всѧ̑ ꙗ҆́коже ри́за ѡ҆бетша́ютъ: и҆ ꙗ҆́кѡ ѻ҆де́ждꙋ свїе́ши и҆̀хъ, и҆ и҆змѣнѧ́тсѧ: ты́ же то́йжде є҆сѝ, и҆ лѣ̑та твоѧ̀ не ѡ҆скꙋдѣ́ютъ. ",
}

