  ["комментарий"] = "Евр., 313 зач., VI, 9–12.",
  ["текст_ру"] = "Бра́тие, наде́емся о вас, возлю́бленнии, лу́чших и придержа́щихся спасе́ния, а́ще и та́ко глаго́лем. Не оби́длив бо Бог, забы́ти дела́ ва́шего и труда́ любве́, ю́же показа́сте во и́мя Его́, послужи́вше святы́м и служа́ще. Жела́ем же, коего́ждо вас явля́ти то́же тща́ние ко извеще́нию упова́ния да́же до конца́, да не лени́ви бу́дете, но подража́тели насле́дствующих обетова́ния ве́рою и долготерпе́нием. ",
  ["текст_цс"] = "Бра́тїе, надѣ́емсѧ ѡ҆ ва́съ возлю́бленнїи, лꙋ́чшихъ, и҆ придержа́щихсѧ спасе́нїѧ, а҆́ще и҆ та́кѡ глаго́лемъ. не ѡ҆би́дливъ бо бг҃ъ, забы́ти дѣ́ла ва́шегѡ, и҆ трꙋда̀ любвѐ, ю҆́же показа́сте во и҆́мѧ є҆гѡ̀, послꙋжи́вше ст҃ы̑мъ и҆ слꙋжа́ще. жела́емъ же коегѡ́ждо ва́съ ꙗ҆влѧ́ти то́же тща́нїе, ко и҆звѣще́нїю ᲂу҆пова́нїѧ да́же до конца̀, да не лѣни́ви бꙋ́дете, но подража́тели наслѣ́дствꙋющихъ ѡ҆бѣтова́нїѧ вѣ́рою и҆ долготерпѣ́нїемъ. ",
}

add_apostol {
  ["номер"] = 314,
  ["комментарий"] = "Евр., 314 зач., VI, 13–20.",
  ["текст_ру"] = "Бра́тие, Авраа́му обетова́я Бог, поне́же ни eди́нем имя́ше бо́льшим кля́тися, кля́тся Собо́ю, глаго́ля: вои́стинну благосло́вствуя благословлю́ тя, и мно́жя умно́жу тя. И та́ко долготерпе́в, получи́ обетова́ние. Челове́цы у́бо бо́льшим клену́тся, и вся́кому их прекосло́вию кончи́на во извеще́ние, кля́тва eсть. В не́мже ли́шше хотя́ Бог показа́ти насле́дником обетова́ния непрело́жное сове́та Своего́, хода́тайствова кля́твою. Я́ко да двема́ ве́щма непрело́жныма, в не́юже не возмо́жно солга́ти Бо́гу, кре́пкое утеше́ние и́мамы прибе́гшии, я́тися за предлежа́щее упова́ние. Eже а́ки ко́тву и́мамы души́, тве́рду же и изве́стну, и входя́щую во вну́треннее заве́сы. Иде́же предте́ча о нас вни́де Иису́с, по чи́ну Мелхиседе́кову, Первосвяще́нник быв во ве́ки. ",
  ["текст_цс"] = "Бра́тїе, а҆враа́мꙋ ѡ҆бѣтова́ѧ бг҃ъ, поне́же ни є҆ди́нѣмъ и҆мѧ́ше бо́льшимъ клѧ́тисѧ, клѧ́тсѧ собо́ю, глаго́лѧ: вои́стиннꙋ бл҃госло́вствꙋѧ бл҃гословлю́ тѧ, и҆ мно́жѧ ᲂу҆мно́жꙋ тѧ̀. и҆ та́кѡ долготерпѣ́въ, полꙋчѝ ѡ҆бѣтова́нїе. человѣ́цы ᲂу҆́бѡ бо́льшимъ кленꙋ́тсѧ, и҆ всѧ́комꙋ и҆́хъ прекосло́вїю кончи́на во и҆звѣще́нїе, клѧ́тва є҆́сть. въ не́мже ли́шше хотѧ̀ бг҃ъ показа́ти наслѣ́дникѡмъ ѡ҆бѣтова́нїѧ непрело́жное совѣ́та своегѡ̀, хода́тайствова клѧ́твою. ꙗ҆́кѡ да двѣма̀ ве́щма непрело́жныма, въ не́юже не возмо́жно солга́ти бг҃ꙋ, крѣ́пкое ᲂу҆тѣше́нїе и҆́мамы прибѣ́гшїи, ꙗ҆́тисѧ за предлежа́щее ᲂу҆пова́нїе, є҆́же а҆́ки ко́твꙋ и҆́мамы дꙋшѝ тве́рдꙋ же и҆ и҆звѣ́стнꙋ, и҆ входѧ́щꙋю во внꙋ́треннее завѣ́сы. и҆дѣ́же прⷣте́ча ѡ҆ на́съ вни́де і҆и҃съ, по чи́нꙋ мелхїседе́ковꙋ, первосщ҃е́нникъ бы́въ во вѣ́ки. ",
}

add_apostol {
  ["номер"] = 315,
  ["комментарий"] = "Евр., 315 зач., VII, 1–6.",
  ["текст_ру"] = "Бра́тие, Мелхиседе́к, царь Сали́мский, свяще́нник Бо́га Вы́шняго, и́же сре́те Авраа́ма возвра́щшася от се́ча царе́й и благослови́ его́, ему́же и десяти́ну от всех отдели́ Авраа́м. Пе́рвее у́бо сказу́ется царь пра́вды, пото́м же царь Сали́мский, е́же есть, царь ми́ра, без отца́, без ма́тере, без при́чта ро́да, ни нача́ла днем, ни животу́ конца́ име́я, уподо́блен же Сы́ну Бо́жию, пребыва́ет свяще́нник вы́ну. Ви́дите же, ели́к сей, ему́же и десяти́ну дал есть Авраа́м патриа́рх от избра́нных. И прие́млющии у́бо свяще́нство от сыно́в Леви́ин за́поведь и́мут одеся́тствовати лю́ди по зако́ну, си́речь, бра́тию свою́, а́ще и от чресл Авраа́мовых изше́дшую. Не причита́емый же ро́дом от них, одеся́тствова Авраа́ма и иму́щаго обетова́ния благослови́. ",
  ["текст_цс"] = "Бра́тїе, мелхїседе́къ цр҃ь сали́мскїй, свѧще́нникъ бг҃а вы́шнѧгѡ, срѣ́те а҆враа́ма возвра́щшасѧ ѿ сѣ́ча царе́й, и҆ благословѝ є҆го̀: є҆мꙋ́же и҆ десѧти́нꙋ ѿ всѣ́хъ ѿдѣлѝ а҆враа́мъ. пе́рвѣе ᲂу҆́бѡ сказꙋ́етсѧ цр҃ь пра́вды, пото́мъ же цр҃ь сали́мскїй, є҆́же є҆́сть цр҃ь ми́ра: без̾ ѻ҆тца̀, без̾ ма́тере, без̾ при́чта ро́да, ни нача́ла днє́мъ, ни животꙋ̀ конца̀ и҆мѣ́ѧ: ᲂу҆подо́бленъ же сн҃ꙋ бж҃їю, пребыва́етъ сщ҃е́нникъ вы́нꙋ. ви́дите же є҆ли́къ се́й, є҆мꙋ́же и҆ десѧти́нꙋ да́лъ є҆́сть а҆враа́мъ патрїа́рхъ ѿ и҆збра́нныхъ. и҆ прїе́млющїи ᲂу҆́бѡ свѧще́нство ѿ сынѡ́въ леѵі̑инъ, за́повѣдь и҆́мꙋтъ ѡ҆десѧ́тствовати лю́ди по зако́нꙋ, си́рѣчь, бра́тїю свою̀, а҆́ще и҆ ѿ чре́слъ а҆враа́мовыхъ и҆зше́дшꙋю. не причита́емый же ро́домъ ѿ ни́хъ, ѡ҆десѧ́тствова а҆враа́ма, и҆ и҆мꙋ́щаго ѡ҆бѣтова̑нїѧ благословѝ. ",
}

add_apostol {
