  ["комментарий"] = "Евр., 316 зач., VII, 7–17.",
  ["текст_ру"] = "Бра́тие, без вся́каго прекосло́вия ме́ньшее от бо́льшаго благословля́ется. И зде у́бо десяти́ны челове́цы умира́ющии прие́млют, та́мо же свиде́тельствуемый, я́ко жив eсть. И да си́це реку́, Авраа́мом и Леви́й прие́мляй десяти́ны, десяти́ны дал eсть. Eще́ бо в чре́слех óтчиих бя́ше, eгда́ сре́те eго́ Мелхиседе́к. А́ще у́бо соверше́нство леви́тским свяще́нством бы́ло, лю́дие бо на нем взаконе́ни бы́ша: ка́я eще́ потре́ба по чи́ну Мелхиседе́кову ино́му воста́ти свяще́ннику, а не по чи́ну Ааро́нову глаго́латися? Прелага́ему у́бо свяще́нству, по ну́жди и зако́ну премене́ние быва́ет. О не́мже бо глаго́лются сия́: коле́ну ино́му причасти́ся, от него́же никто́же приступи́ ко oлтарю́. Я́ве бо, я́ко от коле́на Иу́дова возсия́ Госпо́дь наш, о не́мже коле́не Моисе́й о свяще́нстве ничесо́же глаго́ла. И ли́шше eще́ я́ве eсть, я́ко по подо́бию Мелхиседе́кову воста́нет Свяще́нник ин, И́же не по зако́ну за́поведи плотски́я бысть, но по си́ле живота́ неразруша́емаго. Свиде́тельствует бо, я́ко Ты eси́ свяще́нник во век по чи́ну Мелхиседе́кову. ",
  ["текст_цс"] = "Бра́тїе, без̾ всѧ́кагѡ прекосло́вїѧ, ме́ньшее ѿ бо́льшагѡ благословлѧ́етсѧ. и҆ здѣ̀ ᲂу҆́бѡ десѧти̑ны человѣ́цы ᲂу҆мира́ющїи прїе́млютъ, та́мѡ же свидѣ́тельствꙋемый, ꙗ҆́кѡ жи́въ є҆́сть. и҆ да си́це рекꙋ̀: а҆враа́момъ и҆ леѵі́й прїе́млѧй десѧти̑ны, десѧти̑ны да́лъ є҆́сть. є҆ще́ бо въ чре́слѣхъ ѻ҆́ч҃їихъ бѧ́ше, є҆гда̀ срѣ́те є҆го̀ мелхїседе́къ. а҆́ще ᲂу҆́бѡ соверше́нство леѵі́тскимъ свѧще́нствомъ бы́ло, [лю́дїе бо на не́мъ взаконе́ни бы́ша:] ка́ѧ є҆щѐ потре́ба, по чи́нꙋ мелхїседе́ковꙋ и҆но́мꙋ воста́ти сщ҃е́нникꙋ, а҆ не по чи́нꙋ а҆арѡ́новꙋ глаго́латисѧ; прелага́емꙋ ᲂу҆́бѡ сщ҃е́нствꙋ, по нꙋ́жди и҆ зако́нꙋ премѣне́нїе быва́етъ. ѡ҆ не́мже бо глаго́лютсѧ сїѧ̑: колѣ́нꙋ и҆но́мꙋ причасти́сѧ, ѿ негѡ́же никто́же пристꙋпѝ ко ѻ҆лтарю̀. ꙗ҆́вѣ бо, ꙗ҆́кѡ ѿ колѣ́на і҆ꙋ́дова возсїѧ̀ гдⷭ҇ь на́шъ: ѡ҆ не́мже колѣ́нѣ мѡѷсе́й ѡ҆ сщ҃е́нствѣ ничесо́же глаго́ла. и҆ ли́шше є҆щѐ ꙗ҆́вѣ є҆́сть, ꙗ҆́кѡ по подо́бїю мелхїседе́ковꙋ воста́нетъ сщ҃е́нникъ и҆́нъ, и҆́же не по зако́нꙋ за́повѣди плотскі́ѧ бы́сть, но по си́лѣ живота̀ неразрꙋша́емагѡ. свидѣ́тельствꙋетъ бо: ꙗ҆́кѡ ты̀ є҆сѝ сщ҃е́нникъ во вѣ́къ по чи́нꙋ мелхїседе́ковꙋ. ",
}

add_apostol {
  ["номер"] = 317,
  ["комментарий"] = "Евр., 317 зач., VII, 18–25.",
  ["текст_ру"] = "Бра́тие, отлага́ние быва́ет пре́жде бы́вшия за́поведи за не́мощное ея́ и неполе́зное. Ничто́же бо соверши́л зако́н, привведе́ние же есть лу́чшему упова́нию, и́мже приближа́емся к Бо́гу. И по ели́ку не без кля́твы, они́ бо без кля́твы свяще́нницы бы́вшии, Сей же с кля́твою чрез глаго́лющаго к Нему́: кля́тся Госпо́дь и не раска́ется, Ты еси́ свяще́нник во век по чи́ну Мелхиседе́кову. По толи́ку лу́чшаго заве́та бысть испору́чник Иису́с. И они́ множа́йши свяще́нницы бы́вше, зане́ сме́ртию возбране́ни суть пребыва́ти, Сей же, за е́же пребыва́ти Ему́ во ве́ки, непресту́пное и́мать свяще́нство, те́мже и спасти́ до конца́ мо́жет приходя́щих чрез Него́ к Бо́гу, всегда́ жив сый, во е́же хода́тайствовати о них. ",
  ["текст_цс"] = "Бра́тїе, ѿлага́нїе быва́етъ пре́жде бы́вшїѧ за́повѣди, за не́мощное є҆ѧ̀ и҆ неполе́зное. ничто́же бо соверши́лъ є҆́сть зако́нъ: привведе́нїе же є҆́сть лꙋ́чшемꙋ ᲂу҆пова́нїю, и҆́мже приближа́емсѧ къ бг҃ꙋ. и҆ по є҆ли́кꙋ не без̾ клѧ́твы, ѻ҆ни́ бо без̾ клѧ́твы сꙋ́ть сщ҃е́нницы бы́вшїи: се́й же съ клѧ́твою, чрез̾ глаго́лющаго къ немꙋ̀: клѧ́тсѧ гдⷭ҇ь и҆ не раска́етсѧ, ты̀ є҆сѝ сщ҃е́нникъ во вѣ́къ по чи́нꙋ мелхїседе́ковꙋ. по толи́кꙋ лꙋ́чшагѡ завѣ́та бы́сть и҆спорꙋ́чникъ і҆и҃съ. и҆ ѻ҆нѝ множа́йши сꙋ́ть сщ҃е́нницы бы́вше, занѐ сме́ртїю возбране́ни сꙋ́ть пребыва́ти: се́й же, за є҆́же пребыва́ти є҆мꙋ̀ во вѣ́ки, непрестꙋ́пное и҆́мать сщ҃е́нство. тѣ́мже и҆ спастѝ до конца̀ мо́жетъ приходѧ́щихъ чрез̾ него̀ къ бг҃ꙋ, всегда̀ жи́въ сы́й, во є҆́же хода́тайствовати ѡ҆ ни́хъ. ",
}

add_apostol {
