add_apostol {
  ["номер"] = 319,
  ["комментарий"] = "Евр., 319 зач., VIII, 7–13.",
  ["текст_ру"] = "Бра́тие, а́ще бы пе́рвый зако́н непоро́чен был, не бы второ́му иска́лося ме́сто. Укоря́я бо их глаго́лет: се дни́е гряду́т, глаго́лет Госпо́дь, и совершу́ на дом Изра́илев и на дом Иу́дов заве́т нов, не по заве́ту, его́же сотвори́х отце́м их в день, во́ньже е́мшу ми их за ру́ку, извести́ их от земли́ Еги́петския, зане́ ти́и не пребы́ша в заве́те Мое́м, и Аз неради́х о них, глаго́лет Госпо́дь. Я́ко сей заве́т, его́же завеща́ю дому́ Изра́илеву по о́нех днех, глаго́лет Госпо́дь, дая́ зако́ны Моя́ в мы́сли их, и на сердца́х их напишу́ их, и бу́ду им Бог, и ти́и бу́дут Мне лю́дие. И не и́мать научи́ти ко́ждо и́скренняго своего́ и ко́ждо бра́та своего́, глаго́ля: позна́й Го́спода, я́ко вси уве́дят Мя от ма́ла да́же и до вели́ка их, зане́ ми́лостив бу́ду непра́вдам их и грехо́в их и беззако́ний их не и́мам помяну́ти ктому́. Внегда́ же глаго́лет нов, обветши́ пе́рваго, а обветша́ющее и состаре́ющееся близ есть истле́ния. ",
  ["текст_цс"] = "Бра́тїе, а҆́ще бы пе́рвый зако́нъ непоро́ченъ бы́лъ, не бы̀ второ́мꙋ и҆ска́лосѧ мѣ́сто. ᲂу҆корѧ́ѧ бо и҆̀хъ, глаго́летъ: сѐ дні́е грѧдꙋ́тъ, глаго́летъ гдⷭ҇ь, и҆ совершꙋ̀ на до́мъ і҆и҃левъ, и҆ на до́мъ і҆ꙋ́довъ завѣ́тъ но́въ: не по завѣ́тꙋ, є҆го́же сотвори́хъ ѻ҆ц҃є́мъ и҆́хъ въ де́нь, во́ньже є҆́мшꙋ мѝ и҆̀хъ за рꙋ́кꙋ, и҆звестѝ и҆̀хъ ѿ землѝ є҆гѵ́петскїѧ: занѐ ті́и не пребы́ша въ завѣ́тѣ мое́мъ, и҆ а҆́зъ не ради́хъ ѡ҆ ни́хъ, глаго́летъ гдⷭ҇ь. ꙗ҆́кѡ се́й завѣ́тъ, є҆го́же завѣща́ю до́мꙋ і҆и҃левꙋ, по ѻ҆́нѣхъ дне́хъ, глаго́летъ гдⷭ҇ь, даѧ̀ зако́ны моѧ̀ въ мы́сли и҆́хъ, и҆ на сердца́хъ и҆́хъ напишꙋ̀ и҆̀хъ: и҆ бꙋ́дꙋ и҆̀мъ бг҃ъ, и҆ ті́и бꙋ́дꙋтъ мнѣ̀ лю́дїе. и҆ не и҆́мать наꙋчи́ти ко́ждо и҆́скреннѧго своего̀, и҆ ко́ждо бра́та своего̀, глаго́лѧ: позна́й гдⷭ҇а: ꙗ҆́кѡ всѝ ᲂу҆вѣ́дѧтъ мѧ̀ ѿ ма́ла да́же и҆ до вели́ка и҆́хъ. занѐ ми́лостивъ бꙋ́дꙋ непра́вдамъ и҆́хъ, и҆ грѣхѡ́въ и҆́хъ, и҆ беззако́нїй и҆́хъ не и҆́мамъ помѧнꙋ́ти ктомꙋ̀. внегда́ же глаго́летъ, но́въ, ѡ҆бветшѝ пе́рваго: а҆ ѡ҆бветша́ющее и҆ состарѣ́ющеесѧ, бли́зъ є҆́сть и҆стлѣ́нїѧ. ",
}

add_apostol {
  ["номер"] = 320,
  ["комментарий"] = "Евр., 320 зач., IX, 1–7.",
  ["текст_ру"] = "Бра́тие, име́яше пе́рвая ски́ниа оправда́ния слу́жбы, свято́е же людско́е. Ски́ниа бо сооружена́ бысть пе́рвая, в не́йже свети́льник, и трапе́за, и предложе́ние хле́бов, я́же глаго́лется Свята́я. По вторе́й же заве́се ски́ниа глаго́лемая, Свята́я святы́х. Зла́ту иму́щи кади́льницу, и ковче́г заве́та окова́н всю́ду зла́том, в не́мже ста́мна злата́ иму́щая ма́нну, и жезл Ааро́нов прозя́бший, и скрижа́ли заве́та. Превы́шше же eго́ херуви́ми сла́вы, осеня́ющии oлта́рь, о ни́хже несть ны́не глаго́лати подро́бну. Сим же та́ко устро́eным, в пе́рвую у́бо ски́нию вы́ну вхожда́ху свяще́нницы, слу́жбы соверша́юще. Во втору́ю же eди́ною в ле́то eди́н архиере́й, не без кро́ве, ю́же прино́сит за себе́, и о людски́х неве́жествиих. ",
  ["текст_цс"] = "Бра́тїе, и҆мѣ́ѧше пе́рваѧ ски́нїа ѡ҆правда̑нїѧ слꙋ́жбы, ст҃о́е же людско́е. ски́нїа бо соѡрꙋжена̀ бы́сть пе́рваѧ, въ не́йже свѣти́льникъ, и҆ трапе́за, и҆ предложе́нїе хлѣ́бѡвъ, ꙗ҆́же глаго́летсѧ ст҃а́ѧ. по вторѣ́й же завѣ́сѣ ски́нїа глаго́лемаѧ, ст҃а̑ѧ ст҃ы́хъ, зла́тꙋ и҆мꙋ́щи кади́льницꙋ, и҆ ковче́гъ завѣ́та ѡ҆кова́нъ всю́дꙋ зла́томъ, въ не́мже ста́мна злата̀ и҆мꙋ́щаѧ ма́ннꙋ, и҆ же́злъ а҆арѡ́новъ прозѧ́бшїй, и҆ скрижа́ли завѣ́та. превы́шше же є҆гѡ̀ херꙋві́ми сла́вы, ѡ҆сѣнѧ́ющїи ѻ҆лта́рь: ѡ҆ ни́хже нѣ́сть ны́нѣ глаго́лати подро́бнꙋ. си̑мъ же та́кѡ ᲂу҆стро́єнымъ, въ пе́рвꙋю ᲂу҆́бѡ ски́нїю вы́нꙋ вхожда́хꙋ сщ҃е́нницы, слꙋ̑жбы соверша́юще: во вторꙋ́ю же є҆ди́ною въ лѣ́то є҆ди́нъ а҆рхїере́й, не без̾ кро́ве, ю҆́же прино́ситъ за себѐ, и҆ ѡ҆ людски́хъ невѣ́жествїихъ. ",
}

add_apostol {
