  ["комментарий"] = "Евр., 327 зач., XI, 8, 11–16.",
  ["текст_ру"] = "Бра́тие, ве́рою зово́м Авраа́м послу́ша изы́ти на ме́сто, е́же хотя́ше прия́ти в насле́дие, и изы́де не ве́дый, ка́мо гряде́т. Ве́рою и сама́ Са́рра непло́ды си́лу во удержа́ние се́мене прия́т и па́че вре́мене во́зраста роди́, поне́же ве́рна непщева́ Обетова́вшаго. Те́мже и от еди́наго роди́шася, да еще́ умерщвле́ннаго, я́коже зве́зды небе́сныя мно́жеством и я́ко песо́к вскрай мо́ря безчи́сленный. По ве́ре умро́ша си́и вси, не прие́мше обетова́ний, но издале́ча ви́девше я́, и целова́вше, и испове́давше, я́ко стра́ннии и прише́льцы суть на земли́. И́бо такова́я глаго́лющии явля́ются, я́ко оте́чествия взыску́ют. И а́ще бы у́бо о́но по́мнили, из него́же изыдо́ша, име́ли бы вре́мя возврати́тися, ны́не же лу́чшаго жела́ют, си́речь небе́снаго, те́мже не стыди́тся си́ми Бог, Бог нарица́тися их, угото́ва бо им град. ",
  ["текст_цс"] = "Бра́тїе, вѣ́рою зово́мъ а҆враа́мъ, послꙋ́ша и҆зы́ти на мѣ́сто, є҆́же хотѧ́ше прїѧ́ти въ наслѣ́дїе: и҆ и҆зы́де, не вѣ́дый ка́мѡ грѧде́тъ. вѣ́рою и҆ сама̀ са́рра непло́ды, си́лꙋ во ᲂу҆держа́нїе сѣ́мене прїѧ́тъ, и҆ па́че вре́мене во́зраста родѝ, поне́же вѣ́рна непщева̀ ѡ҆бѣтова́вшаго. тѣ́мже и҆ ѿ є҆ди́нагѡ роди́шасѧ, да є҆щѐ ᲂу҆мерщвле́ннагѡ, ꙗ҆́коже ѕвѣ́зды нбⷭ҇ныѧ мно́жествомъ, и҆ ꙗ҆́кѡ песо́къ вскра́й мо́рѧ безчи́сленный. по вѣ́рѣ ᲂу҆мро́ша сі́и всѝ, не прїе́мше ѡ҆бѣтова́нїй, но и҆здале́ча ви́дѣвше ѧ҆̀, и҆ цѣлова́вше: и҆ и҆сповѣ́давше, ꙗ҆́кѡ стра́ннїи и҆ прише́льцы сꙋ́ть на землѝ. и҆́бо такова̑ѧ глаго́лющїи ꙗ҆влѧ́ютсѧ, ꙗ҆́кѡ ѻ҆те́чествїѧ взыскꙋ́ютъ. и҆ а҆́ще бы ᲂу҆́бѡ ѻ҆́но по́мнили, и҆з̾ негѡ́же и҆зыдо́ша, и҆мѣ́ли бы вре́мѧ возврати́тисѧ: ны́нѣ же лꙋ́чшагѡ жела́ютъ, си́рѣчь нбⷭ҇нагѡ. тѣ́мже не стыди́тсѧ си́ми бг҃ъ, бг҃ъ нарица́тисѧ и҆́хъ: ᲂу҆гото́ва бо и҆̀мъ гра́дъ. ",
}

add_apostol {
  ["номер"] = 328,
  ["комментарий"] = "Евр., 328 зач., XI, 9–10, 17–23, 32–40.",
  ["текст_ру"] = "Бра́тие, ве́рою прии́де Авраа́м на зе́млю обетова́ния, я́коже на чу́жду, в кро́вы всели́ся со Исаа́ком и Иа́ковом, снасле́дникома обетова́ния того́жде. Жда́ше бо основа́ния иму́щаго гра́да, ему́же худо́жник и соде́тель Бог. Ве́рою приведе́ Авраа́м Исаа́ка искуша́емь, и единоро́днаго приноша́ше, обетова́ния прие́мый. К нему́же глаго́лано бысть: я́ко о Исаа́це нарече́т ти ся се́мя. Помы́слив, я́ко и из ме́ртвых воскреси́ти си́лен есть Бог, те́мже того́ и в при́тчи прия́т. Ве́рою о гряду́щих благослови́ Исаа́к Иа́кова и Иса́ва. Ве́рою, Иа́ков умира́я, коего́ждо сы́на Ио́сифова благослови́, и поклони́ся на верх жезла́ его́. Ве́рою, Ио́сиф умира́я, о исхожде́нии сыно́в Изра́илевых па́мятствова, и о косте́х свои́х запове́да. Ве́рою Моисе́й роди́вся сокрове́н бысть три ме́сяцы от оте́ц свои́х, зане́ ви́деша красно́ отроча́, и не убоя́шася повеле́ния царе́ва. И что еще́ глаго́лю? Не доста́нет бо ми повеству́ющу ле́та о Гедео́не, Вара́це же и Сампсо́не, и Иеффа́и, о Дави́де же и Самуи́ле, и о други́х проро́цех, и́же ве́рою победи́ша ца́рствия, соде́яша пра́вду, получи́ша обетова́ния, загради́ша уста́ львов, угаси́ша си́лу о́гненную, избего́ша о́стрея меча́, возмого́ша от не́мощи, бы́ша кре́пцы во бране́х, обрати́ша в бе́гство полки́ чужи́х. Прия́ша жены́ от воскресе́ния ме́ртвыя своя́, ини́и же избие́ни бы́ша, не прие́мше избавле́ния, да лу́чшее воскресе́ние улуча́т. Друзи́и же руга́нием и ра́нами искуше́ние прия́ша, еще́ же и уз, и темни́ц. Ка́мением побие́ни бы́ша, претре́ни бы́ша, искуше́ни бы́ша, уби́йством меча́ умро́ша, проидо́ша в ми́лотех и в ко́зиях ко́жах, лише́ни, скорбя́ще, озло́блени. И́хже не бе досто́ин весь мир, в пусты́нях скита́ющеся, и в гора́х, и в верте́пах, и в про́пастех земны́х. И си́и вси послу́шествани бы́вше ве́рою, не прия́ша обетова́ния, Бо́гу лу́чшее что о нас предзре́вшу, да не без нас соверше́нство прии́мут. ",
  ["текст_цс"] = "Бра́тїе, вѣ́рою прїи́де а҆враа́мъ на зе́млю ѡ҆бѣтова́нїѧ, ꙗ҆́коже на чꙋ́ждꙋ, въ кро́вы всели́сѧ, со і҆саа́комъ и҆ і҆а́кѡвомъ, снаслѣ́дникома ѡ҆бѣтова́нїѧ тогѡ́жде. жда́ше бо ѡ҆снова́нїѧ и҆мꙋ́щагѡ гра́да, є҆мꙋ́же хꙋдо́жникъ и҆ содѣ́тель бг҃ъ. вѣ́рою приведѐ а҆враа́мъ і҆саа́ка, и҆скꙋша́емь: и҆ є҆диноро́днаго приноша́ше, ѻ҆бѣтова̑нїѧ прїе́мый. къ немꙋ́же глаго́лано бы́сть: ꙗ҆́кѡ ѡ҆ і҆саа́цѣ нарече́тъ ти сѧ сѣ́мѧ. помы́сливъ, ꙗ҆́кѡ и҆ и҆з̾ ме́ртвыхъ воскреси́ти си́ленъ є҆́сть бг҃ъ: тѣ́мже того̀ и҆ въ при́тчи прїѧ́тъ. вѣ́рою ѡ҆ грѧдꙋ́щихъ бл҃гословѝ і҆саа́къ і҆а́кѡва, и҆ и҆са́ѵа. вѣ́рою, і҆а́кѡвъ ᲂу҆мира́ѧ, коего́ждо сы́на і҆ѡ́сифова бл҃гословѝ, и҆ поклони́сѧ на ве́рхъ жезла̀ є҆гѡ̀. вѣ́рою, і҆ѡ́сифъ ᲂу҆мира́ѧ, ѡ҆ и҆схожде́нїи сынѡ́въ і҆и҃левыхъ па́мѧтствова, и҆ ѡ҆ косте́хъ свои́хъ заповѣ́да. вѣ́рою мѡѷсе́й роди́всѧ, сокрове́нъ бы́сть трѝ мцⷭ҇ы ѿ ѻ҆тє́цъ свои́хъ: занѐ ви́дѣша красно̀ ѻ҆троча̀, и҆ не ᲂу҆боѧ́шасѧ повелѣ́нїѧ царе́ва. и҆ что̀ є҆щѐ глаго́лю; не доста́нетъ бо мѝ повѣствꙋ́ющꙋ лѣ́та, ѡ҆ гедеѡ́нѣ, вара́цѣ же и҆ самѱѡ́нѣ, и҆ і҆ефѳа́и: ѡ҆ дв҃дѣ же, и҆ самꙋи́лѣ, и҆ ѡ҆ [дрꙋги́хъ] проро́цѣхъ: и҆́же вѣ́рою побѣди́ша ца́рствїѧ, содѣ́ѧша пра́вдꙋ, полꙋчи́ша ѡ҆бѣтова̑нїѧ, загради́ша ᲂу҆ста̀ львѡ́въ: ᲂу҆гаси́ша си́лꙋ ѻ҆́гненнꙋю, и҆збѣго́ша ѻ҆́стреѧ меча̀, возмого́ша ѿ не́мощи, бы́ша крѣ́пцы во бране́хъ, ѡ҆брати́ша въ бѣ́гство полкѝ чꙋжи́хъ. прїѧ́ша жєны̀ ѿ воскресе́нїѧ мє́ртвыѧ своѧ̀: и҆ні́и же и҆збїе́ни бы́ша, не прїе́мше и҆збавле́нїѧ, да лꙋ́чшее воскрⷭ҇нїе ᲂу҆лꙋча́тъ: дрꙋзі́и же рꙋга́нїемъ и҆ ра́нами и҆скꙋше́нїе прїѧ́ша, є҆ще́ же и҆ ᲂу҆́зъ и҆ темни́цъ. ка́менїемъ побїе́ни бы́ша, претре́ни бы́ша, и҆скꙋше́ни бы́ша, ᲂу҆бі́йствомъ меча̀ ᲂу҆мро́ша: проидо́ша въ ми́лѡтехъ, и҆ въ ко́зїѧхъ ко́жахъ, лише́ни, скорбѧ́ще, ѡ҆ѕло́блени: и҆́хже не бѣ̀ досто́инъ [ве́сь] мі́ръ, въ пꙋсты́нѧхъ скита́ющесѧ, и҆ въ гора́хъ, и҆ въ верте́пахъ, и҆ въ про́пастехъ земны́хъ. и҆ сі́и всѝ послꙋ́шествовани бы́вше вѣ́рою, не прїѧ́ша ѡ҆бѣтова́нїѧ: бг҃ꙋ лꙋ́чшее что̀ ѡ҆ на́съ предзрѣ́вшꙋ, да не без̾ на́съ соверше́нство прїи́мꙋтъ. ",
}

