add_apostol {
  ["номер"] = 331,
  ["комментарий"] = "Евр., 331 зач., XII, 1–10.",
  ["текст_ру"] = "Бра́тие, толи́к иму́ще облежа́щь нас о́блак свиде́телей, го́рдость вся́ку отло́жше и удо́бь обстоя́тельный грех, терпе́нием да тече́м на предлежа́щий нам по́двиг, взира́юще на нача́льника ве́ры и соверши́теля Иису́са, И́же вме́сто предлежа́щия Ему́ ра́дости претерпе́ крест, о срамоте́ неради́в, одесну́ю же престо́ла Бо́жия се́де. Помы́слите у́бо таково́е Пострада́вшаго от гре́шник на Себе́ прекосло́вие, да не стужа́ете, душа́ми свои́ми ослабля́еми. Не у до кро́ве ста́сте, проти́ву греха́ подвиза́ющеся, и забы́сте утеше́ние, е́же вам я́ко сыно́м глаго́лет: сы́не мой, не пренемога́й наказа́нием Госпо́дним, ниже́ ослабе́й, от Него́ облича́емь. Его́же бо лю́бит Госпо́дь, наказу́ет, бие́т же вся́каго сы́на, его́же прие́млет. А́ще наказа́ние терпите́, я́коже сыново́м обрета́ется вам Бог. Кото́рый бо есть сын, его́же не наказу́ет оте́ц? А́ще же без наказа́ния есте́, ему́же прича́стницы бы́ша вси, у́бо прелюбоде́йчищи есте́, а не сы́нове. К сим, пло́ти на́шей отца́ име́хом наказа́теля, и срамля́хомся, не мно́го ли па́че повине́мся Отцу́ духово́м, и жи́ви бу́дем? Они́ бо в ма́ло дней, я́коже го́де им бе, нака́зоваху нас, а Сей на по́льзу, да причасти́мся святы́ни Его́. ",
  ["текст_цс"] = "Бра́тїе, толи́къ и҆мꙋ́ще ѡ҆блежа́щъ на́съ ѻ҆́блакъ свидѣ́телей, го́рдость всѧ́кꙋ ѿло́жше, и҆ ᲂу҆до́бь ѡ҆бстоѧ́тельный грѣ́хъ, терпѣ́нїемъ да тече́мъ на предлежа́щїй на́мъ по́двигъ: взира́юще на нача́льника вѣ́ры, и҆ соверши́телѧ і҆и҃са, и҆́же вмѣ́стѡ предлежа́щїѧ є҆мꙋ̀ ра́дости, претерпѣ̀ крⷭ҇тъ, ѡ҆ срамотѣ̀ неради́въ, ѡ҆деснꙋ́ю же престо́ла бж҃їѧ сѣ́де. помы́слите ᲂу҆́бѡ таково́е пострада́вшагѡ ѿ грѣ̑шникъ на себѐ прекосло́вїе, да не стꙋжа́ете сѝ, дꙋша́ми свои́ми ѡ҆слаблѧ́еми. не ᲂу҆̀ до кро́ве ста́сте, проти́вꙋ грѣха̀ подвиза́ющесѧ, и҆ забы́сте ᲂу҆тѣше́нїе, є҆́же ва́мъ ꙗ҆́кѡ сынѡ́мъ глаго́летъ: сн҃е мо́й, не пренемога́й наказа́нїемъ гдⷭ҇нимъ, нижѐ ѡ҆слабѣ́й ѿ негѡ̀ ѡ҆блича́емь. є҆го́же бо лю́битъ гдⷭ҇ь, наказꙋ́етъ: бїе́тъ же всѧ́каго сы́на, є҆го́же прїе́млетъ. а҆́ще наказа́нїе терпитѐ, ꙗ҆́коже сыновѡ́мъ ѡ҆брѣта́етсѧ ва́мъ бг҃ъ. кото́рый бо є҆́сть сы́нъ, є҆гѡ́же не наказꙋ́етъ ѻ҆ц҃ъ; а҆́ще же без̾ наказа́нїѧ є҆стѐ, є҆мꙋ́же прича́стницы бы́ша всѝ, ᲂу҆̀бо прелюбодѣ́йчищи є҆стѐ, а҆ не сы́нове. къ си́мъ, пло́ти на́шей ѻ҆ц҃а̀ и҆мѣ́хомъ наказа́телѧ, и҆ срамлѧ́хомсѧ: не мно́гѡ ли па́че повине́мсѧ ѻ҆ц҃ꙋ̀ дꙋховѡ́мъ, и҆ жи́ви бꙋ́демъ; ѻ҆ни́ бо въ ма́лѡ дне́й, ꙗ҆́коже го́дѣ и҆̀мъ бѣ̀, нака́зовахꙋ на́съ, а҆ се́й на по́льзꙋ, да причасти́мсѧ ст҃ы́ни є҆гѡ̀. ",
}

add_apostol {
